-- Parte 19
<p>
 <em><span><span _msthash="570" _msttexthash="20591350">Mio Dio, sull’esempio di Maria, aiutami a dire di sì alla tua chiamata e a credere che tu puoi operare l’impossibile nella mia vita!</span></span></em></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-08';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="564" _msttexthash="1454481379">
 <span><font _msthash="593" _mstmutation="1" _msttexthash="448871085">Tra i tanti spunti che il Vangelo di oggi ci dona, quello che vogliamo sottolineare è la fede degli amici di questo paralitico. Noi abbiamo bisogno della fede degli altri. Tutti noi nel cammino di questa vita abbiamo bisogno degli altri. Ammetterlo, accettarlo non è un segno di debolezza, ma di consapevolezza! Tante volte, incontrando gli ammalati, ciò che colpisce è che ciò di cui soffrono non è solo la malattia in sé, ma anche il fatto di doversi far aiutare, di non essere autosufficienti, di sentirsi un peso per gli altri. Ma il sogno mondano dell''autonomia esasperata in realtà è una piccola trappola. Chi non accetta di farsi aiutare dagli altri non cresce, rimane chiuso in se stesso e nel suo mondo. In fondo, anche Gesù ha avuto bisogno del cireneo che lo aiutasse a portare la croce lungo il cammino verso il Golgota. Gli amici di questo paralitico hanno fede, non vedono il loro amico come un pesante fardello da portare ma come un fratello da aiutare! </font><font _msthash="610" _mstmutation="1" _msttexthash="290717453"><em _mstmutation="1">«Averne di amici come questi: persone che non si accontentano di commiserarti, ma che si rimboccano le maniche e ti portano a Cristo! Averne di amici che si inventano una soluzione per superare le difficoltà che il mondo frappone alla vera conoscenza di Dio!»</em><font _msthash="625" _mstmutation="1" _msttexthash="128475061"> Loro credono che Gesù possa guarire il loro amico. E Gesù che fa? Grazie alla loro fede fa un dono molto più grande: oltre a guarirlo fisicamente, perdonandolo lo guarisce interiormente, donandogli la salvezza! Davanti a tutto ciò ci farà bene chiederci: mi lascio aiutare-portare dagli altri? Mi lascio perdonare dai miei peccati? E viceversa: cerco di portare gli altri a Gesù? Prego per gli altri e propongo loro, a tempo debito e in modo opportuno, di lasciarsi perdonare e guarire interiormente da Gesù?</font></font></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-09';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="641" _msttexthash="4484531766">
 <span><span><em _msthash="674" _msttexthash="4462648034">«I santi non sono uomini a cui è stata risparmiata la tentazione, bensì persone ben coscienti del fatto che nella vita si affacciano ripetutamente le seduzioni del male, da smascherare e da respingere. Tutti noi abbiamo esperienza di questo, tutti noi: che ti viene un cattivo pensiero, che ti viene un desiderio di fare questo o di sparlare dell''altro... Tutti, tutti siamo tentati, e dobbiamo lottare per non cadere in queste tentazioni. Se qualcuno di voi non ha tentazioni lo dica, perché sarebbe una cosa straordinaria! Ci sono tante persone che si autoassolvono, che reputano di essere "a posto" – "No, io sono bravo, sono brava, io non ho questi problemi". Ma nessuno di noi è a posto; se qualcuno si sente a posto, sta sognando; ognuno di noi ha tante cose da aggiustare, e ha pure da vigilare. E a volte succede che andiamo al sacramento della Riconciliazione e diciamo, con sincerità: "Padre, io non ricordo, non so se ho dei peccati...". Ma questo è mancanza di conoscenza di ciò che succede nel cuore. Tutti siamo peccatori, tutti. E un po'' di esame di coscienza, un po'' di sguardo interiore ci farà bene. Altrimenti rischiamo di vivere nelle tenebre, perché ormai ci siamo assuefatti al buio e non sappiamo più distinguere il bene dal male. Isacco di Ninive diceva che nella Chiesa chi conosce i propri peccati e li piange è più grande di chi risuscita un morto. Tutti dobbiamo chiedere a Dio la grazia di riconoscerci poveri peccatori, bisognosi di conversione, conservando nel cuore la fiducia che nessun peccato è troppo grande per l''infinita misericordia di Dio Padre. E questa è una cosa bella. "Padre, ho tanti peccati!" – "Ma Gesù è con te: parlane, Lui ti aiuterà a uscirne". Gesù mai ci lascia da soli, mai! Pensate bene questo. "Oh, Padre, io ne ho fatte delle grosse!" – "Ma Gesù ti capisce e ti accompagna: capisce il tuo peccato e lo perdona". Mai dimenticare questo! Nei momenti più brutti, nei momenti in cui scivoliamo sui peccati, Gesù è accanto a noi per aiutarci a sollevarci. Questo dà consolazione. Non dobbiamo perdere questa certezza: Gesù è accanto a noi per aiutarci, per proteggerci, anche per rialzarci dopo il peccato. "Ma, Padre, è vero che Gesù perdona tutto?" – "Tutto. Lui è venuto per perdonare, per salvare. Soltanto, Gesù vuole il tuo cuore aperto". Mai Lui si dimentica di perdonare: siamo noi, tante volte, che perdiamo la capacità di chiedere perdono. Riprendiamo questa capacità di chiedere perdono. Ognuno di noi ha tante cose per cui chiedere perdono: ognuno la pensi dentro di sé, e oggi ne parli con Gesù. Parli con Gesù su questo: "Signore, io non so se questo è vero o no, ma io sono certo che Tu non ti allontani da me. Sono certo che Tu mi perdoni. Signore, io sono peccatore, peccatrice, ma per favore non allontanarti". Questa sarebbe oggi una bella preghiera a Gesù: "Signore, non allontanarti da me"» (papa Francesco).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-09';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="3274934832">
 <span><font _msthash="594" _mstmutation="1" _msttexthash="1316854448">Oggi Gesù ci parla di misericordia, della sua misericordia e di ciò che lo rallegra! Ma a noi, che abbiamo una diversa concezione di misericordia e di gioia da vivere, abituati a fare sempre calcoli su ciò che conviene e su ciò che non conviene, potrebbe sembrare alquanto strano il suo modo di agire! Quale pastore prudente metterebbe a repentaglio novantanove pecore, lasciandole sui monti, per andare in cerca di quella che si è smarrita? Non sembra certo conveniente correre questo pericolo! Eppure Gesù non vuole che neanche una di queste pecorelle si smarrisca, cioè Gesù non vuole che nemmeno uno di noi vada perduto, neanche il più incallito dei peccatori. Egli non si stanca mai di cercare chi si è allontanato da Lui. Non è nel suo vocabolario perdere qualcuno! Quanta differenza col nostro comportamento. Noi, infatti, siamo quelli che si stancano di cercare gli altri; anzi, spesso siamo di quelli che preferiscono perdere un fratello o una sorella piuttosto che un pezzo di terra o una parte di eredità. Quante volte ci capita anche di dire: "lascia perdere quella persona", "ormai non c''è più niente da fare"; "l''ha fatta troppo grossa", "non merita il perdono". Quante volte, la nostra mancanza di compassione, di incomprensioni, di ferite subite e mai affrontate, portano all''indurimento del cuore, a quella sklerocardìa che si sperimenta quando il cuore si indurisce verso il nostro prossimo, quando si diventa indifferenti verso l''altro, rancorosi o persino desiderosi e soddisfatti per la sofferenza dell''altro. Ecco allora il rimedio offertoci da Gesù, dal suo esempio, dalle sue parole. Sembrano difficili da comprendere? </font></span></p>
<p _msthash="565" _msttexthash="3274934832">
 <span><font _msthash="619" _mstmutation="1" _msttexthash="438644947"><em _msthash="644" _mstmutation="1" _msttexthash="373217013">Una volta una donna, che non riusciva a capire questa parabola, si rivolse al sacerdote dicendogli: "certo che è proprio strano questo pastore! Che convenienza c''è nel lasciare novantanove pecore da sole, col rischio che si perdano, per andare in cerca di una sola, di quella che si è smarrita! Il sacerdote, guardando questa donna anziana, le disse: "signora, lei quanti figli ha? " Sette", le rispose la donna. Bene, continuò il presbitero: "immagini che un treno stia per partire per un paese lontano senza viaggio di ritorno, e di questi suoi figli ne manchi uno, il più problematico, quello che le ha dato più problemi; lei che fa? Parte in treno senza questo suo figlio, sapendo che non lo vedrà mai più, o lo va a cercare disperatamente?". All''udir queste parole, questa donna chiaramente toccata nel cuore e con le lacrime agli occhi, rispose: "Ora ho capito questa parabola!".</em> </font></span></p>
<p _msthash="565" _msttexthash="3274934832">
 <span><font _msthash="619" _mstmutation="1" _msttexthash="438644947">Ecco, le parole del Signore le capisce bene chi ama. E noi le comprendiamo?</font></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-10';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="650" _msttexthash="2465597173">
 <span><em><span _msthash="683" _msttexthash="2453153963"> «Figlio carissimo, prima di tutto ti esorto ad amare il Signore Dio tuo con tutto il cuore e con tutte le tue forze. Senza di questo non c''è salvezza. Figlio, devi tenerti lontano da tutto ciò che può dispiacere a Dio, cioè da ogni peccato mortale. È preferibile che tu sia tormentato da ogni genere di martirio, piuttosto che commettere un peccato mortale. Inoltre, se il Signore permetterà che tu abbia qualche tribolazione, devi ringraziando, e sopportarla volentieri, pensando che concorre al tuo bene. Se poi il Signore ti darà qualche prosperità, non solo lo dovrai umilmente ringraziare, ma bada bene a non diventar peggiore per vanagloria o in qualunque altro modo, bada cioè a non entrare in contrasto con Dio o offenderlo con i suoi doni stessi. Partecipa devotamente e volentieri alle celebrazioni della Chiesa. Non guardare distrattamente in giro e non abbandonarti alle chiacchiere, ma prega il Signore con raccoglimento, sia con la bocca che con il cuore. Abbi un cuore pietoso verso i poveri, i miserabili e gli afflitti. Per quanto sta in te, soccorrili e consolali. Ringrazia Dio di tutti i benefici che ti ha elargiti, perché tu possa renderti degno di riceverne dei maggiori. Verso i tuoi sudditi comportati con rettitudine, in modo tale da essere sempre sul sentiero della giustizia, senza declinare né a destra né a sinistra. Sta'' sempre piuttosto dalla parte del povero anziché del ricco, fino a tanto che non sei certo della verità. Abbi premurosa cura che tutti i tuoi sudditi si mantengano nella giustizia e nella pace, specialmente le persone ecclesiastiche e religiose. Sii devoto e obbediente alla Chiesa Romana, madre nostra, e al Sommo Pontefice come a padre spirituale. Procura che venga allontanato dal tuo territorio ogni peccato, e specialmente la bestemmia e le eresie. Figlio carissimo, ti do infine tutte quelle benedizioni che un buon padre può dare al figlio. La Trinità e tutti i santi ti custodiscano da ogni male. Il Signore ti dia la grazia di fare la sua volontà, perché riceva onore e gloria per mezzo tuo e, dopo questa vita, conceda a tutti noi di giungere insieme a vederlo, amarlo e lodarlo senza fine. Amen» (Lettera testamentaria del re francese san Ludovico al figlio Filippo, suo successore al trono).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-10';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="1598810343">
 <span><font _msthash="594" _mstmutation="1" _msttexthash="987339314">«Venite a me, voi tutti che siete stanchi e oppressi, e io vi darò ristoro». È chiaro come Gesù, con queste parole, si stia rivolgendo a coloro che sono oppressi dalla fatica, dalla stanchezza di chi è fuori dalla volontà di Dio. Infatti c''è stanchezza e stanchezza. Quante volte un consacrato, una mamma, un papà alla fine della giornata sono stanchi, ma è una stanchezza benedetta, è una stanchezza che porta al cielo, è la stanchezza di chi si è speso per il bene dell''altro. Diversa invece è la stanchezza di chi ha escluso Dio dalla propria vita, di chi si affanna per le cose di questo mondo, di chi fa del proprio lavoro, del successo, del potere, del denaro il proprio dio. Quanti giovani sono spesso stanchi e oppressi perché si ostinano su vie, su progetti che Dio non ha pensato per loro. Non è forse l''esperienza che fa Pietro dopo la morte di Gesù e prima di averlo visto risorto? Egli, chiamato dal Signore ad essere pescatore di anime, ritorna ad essere pescatore di semplici pesci. Il risultato dopo una dura notte di lavoro? Pietro non pesca nulla! È proprio qui che Pietro deve fare l''esperienza di tornare alla chiamata divina perché la sua fatica diventi benedetta e fruttuosa! Domandiamoci dunque se la nostra stanchezza è benedetta perché stiamo lavorando nella vigna del Signore o se siamo affaticati ma anche oppressi perché fuori dalla volontà di Dio! Facciamo dunque nostre queste parole del profeta Aggeo: </font><em>«Riflettete bene sul vostro comportamento! Avete seminato molto, ma avete raccolto poco; avete mangiato, ma non da togliervi la fame; avete bevuto, ma non fino a inebriarvi; vi siete vestiti, ma non vi siete riscaldati; l''operaio ha avuto il salario, ma per metterlo in un sacchetto forato. Così dice il Signore degli eserciti: Riflettete bene sul vostro comportamento» (Aggeo, 1,6-7).</em></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-11';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="624" _msttexthash="427805261">
 <span><span><em _msthash="657" _msttexthash="431645643">«Imparate da me che sono mite e umile di cuore. Andare tutti a scuola di cuore! Tutti a imparare il cuore di Dio! Imparate da me, dal mio modo, delicato, senza violenza e senza arroganza. Il mio giogo è dolce e il mio peso è leggero. Un giogo: che cosa è oltre il ricordo degli animali da tiro, la loro grande fatica? È una metafora che non sentiamo amica: abbiamo fatto di tutto per scuoterceli di dosso, i gioghi. Gesù però dice: il mio giogo... Il giogo resta il suo. A me dice: "amico d''avventura, siamo in due; non sei solo, inchiodato alla fatica del vivere, del prenderti cura di qualcuno". Don Tonino Bello immaginava: «Siamo angeli con un''ala soltanto e possiamo volare solo abbracciati». Gesù è l''altra mia ala, il mio ''cireneo'', il vero maestro che non dà ulteriori obblighi, ma ulteriori ali. Prendete il mio giogo, cioè prendete su di voi l''antica novità del vangelo, che non proibisce mai ciò che all''uomo dà gioia e vita» (p. Ermes Ronchi).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-11';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="564" _msttexthash="484675698">
 <span><font _msthash="593" _mstmutation="1" _msttexthash="358224412">«Il regno dei cieli subisce violenza e i violenti se ne impadroniscono». Certo, con questa frase, erroneamente interpretata, potremmo giustificare tutti quei momenti in cui ci arrabbiamo con gli altri, e a volte lo facciamo! Ma la nostra battaglia non è contro gli altri, ma con ciò che di malato c''è nel nostro cuore. Sì, per entrare nel regno di Dio bisogna usare violenza non contro gli altri ma contro noi stessi! Occorre dirci dei sani no quando ciò che desideriamo, pensiamo o stiamo per fare è sbagliato. Non bisogna mai dimenticare che ogni azione porta una conseguenza. Nella vita spirituale non esistono "azioni neutre", o si migliora, o si peggiora. Per questo, Padre Pio diceva che nella vita spirituale fermarsi equivale ad indietreggiare. Chiediamo la grazia al Signore che ci aiuti ogni giorno a fare un piccolo passo nel bene, ricordandoci che: </font><em _msthash="610" _msttexthash="10201282">«a volte fare il bene all''inizio costa, ma dopo ti ripaga. Fare il male invece all''inizio non costa nulla, ma dopo lo paghi caro» (p. S. Fausti).</em> </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-12';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="616" _msttexthash="284584690">
 <span><em><span _msthash="665" _msttexthash="286800956">«Questa santità a cui il Signore ti chiama andrà crescendo mediante piccoli gesti. Per esempio: una signora va al mercato a fare la spesa, incontra una vicina e inizia a parlare, e vengono le critiche. Ma questa donna dice dentro di sé: "No, non parlerò male di nessuno". Questo è un passo verso la santità. Poi, a casa, suo figlio le chiede di parlare delle sue fantasie e, anche se è stanca, si siede accanto a lui e ascolta con pazienza e affetto. Ecco un''altra offerta che santifica. Quindi sperimenta un momento di angoscia, ma ricorda l''amore della Vergine Maria, prende il rosario e prega con fede. Questa è un''altra via di santità. Poi esce per strada, incontra un povero e si ferma a conversare con lui con affetto. Anche questo è un passo avanti» (papa Francesco).</span></em></span></p>
<p _msthash="616" _msttexthash="284584690">
 <span><em><span><font _msthash="701" _mstmutation="1" _msttexthash="546260">BEATA VERGINE MARIA DI GUADALUPE</font></span></em></span></p>
<div>
 <span><em><span><span _msthash="699" _msttexthash="14843699">Oggi è la memoria (facoltativa) della Madonna di Guadalupe. Soffermiamoci sulla sua misteriosa immagine comparsa miracolosamente sulla tilma di san Juan Diego. </span></span></em></span></div>
<div>
 <span><em><span><span _msthash="698" _msttexthash="21051134">1.Studi oftalmologici realizzati sugli occhi di Maria hanno scoperto che avvicinando loro la luce, la retina si contrae e ritirando la luce, torna a dilatarsi, esattamente come accade a un occhio vivo.</span></span></em></span></div>
<div>
 <span><em><span><span _msthash="697" _msttexthash="15832596">2.La temperatura della fibra di maguey (ricavata da una pianta) con cui è costruito il mantello mantiene una temperatura costante di 36.6 gradi, la stessa di una persona viva.</span></span></em></span></div>
<div>
 <span><em><span><span _msthash="696" _msttexthash="36842312">3.Uno dei medici che analizzò il manto collocò il suo stetoscopio sotto il nastro con fiocchi che Maria ha intorno alla vita (segnale che è incinta) e ascoltò battiti che si ripetevano ritmicamente, contò 115 pulsazioni al minuto, come per un bebè nel ventre materno. </span></span></em></span></div>
<div>
 <span><em><span><span _msthash="695" _msttexthash="126468316">4.Non si è scoperto nessun tratto di pittura sulla tela. In realtà, a una distanza di 10 centimetri dall''immagine, si vede solo la tela cruda: i colori scompaiono. Studi scientifici non riescono a scoprire l''origine della colorazione che forma l''immagine, né la forma in cui la stessa è stata dipinta. Non si riscontrano tracce di pennellate né di altra tecnica conosciuta. Gli scienziati della NASA affermarono che il materiale che origina i colori non è nessuno degli elementi conosciuti sulla Terra.</span></span></em></span></div>
<div>
 <span><em><span><span _msthash="694" _msttexthash="46030114">5.Si è fatto passare un raggio laser lateralmente sopra la tela, e si è evidenziato che la colorazione non è né al dritto né al rovescio, ma che i colori fluttuano a una distanza di tre decimi di millimetro sopra il tessuto, senza toccarlo. I colori fluttuano nell''aria, sopra la superficie del Mantello.</span></span></em></span></div>
<div>
 <span><em><span><span _msthash="693" _msttexthash="82050098">6.La fibra di maguey che costituisce la tela dell''immagine, non può durare più di 20 o 30 anni. Vari secoli fa si dipinse una replica dell''immagine su una tela di fibra di maguey simile, e la stessa si disintegrò dopo alcuni decenni. Mentre, a quasi 500 anni dal miracolo, l''immagine di Maria continua a essere perfetta come il primo giorno. La scienza non si spiega l''origine dell''incorruttibilità della tela.</span></span></em></span></div>
<div>
 <span><em><span><span _msthash="692" _msttexthash="23233730">7.Nell''anno 1791 si rovesciò accidentalmente acido muriatico sul lato superiore destro della tela. In un lasso di 30 giorni, senza nessun trattamento, se ricostituì miracolosamente il tessuto danneggiato.</span></span></em></span></div>
<div>
 <span><em><span><span _msthash="691" _msttexthash="19512103">8.Le stelle visibili nel Manto di Maria riflettono l’esatta configurazione e posizione del cielo che il Messico presentava nel giorno in cui avvenne il miracolo.</span></span></em></span></div>
<div>
 <span><em><span><span _msthash="690" _msttexthash="29534206">9.All''inizio del secolo XX, un uomo nascose una bomba ad alto potenziale in un arredo floreale, che collocò ai piedi della Tela. L''esplosione distrusse tutto ciò che era intorno, meno la Tela, che rimase in perfetto stato di conservazione.</span></span></em></span></div>
<div>
 <span><em><span><span _msthash="689" _msttexthash="15880072">10. La scienza scoprì che gli occhi di Maria possiedono i tre effetti di refrazione dell’immagine di un occhio umano.</span></span></em></span></div>
<p _msthash="933" _msttexthash="148150418">
 <span><em><span><span _istranslated="1" _msthash="688" _msttexthash="148150418">11. Nelle pupille di Maria (di soli 7,8 mm) si sono scoperte minute immagini umane, che nessun artista avrebbe mai potuto dipingere. Sono due scene e si ripetono in tutte e due gli occhi. L''immagine del vescovo Zumárraga negli occhi di Maria fu ingrandita mediante tecnologia digitale, e ha rivelato che nei suoi occhi è ritratta l''immagine dell''indio Juan Diego, che apre la sua Tilma davanti al vescovo. La misura di questa immagine? la quarta parte di un milionesimo di millimetro. </span>(https://tanogabo.com/il-mantello-della-vergine-di-guadalupe/).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-12';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo di oggi ci dice che vi sono diversi atteggiamenti da bambini. Vi sono adulti che somigliano a quei bambini che accolgono il Regno di Dio con stupore, con gioia, che non hanno malizia, sanno subito perdonare, si sanno fidare e affidare. Ma vi sono adulti non cresciuti simili a certi bambini lamentosi e viziati: non sono mai contenti di ciò che hanno, vogliono tutto, anche quello che appartiene agli altri. Non sanno gioire, non sanno accogliere con letizia le difficoltà che la vita presenta, la loro vita è tutto un lamento. Ho incontrato una persona che in un’ora si è lamentata per circa cinquanta minuti di medici e infermieri, piangendosi addosso per ogni suo acciacco! Mi domando: come è possibile scegliere di vivere così male!? Forse anche noi siamo di quelli che si lamentano spesso? Per quale fatto della vita ci lamentiamo? Sappiamo offrire al Signore le nostre difficoltà per il bene nostro e di tanti altri? Non dimentichiamo mai che la sofferenza, le incomprensioni, le difficoltà della vita sono una grande opportunità, possiamo coglierla o sprecarla. Possiamo sempre e solo lamentarci o possiamo farne luogo di grazia e di incontro con il Signore. E poi, in fondo, a che serve sempre lamentarsi delle cose che non ci piacciono? Forse solo per il fatto di lamentarsi migliorano? No, anzi, con questo atteggiamento lamentoso cambia sì qualcosa: cambiamo noi ma in peggio!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-13';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Tante volte noi ci lamentiamo delle difficoltà che abbiamo: il diavolo vuole che noi cadiamo nello spirito di tristezza, amareggiati della vita o dei propri peccati. Ho conosciuto una persona consacrata a Dio che chiamavano “Lamentela”, perché non riusciva a fare altra cosa che lamentarsi: era il premio Nobel delle lamentele. Ma quante volte noi ci lamentiamo…» (papa Francesco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-13';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="564" _msttexthash="1614452840">
 <span _msthash="579" _msttexthash="1599773227">Gesù è il compimento delle profezie, è il Figlio promesso e mandato dal Padre. Ma Gesù deve spiegare ai suoi discepoli, ancora incapaci di comprendere come questa profezia si è compiuta, che Elia è già venuto ma non come loro se lo aspettavano. Il dialogo tra Gesù e i suoi discepoli ci dice tutta la difficoltà nel comprendere l''agire di Dio o, almeno, la grande difficoltà che abbiamo quando ci aspettiamo prodigi e segni eclatanti da parte del Signore che attestino la sua presenza viva nella storia. Noi abbiamo spesso una grande difficoltà a scorgere il filo rosso, apparentemente quasi nascosto, che lega certi eventi che viviamo nella vita. Pensiamo siano cose fortuite, prive di senso, semplici coincidenze, quando invece la mano sapiente di Dio sta conducendo la storia. Tutti quanti siamo un pochino come san Tommaso: vogliamo toccare per credere. Vorremmo comprendere le cose ma senza la fatica di cercare la verità. Vorremmo delle prove, dei segni che ci togliessero la possibilità di dire dei sì o dei no. <em _msthash="580" _msttexthash="13033319">«Ma la verità è che i segni sono solo segni, e molto spesso ci lasciano talmente tanto liberi da poterli persino ignorare o bistrattare» (don Luigi M. Epicoco)</em>. C''è bisogno di una grande sensibilità interiore nell''accorgerci del passaggio di Dio nella nostra vita. Lo stesso sant''Agostino così scrive: <em _msthash="595" _msttexthash="1747343">«Signore ho paura che tu passi e io non me ne accorga».</em> Noi spesso viviamo nel caos, sempre affannati, sempre a correre ma senza comprendere dove stiamo andando, se la strada che stiamo percorrendo è quella che il Signore ha tracciato per noi. Che la parola di oggi ci stimoli a curare un po'' di più la nostra vita interiore, ritagliandoci spazi di preghiera, di silenzio e di intimità con il Signore, per diventare sempre più attenti e sensibili ai suoi passaggi nella nostra vita e nella storia.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-14';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="609" _msttexthash="101544391">
 <span><span><em _msthash="642" _msttexthash="103657463">«I grandi santi hanno questo di particolare che, trovandosi nel dolore della propria tribolazione, non cessano di occuparsi dell''utilità altrui: e, mentre soffrono in se stessi sopportando le proprie tribolazioni, provvedono agli altri, consigliando quanto loro abbisogna. Sono come dei medici eroici, colpiti da malattia: sopportano le ferite del proprio male e provvedono gli altri di cure e di medicine per la guarigione» (S. Gregorio Magno).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-14';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<div>
 Oggi è la terza domenica di Avvento: viene chiamata “la domenica della gioia”. La Chiesa, nella sua sapienza, ci ricorda che questo tempo di attesa è anche un tempo di gioia perché andiamo incontro a Cristo Signore. «Vedete, esistono notizie consolanti e notizie che salvano. La salvezza che mi porta il Signore, non passa per quello che mi aspetto e che mi consola subito. No, la salvezza è qualcosa che mi fa crescere, è un cammino. La buona notizia non è che un problema mi viene spostato per poco tempo, ma che viene risolto fino in fondo. Noi dobbiamo ricevere questa buona notizia, non una pausa, ma qualcosa che risolve veramente la nostra vita: questo ci porta il gaudio!» (don Fabio Rosini). Noi abbiamo bisogno di accogliere il Signore, Colui che è la nostra gioia. Noi abbiamo bisogno di Colui che dona senso alla nostra vita, abbiamo bisogno di Colui che ci dona la vera vita!</div>
<div>
 Dal Vangelo di oggi vogliamo cogliere due aspetti: iniziare ad operare la giustizia e accogliere il Signore che viene a purificarci. </div>

<div>
 Il Battista proclama un battesimo di conversione, un battesimo che permette di porsi davanti al Signore per poterlo accogliere. Perciò in molti vanno da lui a chiedendogli che cosa debbano fare: «Chi ha due tuniche ne dia a chi non ne ha… chi da mangiare faccia altrettanto… non pretendete di più… non maltrattate». Queste parole del Battista sono un’esortazione al dovere. È come se il Signore, attraverso Giovanni, ci dicesse che in noi vi è un’apertura al bene. Noi possiamo operare una giustizia che non è ancora in pieno l’amore di Dio ma ciò che ci predispone ad accoglierlo. Noi possiamo iniziare a vivere bene, a operare la giustizia, a non maltrattare. In ognuno di noi vi è questa possibilità. La predicazione del Battista si colloca al primo livello della conversione: non fare il male per arrivare al bene. A volte vorremo andare in India ed essere la nuova madre Teresa, vorremo andare a predicare in povertà in giro per il mondo ed essere il nuovo s. Francesco, vorremmo fare chissà quante belle cose, ma poi non siamo capaci o non vogliamo fare ciò che ci tocca fare: aiutare quelli che abbiamo vicino, aprirci al perdono, non coltivare sentimenti di rancore, non essere maldicenti... Ma come possiamo donare tutta la nostra vita se prima non siamo capaci di operare la giustizia, se non smettiamo di fare il male? Perciò, cominciamo a smettere con il male, sforziamoci di compiere qualche opera di giustizia, e così facendo arriverà il di più.</div>
<p>
 Il secondo aspetto è che il Signore, con la sua venuta, ci purifica, ci libera, ci spoglia da tante cose inutili. Infatti Giovanni il Battista dice che viene uno più forte di lui, uno che può fare molto di più, e questi è Cristo Gesù. È Lui che battezza in Spirito Santo e fuoco: «Egli tiene in mano la pala per pulire la sua aia e per raccogliere il frumento nel suo granaio; ma brucerà la paglia con un fuoco inestinguibile». Giovanni Battista usa questa analogia: parla di pala e di ventilabro (che serviva per arieggiare il frumento e liberarlo dalle scorie) per dirci che il Signore viene a liberarci dalle nostre scorie, dalle nostre zavorre. Noi abbiamo tanta paglia, tanti attaccamenti, tanti latenti egoismi, insomma, una “parte” di noi che non è vita che deve essere gettata via, purificata. Ecco, noi non siamo capaci di fare tante cose, ma possiamo accogliere il Signore perché questi possa iniziare a togliere le tante scorie inutili che vi sono nella nostra vita e insegnarci ad amare. </p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-15';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em><span _msthash="681" _msttexthash="94055">PREGHIERA</span></em></span></span></p>
<p _msthash="800" _msttexthash="15518490">
 <span _istranslated="1"><span _istranslated="1"><em _istranslated="1"><span _istranslated="1" _msthash="680" _msttexthash="6966674">Aiutami Signore a vivere questo tempo in un''attesa operativa, colma di opere di giustizia e lontano da ogni male, </span></em></span></span><em _istranslated="1"><span _istranslated="1" _msthash="679" _msttexthash="2054572">per accogliere te che sei il compimento di ogni mia attesa, </span></em><em><span _msthash="678" _msttexthash="1689701">realizzazione di ogni mio desiderio più profondo</span></em><em><span _msthash="677" _msttexthash="546715"> e gioia vera nella mia vita.</span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-15';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="1246464908">
 <span>C''è un detto che dice: <em _msthash="602" _msttexthash="1342848">"non c''è peggior sordo di chi non vuol capire".</em><font _msthash="609" _mstmutation="1" _msttexthash="1135757883"> Il Vangelo di oggi ci mostra la domanda capziosa che i sacerdoti e gli anziani del popolo pongono a Gesù. La loro domanda non è chi di vuol capire ma di vuol avere di che accusare. Sono infastiditi dall''agire di Gesù, le persone lo seguono, insegna con autorità rispetto a loro, non manipola la Parola per scopi egoistici come certi sacerdoti e scribi del tempo facevano. La loro interpretazione della Scrittura era così varia che potevano dire tutto e il contrario di tutto. La loro interpretazione lasciava spazio a spazi ambigui di comprensione. Gesù invece insegna con autorità perché prima di proclamare la parola la vive, perché parla con cristallina cognizione di causa, e poi perché il suo parlare è netto: "sì sì, no no". Il Vangelo di oggi ci mostra come Gesù, davanti a certe domande, non risponde ma pone altre domande. Lui vuol tirare fuori quello che ogni uomo porta nel cuore: sincerità o malizia. Davanti a tutto ciò, domandiamoci con sincerità se noi vogliamo capire le cose, anche quando queste non sono secondo i nostri desideri, o se tendiamo a manipolare la realtà, le persone, la stessa Parola del Signore per raggiungere i nostri scopi. Domandiamoci pure come reagiamo quando qualcuno ci dice con autorità delle cose; ci fermiamo alla forma o andiamo alla sostanza? Quanta difficoltà abbiamo ad accettare la correzione, quanta superbia vi è nelle nostre reazioni... Chiediamo al Signore che ci aiuti a crescere nell''umiltà; e non dimentichiamo: chi non sa accettare la correzione prima o poi si smarrisce!</font></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-16';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="645" _msttexthash="471409484">
 <span><font _msthash="660" _mstmutation="1" _msttexthash="468430677">Meditando in modo superficiale, il Vangelo di oggi potremmo quasi pensare che sia un inutile elenco di nomi e basta. Ma tutti questi nomi non sono un elenco telefonico, ma la genealogia umana di Gesù. Lui non è venuto dal nulla, ma si è incarnato nella storia attraverso la nostra umanità. Anche noi abbiamo una genealogia e questo ci dice che non veniamo dal nulla! Leggendo la genealogia di Gesù Cristo notiamo che vi sono donne straniere, peccatori convertiti come Davide, Salomone che si disperse tra donne e idoli stranieri, e Dio era con tutti questi. Questo è il bello: Dio fa storia con tutti noi. Dio realizza il suo piano di salvezza servendosi di tutti, anche di noi poveri peccatori. Quanta fiducia, quanta pazienza, quanto amore ha Dio per ognuno di noi! Nonostante le nostre miserie Egli continua a scommettere su di noi! Forza dunque non scoraggiamoci perché Gesù nasce per ognuno di noi! Ecco perché alla domanda: qual è il cognome di Dio, papa Francesco così risponde:</font> </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-17';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="674" _msttexthash="544691121">
 <span><em><span _msthash="707" _msttexthash="547520792">«Siamo noi, ognuno di noi. Lui prende da noi il nome per farne il suo cognome. Non ci sono solo i padri della nostra fede, ma anche gente comune. Io sono il Dio di Abramo, di Isacco, di Giacobbe, di Pedro, di Marietta di Marisa, di Simone, di tutti. Da noi prende il cognome. Il cognome di Dio è ognuno di noi. Prendendo il cognome dal nostro nome, Dio ha fatto storia con noi; anzi, di più: si è lasciato scrivere la storia da noi. E noi ancora oggi continuiamo a scrivere questa storia, che è fatta di grazia e di peccato, mentre il Signore non si stanca di venirci dietro: questa è l''umiltà di Dio, la pazienza di Dio, l''amore di Dio. Se lui ha fatto la sua storia con noi, se lui ha preso il suo cognome da noi, se lui ha lasciato che noi scrivessimo la sua storia, noi da parte nostra dovremmo lasciare che Dio scriva la nostra. Perché, la santità è proprio lasciare che il Signore scriva la nostra storia. E questo è l''augurio di Natale per tutti noi. Un augurio che è un invito ad aprire il cuore: Fa'' che il Signore ti scriva la storia e che tu lasci che te la scriva» (papa Francesco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-17';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="2448887441">
 <span><font _msthash="594" _mstmutation="1" _msttexthash="2225215447">«Mentre però stava pensando a queste cose...». Giuseppe è un uomo che sa riflettere, egli, lacerato interiormente, pensa se la sua decisione di lasciare Maria sia quella giusta. La sua è un''attesa che sa di purificazione, di ricerca con tutto il cuore della volontà di Dio. E così, solo quando Giuseppe perviene ad una soluzione, nei limiti della sua non perfetta conoscenza della realtà, Dio interviene. Solo allora e non prima Dio gli rivelò il suo volere. Quanto è importante quest''insegnamento di Giuseppe! Noi viviamo spesso tormenti interiori che, anche se non paragonabili a quelli vissuti da Giuseppe, ci lacerano. Conflitti, problemi, passi importanti da compiere che riguardano la nostra vita e quella delle persone che ci stanno accanto. Nessuno vede, nessuno comprende fino in fondo quello che si prova in questi momenti. Quando proviamo in noi sentimenti contrastanti, Giuseppe ci insegna che nessuna decisione affrettata va presa perché non si giunge mai alla giusta soluzione. Non serve neanche rimanere per sempre fermi aspettando che magicamente tutto si risolva da solo o che qualcuno prenda decisioni per noi, scaricando poi la colpa su questi quando qualcosa non va nel verso giusto. Arrivano momenti in cui nessuno può decidere per noi, ma ci è chiesta la maturità e la capacità di fare delle scelte. Ad un certo punto della vita accadono cose che ci chiamano a delle decisioni da prendere senza via di fuga. Giuseppe, nella fede, di fronte ad un Dio fino ad allora silenzioso, dovette affrontare la situazione in un primo momento tutto da solo. La sua riflessione, il suo travaglio, il suo desiderio di capire la volontà di Dio per fare la cosa giusta attirò la benevolenza di Dio. Ecco, questa riflessione di Giuseppe sta aprendo la porta del suo cuore per entrare in quel luogo d''intimità così intimo da essere più interiore di qualsiasi intimità. Ebbene, in questo luogo abitato da Dio si può ascoltare la Sua voce che, senza aggiungere né imporre nulla, rivela ciò che Giuseppe aveva in sé fin dall''inizio, ma che non avrebbe potuto riconoscere fino in fondo senza la Sua visita. A ragione sant''Agostino disse: </font><em>«Rientrato in me stesso, sotto la tua guida, entrai nell''intimità del mio cuore» (s. Agostino).</em> </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-18';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="608" _msttexthash="66775722">
 <span><span><em _msthash="641" _msttexthash="68501498">«La vocazione non è frutto di un progetto umano o di un''abile strategia organizzativa. Nella sua realtà più profonda, è un dono di Dio, un''iniziativa misteriosa e ineffabile del Signore, che entra nella vita di una persona seducendola con la bellezza del suo amore, e suscitando di conseguenza un donarsi totale e definitivo a questo amore divino» (Benedetto XVI).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-18';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span><span _msthash="564" _msttexthash="712576852">Zaccaria, che svolgeva le sue funzioni di sacerdote al Tempio, sperimenta la difficoltà nel credere all''impossibile che Dio può operare! Colui che doveva essere ancora più vicino al Signore, ha un momento di incredulità davanti all''annuncio dell''angelo: che Elisabetta, sua moglie, sterile e avanti negli anni avrebbe avuto un figlio! Certo, quest''annuncio era qualcosa di veramente grande e una persona poteva anche avere difficoltà a credere a tutto ciò, ma noi? Davanti a Dio che porta la vita dove non c''è vita, come viviamo la nostra fede nelle difficoltà che attraversiamo? Quante resistenze abbiamo noi nel credere che Dio può far rifiorire la nostra vita! Non siamo forse anche noi spesso increduli? Per questo oggi ci domandiamo: quali sono le cose che ci opprimono? Abbiamo forse perso la speranza? Certo, la speranza è anche lasciarsi deludere da Dio che sembra non ci ascolti, non esaudendo le nostre richieste, ma la speranza certa è che Dio non ci abbandona mai. Egli, spesso, ci conduce per dei sentieri che noi non avremmo mai voluto umanamente percorrere, eppure sono i sentieri che ha tracciato, non per risolverci momentaneamente un problema ma per donarci qualcosa di molto più grande!</span></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-19';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="612" _msttexthash="160281394">
 <span><span><em _msthash="645" _msttexthash="162918418">«Zaccaria era rimasto muto perché non aveva creduto all''annuncio dell''angelo. Ha chiuso l''orecchio del cuore e da allora ha perso la parola. Non ha ascoltato, e ora non ha più niente da dire. Indicazione che mi fa pensoso: quando noi credenti, noi preti, smarriamo il riferimento alla Parola di Dio e alla vita, diventiamo afoni, insignificanti, non mandiamo più nessun messaggio a nessuno. Eppure il dubitare del vecchio sacerdote non ferma l''azione di Dio. Qualcosa di grande e di consolante: i miei difetti, la mia poca fede non arrestano il fiume di Dio» (p. Ermes Ronchi).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-19';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="587" _msttexthash="1688427208">
 <span><font _msthash="608" _mstmutation="1" _msttexthash="1682897619">L''annuncio dell''angelo è l''annuncio dell''inimmaginabile: Dio viene a visitare e salvare il suo popolo! È proprio vero, tutto è possibile all''Onnipotenza divina, tranne una cosa: costringere la libertà umana. Dio, infatti, per attuare il suo progetto "chiede il consenso" alla Vergine Maria. Cosa possiamo imparare da tutto ciò? Che anche noi, semplici creature come Maria, siamo creati con una libertà che nessuno può toglierci, neanche l''Onnipotente che ha espresso verso di noi un grande atto d''amore: quello di permettere che noi possiamo liberamente accoglierlo o meno. Quante volte Dio parla nella nostra vita e ci fa una proposta: vivere un sano matrimonio, rispondere ad una vocazione religiosa, riconciliarci con qualcuno, aiutare i poveri, visitare chi è solo e malato... ma noi, purtroppo, siamo spesso quelli del no: "troppa fatica, ... non ne son degno, ... non ho capito bene, ... non ce la faccio...". Sono tante le scuse e le paure più frequenti con le quali il demonio ci distoglie dal compiere la volontà di Dio! La paura di perdere la nostra libertà rischia di farci mancare la nostra più alta e splendida possibilità; quella che possa coincidere con la libertà di Dio! <em>«Purtroppo, siamo vittime di una tendenza che ci spinge alla provvisorietà [...] come se desiderassimo rimanere adolescenti per tutta la vita! Non abbiamo paura degli impegni definitivi, degli impegni che coinvolgono e interessano tutta la vita! In questo modo la nostra vita sarà feconda!».</em><font _msthash="656" _mstmutation="1" _msttexthash="162110"> D''altronde: </font><em _msthash="655" _msttexthash="67553707">«Cosa significa libertà? Non è certo fare tutto ciò che si vuole, lasciarsi dominare dalle passioni, passare da un''esperienza all''altra senza discernimento, seguire le mode del tempo; libertà non significa, per così dire, buttare tutto ciò che non piace dalla finestra. La libertà ci è donata perché sappiamo fare scelte buone nella vita!» (Papa Francesco). </em></font></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-20';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="963306591">
 <span _msthash="580" _msttexthash="958325888"><font _msthash="611" _mstmutation="1" _msttexthash="419019848">L''incontro tra Maria ed Elisabetta è sovrabbondante di gioia. Maria era andata per servire e riceve, era andata per capire e viene capita. Qui vi è racchiuso un grande segreto: "il segreto della felicità!". Tutti cerchiamo la felicità e ci diamo da fare per trovarla. A volte pensiamo che sia legata alla salute e così appena la perdiamo siamo tristi; altre volte pensiamo sia legata al raggiungimento di un obiettivo ma una volta raggiunto, dopo un attimo di festa, subito ne sorge un altro; a volte pensiamo sia legata ad un legame affettivo, ma poi ci rendiamo conto che non ci basta... E allora, dove trovarla? Maria ce lo insegna: si è felici quando innanzitutto c''è Dio nella nostra vita, il solo che può appagare il nostro cuore fatto per l''infinito. E in secondo luogo Maria ci insegna che la felicità la si trova quando si cerca di regalarla a chi ci sta vicino, poiché: «C''è più gioia nel dare che nel ricevere» (At 20,35)! Infatti </font><em _msthash="596" _msttexthash="18576636">«il vero amore è un sentimento che, sebbene provochi dolore e ci faccia soffrire, ci rende felici. Ecco perché dobbiamo pregare Dio chiedendogli il coraggio di amare» (S. Teresa di Calcutta).</em><font _msthash="626" _mstmutation="1" _msttexthash="16297762"> Che Maria ci aiuti a non rinchiuderci nella ricerca egoistica del benessere e della felicità passeggera, ma a cercare e trovare quella vera, memori di queste splendide parole: </font><em _msthash="581" _msttexthash="6774287">«Sognavo che la vita fosse gioia. Mi son svegliato ed era servizio. Ho servito, e servendo ho trovato la gioia».</em></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-21';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="648" _msttexthash="83070507">
 <span><em><span _msthash="687" _msttexthash="84976567">«"Ecco, appena il tuo saluto è giunto alle mie orecchie, il bambino ha sussultato di gioia nel mio grembo". Tutto è gioia. Ma noi cristiani non siamo tanto abituati a parlare di gioia, di allegria. Credo che tante volte ci piacciano più le lamentele! Ma non si può portare avanti il Vangelo con cristiani tristi, sfiduciati, scoraggiati; non si può. Questo atteggiamento è un po'' funerario» (papa Francesco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-21';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span><span _msthash="566" _msttexthash="26415610">In questa IV domenica di avvento il Vangelo ci racconta la visita di Maria alla cugina Elisabetta. Noi ci vogliamo soffermare in particolare su due aspetti: portare Gesù agli altri e la gioia che nasce in coloro che lo accolgono.</span></span></p>
<p>
 <span _msthash="607" _msttexthash="1961259469">Maria, dopo l''annuncio dell''angelo, «si alzò». Questo alzarsi è il verbo della Risurrezione: Maria ci dice che la Parola accolta ci risuscita, ci fa alzare. Si inizia ad agire corrispondendo a ciò che Dio ha fatto. Si può correre il rischio di passare la vita da semplici ascoltatori di cose buone come catechesi, messa, momenti di preghiera, ma la nostra vita non cambia di una virgola, non ci alziamo dalle nostre comodità, pensiamo che quel poco tempo donato a Dio, senza il nostro sì, possa bastare per il nostro cammino spirituale. Maria, invece, si alza, deve andare da Elisabetta, l''angelo gli ha parlato di Lei. Maria ci dice e ci testimonia che dopo la Parola ricevuta ci si alza, c''è da comunicare qualcosa di importante, c''è subito da servire. L''opera di Dio non è possesso; non si può tenere per sé. Automaticamente c''è una nuova realtà! Le cose che si facevano prima si possono interrompere. Quando accogliamo seriamente la Parola, abbiamo altre mete, altre cose da fare, c''è da mettersi in cammino. Diceva don Tonino Bello che dopo Gesù, pellegrino per eccellenza che si è persino definito come Via, Maria nel Vangelo è icona del camminare. Il saluto del cielo che Maria ha ricevuto va condiviso. Maria ed Elisabetta così si incontrano nella fede e questa porta sempre ad una relazione. Oggi, invece, abbiamo una visione privata, intimistica della fede; in tante parrocchie non si hanno relazioni vere, non si riesce a creare comunità. In molti si trovano a disagio se trovano la chiesa piena. Questa è la visione di uomo come individuo isolato, non come persona bisognosa di relazioni. Certo, abbiamo bisogno di intimità con Dio, ma se ce ne stiamo sempre da soli che fede è? Anche gli eremiti hanno la regola di incontrare gli altri! La solitudine è l''inferno. Noi saremo giudicati sull''amore, il metro di giudizio che Dio userà sarà questo: "hai amato? Hai fatto qualcosa per far gioire, esultare gli altri?" Questo è ciò che fa Maria e questo è quello che Dio ci chiede di fare se davvero lo abbiamo incontrato.</span></p>
<p>
 <span _msthash="622" _msttexthash="814423454">Il secondo aspetto è che l''incontro tra Maria ed Elisabetta conduce ad un''esplosione di gioia. Elisabetta è come se stesse a dire: "la tua fede serve anche a me; io ho bisogno di te, di te che mi porti la Persona più preziosa, Colui che mi dona la vera gioia". Questo ci ricorda che<em> «L''uomo ha bisogno del nutrimento del corpo, ma nel più profondo ha bisogno soprattutto di Dio stesso» (Benedetto XVI). </em>Quant''è difficile essere nella gioia del Signore! A volte si vedono cristiani che sembrano fermi al Venerdì Santo, tutti tristi senza la gioia pasquale, senza la gioia della Risurrezione. È vero che spesso si hanno problemi che sembrano schiacciarci ma occorre non dimenticare che siamo figli della Risurrezione; che uno dei segni del cristiano che vive una vita nello Spirito è la gioia pur in mezzo ai problemi, a tal punto che l''apostolo Paolo così scrive: «Sovrabbondo di gioia pur in mezzo alle mie tribolazioni». Oggi, dunque, davanti all''invito che Dio fece a Maria attraverso l''angelo a rallegrarsi, davanti alla gioia di Elisabetta, davanti alla gioia di Giovanni Battista ancora nel grembo della madre ci chiediamo: ma come viviamo noi l''irruzione di Dio nella nostra vita? Siamo spesso tristi? Siamo spesso arrabbiati? Riusciamo pur nelle prove di questa vita a vivere la gioia pasquale? </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-22';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span><span _msthash="669" _msttexthash="323897769">«Nella casa di Elisabetta, la venuta di Gesù attraverso Maria ha creato non solo un clima di gioia e di comunione fraterna, ma anche un clima di fede che porta alla speranza, alla preghiera, alla lode. Tutto questo vorremmo avvenisse anche oggi nelle nostre case. Vorremmo che Lei, ancora una volta, portasse a noi, alle nostre famiglie, alle nostre comunità, quel dono immenso, quella grazia unica che dobbiamo sempre chiedere per prima e al di sopra delle altre grazie che pure ci stanno a cuore: la grazia che è Gesù Cristo! Portando Gesù, la Madonna porta anche a noi una gioia nuova, piena di significato; ci porta una nuova capacità di attraversare con fede i momenti più dolorosi e difficili; ci porta la capacità di misericordia, per perdonarci, comprenderci, sostenerci gli uni gli altri» (papa Francesco). </span></span></em></span></p>

<p>
 <span><em><span><span _msthash="668" _msttexthash="94055">PREGHIERA</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="667" _msttexthash="8551920">Noi ti invochiamo Madre della Via, Fiore del Carmelo, aiutaci a camminare sempre sulla via del bene e nel servizio al prossimo.</span></span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-22';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="630" _msttexthash="630277583">
 <span _istranslated="1"><span _istranslated="1" _msthash="566" _msttexthash="9231625">Del Vangelo di oggi prendiamo due piccoli aspetti: aprirsi al nuovo ed essere consapevoli che i figli non appartengono ai genitori </span></span></p>
<p _msthash="630" _msttexthash="899926287">
 <span _msthash="640" _msttexthash="491337236">Il nuovo da accogliere, la rottura col passato, dal "si è sempre fatto così", ci viene da questo bimbo che sta per nascere: «il suo nome è Giovanni». Ma non vi è nessuno della parentela con questo nome, dicono in tanti ad Elisabetta! Ecco, si rompe quella tradizione che porta ad una vita sterile, ad una fede stantìa, incapace di aprirsi al nuovo di Dio. Spesso rimaniamo nelle nostre gabbie, nei nostri schemi mentali impedendo a Dio di manifestarsi nella nostra vita. Pensiamo di progredire nel nostro cammino di fede e invece siamo sempre al punto di partenza. Ascoltiamo il Vangelo e spesso siamo di quelli che dicono "ah sì, lo conosco", come se avessimo compreso tutta la sapienza di Dio che, invece, ogni volta è capace di dirci cose nuove, di fare cose nuove nella nostra vita. Domandiamoci quali sono quelle cose che ancora ci legano, quali progetti disordinati abbiamo da abbandonare, quali sono i pensieri malati che ancora coltiviamo che impediscono a Dio di operare l''impossibile nella nostra vita!</span></p>
<p>
 <span _msthash="615" _msttexthash="142378340">Il secondo aspetto è che i figli vengono alla luce come compimento di un progetto, vengono da Dio. Egli ha affidato loro una missione, non nascono per caso, non sono proprietà privata, ma sono chiamati a diventare dono per l''umanità. Questo è quello che vivono Zaccaria ed Elisabetta e questa è la consapevolezza che ogni genitore dovrebbe avere. <em>«Il genitore è solo l''arco che scocca la freccia, per farla volare lontano»</em>. Che sarà mai di questo Bambino? È la domanda che si ponevano in tanti sapendo della nascita di Giovanni Battista. </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-23';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span><span _msthash="681" _msttexthash="160807959">«Che sarà mai questo bambino? Grande domanda da ripetere, con venerazione, davanti al mistero di ogni culla, davanti ad ogni bambino che nasce. Cosa sarà, oltre ad essere dono che viene dall''alto? Cosa porterà al mondo? Un dono unico e irriducibile. Si chiamerà Giovanni, che in ebraico significa: dono di Dio. Elisabetta ha capito che la vita, l''amore che sente fremere dentro di sé, sono un pezzetto di Dio. Che l''identità del suo bambino è di essere dono. E questa è anche l''identità profonda di noi tutti: il nome di ogni bambino è «dono perfetto» (p. Ermes Ronchi).</span></span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-23';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span><span _msthash="564" _msttexthash="396337110">Zaccaria, incredulo all''annuncio dell''Angelo che avrebbe avuto un figlio, e per questo rimasto senza parole, guarisce dal suo mutismo solo quando si apre al nuovo di Dio: «All''istante gli si aprì la bocca e gli si sciolse la lingua, e parlava benedicendo Dio». Zaccaria manifesta tutta la sua gioia attraverso quello che noi chiamiamo il Benedictus: <em _istranslated="1">«Cantare l''inno di Zaccaria, padre di Giovanni il Battista, significa avere un occhio rivolto all''Antico Testamento ma anche essere ben saldi sulla soglia del Nuovo. Il Benedictus, infatti, è l''annuncio dell''inizio di una nuova era: quella della luce e del compimento delle promesse antiche. Il nome Zaccaria significa "il Signore ricorda". Il suo canto (Lc 1, 68-79) ha la funzione di disporci a celebrare il memoriale del Signore fedele: le attese di Israele sono esaudite. Il Signore è benedetto perché ha visitato e redento il suo popolo» (A. Magnante).</em></span></span></p>
<p>
 <span><span _msthash="563" _msttexthash="674720527"><em _istranslated="1">«Il Signore ha visitato».</em> Quanto è bella questa parola che ci dice l''atteggiamento di Dio che si prende cura in ogni momento di noi. Egli continuamente ci viene a visitare. Quante volte proviamo quella grande emozione, quel grande desiderio di incontrare la persona amata. Quale trepidazione quando la persona che attendiamo ritarda, quale gioia proviamo nel vederla quando arriva, quasi la rimproveriamo per averci fatto attendere, per averci fatto sperimentare un po'' più a lungo la sua mancanza. Attendere di essere visitati: non è forse la condizione di attesa di tanti genitori che hanno i figli lontani? Attendono di essere visitati. Non è forse la condizione di tanti ammalati, di persone sole, di anziani rinchiusi in un ospizio e quasi abbandonati e dimenticati? Attendono, sperano di essere visitati. Noi, spesso, chiusi nel nostro egoismo, siamo incapaci di visitare le persone sole; basterebbe poco, a volte anche solo una telefonata. Ecco, Dio, a differenza di noi, sempre ci visita, non si dimentica di noi. Guardiamo allora Lui, il suo agire verso di noi e magari inizieremo a comprendere sempre più l''importanza di visitare i soli, gli ammalati, i dimenticati.</span></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-24';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="754" _msttexthash="647485007">
 <span><span><em _msthash="787" _msttexthash="653301311">«Insegnare ai ragazzi il valore delle parole è praticamente impossibile, se partiamo dalle parole, perché oggi per impararlo è necessario partire da ciò che genera la parola, il silenzio. Può sembrare paradossale, ma se oggi abbiamo parole che non hanno più presa sulla realtà è perché sono diventate parole-simulacro, parole che non dicono nulla sulla realtà, non aprono la vita. E invece la vita è lì, nascosta dove la meraviglia l''ha manifestata: Aristotele diceva infatti che l''inizio del filosofare – ma anche della conoscenza scientifica – viene sempre dalla meraviglia. E la meraviglia obbliga al silenzio, perché se assisto a qualcosa di straordinario devo stare in silenzio e interrogarmi: allora sì che comincerò a scavare e a cercare la parola giusta per raccontare il nodo della vita che ho ricevuto in quell''incontro. Io farei quindi una bella educazione al silenzio, alla riscoperta dei momenti di vera meraviglia, per poi andare a caccia di parole che siano in grado di nominare il contenuto di vita che ho intercettato» (Alessandro D''Avenia).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-24';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="801" _msttexthash="1090670646">
 <span _istranslated="1"><span _istranslated="1" _msthash="762" _msttexthash="19077994">In principio era il Verbo, e il Verbo era presso Dio e il Verbo era Dio. Egli era, in principio, presso Dio: tutto è stato fatto per mezzo di lui e senza di lui nulla è stato fatto di ciò che esiste.</span></span><span _istranslated="1" _msthash="816" _msttexthash="829334740">In lui era la vita e la vita era la luce degli uomini; la luce splende nelle tenebre e le tenebre non l''hanno vinta. Venne un uomo mandato da Dio: il suo nome era Giovanni. Egli venne come testimone per dare testimonianza alla luce, perché tutti credessero per mezzo di lui. Non era lui la luce, ma doveva dare testimonianza alla luce. Veniva nel mondo la luce vera, quella che illumina ogni uomo. Era nel mondo e il mondo è stato fatto per mezzo di lui; eppure il mondo non lo ha riconosciuto. Venne fra i suoi, e i suoi non lo hanno accolto. A quanti però lo hanno accolto ha dato potere di diventare figli di Dio: a quelli che credono nel suo nome, i quali, non da sangue né da volere di carne né da volere di uomo, ma da Dio sono stati generati. E il Verbo si fece carne e venne ad abitare in mezzo a noi; e noi abbiamo contemplato la sua gloria, gloria come del Figlio unigenito che viene dal Padre, pieno di grazia e di verità. Giovanni gli dà testimonianza e proclama: «Era di lui che io dissi: Colui che viene dopo di me è avanti a me, perché era prima di me». Dalla sua pienezza noi tutti abbiamo ricevuto: grazia su grazia. Perché la Legge fu data per mezzo di Mosè, la grazia e la verità vennero per mezzo di Gesù Cristo. Dio, nessuno lo ha mai visto: il Figlio unigenito, che è Dio ed è nel seno del Padre, è lui che lo ha rivelato (Lc 2,15-20).</span></p>
<p>
 <span><span _msthash="898" _msttexthash="67572050">Il Vangelo di questo giorno di Natale ci presenta il Prologo di Giovanni. In questo Prologo si intrecciano concetti bellissimi; vita, luce, realtà creata, e tutto questo a cascata dall''origine, da Dio stesso. Tra i tanti spunti ne vogliamo cogliere due: il primo è che il Verbo si è fatto carne; il secondo è l''esercizio della nostra libertà nell''accoglierlo o meno.</span></span></p>
<p>
 <span><span _msthash="833" _msttexthash="1375154001">Quest''inno ha il suo punto nodale nel versetto 14: «il Verbo si fece carne e venne in mezzo a noi» Ecco, noi parliamo di una persona concreta, non di un mito, ma di una persona dotata di carne: è carne come noi, ha abitato in mezzo a noi e, dice Giovanni, «noi abbiamo contemplato la sua gloria». Ovvero sia, noi abbiamo da incontrare questa persona concreta. Comprendiamo non solo che Dio si è fatto uomo, ma in quali condizioni si è fatto uomo: Lui si è fatto ultimo tra gli ultimi! Dio non è un concetto da capire, ma un bimbo nato in un posto umile che ha vissuto la nostra vita. Se noi contempliamo fino a dove Lui arriva a spendersi per noi, noi comprendiamo chi siamo, quanta dignità abbiamo, quanto Lui ci ama, quanto gli stiamo a cuore. Contemplare la gloria di Dio vuol dire contemplare come Dio è veramente. La gloria di Dio si manifesta nella sua debolezza, nel suo farsi bambino, nella sua povertà, nella sua morte di croce per amor nostro. <em>«E il Verbo si fece carne». Dio ricomincia da Betlemme. Il grande miracolo è che Dio non plasma più l''uomo con polvere del suolo, dall''esterno, come fu in principio, ma si fa lui stesso polvere plasmata, bambino di Betlemme e carne universale. E se tu devi piangere, anche lui imparerà a piangere. E se tu devi morire, anche lui conoscerà la morte. Da allora c''è un frammento di Logos in ogni carne, qualcosa di Dio in ogni uomo. C''è santità e luce in ogni vita. E nessuno potrà più dire: qui finisce la terra, qui comincia il cielo, perché ormai terra e cielo si sono abbracciati. E nessuno potrà dire: qui finisce l''uomo, qui comincia Dio, perché creatore e creatura si sono abbracciati e in quel neonato, a Betlemme, uomo e Dio sono una cosa sola» (p. Ermes Ronchi).</em></span></span></p>
<p>
 <span><span><span _msthash="758" _msttexthash="110995989">Il secondo punto ci parla dell''esercizio della nostra libertà nell''accoglierlo o meno. <em>«A quanti lo hanno accolto, ha dato il potere di diventare figli di Dio». </em>Ecco l''annuncio meraviglioso: accogliere Gesù nella mia vita, fa sì che possa sbocciare in me quella bellezza sognata da sempre dal Creatore, quell''essere figlio del Padre creato ad immagine e somiglianza di Dio, modellato su Cristo che si è fatto uomo come noi. Qui è il punto: accoglierlo sul serio oppure no!</span></span></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-25';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="942" _msttexthash="728772564">
 <em><span><span><font _msthash="1184" _mstmutation="1" _msttexthash="723134620">«È in questa accoglienza che si gioca il senso del vivere. Più che senso, è meglio dire sapienza. Cioè sapore, gusto. Il sale nella minestra: quello che manca oggi... Di questo senso, di questo orientamento decisivo, di questo intimo significato delle cose, di questo profondo perché, oggi sentiamo tutti un incredibile bisogno. Scoprire, sotto lo scorrere dei grani del tempo, il filo nascosto che articola i giorni, senza frantumarli in monadi chiuse. Leggere, sotto la scorza degli avvenimenti, tristi o luttuosi, la tensione ultima che li lega al Regno. Udire la voce segreta che geme nell''universo, sofferente per i travagli del parto. Intuire che i frammenti di gioia che si sperimentano quaggiù fanno parte di un mare di felicità, in cui un giorno faremo tutti naufragio. Percepire che il nostro vuoto può essere riempito solo «dalla sua pienezza» (Gv 1, 16). È così grande il dono, che san Paolo sente il bisogno di chiedere per tutti da Dio questo «spirito di sapienza» (Ef 1, 17). A noi non resta che augurarci che «possa egli davvero illuminare gli occhi della nostra mente per farci comprendere a quale speranza ci ha chiamati». Se le cose stanno così, benvenuta «tenda di Dio in mezzo a noi»! (don Tonino Bello).</font></span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-25';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="571" _msttexthash="1792799736">
 <span><font _msthash="630" _mstmutation="1" _msttexthash="308261876">Perché il Natale non ci sembri solo una nota poetica, il presepe che costruiamo, il bambinello che adagiamo in una mangiatoia, i cenoni che facciamo, la Chiesa, nella sua sapienza, ci presenta oggi il martirio di s. Stefano, il primo a morire per amore di Gesù, il primo a perseverare nella fede e nella testimonianza. «Chi avrà perseverato fino alla fine sarà salvato», dice il Vangelo di oggi. Quanto è difficile perseverare nel bene, specialmente quando comporta il soffrire! Spesso, davanti a delle difficoltà, a delle incomprensioni, subentra in noi lo scoraggiamento, pensiamo che non ne valga la pena. Tutto ciò ci sembra strano: si può mai combattere la verità, si può chiudere il cuore all''amore? Sì, si può, è il mistero dell''iniquità. Il prologo del Vangelo di Giovanni lo dice: </font><font _msthash="645" _mstmutation="1" _msttexthash="621822903"><em _mstmutation="1">«La luce è venuta nel mondo ma le tenebre non l''hanno accolta».</em> E non solo le tenebre non hanno accolto la luce, ma scatenano contro di essa tutta la rabbia e l''odio possibile. Chi si appresta a servire il Signore occorre che si prepari alla tentazione, perché l''azione del male sarà sempre più forte. <em _msthash="656" _mstmutation="1" _msttexthash="101967814">«La lotta tra il bene e il male è la lotta tra la mentalità del Vangelo e quella del mondo. Quest''ultimo appare sempre più forte perché detiene il potere, usa la violenza, ha la forza del denaro, dell''egoismo, della sopraffazione. Manipola la cultura, la comunicazione, cambia il nome alle cose, cerca di far passare come bene il male e chiama male il bene. Apparentemente sembra sempre che vinca, ma Gesù ci ha insegnato che così non è» (don Luigi M. Epicoco).</em><font _msthash="665" _mstmutation="1" _msttexthash="17108299"> In questo combattimento, sull''esempio di santo Stefano che ha pregato e perdonato i suoi uccisori, chiediamo al Signore la grazia di non rispondere al male con il male, ma con il bene. </font><em _mstmutation="1">«È questo perdono la vera vittoria sul male. Se, invece, con la scusa di difendere il Vangelo, diventiamo più cattivi e spietati del mondo, allora lì si che il mondo ha vinto» (don Luigi M. Epicoco).</em></font></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-26';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="671" _msttexthash="108289870">
 <span><span><em _msthash="710" _msttexthash="110460194">«Per coloro che hanno la missione di svegliare, fratelli e sorelle che li circondano il gallo, col suo canto è un bel modello: canta, fedelmente quando è tempo di svegliare l''alba, e quando il sole, con i suoi raggi, rompe l''orizzonte, si sente appagato: fedele, ha compiuto la sua missione! E coloro che dovrebbero risvegliare le coscienze, le creature umane, i gruppi, i popoli son così fedeli come i galli. E son felici come i galli, nella loro missione?» (Helder Camara).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-26';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="564" _msttexthash="1504417213">
 <span><font _msthash="593" _mstmutation="1" _msttexthash="1398546409">Oggi, giorno in cui celebriamo la festa di san Giovanni apostolo, contempliamo un Vangelo Pasquale. Maria di Magdala si reca al sepolcro ma resta smarrita di fronte alla pietra ribaltata dal sepolcro. Pensa che qualcuno abbia rubato il corpo di Gesù e corre dai discepoli mossa dal timore che sia successo qualcosa di irrimediabile. Alle parole e alla corsa di Maria di Magdala, segue la corsa dei due discepoli che si recano al sepolcro vuoto. Pietro entra nel sepolcro ma non comprende, Giovanni entra e, al contemplare il sepolcro vuote e le bende posizionate in un determinato modo, «vide e credette». Vede una tomba vuota e crede che il Signore è Risorto! Oh, sublime sapienza di Dio! Nulla di miracolistico e appariscente, niente fuochi d''artificio. La fede pasquale di Giovanni non nasce dal contemplare semplicemente una tomba vuota; questa, infatti, può far anche pensare al trafugamento del corpo del Signore. Vi è qui qualcosa di più profondo. È illuminante infatti uno dei versetti successivi: «essi infatti non avevano ancora compreso le scritture!» Ecco, le scritture, solo esse, danno e rafforzano la fede pasquale. Tutti gli eventi che viviamo dovremmo essere capaci di leggerli alla luce della Parola di Dio, come Giovanni che legge quella tomba vuota alla luce della Parola. È questa, dunque, che ci aiuta a comprendere il senso più nascosto di tante cose a prima vista insignificanti e oscure. Per questo domandiamoci quanto il nostro agire sia illuminato dalla Parola di Dio, quanto questa sia lampada ai nostri passi, bussola del nostro cammino. Perché allora la nostra fede sia una fede salda e non evanescente e superficiale, non dimentichiamo queste parole di s. Girolamo: </font><em>«l''ignoranza delle scritture è l''ignoranza di Dio!»</em></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-27';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="615" _msttexthash="221895869">
 <em><span><span _msthash="648" _msttexthash="224995485">«L''atto di entrare nel sepolcro da parte di Pietro e poi del discepolo amato ha una valenza simbolica. Noi entriamo, durante la nostra vita, in numerosi luoghi di morte (lutti, separazioni, abbandoni, fine di relazioni e di amicizie, incomunicabilità) e lasciamo anche entrare la morte in noi, divenendo noi un luogo di morte per gli altri (chiusura egoistica, arroganza, abuso, violenza, manipolazione, indifferenza). La fede nella resurrezione, consente di entrare nelle situazioni di morte guardando oltre la morte e vivendo la resurrezione, ovvero amando o cercando di amare come Cristo ha amato e, soprattutto, credendo al suo amore per noi» (Luciano Manicardi).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-27';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span><span _msthash="640" _msttexthash="278976360">Oggi contempliamo il Vangelo dei Ss. Innocenti martiri, bambini uccisi dalla folle pazzia di Erode che aveva un solo scopo: uccidere il Bambino Gesù, il re dei Giudei, che lui pensava fosse un pericoloso concorrente al trono. Erode non comprendeva che il trono di Gesù sarebbe stata la croce, che il suo regno non era di questo mondo, che Gesù era venuto non per detronizzarlo ma per salvarlo. Ma quando il cuore di un uomo è albergato dal desiderio di potere, di invidia, di gelosia, tutti gli altri per lui diventano nemici, vede complotti da tutte le parti, persone che congiurano contro di lui, per cui questi sono da eliminare, da terrorizzare, da distruggere in maniera abusante, sfruttando il proprio ruolo di potere non per servire, ma per asservire. </span></span></p>
<p>
 <span><span _msthash="639" _msttexthash="1649771474">Giuseppe, all''annuncio dell''angelo (inerente il rischio che correvano a causa della follia di Erode), senza nessuno indugio si mise in cammino con Maria e il piccolo Gesù. Chissà lo stato d''animo di Giuseppe e Maria, e chissà lo stato d''animo di tanti genitori che vivono la paura, l''ansia a causa di un pericolo o per una grave malattia dei loro figli! Anche la fuga travagliata di Giuseppe e di Maria fu vissuta magari con ansia nella paura di essere raggiunti o spiati. Per loro la metà finale fu un paese straniero e sconosciuto, lontano da tutto ciò che era a loro familiare. E lì avrebbero dovuto dimorare fino ad una nuova parola di Dio. La data di ritorno rimase vaga: «resta lì fino a quando non te lo dirò». Certezza del ritorno, sì, ma i tempi di Dio erano oscuri a Giuseppe: quanto tempo dovremo restare qui? Quando potremo tornare? Ecco, tutto ciò portava il segno della provvisorietà e la necessità dell''affidamento. Ma Giuseppe e Maria avevano una visione soprannaturale delle cose che stavano accadendo, per cui sapevano leggerle alla luce del compimento del disegno di Dio. Noi, invece, quante volte non sappiamo attendere: vorremmo tutto e subito, e quando certe cose non si realizzano come e quando avremmo voluto, siamo subito pronti a pensare male di Dio e a lasciarci prendere dallo sconforto. Chiediamo la grazia di un abbandono fiducioso nelle mani del Padre, che non significa un''inerme passività, ma speranza che si apre alla certezza che Dio conduce la storia anche attraverso gli eventi non subito chiari, o persino negativi, o che ci arrecano dolore, che sfuggono alla nostra comprensione... Sì, il nostro Dio, onnipotente nell''amore, opera anche lì, ci conduce anche lì verso la meta, verso il porto sospirato. Impariamo dunque da Maria e Giuseppe a saper attendere e tendere sempre verso il Signore e la sua santa volontà.</span></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-28';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="706" _msttexthash="1039642006">
 <em><span><span _msthash="747" _msttexthash="1043123211">«Gesù Bambino. Il mio pensiero va a tutti i bambini oggi uccisi e maltrattati, sia a quelli che lo sono prima di vedere la luce, privati dell''amore generoso dei loro genitori e seppelliti nell''egoismo di una cultura che non ama la vita; sia a quei bambini sfollati a motivo delle guerre e delle persecuzioni, abusati e sfruttati sotto i nostri occhi e il nostro silenzio complice; e ai bambini massacrati sotto i bombardamenti, anche là dove il figlio di Dio è nato. Ancora oggi il loro silenzio impotente grida sotto la spada di tanti Erode. Sopra il loro sangue campeggia oggi l''ombra degli attuali Erode. Davvero tante lacrime ci sono in questo Natale insieme alle lacrime di Gesù Bambino! Cari fratelli e sorelle, che lo Spirito Santo illumini oggi i nostri cuori, perché possiamo riconoscere nel Bambino Gesù, nato a Betlemme dalla Vergine Maria, la salvezza donata da Dio ad ognuno di noi, ad ogni uomo e a tutti i popoli della terra. Il potere di Cristo, che è liberazione e servizio, si faccia sentire in tanti cuori che soffrono guerre, persecuzioni, schiavitù. Che con la sua mansuetudine questo potere divino tolga la durezza dai cuori di tanti uomini e donne immersi nella mondanità e nell''indifferenza, nella globalizzazione dell''indifferenza. Che la sua forza redentrice trasformi le armi in aratri, la distruzione in creatività, l''odio in amore e tenerezza. Così potremo dire con gioia: "I nostri occhi hanno visto la tua salvezza"» (papa Francesco).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-28';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span><span _msthash="579" _msttexthash="1712432098">Questa domenica celebriamo la festa della Santa Famiglia che ci ricorda la bellezza e l''importanza di essere famiglie unite, dove regna l''amore, perché <em>«la famiglia è la prima scuola di pace [e di amore], e i bambini porteranno nella società quello che hanno vissuto in famiglia» (s. Giovanni Paolo II).</em> È significativo, a tal riguardo, il racconto di un''esperienza che un giorno visse Madre Teresa: <em>«Non dimentico mai l''opportunità che ebbi di visitare una casa dove tenevano tutti questi anziani genitori di figli e figlie che li avevano semplicemente messi in un istituto e forse dimenticati. Sono andata là, ho visto che in quella casa avevano tutto, cose bellissime, ma tutti guardavano verso la porta. E non ne ho visto uno con il sorriso in faccia. Mi sono rivolta alla sorella e le ho domandato: come mai? Com''è che persone che hanno tutto qui, perché guardano tutti verso la porta, perché non sorridono? Sono così abituata a vedere il sorriso nella nostra gente, anche i morenti sorridono; e lei disse: questo accade quasi tutti i giorni, aspettano, sperano che un figlio o una figlia venga a trovarli. Sono feriti perché sono dimenticati – e vedete, è qui che viene l''amore. Come la povertà arriva proprio a casa nostra, dove trascuriamo di amarci. Forse nella nostra famiglia abbiamo qualcuno che si sente solo, che si sente malato, che è preoccupato, e questi sono giorni difficili per tutti. Ci siamo per accoglierli, c''è la madre ad accogliere il figlio? Sono stata sorpresa di vedere in Occidente tanti ragazzi e ragazze darsi alle droghe, e ho cercato di capire perché – perché succede questo, e la risposta è: perché non hanno nessuno nella loro famiglia che li accolga. Padre e madre sono così occupati da non averne il tempo».</em></span></span></p>
<p>
 <span _msthash="648" _msttexthash="11796941">Dal vangelo di questa domenica vogliamo cogliere due ulteriori aspetti: compiere la volontà del Padre e custodire le cose belle nel proprio cuore.</span></p>
<p>
 <span _msthash="663" _msttexthash="699993294">Gesù, alla domanda di Maria «perché ci hai fatto questo» mette al di sopra di tutto l''importanza del fare la volontà del Padre: «non sapevate che devo occuparmi delle cose del Padre mio?». Da questa risposta è chiaro che <em>«La vocazione di Gesù non è quella di essere solamente a servizio di una pur santa famiglia di creature umane, ma quella di essere a disposizione del Padre celeste» (card. G. Ravasi).</em> Questo dovrebbe essere anche il nostro desiderio più grande. I legami familiari, per quanto importanti, non devono ostacolare l''adempimento della nostra missione, quel progetto che Dio ha su di noi sin dall''eternità, nel quale c''è la nostra e l''altrui felicità. Tanti vivono per non deludere "mammà e papà", ma c''è di più! C''è un Padre che ci ama e ci affida una missione, molte volte diversa da quella che hanno pensato i genitori per noi. Dio "scommette" su ciascuno di noi, ha assegnato un compito specifico a ciascuno di noi, un servizio ben definito: <em>«io ho la mia missione sono un anello in una catena, un vincolo di connessione fra persone. Egli non mi ha creato per niente. Farò il bene, compirò la sua opera; sarò un angelo di pace, un predicatore di verità proprio nel mio posto» (San J.H. Newman).</em></span></p>
<p>
 <span _msthash="678" _msttexthash="1263598388">Dopo la risposta difficile di Gesù <em>(«Perché mi cercavate? Non sapevate che io devo occuparmi delle cose del Padre mio?»),</em> è scritto che sua madre custodiva tutte queste cose nel suo cuore. Maria collega gli eventi, se ne impossessa e li custodisce nel suo cuore. Il cuore è la zona della fede, la zona del rapporto con Dio, è il centro dell''essere, come ad esempio quando diciamo: "andiamo al centro del discorso!" Ecco, quando vogliamo andare al centro, noi abbiamo un luogo per vivere, confrontare, serbare, tesorizzare l''opera di Dio, è quello il luogo della relazione con Lui. Noi abbiamo con la parte sensitiva la cura del nostro corpo, e con la parte psichica la cura delle nostre relazioni collegate al nostro carattere, alla nostra memoria... Ma tutto ciò è incompleto, c''è una zona più profonda spesso non ispezionata dalla maggioranza delle persone: è la dimensione spirituale, dove avviene la relazione con Dio che sta nella parte più profonda del nostro cuore. Nella parabola del Padre misericordioso, il figliol prodigo ad un certo punto sta scritto che «rientrò in sé stesso». Dove stava prima? Fuori di sé, stava fuori dal suo cuore. Ora anche noi, per tanti motivi, siamo spesso fuori dal nostro cuore, viviamo in superficie. Allora per ritrovarci, per ritornare all''origine buona, per incontrare il Signore, occorre che facciamo questo viaggio interiore, occorre che rientriamo in noi stessi! La nostra felicità è quando siamo guidati dalla parte più profonda e bella di noi! Anche su questo Maria ci è da modello, ella è sempre in connessione col suo cuore, con la parte più profonda di sé.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-29';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><span _msthash="782" _msttexthash="94055">PREGHIERA</span></span></span></p>
<p _msthash="919" _msttexthash="27110122">
 <em _istranslated="1"><span _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="781" _msttexthash="16018366">«Tu eri dentro di me, e io fuori. E là ti cercavo. Mi hai chiamato, e il tuo grido ha squarciato la mia sordità. Hai mandato un baleno, e il tuo splendore ha dissipato la mia cecità. </span></span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="780" _msttexthash="1880762">Hai effuso il tuo profumo; l''ho aspirato e ora anelo a te. </span></span></span></em><em><span><span><span _msthash="779" _msttexthash="948701">Ti ho gustato, e ora ho fame e sete di te. </span></span></span></em><em><span><span><span _msthash="778" _msttexthash="1888848">Mi hai toccato, e ora ardo dal desiderio della tua pace» </span></span></span></em><em><span><span><span _msthash="777" _msttexthash="190866">(s. Agostino).</span></span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-29';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span><span _msthash="565" _msttexthash="2859147772">L''episodio della presentazione di Gesù al Tempio mette in risalto anche la figura della profetessa Anna. Era molto avanzata negli anni, ne aveva ottantaquattro, ma gli anni non ne avevano fiaccato lo spirito. Era una donna di preghiera, di contemplazione e di speranza! Era una saggia sapiente che sapeva leggere in profondità gli eventi della vita. Era una donna che in quel piccolo bambino seppe riconoscere il Messia e annunciarne la missione. Quanto ci deve istruire ciò! Noi che spesso consideriamo gli anziani come degli scarti, come persone che non hanno più nulla da dire e da dare a questa società. <em _istranslated="1">«Noi viviamo in un tempo nel quale gli anziani non contano. È brutto dirlo, ma si scartano, perché danno fastidio. Gli anziani sono quelli che ci portano la storia, che ci portano la fede e ce la danno in eredità. Sono quelli che, come il buon vino invecchiato, hanno questa forza dentro per darci un''eredità nobile» (Papa Francesco). Papa Francesco ricorda una storiella ascoltata da piccolo. «Protagonista è una famiglia – "papà, mamma, tanti bambini" – e il nonno, che quando a tavola mangiava la zuppa "si sporcava la faccia". Infastidito, il papà spiega ai figli perché il nonno si comporti così quindi compra un tavolino a parte dove isolare il genitore. Quello stesso papà un giorno torna a casa e vede uno dei figli giocare con il legno. "Cosa fai?", gli chiede. "Un tavolino", risponde il bimbo. "E perché?". "Per te, papà, per quando tu diventi vecchio come il nonno": "Questa storia mi ha fatto tanto bene, tutta la vita. I nonni sono un tesoro. La Lettera agli Ebrei (13,7) ci dice: ''Ricordatevi dei vostri capi, che vi hanno predicato, quelli che vi hanno predicato la Parola di Dio. E considerando il loro esito, imitn la fede''. La memoria dei nostri antenati ci porta all''imitazione della fede. Davvero la vecchiaia tante volte è un po'' brutta, eh? Per le malattie che porta e tutto questo, ma la sapienza che hanno i nostri nonni è l''eredità che noi dobbiamo ricevere. Un popolo che non custodisce i nonni, un popolo che non rispetta i nonni, non ha futuro, perché non ha memoria, ha perso la memoria"»</em>. Chiediamo la grazia di aver occhi che sanno guardare e mani che sanno accarezzare la solitudine di tanti anziani, a iniziare da quelli di casa nostra, dato che a volte tendiamo a non aver pazienza con loro dimenticando la pazienza che loro hanno avuto con noi! </span></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-30';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span><span _msthash="565" _msttexthash="295961653">«A quanti l''hanno accolto ha dato potere di diventare figli di Dio». Lasciamoci interpellare da queste parole: «a quanti lo hanno accolto...». In sincerità posso dire di aver veramente accolto Cristo nella mia vita? Spesso accogliamo così tante cose nel nostro cuore che alla fine non c''è molto spazio per Lui. Siamo quelli che hanno sem-pre qualcosa da fare, al punto da dimenticare di essere e vivere da figli di Dio! Alla fine di quest''anno solare è bello e salutare ripensa-re a come lo abbiamo vissuto. Ci saranno state tante cose belle per cui ringraziare ma anche meno belle per cui chiedere perdono; met-tiamo tutto davanti a Dio, e soprattutto, chiediamogli la grazia di vi-vere da suoi veri figli, per essere nel mondo riflesso, segno e somi-glianza del suo amore che salva!</span></span></p>
<p _msthash="598" _msttexthash="183649050">
 <em><span _msthash="784" _msttexthash="184929329"><font _msthash="1361" _mstmutation="1" _msttexthash="182115765">«Cristo nasce perché io nasca. Nasca nuovo e diverso. Nasca dall''alto. Il Verbo di Dio è un seme che genera secondo la propria specie. Dio non può che generare Figli di Dio. Tutte le parole degli uomini ci possono solo confermare nel nostro essere carne, realtà incompleta, fragile e inaffidabile. Ma il salto, l''impensabile accade con il Natale, con la Parola che entra nel mondo e porta la vita stessa di Dio in noi. Ecco la vertigine: la vita stessa di Dio in noi. Questa è la profondità ultima del Natale. Dio in me. "Il cristianesimo non è rinuncia, è ingrandimento sconfinato del nostro essere"» (Ermes Ronchi).</font> </span></em></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2024-12-31';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span><span _msthash="645" _msttexthash="1441791">Il Te Deum, un canto di affidamento e di speranza</span></span></em></span></p>
<p _msthash="841" _msttexthash="428266956">
 <span _istranslated="1"><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="644" _msttexthash="26152984">Nell''ultimo giorno dell''anno, alle 17, dopo i Vespri e l''ostensione e adorazione del Santissimo Sacramento, sarà intonato nelle chiese il Te Deum, preghiera di ringraziamento tra le più antiche. </span></span></em></span><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="643" _msttexthash="266799416">Il Te Deum (noi ti lodiamo Dio), insieme al Gloria in excelsis Deo, è l''inno più antico ed è l''espressione che maggiormente simboleggia il sacro. È completamente proteso verso l''alto per rendere lode al Signore e chiedere protezione e salvezza. È un inno che parla di una liturgia celeste che celebrano gli angeli e alla quale partecipano anche gli uomini. Tuttavia, si tratta di un ringraziamento non rutilante, piuttosto è espressione di un''accettazione paziente della durezza che riserva la vita sulla terra. La vita umana non è nulla se non viene sostenuta dalla misericordia del Signore. Perché tutto è nulla se non c''è la sua pietà, affinché non siamo confusi in eterno. E proprio con queste parole, infatti, si chiude l''inno.</span></span></em></p>

<p>
 <span><em><span><span _msthash="642" _msttexthash="14451307">Questa sera dunque cogliamo anche noi l’occasione, in qualsiasi posto ci troviamo, di lodare e ringraziare il Signore cantando il Te Deum.</span></span></em></span></p>
<p _msthash="888" _msttexthash="655993936">
 <em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="641" _msttexthash="2091960">Noi ti lodiamo, Dio, ti proclamiamo Signore. O eterno Padre, tutta</span></span></em> <em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="640" _msttexthash="14037673">la terra ti adora. A te cantano gli angeli e tutte le potenze dei cieli: Santo, Santo, Santo il Signore Dio dell''universo. I cieli e la terra sono pieni della tua gloria. </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="639" _msttexthash="7004452">Ti acclama il coro degli apostoli e la candida schiera dei martiri; le voci dei profeti si uniscono nella tua lode; </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="638" _msttexthash="4934059">la santa Chiesa proclama la tua gloria, adora il tuo unico Figlio, e lo Spirito Santo Paraclito. </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="637" _msttexthash="2318433">O Cristo, re della gloria, eterno Figlio del Padre, tu nascesti </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="636" _msttexthash="1397071">dalla Vergine Madre per la salvezza dell''uomo. </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="635" _msttexthash="2497755">Vincitore della morte, hai aperto ai credenti il regno dei cieli. </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="634" _msttexthash="5277272">Tu siedi alla destra di Dio, nella gloria del Padre. Verrai a giudicare il mondo alla fine dei tempi. </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="633" _msttexthash="8569392">Soccorri i tuoi figli, Signore, che hai redento col tuo sangue prezioso. Accoglici nella tua gloria nell''assemblea dei santi. </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="632" _msttexthash="2100969">Salva il tuo popolo, Signore, guida e proteggi i tuoi figli. </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="631" _msttexthash="6813352">Ogni giorno ti benediciamo, lodiamo il tuo nome per sempre. Degnati oggi, Signore, di custodirci senza peccato. </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="630" _msttexthash="5325489">Sia sempre con noi la tua misericordia: in te abbiamo sperato. Pietà di noi, Signore, pietà di noi. </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="629" _msttexthash="1920932">Tu sei la nostra speranza, non saremo confusi in eterno. </span></span></em></p>
<p>
 <span><em></em></span><em><span><span _msthash="628" _msttexthash="78977847">Un sacerdote domenicano colombiano, padre Nelson Medina, ha raccolto una lista dei rimorsi più comuni che ha sentito esprimere dalle persone che ha accompagnato alla fine della loro vita. Perché non usare questa lista come opportunità per analizzare la nostra anima e impegnarci a vivere in un modo un po’ diverso? </span></span></em></p>
<p _msthash="1339" _msttexthash="2851719">
 <em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="627" _msttexthash="2851719">1.Per le volte in cui ho dato un cattivo esempio e la gente l''ha seguito.</span></span></em></p>
<p _msthash="1339" _msttexthash="10423803">
 <em><span><span _msthash="626" _msttexthash="2899520">2.Per la mia indifferenza di fronte alla sofferenza del mio prossimo.</span></span></em></p>
<p>
 <span><em><span><span _msthash="625" _msttexthash="6555939">3.Per non aver offerto parole di lode, riconoscimento e incoraggiamento a chi le meritava e ne aveva bisogno.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="624" _msttexthash="8107918">4.Per essere stato pronto a prendermi il merito dei miei successi, dando invece la colpa dei fallimenti alle circostanze.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="623" _msttexthash="5192551">5.Per non aver rispettato l''innocenza di una persona, o per aver ostacolato i sogni di qualcuno.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="622" _msttexthash="3671928">6.Per aver speso dei soldi per cose di cui non avevo bisogno e che non ho mai usato.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="621" _msttexthash="9418929">7.Per le volte in cui mi ci è voluto troppo tempo per perdonare gli altri e non mi sono sforzato abbastanza di farlo più rapidamente.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="620" _msttexthash="3094429">8.Per aver approfittato di chi mi voleva bene solo per motivi egoistici.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="619" _msttexthash="4534933">9.Per non aver guidato bene coloro che avrei dovuto educare prima che fosse troppo tardi.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="618" _msttexthash="10279581">10.Per non aver fatto visita o trascorso più tempo con il mio prossimo, perché non lo ritenevo abbastanza interessante, educato o utile.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="617" _msttexthash="8951982">11.Per aver sprecato tanto tempo in cose inutili – tempo che è perduto per sempre.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="616" _msttexthash="3746301">12.Per essermi compiaciuto dell''adulazione, anche quando sapevo che era falsa.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="615" _msttexthash="2976545">13.Per essermi lamentato più volte di quante sono stato invece grato.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="614" _msttexthash="2033746">14.Per le parole rudi o volgari che mi sono uscite di bocca.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="613" _msttexthash="3592004">15.Per aver partecipato a conversazioni che deridevano Dio, la fede o la Chiesa.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="612" _msttexthash="1750125">16.Per le tante volte in cui sono fuggito dalla croce.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="611" _msttexthash="1073046">17.Per le promesse che non ho mantenuto.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="610" _msttexthash="4535323">18.Per i momenti in cui avrei potuto e dovuto pregare di più, e soprattutto amare di più.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="609" _msttexthash="576745">19.Per aver ignorato Gesù.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="608" _msttexthash="2040792">20.Per aver ferito il mio prossimo in un modo o nell''altro.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="607" _msttexthash="8856913">21.Per non aver amato abbastanza – perché avrei dovuto amare molto di più Dio e il mio prossimo.</span></span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2024-12-31';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span _msthash="188" _msttexthash="763070347">La ricerca dei pastori si incontra con il custodire di Maria. Se i pastori sono cercatori e ci insegnano ad aprire gli orizzonti, Maria è colei che conserva il legame fra la storia e ciò che Dio ci comunica. Dio, infatti, parla nella nostra realtà e persino alcune vicende, anche dolorose, possono essere tesori preziosi per compiere nella nostra vita la volontà di Dio e ascoltare la sua voce. Maria avrebbe potuto vivere quel parto tremendo e precario solo come una sciagura, invece si impegnava a capire, aveva deciso con il suo sì di fidarsi di quelle parole di Dio che l''avevano guidata, di quei segni che attestavano la consolazione di Dio nella realtà. Spesso vogliamo subito soluzioni, percorsi preconfezionati, ma così facendo non siamo capaci di far intervenire Dio nelle vicende umane, non gli diamo spazio, non riconosciamo il suo intervento, oscurati dal buio dei nostri dolori. Il Dio della pace, invece, cammina, agisce, si serve anche di noi per fare meraviglie, per farci camminare nel mondo dando gloria a Lui. Diamogli spazio, tempo e soprattutto custodiamo la realtà. Il demonio opera per farci vivere fuori dalla realtà, alienati e distratti. Predisponiamo il cuore allo Spirito di Dio per essere custodi nel mondo dalla Sua presenza.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-01';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span><span _msthash="374" _msttexthash="268866">Maria Madre di Dio</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="373" _msttexthash="317337904">«“Madre di Dio” è il titolo più importante della Madonna. Ma una domanda potrebbe sorgere: perché diciamo Madre di Dio e non Madre di Gesù? Alcuni, in passato, chiesero di limitarsi a questo, ma la Chiesa ha affermato: Maria è Madre di Dio. Dobbiamo essere grati perché in queste parole è racchiusa una verità splendida su Dio e su di noi. E cioè che, da quando il Signore si è incarnato in Maria, da allora e per sempre, porta la nostra umanità attaccata addosso. Non c’è più Dio senza uomo: la carne che Gesù ha preso dalla Madre è sua anche ora e lo sarà per sempre. Dire Madre di Dio ci ricorda questo: Dio è vicino all’umanità come un bimbo alla madre che lo porta in grembo.</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="372" _msttexthash="451959170">La parola madre (mater), rimanda anche alla parola materia. Nella sua Madre, il Dio del cielo, il Dio infinito si è fatto piccolo, si è fatto materia, per essere non solo con noi, ma anche come noi. Ecco il miracolo, ecco la novità: l’uomo non è più solo; mai più orfano, è per sempre figlio. L’anno si apre con questa novità. E noi la proclamiamo così, dicendo: Madre di Dio! È la gioia di sapere che la nostra solitudine è vinta. È la bellezza di saperci figli amati, di sapere che questa nostra infanzia non ci potrà mai essere tolta. È specchiarci nel Dio fragile e bambino in braccio alla Madre e vedere che l’umanità è cara e sacra al Signore. Perciò, servire la vita umana è servire Dio e ogni vita, da quella nel grembo della madre a quella anziana, sofferente e malata, a quella scomoda e persino ripugnante, va accolta, amata e aiutata» (papa Francesco).</span></span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-01';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="636" _msttexthash="3834599704">
 <span><span _msthash="568" _msttexthash="219429314">È interessante che Giovanni si rivela con un atteggiamento di grande umiltà, che parte dalla verità su sé stesso. Mette i suoi interlocutori davanti alla possibilità di non avere dubbi: dice subito chi non è! Solo dopo si definisce non con il suo nome ma con la sua missione, con la sua testimonianza. I farisei ci tenevano a capire se quel personaggio particolare, Giovanni, fosse un pericolo, se il suo comportamento rientrasse nella loro visione su ciò che Dio poteva operare. Soprattutto erano preoccupati perché non solo attirava le folle ma aveva dei seguaci, e questo inquietava i potenti, in particolare Erode Antipa, il tetrarca, governatore della Galilea. </span></span><span _istranslated="1"><span _istranslated="1" _msthash="567" _msttexthash="448603506">Spesso anche noi siamo così: vogliamo valutare le persone, soprattutto se le riteniamo particolari e chiediamo loro di definirsi. È brutto definire gli altri cogliendone i connotati in modo statico, per possederli in qualche modo, anche solo nei nostri schemi mentali, anche solo per avere un appellativo con il quale ricordarli. Facendo ciò possiamo cadere nell''errore di limitare nel nostro pensiero l''opera di Dio e toglierci persino la possibilità di incontrare voci profetiche di ogni tempo, che spesso gridano nel deserto, testimoniano bellezza, indicano la via di Dio. Uno dei segni di ciò che viene da Dio è la verità con cui si presenta; il profeta è sempre qualcuno che ti indica un di più, che non colloca mai la grandezza in sé stesso. È facile che davanti a ciò i potenti siano scontenti: il profeta non può essere posseduto o comprato in nessun modo, sfugge. </span></span><span _istranslated="1">Nel Vangelo di Luca vengono descritti i farisei con queste parole «I farisei, erano attaccati al denaro, ascoltavano tutte queste cose [che diceva Gesù] e si facevano beffe di lui. Egli disse loro: "Voi siete quelli che si ritengono giusti davanti agli uomini, ma Dio conosce i vostri cuori: ciò che fra gli uomini viene esaltato, davanti a Dio è cosa abominevole"» (Lc 16,1415). Questo passo del Vangelo ci dona un criterio di discernimento: i profeti sono diversi dai prepotenti. Questi ultimi si nutrono di megalomania, perciò credono di poter sbeffeggiare gli altri; i profeti, invece, si misurano davanti a Dio e mantengono il senso delle proporzioni, perciò indicano chiaramente chi è il Signore, a cui non sono degni di slegare i lacci dei sandali. Noi spesso siamo lontani da una mentalità libera come quella del Vangelo e questo potrebbe non farci riconoscere i profeti, utilizzando criteri di opportunismo umano, cadendo nel rischioso fascino dell''apparenza. Chiediamo perciò al Signore questo dono: poter essere non persone che cercano il potere e valutano gli altri in base al guadagno che la loro presenza può procurare, ma persone libere che accolgono la diversità benedetta con la quale Cristo ci sorprende consegnandoci la profezia che l''altro porta.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-02';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="642" _msttexthash="213881473">
 <em><span><span>«Anche tanti pensatori nella Chiesa sono stati perseguitati. Io penso ad uno, adesso, [...] un uomo di buona volontà, un profeta davvero, che con i suoi libri rimproverava la Chiesa [...]. Subito è stato chiamato, i suoi libri sono andati all''indice, gli hanno tolto le cattedre e quest''uomo così finisce la sua vita: non tanto tempo fa. È passato il tempo ed oggi è beato! Ma come ieri era un eretico e oggi è un beato? È che ieri quelli che avevano il potere volevano silenziarlo, perché non piaceva quello che diceva. Oggi la Chiesa, che grazie a Dio sa pentirsi, dice: ''No, quest''uomo è buono!''. Di più, è sulla strada della santità: è un beato!» (papà Francesco).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-02';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="2216498128">
 <span>Giovanni "vede" Gesù e il termine usato per descriverlo è al participio presente (<em>erkómenon</em>) che significa "il veniente"; quindi ci dona non solo un''indicazione visiva ma ci dice che Colui che si vede è Colui che è stato atteso. La prima riflessione che possiamo fare è sul modo di guardare di Giovanni, che nella sua spiritualità così austera ci ha insegnato come ammorbidire lo sguardo fino a cogliere la grandezza di Gesù. Ciò ci dice quanto è importante chiedere il dono di una sana vista spirituale per poter riconoscere le cose di Dio. Con questi occhi accoglienti Giovanni riconosce Gesù come "l''agnello di Dio"; è un''immagine carica di significati che descrive un animale noto per la sua mansuetudine. Tutto ciò ricorda la liturgia eucaristica nella quale ripetiamo le parole: "ecco l''agnello di Dio, ecco colui che toglie i peccati del mondo"; sono parole che vivificano un sacrificio che dona salvezza, il sacrificio non di un predatore ma di un mite agnello che nella debolezza più estrema si dona. Sì, l''Onnipotente si presenta con i segni della debolezza. Questo ci ricorda che il senso profondo del nostro vivere non può risiedere nel potere abusante e predatorio, che in cielo non andremo con i titoli o occupando posti, oppure affermando la nostra forza in qualsiasi forma, ma elevando la nostra debolezza. Anche in famiglia quanti giochi di potere animano le nostre case e altrettanto può succedere a lavoro o persino e con vergogna nelle nostre chiese o nelle comunità religiose. Subito ci facciamo padroni, cerchiamo di portare le insegne del potere e del dominio sulla realtà. Quanti nel mondo apprezzano di essere considerati agnellini? Per noi sarebbe un sinonimo di "sempliciotti", di gente che si "sottomette", persone che subiscono! Ebbene no. L''agnello vince, è il principe della pace, è Colui che è re, è Colui che avrà l''ultima parola sulla vita di tutti, sull''umanità intera, e siamo chiamati per vocazione a somigliargli. La Sua Onnipotenza si rivela nell''amore, che è un guadagno diverso, che va percepito con occhi diversi, con occhi divenuti belli, pieni di Spirito Santo, come quelli di Giovanni Battista.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-03';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="603" _msttexthash="339846325">
 <span><em><span>«Gesù prende le radici del potere, le strappa, le capovolge al sole e all''aria, capovolge quella logica che metteva in cima a tutto un Dio dal potere assoluto, compreso quello di decretare la tua morte; e sotto di lui uomini che applicavano a loro volta questo potere, ritenuto divino, su altri uomini, più deboli di loro, in una scala infinita, giù fino all''ultimo gradino. L''agnelloservo, il senza potere, è un "no!" gridato in faccia alla logica del mondo, dove ha ragione sempre il più forte, il più ricco, il più astuto, il più crudele. E l''istituzione non l''ha sopportato e ha tolto di mezzo la voce pura, il sogno di Dio. Ecco l''agnello, mitezza e tenerezza di Dio che entrano nelle vene del mondo, e non andranno perdute, e porteranno frutto; se non qui altrove, se non oggi nel terzo giorno di un mondo che sta nascendo» (p. Ermes Ronchi).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-03';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="4008581226">
 <span>Gesù usava poche parole ben misurate, non spiegava tutto, non chiacchierava a vuoto, diceva ciò che poteva servire a chi ascoltava e che preservava la libertà dell''altro di aderire alle sue parole. Stimolava con le sue domande la ricerca, non dava certezze né assicurava possessi ma invitava a camminare. Non lasciare spazio all''altro, spiegando tutto, rivelando ogni cosa della nostra vita, delle nostre intenzioni, di quello che viviamo, toglie all''altro la partecipazione alla realtà. In un tempo veloce, dove tutto si deve dire e comunicare, dove la gente vuole sapere in anticipo ogni cosa, il Signore ci invita ad assaporare ciò che facciamo, a fare esperienza della Sua presenza. Anche nella nostra vita relazionale, alcune persone pensano che essere familiari, amici, marito e moglie o comunità, significa sapere tutto dell''altro, domandare ogni cosa, cercare compagnia convulsivamente per possedere un po'' dell''altro e vincere la solitudine, senza avere una propria intimità. Se la condivisione è importante lo è altrettanto il conoscersi, l''attendere, il rispetto dell''intimità altrui, la delicatezza quando ci avviciniamo alla vita degli altri. Perciò diventiamo sempre più superficiali quando parliamo e indaghiamo troppo ma non sappiamo tacere, custodire. È così che perdiamo la bellezza dell''attendere, di aspettare il giusto tempo per scoprire l''altro, per gioire, per piangere, per condividere, per veder crescere. Anche di un film noi vogliamo sapere sempre le anticipazioni, così come della vita degli altri; amiamo guardare dal buco della serratura, svelare i segreti, sentire, far parlare gli altri affinché ci rivelino aspetti inediti della loro vita... non vogliamo ricevere troppe domande, ma piuttosto avere risposte e rivelazioni. Pietro si sentì dire da Gesù: "tu Simone, sarai Cefa". Ma cosa vuol dire? Cosa succederà? Qual è la vocazione di Pietro? Egli la scoprirà camminando, attendendo, andando e vedendo, attuando un approccio equilibrato alla vita, che ti fa assaporare la bellezza degli incontri, di ciò che fai, di ciò che senti e vivi. "Andando vedendo" è la traduzione pratica dell''invito di Gesù "venite e vedete", cioè assaporate le cose, attendete nella gioia. Ecco, questa è la bellezza dell''attesa, del camminare verso una meta senza sapere cosa ti riserverà il percorso: questo è vivere. E vivi bene e nella gioia, non perché sai prima cosa ti succederà ma perché conosci la meta. Perciò oggi, in questi esercizi spirituali quotidiani, alla luce del Vangelo, chiediamoci se vogliamo essere gente che vive sempre in avanti, che non sa attendere, che consuma la vita propria e quella altrui, che vuole possedere il tempo, le cose, le verità. Oppure, se vogliamo essere persone che sanno assaporare la vita, che sanno camminare verso la meta, che sanno cantare di gioia mentre vivono l''incertezza del momento.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-04';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="585" _msttexthash="38947090">
 <span><em><span>«Aspettare procura dolore. Qualcosa si contrae in una regione del corpo, si crea una specie di corrente d''aria fra due porte lasciate aperte per distrazione. L''attesa ha diverse temperature. Si può aspettare con il freddo nel cuore o bruciando di desiderio» (Andrea Köhler).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-04';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span><span _msthash="630" _msttexthash="72416903">La seconda domenica di Natale offre la possibilità di soffermarsi sul <em>prologo</em> del Vangelo secondo Giovanni. È un testo importantissimo, in forma poetica, che non soltanto anticipa e riassume in parte il Vangelo stesso ma offre delle chiavi preziose per leggerlo e comprenderlo. Trattandosi di un testo molto vasto, soffermiamoci su tre parole: il principio, la luce, la grazia.</span></span></p>
<p>
 <span><span _msthash="629" _msttexthash="1156455911">La prima parola è in <em _istranslated="1">principio</em>. Il prologo inizia così: «In principio era il Verbo, e il Verbo era presso Dio e il Verbo era Dio». L''evangelista richiama il libro della Genesi («In principio Dio creò il cielo e la terra») e lo supera. All''origine di tutto, in principio, c''era il Verbo, in greco il logos, la Parola. E questo Verbo era «presso Dio», che più precisamente si potrebbe tradurre: "era rivolto a Dio"; e questo Verbo «era Dio». Dunque, in principio, all''origine di tutto c''era Dio, con la sua Parola con la quale è da sempre in amorevole dialogo e per mezzo della quale ha creato tutto. Perciò Marzotto traduce: «all''inizio era il Dialogo». Dunque Dio esiste da sempre e per sempre, non un Dio solitario ma un Dio uno e trino, ovvero un "Dio comunione". Dunque tutto parte dall''amore e tende alla comunione. Tutto ciò, tra le altre cose, ci ricorda che il vero punto di partenza è Dio stesso, che a Lui dobbiamo guardare e tendere se desideriamo che la nostra vita non sia un aggrovigliato gomitolo ma un tessuto di senso e d''amore. Sbagliare il punto di partenza e non avere la giusta meta significa condannarsi a vivere da erranti, privi del senso ultimo di orientamento per la propria vita. Per questo il Verbo eterno del Padre si è fatto uomo: per salvarci, ricordandoci peraltro chi siamo, da dove veniamo e verso dove siamo diretti! Questo ci fa chiedere: qual è il mio principio? A cosa tendono le mie azioni e le mie scelte? Qual è "la bussola" che orienta le mie scelte? Posso dire che il mio centro è Gesù e che per me amare è la cosa più importante?</span></span></p>
<p _msthash="813" _msttexthash="554792017">
 <span _istranslated="1">La seconda parola è la </span><em _istranslated="1">vita</em><span _istranslated="1">. Giovanni nel prologo ci dice che «in Lui [nel Verbo] era la vita e a vita è la luce degli uomini». Ci fa capire che il Verbo che si è fatto carne in Gesù ha in sé la vita e ci dona la vita. Una vita nuova, redenta, la vita di Dio nel cuore. Ridurre il cristianesimo a una serie di regole o a un''etica di vita significa decurtarlo della sua pienezza. La fede cristiana è adesione a Cristo, e aderire a Lui significa accogliere in noi la Sua presenza, la Sua vita (eterna). Significa poter vivere una vita nuova, redenta, libera dalle ristrettezze del proprio ego e dell''egoismo. Noi siamo affamati di vita e la risposta a questa fame di pienezza, di senso, è solo una: Cristo Gesù. Questo ci aiuta a chiederci: e io cosa chiedo al Signore? Per cosa lo cerco? Solo per le cose materiali? Solo per risolvere problemi? O gli chiedo in dono lo Spirito Santo, di darmi un cuore nuovo, di rendermi capace di amare come Lui, di perdonare, di sopportare? Ho capito che Gesù non mi dà solo delle cose o "delle grazie" ma è venuto a darmi se stesso? Perché io possa diventare come Lui?</span></p>
<p _msthash="798" _msttexthash="463344115">
 <span _istranslated="1">La terza parola è la </span><em _istranslated="1">luce</em><span _istranslated="1">. È un''immagine significativa, usata dall''evangelista per parlarci della Rivelazione che Gesù è venuto a portarci. All''opposto, ecco le tenebre del peccato e della morte. È semplice capire la valenza della luce. Essa rischiara, permette di vedere, rasserena. Ecco, accogliere la parola del Signore, meditando le Sacre Scritture e accogliendo la sapienza della Chiesa, significa accogliere questa "luce" capace di rischiare le nostre tenebre, ovvero la confusione, il non senso che ci abita. Significa poter cogliere il senso profondo della realtà, capire qual è il bene da compiere, cogliere chi è Dio e chi sono io. Questa luce è fondamentale. Quante volte soffriamo nella vita, non tanto per gli eventi, ma per l''interpretazione che gli diamo. Accogliere la luce significa diventare capaci di scorgere la Provvidenza dietro una sofferenza, un''occasione dietro una tribolazione, una chiamata alla santificazione dietro una tribolazione...</span></p>
<p>
 <span _msthash="783" _msttexthash="20246642">Questa domenica ci chiama a riscoprire il nostro vero principio, ad accogliere la vita e la luce che Cristo è venuto a donarci, per vivere secondo la Sua Parola una vita piena che profuma d''eternità!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-05';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span><span _msthash="826" _msttexthash="94055">PREGHIERA</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="825" _msttexthash="1967056">Signore, rischiara le mie tenebre, pacifica il mio cuore</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="824" _msttexthash="1135771">e insegnami a vivere secondo il tuo amore!</span></span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-05';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="633" _msttexthash="3610457071">
 <span _istranslated="1"><span _istranslated="1" _msthash="592" _msttexthash="2913179087"><em>"Se l''unico strumento che hai in mano è un martello, ogni cosa inizierà a sembrarti un chiodo"</em>, diceva Abraham Maslow. Questa citazione fa pensare a ciò che attuiamo quando siamo privi di risorse per affrontare le nostre paure e le nostre fragilità. Erode, come tutti coloro che "si nutrono di onnipotenza", tentava di custodire la propria regalità. Anche noi spesso siamo così (anche se ci piace riconoscerci sempre dalla parte dei buoni!). Anche a noi le parole dei re magi, cariche di attese, possono non suscitarci sorpresa e meraviglia. Erode, infatti, ad un annuncio lieto, rispose con l''unico mezzo che aveva per difendere sé stesso: colpire. Molte persone vivono così, ritenendo gli altri colpevoli di insidiare il loro posto, la loro importanza, perciò tramano insidie, accecati dall''egoismo. Anche noi spesso somigliamo più ad Erode che ai magi. Viviamo sulla difensiva, perciò non sappiamo cogliere la bellezza che ci circonda, sempre preoccupati di complotti ai nostri danni, di disgrazie che stanno sopraggiungendo con il fallimento conseguente. Eppure la stella della presenza di Cristo brilla ancora, e spesso si affaccia sul nostro cielo. Si tratta di una stella che ci precede, che indica la via e ci attesta la presenza del Signore, che abita anche i nostri sogni, come quelli dei re magi, avvertiti di allontanarsi da Erode. Quest''ultimo perse l''occasione di assistere alla vera regalità, di poter vedere con gli occhi della carne il Dio bambino. Che tristezza, quando il nostro egoismo prende il sopravvento e offusca la presenza di Dio! Anche a lavoro, in famiglia o nella comunità cristiana, tante volte Dio si fa presente mentre noi siamo più impegnati a difendere noi stessi e la nostra immagine, perdendo così la bellezza che possiamo vivere. Quanti prima di morire pensano: perché ho passato tutta la mia vita a litigare e a trovare "chiodi da colpire"? Perché non ho pensato prima ad andare all''essenziale, a vivere di cose belle, a percepire tutta la bellezza di cui sono stato circondato? </span></span><span _istranslated="1">Che l''esempio dei magi ci illumini; tanti re magi percorrono la nostra storia e sono esempi di bellezza, persone non impegnate a colpire gli altri ma a riconoscerli nella loro dignità, ascoltatori di Dio, promotori di bellezza, collaboratori di una gioia grandissima a beneficio dell''umanità. A chi vogliamo somigliare? Anche noi possiamo entrare come i magi nella casa di Nazareth, per vedere il Dio bambino ed accoglierlo nella nostra vita. Facciamo nostri questi esempi costruttivi, impariamo ad essere pacificatori, non gente sempre armata! Cosa dobbiamo vincere con la prepotenza? E soprattutto: vale la pena perdere la presenza di Dio, per una falsa "gloria" o per un delirio di grandezza? Cosa vale davvero?</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-06';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="760187493">
 <span>Il popolo che abitava nelle tenebre, si era abituato alle tenebre! Sì, se provassimo a vivere al buio per un po'' di tempo, sapremmo come può essere doloroso incontrare la luce e sentire realmente di volerla rinnegare. Questa immagine rende bene cosa arreca l''abitudine al male, il fare spazio al peccato che genera tenebre in noi e attorno a noi. Oggi, perciò, impariamo a non sottovalutare il peccato e anche i luoghi bui che frequentiamo, che possono accrescere le tenebre e renderci incapaci di accogliere la bellezza di Dio che si presenta a noi. Non è scontato tutto ciò: spesso sottovalutiamo sia il peccato personale (come se i nostri "peccatucci" non procurassero tenebra nel mondo), sia i sistemi tenebrosi che uccidono la bellezza nel mondo. Sì, anche i nostri peccati portano quel tanto di tenebra che imbruttisce le nostre relazioni, le nostre famiglie, le comunità e persino i nostri volti, che prendono sembianze tenebrose, diventano scuri, cupi. Le tenebre sono pronte ad avvolgerci non appena liberiamo il peccato nel nostro cuore e nel mondo. La confessione, perciò, è un rimedio santo, un abbraccio di luce che stabilisce nuovamente il nostro valore indissolubile, e ci ricorda che Dio è sempre pronto a riconnetterci alla luce.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-07';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="585" _msttexthash="453935014">
 <span><em><span>"C''è gente – anche noi, tante volte – che non può vivere nella luce perché abituata alle tenebre. La luce li abbaglia, sono incapaci di vedere. Sono dei pipistrelli umani: soltanto sanno muoversi nella notte. E anche noi, quando siamo nel peccato, siamo in questo stato: non tolleriamo la luce. È più comodo per noi vivere nelle tenebre; la luce ci schiaffeggia, ci fa vedere quello che noi non vogliamo vedere. Ma il peggio è che gli occhi, gli occhi dell''anima dal tanto vivere nelle tenebre si abituano a tal punto che finiscono per ignorare cosa sia la luce. Perdere il senso della luce, perché mi abituo più alle tenebre. E tanti scandali umani, tante corruzioni ci segnalano questo. I corrotti non sanno cosa sia la luce, non conoscono. Anche noi, quando siamo in stato di peccato, in stato di allontanamento dal Signore, diventiamo ciechi e ci sentiamo meglio nelle tenebre e andiamo così, senza vedere, come i ciechi, muovendoci come possiamo" (papa Francesco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-07';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="534342159">
 <span>Questo Vangelo mette insieme l''ordinario e lo straordinario, il poco e la grandezza di Dio che moltiplica. È bello oggi riflettere sulla bellezza delle cose quotidiane, di quei gesti che ci sembrano inutili, infantili, come pensare di sfamare la folla con cinque pani e due pesci. La grandezza delle cose semplici consiste proprio in questo: credere veramente che Dio può intervenire con il mio poco. Perciò dall''infanzia dei bambini e dall''entusiasmo degli adolescenti, dobbiamo imparare a non limitare lo slancio di chi, mettendo il suo poco, vuole dare molto al mondo. Soprattutto non dobbiamo mettere limiti a Dio che ha creato il mondo, ha sfamato folle partendo da cinque pani e due pesci, ha trasformato la vita di grandi peccatori, ha risuscitato morti e perdona ogni peccato: avrà forse remore nel moltiplicare il nostro poco? Coltiviamo una grande fiducia nel Signore e preoccupiamoci solo di amare, di condividere, di allargare gli orizzonti, con Lui niente di ciò che è amore verrà perduto, anche un granello di polvere di bontà.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-08';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="585" _msttexthash="282807317">
 <span><span><em>«Ogni piccola azione è un avvenimento immenso nel quale ci viene dato il paradiso, nel quale possiamo dare il paradiso. Non importa quel che dobbiamo fare: tenere in mano una scopa o una stilografica. Parlare o tacere, rammendare o fare una conferenza, curare un malato o battere a macchina. Tutto ciò non è che la scorza della realtà splendida, l''incontro dell''anima con Dio rinnovata ad ogni minuto, che ad ogni minuto si accresce in grazia, sempre più bella per il suo Dio. Suonano? Presto, andiamo ad aprire: è Dio che viene ad amarci. Un''informazione? … eccola: è Dio che viene ad amarci. E'' l''ora di metterci a tavola? Andiamoci: è Dio che viene ad amarci. Lasciamolo fare» (Madeleine Delbrêl).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-08';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="569" _msttexthash="1129214177">
 <span>Quante paure abbiamo, soprattutto quando ci sentiamo impotenti e soli. Anche per noi alcune volte il vento è contrario: malattie, persone care che soffrono, dipendenze, litigi, amori disordinati, contese, tenebre che arrivano improvvise. E Gesù, che non ha inventato il peccato, la morte, la sofferenza, si fa presente con noi, cammina verso di noi, infinitamente fragile si rivela a noi come l''Onnipotente che interviene e ci dice: "Coraggio, non sentirti solo, io ci sono proprio mentre tutto ti sembra andare al contrario". Riconosciuto l''arrivo del Signore, il vento cessa di soffiare, tutto acquista un altro senso! Anche noi come i discepoli possiamo coltivare la durezza di cuore, lamentarci della sua assenza e non riconoscerlo; non solo avere paura, come se Lui non si interessasse di noi, ma continuare a indurire il cuore anche mentre si fa presente. Come i discepoli, che dopo aver visto i pani moltiplicarsi, non avevano ancora capito che Dio è per noi, scommette su noi, si fa vicino concretamente. Non dimentichiamo mai non solo di non essere soli ma che dobbiamo avere cuori aperti per accogliere la bellezza, altrimenti la durezza ci fa rifiutare il bello e ci fa chiudere nella depressione e nel lamento, mentre Dio è con noi. Non concentriamoci sul disagio ma sulla bellezza di un Dio che ci raggiunge ad ogni costo, persino camminando sul mare per venire da noi. Decentriamoci, così possiamo avere occhi profondi, capaci di partecipare attivamente all''opera di Dio, per diffondere speranza e pace nel mondo</span>.</p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-09';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="707" _msttexthash="1913743">
 <span _istranslated="1"><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="606" _msttexthash="385177">Quando Ti chiedo pace, </span></span></em></span></p>
<p _msthash="707" _msttexthash="1889498">
 <span _istranslated="1"><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="606" _msttexthash="19812">Tu</span></span></em></span> <em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="605" _msttexthash="705081">mi mandi contese da pacificare. </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="604" _msttexthash="385164">Quando Ti chiedo casa,</span></span></em></p>
<p>
 <span><em><span><span _msthash="603" _msttexthash="548457">Tu mi porti mari da solcare.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="602" _msttexthash="389805">Quando Ti chiedo luce, </span></span></em></span></p>
<p>
 <span><em><span><span _msthash="601" _msttexthash="503139">Tu mi conduci attraverso </span></span></em></span></p>
<p>
 <span><em><span><span _msthash="600" _msttexthash="434330">tenebre da illuminare.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="599" _msttexthash="1112774">Quando cerco la Tua presenza, Tu ti celi....</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="598" _msttexthash="470366">Ti amo, o Dio silente, che, </span></span></em></span></p>
<p>
 <span><em><span><span _msthash="597" _msttexthash="704717">ogniqualvolta fisso gli occhi </span></span></em></span></p>
<p>
 <span><em><span><span _msthash="596" _msttexthash="305396">sul mio desiderio, </span></span></em></span></p>
<p>
 <span><em><span><span _msthash="595" _msttexthash="1037296">mi inviti a volgere lo sguardo altrove, </span></span></em></span></p>
<p>
 <span><em><span><span _msthash="594" _msttexthash="907062">spalancando orizzonti più grandi </span></span></em></span></p>
<p>
 <span><em><span><span _msthash="593" _msttexthash="476424">delle mie povere attese.</span></span></em></span></p>
<p>
 <span><em><span><span _msthash="592" _msttexthash="324298">(Luigi Santopaolo)</span></span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-09';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="2107149330">
 <span>La potenza dello Spirito accompagnava l''opera di Gesù, una meraviglia che segnò le sorti dell''umanità. Tuttavia colpisce constatare che come nella vita di Cristo, anche in quella di uomini e donne di ogni tempo, la difficoltà più grande è essere riconosciuti lì dove si è cresciuti. Spesso per le persone che pensano di sapere tutto su di noi, non siamo altro che "quelli che già conoscono", niente di più. È difficile, infatti, cogliere la straordinarietà della vita ordinaria, saper vedere la grandezza dell''amore fedele e costante, saper riconoscere un <em>leader</em> fra i nostri amici e conterranei, saper riconoscere e sponsorizzare qualsiasi talento o caratteristica di accoglienza e bontà di qualcun''altro. Persino nel nucleo familiare spesso non si incoraggiano le attitudini positive, anzi, non si riconoscono affatto! Perciò, ritornando al Vangelo, i compaesani di Gesù, al sentirgli dire di essere venuto per compiere la Parola che aveva letto, rimasero increduli. Avranno pensato che fosse diventato matto! Eppure quella per loro era un''occasione, avevano a che fare con Dio, con Colui che non solo compie ma è la Parola fatta carne. Anche in noi deve farsi carne la Parola nella pratica, così ci verrà più facile percepire che l''opera di Dio non può essere limitata ai nostri schemi mentali, anche quando si compie nel fratello e nella sorella che ho accanto. Come Gesù, Dio fattosi uomo, ha dovuto attraversare l''irriconoscenza, anche noi possiamo vivere lo stesso, ma questo non può comunque fermare lo Spirito che ci spinge ad agire nella storia. La Sua Parola continua a incarnarsi e non possiamo pensare di riconoscere Dio in azione solo nello straordinario, perché la potenza di Dio opera abitualmente nell''ordinario. Se avessimo più fiducia nella sua Parola, più di quanta ne abbiamo per le nostre elaborazioni della realtà e per i nostri piani strategici e visioni stravaganti, sapremo fare del nostro quotidiano un capolavoro. Dovunque ci troviamo, in ogni posto, in ogni situazione, può entrare la potenza dello Spirito di Dio ed essere riconosciuta.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-10';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="593" _msttexthash="285949638">
 <em><span><span>«Un giorno mi trovavo con le mie compagne e, aprendo il piccolo libro, lessi: "Padre, che tutti siano una cosa sola (Gv 17,21). Era la preghiera di Gesù prima di morire. Per la sua presenza fra di noi e per un dono del suo Spirito, mi parve di capire un po'' quelle parole difficili e forti, e mi nacque in cuore la convinzione che per quella pagina del Vangelo fossimo nate: per l''unità, e cioè per contribuire all''unità degli uomini con Dio e fra di loro... Per noi fu chiaro, fin dal primo momento, che quest''unità aveva un solo nome: Gesù. Essere uno, per noi, significava essere Gesù, esser tutti Gesù. Infatti solo Cristo può far di due uno, perché il suo amore che è annullamento di sé, che non è egoismo, ci fa entrare fino in fondo nel cuore degli altri» (Chiara Lubich).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-10';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span><span _msthash="565" _msttexthash="970225074">Oggi vogliamo meditare su due punti importanti: il primo è la guarigione che ci porta Gesù. Egli è disposto a toccare anche il nostro corpo infetto per guarirci. Sì, Gesù si espone al contagio per liberare il nostro cuore, non ha paura di avere a che fare persino con le cose più brutte che abbiamo fatto o coltivato dentro di noi, quelle malattie invisibili che ci si attaccano addosso. Questo vuol dire che nel cuore di Dio c’è spazio per tutti, c’è spazio per me nonostante tutto! Di conseguenza questo è il motivo per cui non possiamo sentirci a posto davanti ai problemi degli altri, perché come Gesù ha misericordia di noi, e ci accoglie nonostante i nostri limiti, così siamo chiamati a fare con gli altri dando testimonianza con la nostra vita. Se Gesù fa spazio a tutti, perché dovremmo tenere fuori dal nostro amore qualcuno? Spesso la nostra morale rigida e intransigente è divenuta il pretesto per non avvicinarci a nessuno, per “non contagiarci” con la vita altrui. Operando così, però, contraddiciamo il principio di universalità dell’amore: la Chiesa è per tutti, così come Cristo non ha ristretto la salvezza ad alcuni. </span></span></p>
<p>
 <span><span _msthash="564" _msttexthash="781060124">L’altro punto importante su cui oggi vogliamo meditare è la modalità con cui opera Gesù, rifiutando ogni forma di clamore, per cui si ritirava a pregare in luoghi deserti quando la folla si accalcava. Noi spesso quando vediamo folle ci esaltiamo, cominciamo a contare e annunciare i numeri che per noi dovrebbero significare la riuscita e la bontà della nostra opera. Così facendo rinunciamo ad ascoltare la sete di verità, la gratuità della folla. E più ci esaltiamo e più ci organizziamo per far sì che i numeri aumentino in qualche modo, così che il Vangelo ci diciamo raggiunga tutti. Ma non è che nascondiamo la vanagloria sotto buoni propositi? Forse il criterio di Gesù era quello del clamore? Quando operiamo per cosa lo facciamo, per la salvezza, per i numeri, per la riuscita e la gloria conseguente? Utilizziamo la vita cristiana per la nostra gloria personale? Badiamo a questa sottile tentazione che non ci fa essere strumenti di guarigione, perché ci fa fermare solo dove c’è la folla che acclama, dimenticando di ascoltare l’altro e ignorando i lebbrosi, i poveri, i vagabondi, i cercatori di Dio.</span></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-11';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="607" _msttexthash="525159245">
 <span><em><span>«La Chiesa siamo tutti! Tutti! Dal primo battezzato, tutti siamo Chiesa, e tutti dobbiamo andare per la strada di Gesù, che ha percorso una strada di spogliazione, Lui stesso. E'' diventato servo, servitore; ha voluto essere umiliato fino alla Croce. E se noi vogliamo essere cristiani, non c''è un''altra strada. Ma non possiamo fare un cristianesimo un po'' più umano – dicono – senza croce, senza Gesù, senza spogliazione? In questo modo diventeremo cristiani di pasticceria, come belle torte, come belle cose dolci! Bellissimo, ma non cristiani davvero! Qualcuno dirà: "Ma di che cosa deve spogliarsi la Chiesa?". Deve spogliarsi oggi di un pericolo gravissimo, che minaccia ogni persona nella Chiesa, tutti: il pericolo della mondanità. Il cristiano non può convivere con lo spirito del mondo. La mondanità che ci porta alla vanità, alla prepotenza, all''orgoglio. E questo è un idolo, non è Dio. È un idolo! E l''idolatria è il peccato più forte!» (papà Francesco). </span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-11';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span _msthash="188" _msttexthash="8508630">Il battesimo del Signore è una bella occasione per soffermarci sul senso del suo battesimo e sul senso del nostro battesimo.</span></p>
<p>
 <span _msthash="189" _msttexthash="2759267602">Mediante il battesimo, Gesù si rivela al popolo e a noi. Giovanni Battista dice il fine della sua missione (battezzare nello Spirito Santo e nel fuoco, ovvero immergerci nella vita di Dio e purificarci dal peccato). Dio Padre ci dice chi è Gesù (il Figlio amato). Gesù invece rivela il suo stile, il suo modo di essere. È dunque importante capire "come" si rivela. Se noi fossimo stati Dio, come ci saremmo presentati al mondo? Ognuno risponda... Gesù invece si mette in fila tra i peccatori, ricevendo il battesimo di Giovanni! Come ha spiegato bene Benedetto XVI: <em _istranslated="1">«Avviene quello che ai nostri occhi potrebbe apparire paradossale. Gesù ha bisogno di penitenza e di conversione? Certamente no. Eppure proprio Colui che è senza peccato si pone tra i peccatori per farsi battezzare, per compiere questo gesto di penitenza; il Santo di Dio si unisce a quanti si riconoscono bisognosi di perdono e chiedono a Dio il dono della conversione, cioè la grazia di tornare a Lui con tutto il cuore, per essere totalmente suoi. Gesù vuole mettersi dalla parte dei peccatori, facendosi solidale con essi, esprimendo la vicinanza di Dio. Gesù si mostra solidale con noi, con la nostra fatica di convertirci, di lasciare i nostri egoismi, di staccarci dai nostri peccati, per dirci che se lo accettiamo nella nostra vita Egli è capace di risollevarci e condurci all''altezza di Dio Padre. E questa solidarietà di Gesù non è, per così dire, un semplice esercizio della mente e della volontà. Gesù si è immerso realmente nella nostra condizione umana, l''ha vissuta fino in fondo, fuorché nel peccato, ed è in grado di comprenderne la debolezza e la fragilità. Per questo Egli si muove a compassione, sceglie di "patire con" gli uomini, di farsi penitente assieme a noi. Questa è l''opera di Dio che Gesù vuole compiere: la missione divina di curare chi è ferito e medicare chi è ammalato, di prendere su di sé il peccato del mondo... Di fronte a questo atto di amore umile da parte del Figlio di Dio, si aprono i cieli e si manifesta visibilmente lo Spirito Santo sotto forma di colomba, mentre una voce dall''alto esprime il compiacimento del Padre, che riconosce il Figlio unigenito, l''Amato. Si tratta di una vera manifestazione della Santissima Trinità, che dà testimonianza della divinità di Gesù, del suo essere il Messia promesso, Colui che Dio ha mandato a liberare il suo popolo, perché sia salvato» (cfr Is 40,2).</em></span></p>
<p>
 <span _msthash="190" _msttexthash="634398739">Passiamo ora al senso del nostro battesimo. Ricevendo il battesimo, siamo stati immersi nella vita della SS. Trinità, siamo stati uniti in modo profondo e vitale a Cristo, resi partecipi della sua relazione filiale con il Padre. Siamo stati immersi nel mistero della sua morte e siamo stati resi partecipi della sua risurrezione che è fonte di vita nuova. Con il battesimo ci è stato fatto un dono grande, immenso, che a volte neanche conosciamo. Come dice il Catechismo della Chiesa Cattolica: <em _istranslated="1">«Il Battesimo non soltanto purifica da tutti i peccati, ma fa pure del neofita una "nuova creatura" (2 Cor 5,17), un figlio adottivo di Dio che è divenuto "partecipe della natura divina" (2 Pt 1,4), membro di Cristo e coerede con lui, tempio dello Spirito Santo. La Santissima Trinità dona al battezzato la grazia santificante, la grazia della giustificazione che I) lo rende capace di credere in Dio, di sperare in lui e di amarlo per mezzo delle virtù teologali; II) gli dà la capacità di vivere e agire sotto la mozione dello Spirito Santo per mezzo dei doni dello Spirito Santo; III) gli permette di crescere nel bene per mezzo delle virtù morali» (CCC 1265-1266). </em></span></p>
<p>
 <span _msthash="191" _msttexthash="147282252">Sì, dal giorno del battesimo è stata seminata nei nostri cuori la vita del cielo che siamo chiamati ad accrescere e alimentare mediante la preghiera, la partecipazione ai sacramenti e la carità, incarnando quello stile di vicinanza, di tenerezza e di compassione che Cristo ci ha mostrato. Siamo chiamati alla grandezza, alla santità, a vivere sulla terra secondo il cielo, uniti a Cristo, seminando amore, giustizia, fraternità. Chiediamoci in sincerità: stiamo facendo fruttificare questo tesoro immenso? Se no, per cosa stiamo vivendo? </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-12';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span _msthash="279" _msttexthash="94055">PREGHIERA</span></span></em></p>
<p>
 <em><span><span _msthash="280" _msttexthash="17301713">O Padre, che nel battesimo del Giordano con l''autorità della tua voce e la discesa dello Spirito ci hai presentato solennemente il Signore Gesù come l''Unigenito che tu ami, dona a chi, </span></span></em></p>
<p>
 <em><span><span _msthash="281" _msttexthash="8431397">rigenerato dall''acqua e dallo Spirito, è diventato tuo figlio di vivere senza smarrimenti secondo il tuo disegno di amore. </span></span></em></p>
<p>
 <em><span><span _msthash="282" _msttexthash="11556896">Per Gesù Cristo, tuo Figlio, nostro Signore e nostro Dio, che vive e regna con te, nell''unità dello Spirito Santo, per tutti i secoli dei secoli. Amen. </span></span></em></p>
<p>
 <em><span><span _msthash="283" _msttexthash="901914">(Orazione della liturgia delle ore)</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-12';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="1141584288">
 <span>Gesù nel Vangelo si rivela con un''immagine a noi cara, quella del viandante: Egli andando parlava, chiamava, guariva. L''intera Scrittura ci rivela questo camminare di Dio nella storia, un processo di avvicinamento all''umanità che ha il suo culmine in Gesù. Questo camminare, però, non riguarda solo il passato; infatti, anche oggi tante persone, incontrando Gesù, vedono trasformata la loro vita. Alcuni, vivono una rivoluzione tale da decidere di lasciare tutto, come Giovanni e suo fratello, che seguirono Gesù lasciando il loro padre Zebedeo nella barca con i garzoni, Questa sottolineatura nel testo ci dice la grandezza di un''esperienza che tocca la vita: dal momento in cui Gesù si affaccia realmente nella vita accade che si è disposti a trasformare tutto, ogni cosa splende di una gioia e bellezza tale che si relativizza la storia, la si vive concretamente e fino in fondo con occhi pieni di ulteriorità. Questa è quella che alcune persone chiamano follia! Ci vogliamo chiedere: Da quando abbiamo perso questa grandezza e radicalità, da quando siamo diventati un club di gente per bene? Forse è più la follia la caratteristica del cristiano, cioè la vita di una persona che vive con i piedi a terra e il cuore rivolto al cielo, la vita di chi è disposto a testimoniare concretamente e a pagare per quello in cui crede, perciò non ha paura di svuotare la propria tasca, di lasciare qualcosa, perché ha trovato molto di più. La tiepidezza non ci si addice come cristiani, siamo i seguaci gioiosi del Dio della risurrezione!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-13';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="585" _msttexthash="26249821">
 <span><span><em>«Il fine della vita cristiana è l''acquisizione dello Spirito Santo. Egli opera in noi una spiritualizzazione del cuore, rendendolo cuore cosciente, cuore presente, cuore amante, cuore santificato» (san Serafino di Sarov).</em></span></span></p>

<p _msthash="585" _msttexthash="26249821">
 <em><span>Parole del santo del giorno, sant’Ilario di Poitiers:</span></em></p>
<p>
 <em><span><span>«Dio non sa essere altro se non amore, non sa essere altro se non Padre. E chi ama non è invidioso, e chi è Padre lo è nella sua totalità. Questo nome non ammette compromessi, quasi che Dio sia padre in certi aspetti, e in altri non lo sia» (De Trinitate, 9,61). </span></span></em></p>
<p>
 <em><span>«Fa’, o Signore che io mi mantenga sempre fedele a ciò che ho professato nel Simbolo della mia rigenerazione, quando sono stato battezzato nel Padre, nel Figlio e nello Spirito Santo. Che io adori te, nostro Padre, e insieme con te il tuo Figlio; che io meriti il tuo Spirito Santo, il quale procede da te mediante il tuo Unigenito... Amen» (La Trinità 12,57).</span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-13';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="567" _msttexthash="864605755">
 <span>L''autorità di Gesù si fonda sulla sua testimonianza credibile, al punto che persino i sacerdoti del tempo riconoscono il suo insegnamento come qualcosa che non necessita di essere imposto con la forza o la persuasione. Anche i demoni riconoscono questa autorevolezza di Gesù, sentendosi disturbati dalle sue parole, perciò gli dicono: "Sei venuto a rovinarci?", come a dire "Sei venuto a turbare la nostra quiete e a mettere in discussione il nostro operato?". L''annuncio del Vangelo ha un effetto potente che non si impone con la forza, ma ci tocca profondamente. Perciò anche noi possiamo sentirci disturbati dal Signore, possiamo essere quelli che si sentono scomodati e che cercano di silenziare gli annunci che ricevono. Al contempo quando la nostra vita non prende autorità da Dio stesso, per accaparrarci l''ascolto degli altri usiamo o l''autoritarismo o, all''opposto, un atteggiamento eccessivamente mondano. Questo accade spesso nelle relazioni genitoriali, dove il dialogo e l''ascolto che mancano vengono sostituiti dall''autoritarismo o, al contrario, dall''essere "amiconi dei figli", mancando di quella autorevolezza necessaria per accompagnarli nella crescita in modo sano. Gesù, invece, ci mostra la strada della sequela e della testimonianza umile del discepolo, rendendo la vita autorevole e pacifica.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-14';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="587" _msttexthash="637700479">
 <span><em><span>San Felice da Nola, è un grande esempio di autorevolezza, che ci mostra come i santi hanno saputo incarnare il messaggio evangelico. Pur non essendo morto a causa della persecuzione anticristiana, è ricordato come martire. Vissuto tra il III e il IV secolo, Felice era un collaboratore del vescovo di Nola, Massimo, che fu costretto a fuggire a causa delle violenze contro i cristiani dell''Impero Romano. Rimasto in città, venne catturato e torturato ma venne liberato miracolosamente da un angelo e portato dal suo vescovo, che, ormai privo di forze, si trovava in un luogo desertico. Riportò quindi Massimo a Nola e riprese il suo ministero sacerdotale grazie a una pausa della persecuzione. Alla ripresa delle violenze, però, Felice si nascose, riuscendo così a sfuggire a una seconda cattura. Nel 313, infine, poté tornare a Nola, e per l''autorevolezza della sua testimonianza venne candidato alla cattedra episcopale. Egli però rifiutò e non volle nemmeno indietro i beni che gli erano stati sequestrati, preferendo vivere in povertà fino alla morte. La sua storia ci è giunta grazie al racconto di san Paolino da Nola (cf Matteo Liut).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-14';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="1369647175">
 <span>Gesù opera sempre per la guarigione, per donare a chi incontra una vita nuova che sia a servizio degli altri, proprio come ha fatto con la suocera di Pietro. Inoltre, fa tacere i demoni che vogliono paradossalmente parlare di Lui e distorcere l''opera di Dio. Questo è proprio il <em>modus operandi</em>, cioè la modalità con la quale agisce il male che cerca di mescolare verità e menzogna. Quanto dobbiamo essere prudenti quando ascoltiamo e parliamo delle cose di Dio e della vita degli altri! Possiamo rischiare anche noi di essere strumenti del male, soprattutto quando non sentendoci realizzati cerchiamo di abbassare gli altri per sentirci migliori. Gesù non solo incontrò l''opposizione del male che tentava di ostacolarlo, ma stava diventando anche una figura acclamata, esattamente quello che spesso desideriamo per noi stessi. Come reagisce Gesù davanti al clamore della folla? Non si ferma a ricevere consensi ma prosegue nella sua missione. Quando il nostro essere cristiani non è riconosciuto, siamo tentati di fermarci a guardare i risultati e cercare conferme del nostro operato. Questa può essere una grande tentazione: cercare nel consenso il frutto tangibile delle nostre azioni. Questo moto di superbia, che tutti noi abbiamo un po'' dentro, non va sottovalutato; molti si perdono nella vanagloria semplicemente perché non hanno uno scopo e non sanno dove stanno andando, quindi cercano di possedere tutto il bene possibile nell''immediato, cercano la ricompensa (cf Mt 6,14). Chi ha uno scopo, invece, sa sopportare anche la sofferenza, persino il nascondimento, perché sa verso dove sta andando. E tu verso dove stai andando? Verso dove è rivolto il tuo cuore?</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-15';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="593" _msttexthash="1137644560">
 <em><span><span>«La vanagloria. Essa va a braccetto con il demone dell''invidia, e insieme questi due vizi sono propri di una persona che ambisce ad essere il centro del mondo, libera di sfruttare tutto e tutti, oggetto di ogni lode e di ogni amore. La vanagloria è un''autostima gonfiata e senza fondamenti. Il vanaglorioso possiede un "io" ingombrante: non ha empatia e non si accorge che nel mondo esistono altre persone oltre a lui. I suoi rapporti sono sempre strumentali, improntati alla sopraffazione dell''altro. La sua persona, le sue imprese, i suoi successi devono essere mostrati a tutti: è un perenne mendicante di attenzione. E se qualche volta le sue qualità non vengono riconosciute, allora si arrabbia ferocemente. Gli altri sono ingiusti, non capiscono, non sono all''altezza. Nei suoi scritti Evagrio Pontico descrive l''amara vicenda di qualche monaco colpito dalla vanagloria. Succede che, dopo i primi successi nella vita spirituale, si sente già un arrivato, e allora si precipita nel mondo per ricevere le sue lodi. Ma non capisce di essere solo agli inizi del cammino spirituale, e che è in agguato una tentazione che presto lo farà cadere. Per guarire il vanaglorioso, i maestri spirituali non suggeriscono molti rimedi. Perché in fondo il male della vanità ha il suo rimedio in sé stesso: le lodi che il vanaglorioso sperava di mietere nel mondo presto gli si rivolteranno contro. E quante persone, illuse da una falsa immagine di sé, sono poi cadute in peccati di cui presto si sarebbero vergognate!» (papa Francesco).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-15';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="591753994">
 <span>È commovente l''incontro tra un lebbroso che sfida tutte le barriere sociali per avvicinarsi a Gesù e quest''ultimo, che dopo averlo guarito deve ritirarsi in luoghi deserti perché la gente accorreva a Lui da ogni parte. Il lebbroso ci mostra che possiamo essere isolati da tutti, persino dai nostri parenti ma non siamo mai ignoti al Signore, che si muove a compassione per noi. Si compie quasi un matrimonio di misericordia con il lebbroso che dice a Gesù: "Se vuoi", e Gesù che risponde: "Lo voglio!". Tuttavia, in questo legame, Gesù si irrita con il lebbroso, lo scaccia e gli proibisce di divulgare la guarigione per evitare fraintendimenti. Gesù è vinto dalla compassione ma l''epilogo della situazione lo costringe a prendere su di sé la medesima condizione del lebbroso, dovendosi ritirare in luoghi deserti. È meraviglioso pensare che Dio possa essere vinto dalla compassione, che senta il nostro dolore e la nostra delicatezza nel chiedere, comprendendo i nostri sforzi per cercarlo nonostante le barriere. Nel mondo abbiamo un urgente bisogno di compassione, sia da ricevere che da donare!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-16';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="585" _msttexthash="102024546">
 <span><em><span>«Nell''amore vero non siamo noi ad amare gli sventurati in Dio, è Dio in noi che li ama. Quando siamo nella sventura, è Dio in noi che ama coloro che ci vogliono bene. La compassione e la gratitudine discendono da Dio, e quando vengono donate attraverso uno sguardo, Dio è presente nel punto in cui gli sguardi si incontrano [...] Una delle verità fondamentali del cristianesimo, oggi misconosciuta da tutti, è che lo sguardo è ciò che salva» (Simone Weil).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-16';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="622" _msttexthash="482196767">
 <span _istranslated="1"><span _istranslated="1" _msthash="571" _msttexthash="213210608">«Figlio, ti sono perdonati i peccati». Questo è ciò che viviamo nella confessione: siamo come paralitici che si alzano in piedi. Ciò che fa gioire il cuore è che questo perdono ricevuto ci libera e ci rende capaci di aprire il cuore agli altri. Non solo possiamo non meravigliarci del fatto che Dio perdona ma possiamo anche scoprirci simili a Lui, capaci di perdonare, di far camminare gli altri, di farli rialzare nella loro dignità che non viene soppressa dagli errori commessi. Come Dio rialza noi, possiamo essere persone che liberano, donando al mondo il coraggio di rialzarsi, spargendo perdono, cioè facendo un dono agli altri che libera noi per primi. </span></span><span _istranslated="1">È meraviglioso imparare da Dio l''arte del perdono che vale più di due gambe che camminano di nuovo. Infatti possiamo essere in perfetta salute fisica ma malati di rancore e odio, paralitici dentro. C''è una paralisi peggiore di quella delle gambe e la sentiamo ogni volta che non chiediamo perdono o non perdoniamo gli altri di vero cuore.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-17';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="636" _msttexthash="70509075">
 <span><span><em>«Il perdono è forse la sola esperienza che permetta a un essere umano di toccare qualcosa della resurrezione, perché nel perdono facciamo esperienza di qualcosa che è morto – per esempio, un amore tradito – e grazie al perdono ritorna in vita» (Massimo Recalcati).</em></span></span></p>

<p _msthash="636" _msttexthash="70509075">
 <span><span><em>Parole di sant’Antonio Abate: </em></span></span></p>
<p _msthash="636" _msttexthash="70509075">
 <em>«L''anima in possesso della sapienza pura e della vita autentica si manifesta nel modo di guardare, di comportarsi, di parlare, di sorridere, di conversare e di agire della parte fisica. Tutto in lei è trasformato e positivamente buono. La sua parte mentale, fertile per l''amore divino, è simile ad un vigilante guardiano che non permette l''ingresso a pensieri di male e di passionalità». </em></p>
<p _msthash="636" _msttexthash="70509075">
 <em>«La mente che attraverso l''amore diviene una sola realtà con Dio, è una benedizione invisibile per tutti gli esseri, offerta da Dio stesso per condurre alla vita pura chi ne è degno» (sant’Antonio Abate). </em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-17';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="1559044682">
 <span>Gesù ricorda, specie a chi è incline a giudicare gli altri, che sono i peccatori ad avere bisogno di Dio. Notando come Gesù si rivolgeva ad alcuni farisei, chiamandoli "guide cieche" (Mt 23,16) e "ipocriti" (Mt 23,23), e come accusava coloro che chiudevano il regno dei cieli agli altri con il loro cattivo esempio (cf Mt 23,13), diventa chiaro che tutti siamo peccatori davanti a Dio soprattutto quando ci sentiamo perfetti, sicuri di noi stessi al punto da sentirci in diritto di additare e condannare gli altri. I farisei giudicavano non solo i peccatori ma anche Gesù stesso, sostenendo che un vero maestro non dovrebbe contaminarsi con quelli considerati "inferiori". Anche i discepoli faticavano ad accettare l''apertura di Gesù al dialogo e la sua disponibilità verso tutti che poteva sembrare dissacrante. Gesù, oltre a sedere a tavola con pubblicani e peccatori, parlava dei e con i samaritani, discuteva sull''importanza dei bambini e permetteva persino a una donna discussa di bagnargli i piedi con le sue lacrime. Per quell''epoca il suo comportamento era propriamente fuori dagli schemi ma la sua opera aveva un significato ulteriore, non solo socialmente rivoluzionario. Come cristiani siamo chiamati ad imitare Gesù e diffondere il suo annuncio di un amore universale riversato su ogni creatura, di una salvezza da portare fino agli estremi confini della terra. Non dimentichiamo perciò di essere persone accoglienti, che dialogano e che lasciano da parte le manie di grandezza e di dominio, mettendosi a servizio per custodire l''umanità. Quando una famiglia, una chiesa, una comunità o qualsiasi gruppo inizia a operare secondo una logica di potere anziché di fraternità, ascolto e dialogo, si avvia a perpetuare la violenza, a diffondere odio e a costruire barriere.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-18';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="585" _msttexthash="28640014">
 <span><span><em>«Quante volte uomini e donne di dialogo, musulmani e cristiani, dovranno essere emarginati nella propria comunità, perseguitati, forse uccisi, affinché la violenza venga esclusa dalle nostre relazioni?» (padre Paolo Dell''oglio).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-18';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="733" _msttexthash="9304791262">
 <span _istranslated="1"><span _istranslated="1" _msthash="567" _msttexthash="2182441937">A Cana di Galilea c''è una festa di nozze, un momento di gioia e festa della vita e dell''amore. Tanti sposi possono ricordare il loro matrimonio, vissuto come la celebrazione gioiosa dell''amore. Ma queste nozze narrate nel Vangelo ci raccontano di un intoppo imbarazzante accaduto durante la festa: il vino non era abbastanza! Dunque, il vino c''era ma era terminato! Possiamo leggere nell''immagine del vino la rappresentazione della bellezza e della gioia del vivere che all''improvviso viene a mancare. Quando in una relazione (qualsiasi relazione d''amore sia) subentra la stanchezza, la monotonia, il soffermarsi di più sui difetti dell''altro, accade che i silenzi e le incomprensioni sono all''ordine del giorno e spesso l''ideale di famiglia o di amicizia si scontra con una realtà differente. Non vi è un''esperienza d''amore dove non ci sia un momento di vuoto, il momento in cui niente è abbastanza! Sempre, in tutti i rapporti, c''è un momento in cui finisce il vino, l''allegria, il sapore, e questo non accade perché la relazione è sbagliata ma perché, inevitabilmente, vi è un momento di crisi. Tuttavia, la crisi è un momento di crescita, perlomeno quando è affrontata con maturità; la crisi dovrebbe servire proprio a questo! <em _istranslated="1">«Il primo vino è bellissimo: è l''innamoramento. Ma non dura fino alla fine: deve venire un secondo vino, cioè deve fermentare, crescere e maturare. Un amore definitivo che diventi realmente "secondo vino", più bello, migliore del primo e questo dobbiamo cercare» (Benedetto XVI). </em></span></span><span _istranslated="1"><span _istranslated="1" _msthash="566" _msttexthash="306105722">Ecco, occorre che l''innamoramento diventi amore, amore vero che si sa donare nella gioia e nel dolore; amore che sa perdonare e chiedere perdono; amore che diventa anche sacrificio, amore che affronta le inevitabili stanchezze della vita. Ma noi, con le sole nostre forze non siamo capaci di fare ciò! Quante volte ci abbiamo provato da soli ma abbiamo sperimentato solo delusioni, perché siamo fragili, spesso egoisti, perché amiamo a tempo. <em _istranslated="1">«Per amare fino in fondo, infatti, non basta la buona volontà, l''amore è una virtù teologale, tanti si aprono all''amore in maniera bellissima, ma vincere il nulla lo fa solo il Signore» (don Fabio Rosini). </em></span></span><span _istranslated="1">Ecco allora la mediazione di Maria verso suo Figlio. </span><em _istranslated="1">«A Cana c''era molta gente, però solo Maria si rese conto che il vino cominciava a scarseggiare. Ebbe compassione di quella giovane coppia e volle evitarle l''umiliazione di non avere vino sufficiente per gli invitati. Che cosa fece? Senza richiamare l''attenzione, con discrezione, lasciò la sala (perché nelle feste ebraiche gli uomini e le donne stavano separati tra loro) e, avvicinandosi a Gesù, disse con la più grande semplicità: "Non hanno vino". E qui si vede la carità di Maria. Avverte il bisogno degli altri e lo comunica a Gesù con delicatezza» (s. Teresa di Calcutta).</em><span _istranslated="1"> Che bello vedere con quanta premura Maria intercede presso Gesù, quanta attenzione verso questi sposi. L''agire di Maria ci deve essere di grande esempio. Anche noi, come lei, siamo chiamati a essere attenti ai bisogni di chi ci sta accanto, anche nelle più piccole cose. Noi siamo chiamati, con la grazia di Dio, a correre verso i più bisognosi, perché è cosa brutta commettere peccato, ma è anche una cosa brutta non fare il bene che si può e si è chiamati a fare!</span><span _istranslated="1">In questa domenica vogliamo pregare per tutte le famiglie, e in particolare per quelle famiglie che stanno attraversando delle difficoltà. La riflessione sulle nozze di Cana ci ricorda che non dobbiamo disperare ma aprirci alla grazia di Dio, perché: </span><em _istranslated="1">«Quando una coppia si apre all''azione dello Spirito Santo, egli comunica quello che lui stesso è: amore, pace, gioia, bellezza... dunque li contagia, rinnovando in essi la capacità e la gioia di donarsi l''uno all''altro. Segno di ciò, quando l''agape prende il sopravvento sull''eros, quando ognuno smette di chiedersi: cosa potrebbe fare l''altro di più per me, e invece dice: cosa posso fare io di più per lui/lei?». «Ho conosciuto una coppia con figli ormai grandi, ma molto unita. Mi hanno confidato qual è stato il segreto della loro riuscita: "Il giorno del matrimonio abbiamo preso come programma la parola di S. Paolo: "Non tramonti il sole sopra la vostra ira", e così abbiamo deciso di non metterci mai a letto dopo un battibecco o un contrasto, senza riconciliarci. Magari a fatica e brontolando, ma sempre abbiamo steso la mano per stringere quella dell''altro» (card. R. Cantalamessa).</em></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-19';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>PREGHIERA</em></span></span></p>

<p>
 <span><span><em>O signore, ti preghiamo perché ogni famiglia </em></span></span></p>
<p>
 <span><span><em>sia culla della pace e dell’amore!</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-19';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="607" _msttexthash="1024460203">
 <span _istranslated="1"><span _istranslated="1" _msthash="566" _msttexthash="1212854604">Più ci sentiamo fragili e più cerchiamo in tutti i modi di ostacolare gli altri, di essere minuziosi nell''indicare le loro mancanze e i loro difetti, sempre pronti a confrontarci per affermare ossessivamente il nostro valore, pungenti, pronti a stuzzicare l''altro per creare una reazione che gli faccia capire che ci siamo anche noi nel mondo. Quando qualcuno sembra privarci di qualcosa, sa qualcosa più di noi o sembra ledere il nostro valore o i nostri sentimenti, abbiamo la stessa reazioni dei farisei: facciamo domande sbagliate in partenza, domande di confronto per capire chi è migliore: "l''altro ha fatto... mentre io..."; "io non avrei mai fatto quello che hai fatto tu!". Ecco, Gesù ci invita, parlando dello sposo e del vestito con la toppa, ad andare in profondità, a curare e guarire il nostro cuore, le nostre parole, il nostro pensiero. Nessuno sarà buono ai nostri occhi finché il nostro cuore non sarà pronto ad ospitare un pacificante amore. Quando la pace sarà nel nostro cuore, sarà anche nel nostro sguardo, nelle nostre mani, nei nostri pensieri, nelle nostre osservazioni, che non sapranno più di egoismo o di possesso ma saranno immagine di Colui che fa nuove tutte le cose. Gesù ci vuole donare una vita nuova, una vita che si nutre del suo esempio. </span></span><span _istranslated="1" _msthash="631" _msttexthash="16609320">Non possiamo pensare di risolvere il problema del nostro egoismo, della nostra immaturità, dei nostri vizi, mettendo una toppa dietro un esteriore moralismo intransigente. </span><span _msthash="624" _msttexthash="58263712">I santi sono stati maestri di amore, hanno formato cuori buoni e disposti ad accogliere il bene; sapevano fare richieste e domande che facevano crescere nella santità; toccavano i punti scoperti non per umiliare ma per elevare gli altri, per farli crescere e far maturare nel cuore un amore autentico, senza finzioni, come quello di Cristo.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-20';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="637" _msttexthash="405455674">
 <em><span><span>«Ignazio aveva per abitudine di raccomandare a uno dei suoi primi compagni il compito di spazzare il cortile della residenza in cui vivevano con una scopa vecchia e rotta. Il gesuita spazzino passava la scopa più e più volte, però gli rimaneva sempre un po'' di sporcizia da spazzare. Con lacrime di rabbia e d''impotenza, quel novizio si domandava: "Che ho fatto a padre Ignazio per essere trattato così?". Quell''uomo confuso e turbato era padre Diego Laínez, il quale non sapeva ciò che invece sapeva Ignazio: cioè che lui sarebbe stato il prossimo generale dell''ordine. Ignazio lo stava provando nella pazienza. Avrà pensato Ignazio: "Se questo non sopporta adesso una scopa rotta e il fatto di non poter governare un po'' di sporcizia, come potrebbe sopportare il governo di migliaia di gesuiti? Se non impara a prendere le cose con calma e tranquillità, è un candidato destinato all''ulcera» (Ángel Rossi SJ).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-20';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="1393312583">
 <span>Ci sono persone che vivono una vita di fede piena di sensi di colpa, perché spesso le regole diventano motivo di rigidità anziché di apertura all''amore. Per chi è eccessivamente schematico è difficile comprendere come si possa rimanere intrappolati in schemi apparentemente impeccabili ma privi di amore. La rigidità rende normale solo quello schema ripetitivo, quella modalità sempre utilizzata che fa sentire sereni. Il Signore, invece, ci invita a farci guidare dall''amore prima di tutto, dal Vangelo prima di tutto. La vita di Cristo, infatti, è proprio la rivelazione di ciò che è amore, di ciò che vale realmente per la vita di una persona di ogni tempo. Anche se nessuno ce lo dicesse lo sappiamo perfettamente che l''amore viene al primo posto, è scritto nei nostri desideri, nei nostri pensieri: tutti vogliamo essere amati. Eppure, spesso l''amore quando si traduce in leggi per custodirsi può estremizzarsi, chiudersi; non sono più le leggi a custodire l''uomo ma l''uomo si mette a custodire le leggi, a trovare cavilli per sentirsi a posto senza dover morire d''amore. L''amore infatti porta a una morte di noi stessi, a fare spazio all''altro, a superare la giustizia legalistica. L''amore ci rende capaci non solo di fare quello che è giusto ma di perdere per dare all''altro, a colui che è soggetto del nostro amore; l''amore ci rende fragili. Dio, perciò, nella sua onnipotenza è capace di farsi infinitamente piccolo, di perdersi, di nascondersi, di prendere su di sé i nostri peccati. Ecco la sua signoria: il creatore diventa Signore del sabato, pone l''amore al di sopra di tutte le leggi, ci porta al cuore della domanda: cosa conta davvero nella vita? Cosa conta davvero in quello che fai?</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-21';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span><span _msthash="590" _msttexthash="85435298">«La legge tutta è preceduta da un “sei amato” e seguita da un “amerai”. “Sei amato” è la fondazione della legge; “amerai”, il suo compimento. Chiunque astrae la legge da questo fondamento amerà il contrario della vita» (Paul Beauchamp). </span></span></em></span></p>
<p>
 <em><span><span _msthash="589" _msttexthash="4351061">Il candore della martire sant’Agnese</span></span></em></p>
<p>
 <em><span><span _msthash="588" _msttexthash="467995541">Il culto di Agnese risale al IV secolo. Dalle fonti più antiche si può ricostruire a grandi linee la storia della santa. Era una fanciulla di dodicitredici anni, come ha confermato l’analisi anatomica del suo capo conservato nella chiesa di Sant’Agnese in Agone. Così giovane non aveva il dovere di presentarsi alle autorità, come ordinava il quarto editto di Diocleziano nel marzo del 304, imponendo a tutti i cristiani di sacrificare pubblicamente agli dei. «Erano tutti stupefatti che si presentasse a rendere testimonianza di Dio proprio lei che non aveva neppure raggiunto gli anni per disporre di sé» riferisce sant’Ambrogio. Agnese lo fece spontaneamente. Quanto al martirio, Damaso parla del fuoco mentre Ambrogio allude alla morte con la spada («piegò il capo»): la seconda sembra la tesi più convincente perché le ossa non recano traccia di combustione.</span></span></em></p>
<p>
 <em><span><span _msthash="587" _msttexthash="395272332">Secondo una consuetudine plurisecolare nella basilica di Sant’Agnese fuori le mura il 21 gennaio, in occasione della festa della santa, vengono benedetti sul suo altare due bianchi agnellini, allevati dai monaci trappisti delle Tre Fontane. Trasportati nel Vaticano, gli agnelli sono poi offerti al pontefice, che a sua volta li affida alle monache del monastero di Santa Cecilia a Trastevere. Con la loro lana, le monache tessono i sacri pallii che saranno benedetti dal papa sulla tomba di San Pietro, la sera del 28 giugno, vigilia della festa dei santi patroni di Roma Pietro e Paolo. I pallii sono quelle strisce di lana con delle croci ricamate che il pontefice dona agli arcivescovi metropoliti, e si indossano sulle spalle a ricordare la pecorella smarrita che il Buon Pastore mette sulle spalle per ricondurla al gregge (cf NICA FIORI, Associazione culturale Etgraphiae, Roma 24 gennaio 2021,).</span></span></em></p>
<p>
 <em><span><span _msthash="586" _msttexthash="321878921">La martire Agnese, il cui nome ricorda l’agnello, simbolo di purezza e di sacrificio è dunque per la chiesa un simbolo del dono di sé con la caratteristica purezza che questa santa ci ha manifestato; perciò, il papa fa dono ai vescovi metropoliti di un pallio prodotto con la lana di agnelli posati sull’altare di sant’Agnese. Alcuni abiti e simboli utilizzati dal papa, dai cardinali, dai vescovi, dai sacerdoti e diaconi, sono segni che richiamano alla chiesa dell’origine e hanno un significato profondo di donazione totale al Signore e ricordano il legame con gli apostoli. La ricchezza di testimoni della fede arricchisce la simbologia utilizzata nella liturgia.</span></span></em></p>
<p _msthash="827" _msttexthash="1186558932">
 <em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="585" _msttexthash="1160068">Ecco le parole di Benedetto XVI sul pallio: </span></span></em><em _istranslated="1"><span _istranslated="1"><span _istranslated="1" _msthash="584" _msttexthash="1514085209">«Il primo segno è il Pallio, tessuto in pura lana, che mi viene posto sulle spalle. Questo antichissimo segno, che i Vescovi di Roma portano fin dal IV secolo, può essere considerato come un''immagine del giogo di Cristo, che il Vescovo di questa città, il Servo dei Servi di Dio, prende sulle sue spalle. Il giogo di Dio è la volontà di Dio, che noi accogliamo. E questa volontà non è per noi un peso esteriore, che ci opprime e ci toglie la libertà. Conoscere ciò che Dio vuole, conoscere qual è la via della vita – questa era la gioia di Israele, era il suo grande privilegio. Questa è anche la nostra gioia: la volontà di Dio non ci aliena, ci purifica – magari in modo anche doloroso – e così ci conduce a noi stessi. In tal modo, non serviamo soltanto Lui ma la salvezza di tutto il mondo, di tutta la storia. In realtà il simbolismo del Pallio è ancora più concreto: la lana d''agnello intende rappresentare la pecorella perduta o anche quella malata e quella debole, che il pastore mette sulle sue spalle e conduce alle acque della vita [...] Una delle caratteristiche fondamentali del pastore deve essere quella di amare gli uomini che gli sono stati affidati, così come ama Cristo, al cui servizio si trova. "Pasci le mie pecore", dice Cristo a Pietro, ed a me, in questo momento. Pascere vuol dire amare, e amare vuol dire anche essere pronti a soffrire» (Benedetto XVI, omelia della Messa di inizio pontificato, 24 aprile 2005).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-21';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span><span _msthash="564" _msttexthash="2192283158">È brutto quando anche fare il bene diventa un pretesto per accusare e per separarci dagli altri. Questo è ciò che facevano alcuni sacerdoti del tempio: proprio loro che dovevano custodire il bene, non solo lo disprezzavano ma cercavano di contenere il bene in formule preconfezionate; il bene doveva essere ristretto nelle loro regole. Tutto ciò veniva proposto come segno di amore per Dio ma in realtà nascondeva il desiderio di cercare pretesti per accusare un fratello, per sentirsi possessori di un bene assoluto e di cui disporre. L’apostolo Paolo nella lettera ai Galati scrive: «Voi infatti, fratelli, siete stati chiamati a libertà. Che questa libertà non divenga però un pretesto per vivere secondo la carne; mediante l''amore siate invece a servizio gli uni degli altri» (Gal 5,13). L’amore di Dio ci porta a misurarci davanti all’amore, a essere liberi, non imprigionati da schemi che con l’amore non hanno nulla a che fare. Piuttosto le regole, per un cristiano, servono proprio per esplicare l’amore. Spesso la gente si allontana dalla Chiesa, da associazioni o gruppi o dalla nostra amicizia, quando sente che l’amore non viene prima di tutto ma ciò che emerge come predominante è la faziosità, l’interesse personale, il beneficio economico, il fatto che ci si sente superiori anche imponendo delle regole comuni che si utilizzano per mercificare l’amore di Dio. Perciò interroghiamoci, chiediamoci se siamo anche noi così, persone che tengono consiglio contro gli altri non per valorizzare il loro bene possibile ma per creare dispiacere. È un peccato grande se si impara ad essere fedeli a tutti i propri schemi mentali, disobbedendo all’amore.</span></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-22';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="602" _msttexthash="266353425">
 <span><em><span>«L''etica cristiana non nasce da un sistema di comandamenti, ma è conseguenza della nostra amicizia con Cristo. Questa amicizia influenza la vita: se è vera si incarna e si realizza nell''amore per il prossimo. Per questo, qualsiasi decadimento etico non si limita alla sfera individuale, ma è nello stesso tempo svalutazione della fede personale e comunitaria: da questa deriva e su essa incide in modo determinante. Lasciamoci quindi raggiungere dalla riconciliazione, che Dio ci ha donato in Cristo, dall''amore "folle" di Dio per noi: nulla e nessuno potranno mai separarci dal suo amore (cfr Rm 8,39). In questa certezza viviamo. È questa certezza a donarci la forza di vivere concretamente la fede che opera nell''amore» (Benedetto XVI).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-22';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="1864897762">
 <span>C''è una folla che cerca Gesù e sembra fare ressa su di lui al punto che può diventare pericolosa. Il Signore chiede perciò una barca per poter annunciare senza essere schiacciato, mantenendo una certa distanza di sicurezza. La gente si gettava persino su di lui per poterlo toccare e si lanciava ai suoi piedi, cercava tutti i modi per avvicinarlo. Ogni relazione con il Signore e anche con i fratelli ha bisogno di entrare nel non possesso, nel non afferrare l''altro. Gesù è così vicino da donarsi ma non è mai un possesso. Possiamo dire che il contrario dello schiacciare è il toccare Gesù, avere una relazione sana, con Dio e con gli altri. L''essere vicino, il condividere, l''essere fratelli e sorelle ha un argine che è quello del contemplare l''opera di Dio, del rispetto dell''altro, la distanza sana che genera la possibilità di esprimersi nella propria bellezza. Non facciamo di Gesù un talismano che teniamo in tasca, non schiacciamo il Signore, non gettiamoci su di Lui nel tentativo di possederlo tutto per noi. Tante relazioni anche fra noi fratelli e sorelle spesso invadono lo spazio dell''altro, sono troppo, diventano irrispettose del limite che preserva la bellezza dell''altro. Anche con Dio non si tratta di attuare una sacralità distante, di percepire il Signore come intoccabile, lontano ma di una vicinanza vera, buona e bella, che fa risplendere l''onnipotenza di Dio. Anche nell''annuncio del Vangelo dobbiamo imparare da Gesù a rispettare gli altri, a dialogare senza arroganza con chi pensa diversamente da noi, a non schiacciare l''altro con le nostre pretese, a non imporre neanche la salvezza. Dio non fa così con noi? La bellezza di ciò che annunciamo e testimoniamo deve essere accolta liberamente. Il libero arbitrio, grande dono di Dio, è fondamentale; nulla di ciò che facciamo può riflettere il Vangelo senza la possibilità di scelta. Questa scelta ci conduce alla vera libertà, che è legata all''amore. Solo chi ama è veramente libero.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-23';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="585" _msttexthash="336184992">
 <span><em><span>«Per avere una relazione ordinata non c''è bisogno di confondersi, anzi c''è una distanza che salvaguarda la relazione stessa, che consente all''una e all''altra persona di essere se stessi nella propria verità. Il rischio è sempre quello di confondersi, di mangiarsi. In Genesi 1, uno dei verbi che viene utilizzato per descrivere l''azione creatrice di Dio è separare (per esempio, separare le acque dalla terra). Quando l''acqua arriva sulla terra porta morte, quando l''acqua non rispetta più i propri limiti porta la morte sulla terra, così anche quando nelle relazioni non si rispettano i propri limiti vuol dire che io non rispetto più l''altro, che penso l''altro come una parte di me e che lo posso schiacciare. E questo lo possiamo portare anche nella relazione con Dio, pensando di essere noi i padroni» (p. Silvano Fausti sj).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-23';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="253203379">
 <span>È meraviglioso che Gesù chiami ognuno per nome, nobilitando la vita con una grazia divina smisurata. Dovremmo anche noi percepirci così: amati, chiamati per nome, missionari. Tutti siamo così, anche Giuda, da cui spesso vogliamo dissociarci. Anche lui è stato scelto da Gesù ed era destinato a cose grandi e belle. Decidiamo quindi di iniziare col sentirci benedetti, sapendo che ogni vita è benedetta, e ricordando che nella famiglia, nella comunità cristiana, nel monastero o per le strade del mondo, siamo guardati da Dio, chiamati per nome e benedetti. Partendo da questa meravigliosa certezza, possiamo decidere liberamente di fare la differenza e rispondere a un grande amore che ci viene incontro per primo.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-24';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<div>
 <em>“Oh anima bellissima fra tutte le creature, che tanto desideri sapere il luogo in cui sta il tuo Amato per cercarlo e unirti a lui!... Tu stessa sei la dimora dove egli abita e il ritiro e il nascondiglio dove sta nascosto; per te è motivo di grande contentezza e gioia vedere che tutto il tuo bene e la tua speranza sono così vicini a te da essere in te o, per meglio dire, che tu non puoi stare senza di Lui” (San Giovanni della Croce). </em></div>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-24';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="528654802">
 <span>Gesù inviò i suoi discepoli ad annunciare il Vangelo a tutte le creature. Anche se può sembrare difficile accogliere tutti, Gesù è stato chiaro: ha parlato di tutte le creature, senza lasciare spazio a interpretazioni che potessero generare categorie privilegiate alle quali rivolgersi. Il Vangelo della pace e della salvezza deve essere proclamato a tutto il creato! Questo annuncio da portare a tutti non è solo un messaggio di compassione o un annuncio motivazionale, ma una lieta notizia di salvezza accompagnata dalla vivificante presenza dello Spirito. Oggi ricordiamo la conversione di Paolo che venne raggiunto dal Signore sulla via di Damasco. Lì ebbe un''illuminazione, riconoscendo la presenza del Cristo nella sua vita, che toccò profondamente la sua esistenza. Il regno di Dio non è una semplice storia edificante che i cristiani narrano ma l''annuncio di una presenza viva, quella di Gesù. Il cristiano, quindi, vive alla presenza di Gesù e non solo nel suo ricordo. Si tratta di una presenza reale, concreta e per tutti.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-25';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="585" _msttexthash="92991873">
 <span><span><em>«Nella vita spirituale come in quella pastorale, rischiamo a volte di concentrarci sui contorni, dimenticando l''essenziale. Troppo spesso le cose secondarie prendono il posto di ciò che è necessario, le esteriorità prevalgono su quello che conta davvero. E, invece, abbiamo sempre bisogno di ritornare al centro, di recuperare il fondamento, di spogliarci di ciò che è superfluo per rivestirci di Cristo» (papa Francesco).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-25';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span><span _msthash="568" _msttexthash="1129790207">Oggi, in questa terza domenica del tempo ordinario, celebriamo la giornata della Parola. L’evangelista Luca dice di aver scritto il Vangelo per aiutare Teofilo (dal greco: “amico di Dio), cioè tutti noi, perché possiamo renderci della solidità dell’insegnamento ricevuto. Ecco, questo ci dice che noi abbiamo bisogno di certezze; qualcosa che ci sostiene, che ci rialza quando cadiamo. Noi abbiamo bisogno di una lampada per vedere dove camminiamo e questa lampada e la luce della Parola di Dio, come sta scritto: «Lampada ai miei passi è la tua Parola, luce sul mio cammino» (Sal 119,105). La parola di Dio che è vita per la nostra vita, viene proclamata nella prima lettura dove Esdra apre il libro in presenza di tutto il popolo e il popolo ascolta: è il libro della volontà di Dio, e il popolo capisce la sua vita e piange. Ma se vi è anche dolore e contrizione, Esdra e Neemia dicono che questo giorno è un giorno di gioia: non fate lutto e non piangete! La parola udita e accolta ha dato luce alla storia di questo popolo che ha sofferto, che è ritornato alla propria terra dopo settant’anni di esilio. E questo avviene anche per noi! È la Parola di Dio che ci aiuta a rileggere la nostra storia, che ci aiuta a riconciliarci con la nostra storia, a comprendere che quel momento difficile che abbiamo attraversato è stato anche un momento di grazia, non un punto di arrivo ma un punto di partenza perché Dio è entrato nella nostra vita!</span></span></p>
<p _msthash="645" _msttexthash="1651164775">
 <span _istranslated="1">La prima lettura ci introduce al Vangelo dove vediamo Gesù che entra nella sinagoga secondo il suo solito. Lì apre il rotolo e lui dà la spiegazione di senso: annunzia il Messia, l''unto (= il consacrato) inviato da Dio che arriva per portare il lieto annuncio, la luce nuova, la libertà, il tempo di grazia. Gesù, riavvolto il rotolo e guardando il popolo, cominciò a dire: «Oggi si è compiuta questa Scrittura che voi avete ascoltato». Gesù dice che le promesse oggi si compiono non domani! </span><em _istranslated="1">«Una parola in cui non pulsa la forza dell''oggi non è degna di Gesù e non aiuta la vita della gente. Per questo chi predica, per favore, è il primo a dover sperimentare l''oggi di Gesù, così da poterlo comunicare nell''oggi degli altri» (papa Francesco).</em><span _istranslated="1"> Oggi la Parola spiega la mia vita, e mi dice che posso iniziare una vita nuova. Il Signore viene a guarire le mie ferite, le mie infermità, viene a donarmi la grazia per vivere la vita nuova, la vita bella. Noi leggiamo e accogliamo la Parola per vivere bene oggi! </span><em _istranslated="1">«La Parola di Dio, infatti, è viva ed efficace, ci cambia, entra nelle nostre vicende, illumina il nostro quotidiano, consola e mette ordine. Ricordiamoci: la Parola di Dio trasforma una giornata qualsiasi nell''oggi in cui Dio ci parla» (papa Francesco).</em><span _istranslated="1"> È allora importante ascoltare e soprattutto praticare la Parola. Diceva s. Girolamo che «chi ignora le Scritture, ignora Cristo!». Noi non comprendiamo Cristo senza le Scritture. E dunque ci domandiamo: quanto la lettura della Parola di Dio è presente nella mia vita? Quanto la leggo e, soprattutto, quanto da me è vissuta? In questa domenica abbiamo da capire che questo è tempo di liberazione, luce per i non vedenti, perdono per il nostro passato, grazia e allegria per il nostro presente, e Provvidenza per il nostro futuro! Coraggio, dunque, oggi è tempo di ripartire, oggi è tempo di cose nuove!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-26';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span><span _msthash="663" _msttexthash="94055">PREGHIERA</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="662" _msttexthash="15901912">Ecco l’invito di Gesù: Dio si è fatto vicino a te, perciò accorgiti della sua presenza, fai spazio alla sua Parola e cambierai lo sguardo sulla tua vita (papa Francesco).</span></span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-26';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="606" _msttexthash="609019372">
 <span>L''opera del male è fondata sulla divisione: cerca di allontanarci da tutto ciò che è buono per la nostra anima e può sanare anche l''anima altrui. Non possiamo resistere al male se diamo ascolto ai suoi suggerimenti, come le voci di divisione, di rancore e di orgoglio. Se ci impegniamo a dialogare con il diavolo egli sarà pronto a saccheggiarci ogni volta che lo ospitiamo nel nostro cuore, ogni volta che trova uno spiraglio di disponibilità. Dobbiamo, inoltre, essere ancora più vigilanti perché per l''opera del male in noi può farsi strada un grave peccato, quello contro lo Spirito Santo. Questo è il peccato di chi nega la verità e la bellezza, rinnegando consapevolmente ciò che è di Dio e la sua salvezza. Il Vangelo ci dice che di Gesù dicevano: "È posseduto da uno spirito impuro!". Non possiamo che pregare il Signore ed essere vigilanti, per non cadere in trappola. Più siamo convinti di essere esenti da divisioni, litigi, contese, di non coltivare cattiverie ed essere lontani dal male e più rischiamo di rimanerne preda. Preghiamo il Signore, fonte di ogni liberazione, per essere custoditi nel suo cuore.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-27';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span><span _msthash="629" _msttexthash="1322373">Il diavolo apparve a tre Pastori e disse loro: </span></span></span></em></p>
<p>
 <em><span><span><span _msthash="628" _msttexthash="108277585">"Se vi dessi il potere di cambiare qualcosa nel passato, cosa cambiereste? ". Il primo di loro, con grande fervore apostolico, rispose: "Vorrei impedirti di condurre Adamo ed Eva al peccato, affinché l''umanità non si separi da Dio." Il secondo, un uomo pieno di misericordia, gli disse: «Io ti impedirò di allontanarti da Dio e di condannarti per sempre". Il terzo di loro era il più semplice e invece di rispondere al tentatore si inginocchiò, chinò il capo e pregò: </span></span></span></em></p>
<p>
 <em><span><span><span _msthash="627" _msttexthash="31070156">"Signore, liberami dalla tentazione di ciò che sarebbe potuto essere e ciò che non era. "Il demone, urlando e tremando di dolore, è fuggito. Gli altri due rimasero sorpresi e gli dissero: "Fratello, perché hai reagito così?". Ed egli rispose loro:</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="626" _msttexthash="132001740"> «Prima, non dovremmo mai parlare con il nemico. In secondo luogo, nessuno al mondo ha il potere di cambiare il passato. Terzo: l’interesse di Satana non era dimostrare la nostra virtù, ma intrappolarci nel passato, affinché trascuriamo il presente, l’unico momento in cui Dio ci dà la Sua grazia e possiamo collaborare con Lui per adempiere la Sua volontà”. </span></span></span></em></p>
<p>
 <span _msthash="738" _msttexthash="23094682">Il passato è lasciato alla misericordia di Dio e il futuro alla Sua provvidenza, solo il presente è nelle nostre mani. Vivi oggi amando Dio con tutto il tuo cuore; oggi è il momento di essere vigilanti sull''amore.</span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-27';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Sembra quasi che Gesù stia rinnegando la sua famiglia con queste parole chiare e forti come il rumore di un tuono; pare che neghi di conoscere persino sua madre! Piuttosto, Gesù ci mostra come rendere eterni i nostri legami: non ci uniamo agli altri con il sangue, le parentele o gli stessi ideali, ma riconnettendoci al germe più intimo innestato in noi, che ci porta a Dio. Fare la volontà di Dio ci aiuta a comprendere che il discernimento delle nostre decisioni non si può basare sulle opinioni della maggioranza o sul senso comune. In un contesto come quello di Gesù nel quale la discendenza era tutto e le decisioni dovevano essere discusse nel gruppo familiare che era da considerarsi sacro, Gesù pone davanti un nuovo criterio di decisione, insegnando a costruire l’albero genealogico dello Spirito, quella linfa vitale che ci riconnette a Dio stesso. È Dio il centro di gravità e fare la sua volontà è abitare il mondo con il peso specifico della nostra missione, riconnettendoci come fratelli e sorelle secondo giuste proporzioni, quelle eterne. I legami diventano così belli e saldi perché proiettati verso un’ulteriorità! Il Vangelo, perciò, in ogni tempo, nei tanti contesti in cui è il gruppo o la società a dominare il reale, diventa seme di impopolarità, segno di contraddizione. Anche Maria ascoltando quelle parole di Gesù dovette decidere se seguire il clan familiare o quelle parole di eternità che chiamavano a fare del riferimento ultimo Dio stesso, che unisce con legami diversi, più aperti, più profondi. Maria riceve un altro annuncio: vuoi essere veramente discepola dell’Altissimo? Sei disposta a perdere tutto, anche l’appoggio dei tuoi legami familiari? Se di Gesù dicevano che fosse “fuori di sé” (cf Mc 3, 21), pensate che non mormorassero pure di Maria che lo assecondava? Gesù mentre pronuncia le ultime parole che abbiamo letto in questo brano evangelico, tanto forti e belle, gira lo sguardo, osserva tutti, con la presenza di sua madre comunica a tutti la grandezza dell’essere discepoli, apre gli orizzonti. Così Maria fu proiettata da quello sguardo sin sotto la croce, il momento in cui non fu affidata al clan familiare, ma a Giovanni, proprio in virtù di legami eterni ed elevati. Riusciamo a fare questo salto di qualità come cristiani, sull’esempio di Maria? Qual è il criterio ultimo delle nostre decisioni? Agiamo come se fossimo davanti all’eternità di Dio oppure no? Vogliamo veramente essere suoi discepoli?</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-28';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span>«Fratelli miei, ponete attenzione, ve ne scongiuro, a ciò che dice Cristo Signore stendendo la mano verso i suoi discepoli: “Questa è mia madre, questi i miei fratelli. Chi fa la volontà del Padre, che mi ha mandato, mi è fratello, sorella e madre”. Non fece forse la volontà del Padre la Vergine Maria, la quale per fede credette, per fede concepì, fu scelta perché da lei venisse a noi la salvezza, fu creata da Cristo, prima che Cristo fosse fatto nel suo seno? Santa Maria fece la volontà del Padre e la fece interamente; e perciò vale di più per Maria essere stata discepola di Cristo anziché madre di Cristo. Vale di più, cioè c’è più felicità essere stata discepola anziché madre di Cristo» (Sant’Agostino).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-28';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="569" _msttexthash="3461541772">
 <span>Questa parabola potremmo definirla "la parabola della custodia". La parola di Dio, bene prezioso per la crescita spirituale, se non viene seminata nel cuore e non entra in profondità, se non viene accolta dal calore benefico della bontà e alimentata da una relazione con Dio, può essere sprecata e non portare frutto nella nostra vita. È un concetto profondo: non basta andare in chiesa se non si fa un passo in più, se non si decide di vivere la vita in Cristo, facendo diventare la sua Parola vita concreta. Si può benissimo andare in chiesa ma essere come un rovo, ergersi ed apparire come un essere spinoso senza frutti, soffocando tutte le cose buone in una morsa pungente; oppure si può credere che vada bene essere "fedeli asfalto" che vanno in chiesa ma rimangono duri, senza bontà, come un mantello di asfalto sacro che ricopre la durezza di una strada di pietra che non si apre all''amore. Oppure si può mettere un po'' di bontà superficiale, quella delle buone maniere, far germogliare subito un seme che poi non va in profondità e non crea radici salde. Il Signore ci invita a saper custodire la sua Parola nel nostro cuore, ma anche a preparare un terreno, a far penetrare nella nostra storia, spesso piena di ferite, la sua linfa vitale. Custodire la bellezza è quindi fondamentale: imparare ad essere fedeli alla bontà, a conservare con cura le cose buone e belle e per analogia anche le relazioni fondamentali per la nostra vita. Chi non sa custodire incappa negli errori classici, che fanno sì che un seme prezioso venga disperso. Se non curiamo il nostro cuore può diventare un luogo inospitale dove non cresce nulla o dove tutto viene soffocato o, peggio ancora, dove germoglia tutto ma nulla viene custodito. Alcuni hanno bisogno di rivedere il linguaggio della custodia, questa parola diventata ignota a molti; il diavolo, infatti, ci insegna l''arte dello spreco delle cose belle. Non farlo trionfare: quando senti che il tuo cuore è portato allo spreco, lavoralo, richiama alla bontà la tua coscienza. Possiamo non custodire, non proteggere dal cinismo, dalla rabbia, dalla sfiducia, dall''abuso tante persone, tante situazioni, tante cose che profumano di trascendenza. Ci sono persino parole che vanno custodite, protette, curate per non farle finire nel baratro della rassegnazione e del non senso. Ci sono poveri e oppressi che vanno custoditi nel cuore di Dio. Ciascuno di noi può essere l''angelo custode che chiede a Dio: "Benedici il mio cuore per renderlo pronto ad accogliere bellezza, tocca il mio cuore affinché io stesso possa essere il custode del fratello, parola vivente, e che in Te e come Te, io possa essere seminatore di bontà da diffondere nel mondo".</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-29';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span><span _msthash="601" _msttexthash="605111">Visita il mio cuore che anela</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="600" _msttexthash="363740">al tuo amore supremo </span></span></span></em></p>
<p>
 <em><span><span><span _msthash="599" _msttexthash="814567">colmalo di granitica grazia, in te</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="598" _msttexthash="247143">arda per sempre,</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="597" _msttexthash="293930">fiamma senza fumo</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="596" _msttexthash="308321">eterno splendore. </span></span></span></em></p>
<p>
 <em><span><span><span _msthash="595" _msttexthash="618735">Avvinghiami con il tuo amore</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="594" _msttexthash="678054">fuoco soave, fiamma di candore</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="593" _msttexthash="1189006">che fai spuntare frutti da una terra arida.</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="592" _msttexthash="810342">Il mio cuore, mio buon seminatore,</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="591" _msttexthash="4314349">non chiede altro che semenza d’amore</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="590" _msttexthash="604734">che cresca subito il frutto,</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="589" _msttexthash="479687">ciò che mendico è amore.</span></span></span></em></p>
<p>
 <em><span><span><span _msthash="588" _msttexthash="985374">(Preghiera di Santa Umiltà da Faenza).</span></span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-29';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="560" _msttexthash="354783247">
 <span>Venire alla luce vuol dire apparire senza nulla di nascosto. Questo è ciò che ci accadrà in pienezza quando saremo davanti a Dio, quando un giorno saremo giudicati sull''amore e verrà misurata tutta la nostra vita secondo la misura d''amore che avremo utilizzato fra di noi. Quanto più grande sarà stata la nostra responsabilità di servizio, tanto più ci sarà chiesto se abbiamo servito i fratelli e se siamo stati lontani dalla brutta pratica del servirci dei fratelli. Ancor di più il Signore sarà esigente, perché l''essere cristiani non solo ci porta alla luce ma il cristiano stesso, per opera di Cristo, è chiamato a essere luce (cf Mt 5,14). La luce posta sul candelabro perché risplenda ogni cosa ci chiama alla realizzazione della piena volontà di Dio in noi, per essere persone unificate, risplendenti, accoglienti, che non giocano al ribasso.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-30';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="580" _msttexthash="23835344">
 <span><span><em>«Per essere grande, sii intero: non esagerare e non escludere niente di te. Sii tutto in ogni cosa. Metti quanto sei nel minimo che fai. Come la luna in ogni lago tutta risplende, perché in alto vive» (Fernando Pessoa).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-30';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p _msthash="565" _msttexthash="5174371137">
 <span>Gesù parlava spesso in parabole. Queste avevano il pregio di entrare nella coscienza con l''immediatezza e l''impatto emotivo tipico di un racconto, lasciando lo spazio della libertà e invitando ad andare al cuore delle cose importanti. Molti ascoltatori, ci dice il Vangelo, comprendevano secondo le loro capacità. I discepoli però, nel loro cammino di crescita, chiedevano spiegazioni e forse era lo stesso Gesù a premurarsi di fornire loro degli elementi ulteriori per comprendere le parabole. La missione dei discepoli era infatti quella di essere annunciatori dell''amore di Dio, ed alcuni di loro avevano dedicato l''intera esistenza alla missione. Oggi, perciò, meditando la Parola di Dio, preghiamo intensamente per i consacrati che hanno donato la loro vita per vivere profeticamente questo legame con le cose di Dio, e preghiamo per tutto il popolo di Dio, per tutti i discepoli che sono chiamati ad accogliere il messaggio di Gesù e a somigliargli profondamente. C''è bisogno di molta preghiera perché il nostro terreno interiore, il nostro cuore, il cuore di tutti somigli al Sacro Cuore di Gesù. Il nostro cuore, infatti, può accogliere anche erbacce o diventare di pietra, impenetrabile. Quando veniamo amati o amiamo intensamente, sentiamo e chiediamo che le cose raggiungano il cuore, la parte più profonda, perché lì si trova il giusto calore per far crescere e germogliare il bene! Dio ci chiede questo, e da vero innamorato semina, e sembra che lo faccia in modo sprovveduto e illogico. Può sorprendere che il seminatore della parabola getti il seme in terreni dove ovviamente verrà perduto. Questo dice che Dio parla a tutti, la sua semina è magnanima, la sua Parola arriva comunque, la sua presenza ci raggiunge. Dio, perciò, ci chiede di fare spazio nel cuore alla sua Parola, perché ciò che opera nella nostra vita non è una magia; preparare il cuore è anche una nostra responsabilità! La semente di Dio è sempre buona, quindi se non cresci, se non giungi a maturazione, se non ti apri alla grazia, se non lavori il tuo cuore, potresti sprecare il buon seme, potresti sprecare l''opera di Dio in te. Egli donandoti la sua Parola ti dona un pezzo del suo cuore affinché, crescendo in te, tu possa somigliare al suo cuore. Ci ricorda san Giacomo: «Siate di quelli che mettono in pratica la parola e non soltanto ascoltatori, illudendo voi stessi. Perché, se uno ascolta soltanto e non mette in pratica la parola, somiglia a un uomo che osserva il proprio volto in uno specchio: appena s''è osservato, se ne va, e subito dimentica com''era. Chi invece fissa lo sguardo sulla legge perfetta, la legge della libertà, e le resta fedele, non come un ascoltatore smemorato ma come uno che la mette in pratica, questi troverà la sua felicità nel praticarla» (Gc 1, 22-25). Forse stamattina ci siamo guardati allo specchio e poi abbiamo dimenticato le fattezze del nostro volto? Cerchiamo allo stesso modo di custodire la Parola, di ricordarla, di viverla, di spingerla in profondità, per fare la nostra parte: preparare il terreno, irrigarlo con la preghiera, vangarlo con la temperanza, nutrirlo con le virtù e curarlo estirpando i vizi che vogliono radicarsi. Il nostro è il Dio dei piccoli semi e dei grandi doni, non sprechiamo occasioni per fiorire: andiamo al cuore!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-01-31';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p _msthash="585" _msttexthash="348080317">
 <span><em><span>«Il libro dei Proverbi ci chiede: "Più di ogni cosa degna di cura custodisci il tuo cuore, perché da esso sgorga la vita. Tieni lontano da te la bocca bugiarda" (4,23-24). La mera apparenza, la dissimulazione e l''inganno danneggiano e pervertono il cuore. Al di là dei tanti tentativi di mostrare o esprimere qualcosa che non siamo, tutto si gioca nel cuore: lì non conta ciò che si mostra all''esterno o ciò che si nasconde, lì siamo noi stessi. E questa è la base di qualsiasi progetto solido per la nostra vita, poiché niente di valido si può costruire senza il cuore. Le apparenze e le bugie offrono solo il vuoto [...] Sentire e gustare il Signore e onorarlo è cosa del cuore. Solo il cuore è capace di mettere le altre facoltà e passioni e tutta la nostra persona in atteggiamento di riverenza e di obbedienza amorosa al Signore» (papa Francesco). </span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-01-31';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Da una parte c’è Gesù che riposa nel bel mezzo della tempesta. Dall’altra ci sono i discepoli che, nonostante la sua presenza, si sentono perduti. L’evolversi della situazione ci fa capire che il riposo di Gesù non era dovuto a una stanchezza micidiale ma ad un atteggiamento profondo opposto a quello dei discepoli. Loro si fanno prendere dalla paura, si sentono perduti, dubitano che al Signore importi di loro; Gesù invece riposa fiducioso nel Padre. La differenza non è data dalla situazione esterna (sia Gesù che i discepoli affrontano la tempesta) ma dall’approccio interiore. Così è per noi: quando arrivano le tempeste, quando affrontiamo momenti critici, quando attraversiamo situazioni difficili, possiamo poggiarci su Cristo o lasciarci travolgere dalle nostre paure; possiamo aggrapparci a Lui o prendercela con Lui. Possiamo fissarci su di Lui e galleggiare o guardare solo ai problemi e affondare. Sì, nella tempesta possiamo affidarci a Lui o dubitare di Lui. In fondo, qual è l’invito che il testo ci propone? Invocarlo, “svegliarlo”, certi che Lui è più forte delle nostre tempeste e che, al momento giusto, farà tornare la bonaccia. Lui è qui, nella barca della Chiesa, nella barca della nostra anima: “non lasciamolo in pace”. </span><span>Chiamiamolo, invochiamolo, cerchiamolo, aggrappiamoci a Lui senza scoraggiarci, senza disperarci. Dio è più grande, Dio è più forte. In Lui non dobbiamo temere.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-01';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span>«In che cosa consiste la mancanza di fede dei discepoli, che si contrappone alla fiducia di Gesù? Essi non avevano smesso di credere in Lui, infatti lo invocano. Ma vediamo come lo invocano: «Maestro, non t’importa che siamo perduti?» (v. 38). Non t’importa: pensano che Gesù si disinteressi di loro, che non si curi di loro. Tra di noi, nelle nostre famiglie, una delle cose che fa più male è quando ci sentiamo dire: “Non t’importa di me?”. È una frase che ferisce e scatena tempeste nel cuore. Avrà scosso anche Gesù. Perché a nessuno più che a Lui importa di noi. Infatti, una volta invocato, salva i suoi discepoli sfiduciati. La tempesta smaschera la nostra vulnerabilità e lascia scoperte quelle false e superflue sicurezze con cui abbiamo costruito le nostre agende, i nostri progetti, le nostre abitudini e priorità. Ci dimostra come abbiamo lasciato addormentato e abbandonato ciò che alimenta, sostiene e dà forza alla nostra vita e alla nostra comunità. La tempesta pone allo scoperto tutti i propositi di “imballare” e dimenticare ciò che ha nutrito l’anima dei nostri popoli; tutti quei tentativi di anestetizzare con abitudini apparentemente “salvatrici”, incapaci di fare appello alle nostre radici e di evocare la memoria dei nostri anziani, privandoci così dell’immunità necessaria per far fronte all’avversità. Con la tempesta, è caduto il trucco di quegli stereotipi con cui mascheravamo i nostri “ego” sempre preoccupati della propria immagine; ed è rimasta scoperta, ancora una volta, quella (benedetta) appartenenza comune alla quale non possiamo sottrarci: l’appartenenza come fratelli… «Perché avete paura? Non avete ancora fede?». L’inizio della fede è saperci bisognosi di salvezza. Non siamo autosufficienti, da soli; da soli affondiamo: abbiamo bisogno del Signore come gli antichi naviganti delle stelle. Invitiamo Gesù nelle barche delle nostre vite. Consegniamogli le nostre paure, perché Lui le vinca. Come i discepoli sperimenteremo che, con Lui a bordo, non si fa naufragio. Perché questa è la forza di Dio: volgere al bene tutto quello che ci capita, anche le cose brutte. Egli porta il sereno nelle nostre tempeste, perché con Dio la vita non muore mai» (papa Francesco).</span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-01';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Oggi celebriamo la festa della Presentazione del Signore, quando cioè Gesù piccolino fu presentato al Tempio da Giuseppe e Maria. Ed è anche la Giornata della vita consacrata, che richiama alla gratitudine e alla preghiera per quel dono meraviglioso che è la vita consacrata abbracciata da coloro che seguono il Signore da vicino professando i consigli evangelici. </span><span>Il Vangelo racconta che, quaranta giorni dopo la nascita, i genitori di Gesù portarono il Bambino al Tempio per consacrarlo a Dio. Era infatti usanza che il primogenito venisse consacrato al Signore. Nel caso di Gesù qualcosa cambiò; non fu tanto il piccolo ad essere presentato a Dio ma, mediante le parole di Simeone ed Anna, fu Lui (che è Dio!) a essere presentato a noi! Vogliamo soffermarci sull’atteggiamento dei personaggi di questo brano ovvero Giuseppe, Maria, Simeone ed Anna, riassumibile in tre parole: movimento, condivisione, stupore.</span></p>
<p>
 <span>Anzitutto il movimento: possiamo notare come tutti si mettono in cammino. Maria e Giuseppe si incamminano verso Gerusalemme, Simeone va al Tempio, Anna serve continuamente il Signore, senza sosta. Sono tutti in movimento. Da che cosa sono mossi? Dall’amore per il Signore, dall’osservanza della Legge (dunque dalla parola di Dio) e dagli impulsi dello Spirito. Questo ci suggerisce che la fede è un cammino e chiede di camminare. Lo Spirito Santo spinge ad andare oltre, a muoverci, a crescere, ad amare, a evangelizzare. Noi, tante volte, stanchi e delusi, tendiamo a sederci, a fermarci, ad appollaiarci in casa o nelle sacrestie. No, c’è da camminare, da muoversi, da uscire, da andare incontro! Idem per il discernimento vocazionale: non si può pensare di farlo seduti davanti al PC o aspettando che piovano certezze nella stanza! C’è da mettersi in cammino, pregando, vivendo dei tempi di ritiro, lasciandosi accompagnare spiritualmente perché Dio possa parlare al cuore!</span></p>
<p>
 <span>Il secondo atteggiamento è la condivisione. I personaggi del Vangelo dialogano tra loro, condividono ciò che hanno nel cuore, tirano fuori parole belle non banali. Condividere. Quanto è importante in famiglia, in comunità. Aprire il cuore e non fermarsi a parlare del più e del meno, dello sport come del lavoro fatto, ma scendere più in profondità. Condividere le cose del Signore, le cose importanti della propria vita. E dire cose belle, che possano edificare! Simpaticamente papa Francesco ha fatto notare che: <em>«”Anna si mise anche lei a lodare Dio” (v. 38) e ad andare ad indicare alla gente Gesù. Questa è una santa chiacchierona, chiacchierava bene, chiacchierava di cose buone, non cose brutte. Diceva, annunciava: una santa che andava da una all’altra donna facendo loro vedere Gesù»</em>. </span></p>
<p>
 <span>Infine, il terzo atteggiamento è quello dello stupore. Maria e Giuseppe si stupirono per le cose che dicevano del bambino; Simeone si stupì al vederlo; idem Anna. Come ha detto bene il papa: <em>«Queste figure di credenti sono avvolte dallo stupore, perché si sono lasciate catturare e coinvolgere dagli avvenimenti che accadevano sotto i loro occhi. La capacità di stupirsi delle cose che ci circondano favorisce l’esperienza religiosa e rende fecondo l’incontro con il Signore. Al contrario, l’incapacità di stupirci rende indifferenti e allarga le distanze tra il cammino di fede e la vita di ogni giorno».</em> </span></p>
<p>
 <span>Alla luce di tutto ciò, chiediamo alla Vergine Maria, che ci aiuti a metterci in cammino, a saper condividere ciò che conta e a lasciarci stupire da Dio, per le piccole come per le grandi cose. E allora sì che impareremo a riconoscerne la presenza e le visite anche nelle più semplici situazioni di ogni giorno! </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-02';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span>PREGHIERA</span></span></em></p>
<p>
 <em><span><span>Santa Maria, donna missionaria, concedi alla tua Chiesa il gaudio di riscoprire, nascoste tra le zolle del verbo «mandare», le radici della sua primordiale vocazione. Aiutala a misurarsi con Cristo, e con nessun altro: come te, che, apparendo agli albori della rivelazione neotestamentaria accanto a lui, il grande missionario di Dio, lo scegliesti come unico metro della tua vita (don Tonino Bello).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-02';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Gesù si trova davanti ad un uomo posseduto da spiriti impuri. Se da una parte vi è chi dubita ancora dell’esistenza del demonio (pure tra i credenti), dall’altra vi è chi ne riduce l’opera a manifestazioni esteriori, influenzate da film versione <em>l’esorcista</em> o da superstizioni popolari. Il Vangelo di oggi è un invito a scendere in profondità. Tutto quello che fa l’indemoniato del Vangelo che spezza le catene ed è indomabile, che si percuote con le pietre, che grida, che spaventa tutti e supplica Dio di allontanarsi da lui, giudicando il Salvatore come una fonte di problemi, è la manifestazione plateale ed esteriore del lavoro che il maligno vuole compiere in noi. Egli, mediante le sue suggestioni, mira a separarci da Dio, a farci pensare male di Lui, ad allontanarci dal bene, a isolarci, a dividerci gli uni dagli altri. Egli vuole rinchiuderci nella rabbia, nell’insoddisfazione, sottolineando (nei pensieri) sempre ciò che non va; cerca in tutti i modi di spingerci verso il male, perché possiamo diventarne schiavi… Perciò Gesù per primo e gli apostoli in scia, ci invitano alla vigilanza! San Pietro scrisse: <em>«Siate temperanti, vigilate. Il vostro nemico, il diavolo, come leone ruggente va in giro, cercando chi divorare. Resistetegli saldi nella fede, sapendo che i vostri fratelli sparsi per il mondo subiscono le stesse sofferenze di voi» (1 Pt 5,89).</em> Anche noi, senza vigilanza, siamo esposti alle trame del male e possiamo incominciare a vivere nelle tomba della solitudine, a coltivare asocialità e relazioni a due assolutizzanti, possiamo vivere come morti, possiamo incominciare a farci del male da soli e rendere gli altri impossibilitati ad aiutarci, possiamo anche noi guardare gli altri come persone che ci raggirano o che non ci capiscono, finendo col sentirci attorniati dalla morte. Nessuna spiegazione psicologica o umana possiamo rendere dell’opera di satana che ci vuole distruggere attraverso la sua seduzione. Svegliamoci! Possiamo vivere anche noi i sacramenti come una pesantezza, non confessarci, non comunicarci e vivere la presenza di Dio come una tortura. Tutta farina del sacco del demonio! Una legione di spiriti impuri può vivere in noi se non vigiliamo costantemente e perseverando fino alla fine. Abbiamo fede nel Vangelo e speranza nell’opera di Dio che, al contrario del maligno, opera per la nostra libertà: cioè relazionarsi con gli altri, saper perdonare, avere pensieri di bene e di purezza, amare veramente, essere felici veramente! Perciò svegliamoci! </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-03';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <em><span>Oggi anche a noi Gesù rivolge le parole “Talità kum”, un’espressione che in aramaico significa “Fanciulla, alzati!”. Con queste parole Gesù ci ricorda la nostra dignità. La dignità che abbiamo anche quando perdiamo sangue, cioè quando perdiamo la vita o ci assopiamo in uno stile cupo e mortifero che ci addormenta, cullati dal non senso. Alzarsi non è una richiesta di straordinario ma la grazia di vivere l’ordinario in modo straordinario: è camminare e non stare fermi, avere occhi aperti, portamento ritto. Nelle nostre mani c’è tanta grandezza e non possiamo stare chinati a far scorrere il sangue della nostra vita: dobbiamo toccare Gesù, toccare la vita vera e afferrare un progetto di felicità e pace. A quanti giovani dediti alla “divanoterapia” bisogna dire “Alzati!”; a quante persone sconfortate o chinate sul proprio dolore o raggomitolate nelle proprie sventure bisogna dire “Alzati!”. A quanti che passano le ore cercando i colpevoli, che si sentono spenti o che cercano surrogati di amore, vivendo in funzione degli altri ed incapaci di cogliere il proprio valore, dobbiamo ripetere “Alzati!”. Sì, nel nome di Cristo, anche a noi dobbiamo ripetere: “Alzati!”, “Vai”, “Vivi” “Cammina”. Un giorno vidi una ragazza all’apparenza distaccata, non realizzata nel suo percorso di vita e con un atteggiamento passivo  aggressivo, partecipare ad un incontro in cui parlava una suora. Quest’ultima incoraggiava a guardare la bellezza che abbiamo dentro e io mi commossi profondamente al vedere questa ragazza piangere copiose lacrime; mi sembrò che anche a lei il Signore stesse dicendo: “Fanciulla bellissima e da me amata, alzati”. Forse dovremmo smetterla di pensare che per avere un valore si debbano avere grandi doti, sapendo che c’è la voce di amato che ci invita a camminare. Forse dovremmo smetterla di aspettare chissà quali cambiamenti esterni per rimetterci in gioco, sapendo che c’è l’Amore che qui ed ora ci invita ad alzarci! Forse Michelangelo a ventitré anni nel 1498 non avrebbe scolpito la pietà, una delle opere più belle al mondo, senza lo sprone a scoprirsi e a mettersi in azione. E Dio ha usato le sue mani per donarci tanta meraviglia! Forse le nostre mani verranno usate per fare una carezza che vale tante opere d’arte messe insieme, o per indicare una strada, o forse c’è chi le mani non le ha ma impara ad accarezzare con l’anima. Comunque e dovunque siamo, impariamo a donare la nostra vita e Dio venendoci incontro dirà: “alzati, vali tanto!”. E da quel giorno diventeremo “gioiosi messaggeri dell’alzati di Dio”.</span></em></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-04';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>«Non c’è solo la morte del corpo, c’è anche la morte del cuore e dell’anima. La morte dell’anima è quando si vive nel peccato; la morte del cuore è quando si vive nell’angoscia, nello scoraggiamento o in una tristezza cronica. Le parole di Gesù: “Talità kum”, fanciulla, alzati! non sono dunque rivolte solo a ragazzi e ragazze morte, ma anche a ragazzi e ragazze viventi. Quando è triste vedere dei giovani…tristi. E ce ne sono tantissimi intorno a noi. La tristezza, il pessimismo, la nonvoglia di vivere sono sempre cose brutte, ma quando li si vede o li si sente esprimere da ragazzi ancora di più stringono il cuore. Ci sono adolescenti, che hanno apparentemente tutto, computer e moto compresi. Ma se si cerca di esortarli alla speranza e alla gioia, rispondono (e il loro volto mostra che non si tratta di una posa): “Mi sai dire un motivo, uno solo, per il quale dovrei essere felice?”. Si vorrebbe rispondere: “Perché sei giovane, perché Dio ti ama, perché i tuoi genitori ti amano…”, ma ci si rende conto che non serve e ci si limita a guardarli con pietà e tenerezza. A volte viene da gridare tra sé in questi casi: “Mondo perfido e cinico, che uccidi così la gioia di vivere di questi ragazzi! Prometti loro mari e monti e li lasci con la bocca (e il cuore) asciutti”. L’invito ad avere fede è rivolto però anche a chi spiega il Vangelo agli altri. Perciò, con la fede nella potenza misteriosa delle parole di Cristo, non dobbiamo aver paura di gridare ai tanti ragazzi di oggi morti nel cuore: Talità kum! Su, ragazzo, su ragazza, alzati, scuotiti, “spogliati della tua tristezza”; smetti di crogiolarti nel tuo sterile pessimismo, vai verso gli altri e gli altri verranno verso di te!» (p. Raniero Cantalamessa). </em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-04';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Gesù tornò nella sua patria e, di sabato, si mise ad insegnare nella sinagoga. Tutti rimasero stupiti, sì, ma di uno stupore carico di perplessità, di dubbio, come a dire: “come è possibile che costui parli così? Noi lo conosciamo, non è che il figlio del falegname! Come può pretendere di insegnare a noi le Scritture? Da dove gli viene questa sapienza?”. E così, a causa dell’incredulità dei suoi compaesani, Gesù non poté compiere molti miracoli. Eppure, chi più di loro, persone credenti, non avrebbe dovuto riconoscere l’opera di Dio e le sue meraviglie? Egli può far sì che un semplice amico diventi una guida spirituale, che un parente cambi vita e da persona dissoluta diventi un esempio. Insomma, Dio può intervenire concretamente nella nostra vita e renderci molto più di quello che pensiamo di essere. Gesù era da sempre “molto di più” di un falegname, era molto di più del figlio di Maria e di ciò che pensavano di lui tanti parenti, eppure viene disprezzato proprio da coloro che pensavano di conoscerlo. Senza l’umiltà e senza l’apertura al “di più” presente in ogni persona, “pensare di conoscere” può rivelarsi una trappola. Quante volte ci siamo caduti, etichettando gli altri o non credendo al loro cambiamento, finendo per far sì che, come alla fine di questo Vangelo, l’unico a stupirsi davanti alla nostra incredulità sia Dio stesso! Dovremmo ripeterci spesso che <em>“Dio può tutto!”</em> e che le persone non sono pezzi da collezione elencati in un catalogo! Perciò anche se abbiamo fatto tanti errori, dobbiamo sapere che Dio guarda più in profondità. Cosa vide Gesù guardando la donna adultera e peccatrice? Una donna che ha tanto amato, cioè guarda nel suo cuore e non si ferma agli errori o all’apparenza. Cosa vide il Signore guardando Saulo che perseguitava i credenti? Un potenziale santo, un futuro apostolo. Tante volte per i nostri giudizi temerari non cogliamo la presenza di Gesù, rischiando di ostacolare l’opera di Dio e far scappare persone buone perché non sono conformi ai nostri pensieri o al modo di fare comune. Gesù ha vissuto questa discriminazione da parte delle persone del suo stesso popolo e conosce il potere discriminatorio dell’umanità. Oggi è venuto a dirci di accogliere tutti, ricordandoci che qualsiasi persona è molto di più della sua storia, delle sue capacità e qualità, ed è in potenza una via di santità per l’umanità. Quanti evangelizzatori ci vorrebbero per far comprendere ad un giovane sbandato o ad una persona smarrita che vale molto di più, che è il sogno di Dio! Passiamo dunque dai cataloghi moralisti al guardare con gli occhi di Dio i nostri fratelli e sorelle. </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-05';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Non nello straordinario, ma nel quotidiano noi assomigliamo a Cristo, in un bicchiere d''acqua fresca offerto, in un pezzo di strada fatto con chi ha paura, in una lacrima asciugata. In gesti come quelli di Gesù: quante volte si ferma, solo perché qualcuno lo chiama. Si ferma e si gira, non lo vediamo mai progettare grandi opere, ma ascoltare, imporre le mani, toccare occhi, orecchi, labbra, spezzare il pane, entrare nelle case, sedere a mensa. Vale per noi tutti: meno opere e più gesti» (p. Ermes Ronchi).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-05';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il mandato missionario che Gesù rivolge ai Dodici ha due segni che lo contraddistinguono. Un primo segno è la comunione. L’invio a due a due ci dice che, contro ogni forma di individualismo, la prima testimonianza di fede che siamo chiamati a dare è quella di saper stare insieme, saper collaborare, insomma creare comunione. La comunione fra noi e con gli altri è il primo segno della presenza del Signore nella nostra vita ed è il primo mezzo di evangelizzazione. Questo elemento non è semplicistico, è fondamentale: ci indica che la salvezza della Chiesa, della famiglia, del mondo viene dalla comunione, che per noi non è affatto facile. Quante volte diffidiamo gli uni degli altri, tendiamo ad isolarci, a dividerci, pensando che da soli riusciamo meglio. Talvolta non sappiamo creare dialogo con persone diverse o fuori dalla nostra cerchia, e si ripetono ancora oggi, anche nella Chiesa, situazioni di non collaborazione per il bene comune. Perciò alcuni responsabili (anche nelle Diocesi o negli Istituti religiosi) utilizzano il ruolo ricoperto per portare avanti se stessi o i propri progetti, senza valutare le esigenze degli altri, i loro bisogni, le loro sofferenze. Spesso tutto ciò parte da lontano; basti pensare quanti figli, al primo stipendio, chiedono ancora i soldi ai genitori e non collaborano al bene comune in famiglia: anche questo è individualismo. Proseguendo, notiamo un secondo segno importante che Gesù insegna ai discepoli: l’efficacia dell’annuncio della Chiesa non dipende dai mezzi. L’evangelizzazione è un’opera, uno stile che prescinde dai soldi e dalle strutture: è il mandato di amore e di incontro che Dio ha lasciato per annunciare a tutti la buona notizia. Anche noi dobbiamo superare quei convincimenti che ci paralizzano, pensando che per portare l’amore di Gesù dobbiamo fare grandi cose o che dobbiamo rivolgerci solo a gente povera e disperata. E quando questa comunione di amore in Dio non avviene e non accolgono il messaggio del Vangelo i discepoli continuano ad andare avanti nel cammino. Come faccio dunque ad evangelizzare? Anzitutto con la bontà di Dio che mostro al mio prossimo nel quotidiano; e qualora non venisse accolta, sarà meglio non focalizzarsi tanto che “neanche la polvere resti attaccata ai piedi”, per procedere nel nostro gioioso percorso. E farlo con le parole incoraggianti, benedicenti, non banali, che sanno toccare e indirizzare la vita. Senza dimenticare che la conversione non è un’opera di convincimento ma opera della grazia di Dio nel cuore, di cui noi siamo semplici collaboratori! Infine, notiamo come i discepoli sperimentano l’efficacia della potenza di Dio nella loro vita: gente che si convertiva, demoni che fuggivano, malati che guarivano. Da notare: loro desideravano solo portare il Signore alle persone e le persone al Signore, e Dio operava. Se anche noi faremo lo stesso, se avremo a cuore il vero bene di chi incontreremo, anche noi potremo sperimentare i prodigi di Dio!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-06';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Non si può evangelizzare senza testimonianza. È indispensabile per evangelizzare. Il mondo ha bisogno di evangelizzatori che gli parlino di un Dio che essi conoscano e che sia loro familiare. Non è trasmettere una ideologia, una dottrina su Dio, è Dio che si fa vita in me» (papa Francesco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-06';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Erode Antipa seguì le orme del padre, soprannominato Erode “il grande”. Le fonti storiche ci fanno comprendere che il ruolo “regale” che rivestiva non corrispondeva a una regalità d’animo. Egli iniziò la ricostruzione del tempio di Gerusalemme, abbellì e costruì teatri e anfiteatri, edifici agli dei pagani e in onore dell’imperatore Augusto e fondò la capitale di Cesarea Marittima. Perciò fu soprannominato Erode “il grande”. Egli non amava il suo popolo e anche nella sua famiglia non si respirava una buona aria. Fece uccidere diversi familiari ed entrò in un vortice di violenza e diffidenza che lo portò a odiare e dubitare delle persone a lui vicine. Il figlio, Erode Antipa, che incontreremo nuovamente nella passione di Gesù, ereditò una “spirale di morte” che, come leggiamo nel Vangelo, continuò con brutali crudeltà, proseguendo nel disonorare la regalità del suo ruolo. Non solo intrecciò una relazione con la moglie del fratello Filippo ma, preso dalla lussuria, ammaliato dalla danza della figlia di questa donna, per lei e per la brutalità che costei ereditò dalla madre, uccise Giovanni Battista. Davanti a tutto ciò, oggi vogliamo chiedere al Signore di aiutarci perché possiamo vivere quella vera regalità che, in germe, abbiamo ricevuto nel cuore il giorno del battesimo. Essere veri “re e regine”, capaci di governare sé stessi e, ad immagine e somiglianza di Dio, capaci di servire, di amare, di trasmettere bontà. Qualsiasi ruolo abbiamo nella società, possiamo esprimere una regalità celeste nel nostro lavoro. Non importa se siamo impiegati, operai o dirigenti; ciò che conta è che ci si rivesta di bontà affinché l’odio non continui a propagarsi. Giovanni non fu l’unica vittima di Erode, capace di intristirsi solo per il suo onore e non per il male che generavano le sue azioni; tanti altri furono sue vittime ed egli stesso fu la prima vittima del male che coltivava dentro! Erode avrebbe potuto servire con il suo potere, invece ne abusò, cercando i propri interessi, seminando rabbia nei cuori e diffondendo sospetto e cattiveria. Che il Signore ci liberi da tutto ciò! Perciò, impariamo a non far propagare il male, ad essere cittadini onesti e collaboratori spirituali della grazia di Dio, che sanno riconoscere i tanti Giovanni Battista che si immolano per portare la verità, a costo di “perderci la testa”. Sì, anche noi impariamo a perdere la testa per il bene!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-07';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span>«Erode pensava, con l’uccisione di Giovanni il Battista, di aver fatto tacere chi denunciava con coraggio le ingiustizie e la corruzione del suo regno, tuttavia si rende conto che qualcosa del suo piano è andato storto. Non è così semplice far tacere la verità. La violenza e la morte non hanno l’ultima parola… Proprio questa denuncia destabilizza Erode perché il suo regno si basa sulla violenza e sulla prepotenza. Il regno di Erode è intriso di questa violenza che scaturisce dalla paura di perdere il proprio potere. Il mantenimento della propria immagine e del proprio potere ingabbia anche la sua volontà, che egli non conosce bene, ma che è rivelata da quel sentimento di tristezza che affiora. Erode non solo non vuole ascoltare il messaggio di Giovanni e quello di Gesù, ma non riesce neanche ad ascoltare sé stesso. È assordato dal rumore del potere e della violenza che al momento si incarna nella richiesta di Erodiade e poco più avanti dallo sguardo dei commensali che sono in attesa di controllare se il loro re ha il coraggio di mantenere la parola data. Tuttavia non si tratta di coraggio, si tratta piuttosto di pusillanimità e di asservimento al bisogno di custodire la propria immagine esteriore che deve sottostare ai desideri di Erodiade e dei suoi commensali. Quello che manca ad Erode è il coraggio di ascoltare Giovanni e di lasciare che le sue parole plasmino la sua coscienza così da poter prendere delle decisioni in autonomia e non in balia di quanto gli altri si aspettano da lui. Nonostante Erode voglia dimostrare la sua forza e il suo potere alla fine fa fuoriuscire solo dipendenza dal potere e dalla volontà degli altri e dalla dipendenza scaturisce la violenza e la morte. La parola di Giovanni e successivamente quella di Gesù, al contrario, generano una comunità, quella descritta oggi dai discepoli di Giovanni che vanno a recuperare il corpo del loro maestro, che ha il coraggio di compiere azioni come quella di seppellire il profeta che è stato ucciso per la sua audacia. Essi con tale gesto dimostrano un rispetto profondo verso Giovanni e dimostrano di voler mettere in pratica l’audacia e il coraggio di quella parola che non guarda in faccia a nessuno, neanche la morte violenta perché sono ben consapevoli che la morte non ha l’ultima parola» (sorella Beatrice, Bose).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-07';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Gesù insegna ai suoi discepoli a non essere “cibi in scatola a lunga conservazione” ma a farsi nutrimento per gli altri, ad essere continui dispensatori di compassione e d’amore. Questo non vuol dire che non si debba mai riposare: è Dio che ha inventato il riposo. Se ricordiamo bene, nel racconto della creazione, Egli stesso ci insegna ad ammirare il bene compiuto riposando. Semplicemente, Gesù vuole insegnarci a dare priorità al bene. Se il bene bussa alla porta, niente gli va anteposto e i santi ci sono maestri in questo. Quando qualcuno cerca ristoro, aiuto, una parola, una carezza, noi dobbiamo essere disponibili, fruibili, farci pane spezzato. Il tempo che mai rimpiangeremo è quello donato, trascorso per far sentire amate e curate le persone che abbiamo accanto e che il Signore mette lungo il nostro cammino. Soprattutto, il tempo speso per esercitare quella compassione che ci rende vicini e capaci di comprendere coloro che cercano Dio senza saperlo, e lo cercano nella nosta carezza, nel nostro ascolto, nella parola amorevole che gli rivolgiamo. Quante occasioni abbiamo per essere prolunghe di Dio nel mondo e quanto lavoro c’è da fare per scavare nel nostro cuore in modo da non farci travolgere dalla mentalità del giudizio ma dalla compassione, cioè <em>patire-con</em>, avere il grembo di una madre che soffre per i figli. Che occhi profondi sono quelli dei santi che sapevano essere per tutti padri e madri, occhi amorevoli, dispensatori di consigli divini.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-08';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Non dovete preoccuparvi e credere di aver mancato, se per il servizio dei poveri avete lasciato l’orazione. Non è lasciare Dio, quando si lascia Dio per Iddio, ossia un’opera di Dio per farne un’altra. Se lasciate l’orazione per assistere un povero, sappiate che far questo è servire Dio. La carità è superiore a tutte le regole, e tutto deve riferirsi ad essa. È una grande ignora: bisogna fare ciò che comanda» (san Vincenzo de’ Paoli).</span></em></span></p>
<p>
 <em><span>«La compassione ti fa vedere le realtà come sono; la compassione è come la lente del cuore: ci fa capire davvero le dimensioni. E nei Vangeli, Gesù tante volte viene preso dalla compassione. La compassione è anche il linguaggio di Dio. Non incomincia, nella Bibbia, ad apparire con Gesù: è stato Dio a dire a Mosè “ho visto il dolore del mio popolo” (Es 3,7); è la compassione di Dio, che invia Mosè a salvare il popolo. Il nostro Dio è un Dio di compassione, e la compassione è – possiamo dire – la debolezza di Dio, ma anche la sua forza. Quello che di meglio dà a noi: perché è stata la compassione a muoverlo ad inviare il Figlio a noi. È un linguaggio di Dio, la compassione. La compassione “non è un sentimento di pena”, che si prova, ad esempio, quando si vede morire un cane sulla strada: “poveretto, sentiamo un po’ di pena”, nota Francesco. Ma è “coinvolgersi nel problema degli altri, è giocarsi la vita lì”. Il Signore, infatti, si gioca la vita e va lì» (papa Francesco).</span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-08';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo di questa domenica ci propone un momento significativo nella vita di Pietro: il suo incontro con Gesù. Siamo all’inizio della sua chiamata, dell’inizio della sua sequela di Gesù. È sempre bello tornare alle origini, e ripensare ai momenti in cui Cristo ci ha conquistati con il suo amore. Aiuta a rinfrescare l’anima, a riaccenderci di un sano entusiasmo, talvolta sopito dal tempo, dalla fatica… Anche in un rapporto, in un matrimonio, in un’amicizia significativa fa bene ripensare alle origini, ai momenti iniziali; sono ricordi belli capaci di rinvigorire le nostre forze e aiutarci a ridirigere i passi nella giusta direzione, qualora l’avessimo smarrita.</span></p>
<p>
 <span>Ritornando al Vangelo, possiamo ipotizzare che Pietro sapesse già chi era Gesù, forse lo aveva già ascoltato. Ora Gesù entra più concretamente nella vita di Pietro, nella sua barca, della quale si serve a mo’ di ambone per predicare. È interessante notare che Gesù entri in un momento di crisi. Pietro e gli altri stavano rassettando le reti: non avevano pescato nulla quel giorno. Gesù entra in quel vuoto per riempirlo come solo Lui può fare. Quel momento di crisi si rivelerà il momento decisivo, il tempo della grazia più grande per Pietro. Ribadiamo: non il momento del successo ma quello del vuoto, della crisi. Vale la pena ricordare che da una crisi tutto è partito e da una crisi tutto ripartirà: Pietro dopo la morte di Gesù tornerà a pescare ma anche in quel caso non prenderà nulla. Sarà Gesù risorto ad andargli nuovamente incontro, ribadendo: «gettate le reti a destra». E all’obbedirgli, la barca di riempì di grossi pesci. Cosa sono i tempi di crisi, di vuoto, di fallimento? Il Vangelo ci suggerisce: i tempi della possibile irruzione di Dio!</span></p>
<p>
 <span>Gesù entra e chiede a Pietro un atto di fiducia enorme. Chiede di fidarsi di Lui – un maestro di sacra scrittura, non di certo un pescatore –, di prendere il largo e di gettare le reti dalla parte opposta a quella dove si solito si gettano, perdipiù non di notte ma di giorno. Pietro si fida. Lo stare con Gesù, l’aver ascoltato le sue parole, devono avergli fatto percepire che in Lui “c’è di più”. Perciò si fida, getta le reti sulla sua parola e compie una pesca sovrabbondante, impossibile di giorno. È bellissimo: Gesù non punta il dito contro Pietro, non sottolinea il suo fallimento, gli chiede solo fiducia. Noi troppo spesso ci ripieghiamo su noi stessi, piangendoci addosso, colpevolizzandoci per ciò che non è andato bene… Troppo spesso rimaniamo fissati sui nostri fallimenti, ipnotizzati sul vuoto. Ma più fissiamo il vuoto più gli facciamo spazio. Il Vangelo di oggi sembra dirci: non perdere tempo con il vuoto, non cercare colpevoli, non stagnare nella crisi, piuttosto lasciati incontrare nella crisi. Lasciati riportare da Cristo alla concretezza della vita, e riparti dalla sua parola, tornando a prendere il largo! Qui sta la bellezza e la concretezza della fede: una fiducia concreta in Gesù e nella sua Parola, obbedendo alla quale possiamo permettere allo straordinario di Dio di operare nel nostro ordinario, dando senso e pienezza al nostro quotidiano.</span></p>
<p>
 <span>Pietro, vedendo la pesca miracolosa, capisce di essere al cospetto di Dio. Solo Dio poteva fare una cosa del genere: <em>«Per questo Pietro cade in ginocchio davanti a Gesù, cosa che un ebreo fa soltanto davanti al Creatore. Per questo chiama Gesù “Signore”, che è il nome di Dio nella Bibbia greca. E per questo, gli diventa chiaro soprattutto in questo incontro chi è lui stesso: un essere umano che vive nella lontananza da Dio, nell’ingiustizia, nel peccato. Nell’incontro con la potenza di Dio Pietro rientra in se stesso in una salutare conoscenza di sé. Egli sperimenta di non essere grande ma piccolo. Sperimenta che… in Gesù lo viene ad incontrare colui che è davvero grande» (Klaus Berger)</em>. Ecco i connotati dell’esperienza di Dio: davanti alla sua grandezza ci si sente piccoli, poveri, peccatori, tuttavia non schiacciati ma amati! </span></p>
<p>
 <span>Dinanzi a tutto ciò, chiediamo al Signore che ci aiuti a saper valorizzare i nostri momenti difficili, lasciandoci incontrare da Lui, mettendocela tutta per seguire la sua Parola. Siamone certi: ne vale la pena!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-09';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>PREGHIERA</em></span></span></p>
<p>
 <span><span><em>O Dio, nostro Padre, che guidi i nostri passi e ispiri le nostre vie,</em></span></span></p>
<p>
 <span><span><em>concedici la grazia di gettare le nostre reti sulla tua parola e di pescare abbondantemente a tua lode e gloria.</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-09';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Come cerchiamo Gesù? Quale guarigione vuol portarci Gesù? Ecco due punti sui quali vogliamo soffermarci. </span><span>Anzitutto: come cerchiamo Gesù? Il Vangelo ci mostra la ricerca intensa, decisa, a tratti commovente di tanti sofferenti e malati. L’indigenza, la povertà, il bisogno diventano le porte di accesso a Cristo. Quante volte ci chiudiamo in noi stessi perché provati, feriti, delusi, come se tutto ciò ostacolasse la vita. I malati del Vangelo di oggi, invece, “gridano” che proprio dove la vita è ferita Cristo vuol entrare. Non temiamo dunque: cerchiamolo, invochiamolo, aggrappiamoci con forza a Lui. Mettiamo davanti al medico celeste le nostre fragilità, le nostre fatiche; lasciamoci toccare, lasciamoci sanare! </span><span>E da qui il secondo punto: quale guarigione vuol portarci Gesù? Le guarigioni fisiche sono grazie grandi che ci illuminano sulla guarigione più profonda, quella dell’anima e, in fondo, di tutto il nostro essere. Per qualcuno questa sarebbe una banalità che si dice quando si guarisce fisicamente, mentre in realtà è il miracolo più straordinario che Dio compie nel cuore dell’uomo. Ed è straordinario proprio perché è visibile a pochi e risiede nell’intimità del cuore. Nascosto, sì, ma potente, capace di salvare e cambiare tutta la vita. Conosco tante persone che raccontano com’erano prima di aver fatto entrare Gesù nella loro vita; guardandole, non riesco a pensare a come potessero essere o non riesco a ricordare quando erano attaccate al denaro, peccatrici e peccatori incalliti o vanitosi, che vivevano nella confusione totale e senza una direzione. Sì, perché il loro cambiamento interiore è così profondo da averle rese persone diverse. Ecco il miracolo di guarigione di chi crede, di chi non si ferma in superficie ma lascia scendere Cristo e la sua parola in profondità. A volte cerchiamo miracoli più evidenti, più superficiali, scoraggiandoci se non arrivano. Oggi il Vangelo ci ricorda che se apriamo il cuore al Signore, anche se non arriva il miracolo che chiediamo, ne può arrivare uno più grande, più decisivo per la nostra vita e la nostra eternità. Oggi perciò preghiamo con tutto il cuore per la guarigione totale dell’uomo, corpo e anima, e pensiamo in particolare a qualcuno per il quale vogliamo intercedere presso il Signore…</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-10';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Cerchiamolo per trovarlo, cerchiamolo dopo averlo trovato. Perc hé lo cercassimo per trovarlo, è nascosto; perché, dopo averlo trovato, di nuovo lo cerchiamo. Egli è immenso. Sazia chi, cercandolo, diventa capace di coglierlo, e fa più capace chi trova» (Sant’Agostino).</span></em></span></p>
<p>
 <em><span>«Trovare Dio è cercarlo senza fine. In effetti cercare e trovare Dio non sono cose diverse, ma il guadagno della ricerca è la ricerca stessa. Il desiderio di Dio nell’anima è appagato dal fatto stesso di restare insaziabile, poiché vedere Dio è propriamente non esser mai sazi di desiderarlo» (San Gregorio di Nissa).</span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-10';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Oggi ricorre la memoria facoltativa della Beata Vergine Maria di Lourdes. Molti pellegrini da tutto il mondo si recano in questa cittadina francese per chiedere l’intercessione di Maria per la guarigione propria o altrui. E proprio Gesù nel Vangelo si rivela come la fonte di ogni guarigione per l’uomo, fino alla guarigione più profonda, la vittoria sulla morte. Il messaggio della Madonna a Lourdes o in altri luoghi ha una centralità: Gesù. Nessuna guarigione può essere autentica al di fuori della verità del Vangelo. Maria, infatti, riporta sempre a Gesù e ogni apparizione autentica viene ricapitolata in Cristo dalla Chiesa. Perché ci sono delle apparizioni e a chi sono rivolte? Le apparizioni sono delle rivelazioni private rivolte anzitutto ai veggenti, scelti da Dio con gli stessi criteri che ha usato quando era in mezzo a noi: infatti sono spesso gli ultimi, i piccoli e i semplici. Segno evidente della veridicità di un’apparizione è la loro vita; una vita che rimane semplice, nascosta, dedita al Signore e agli altri. Spesso queste apparizioni hanno un’eco profonda nella coscienza di molti, ma non si deve mai dimenticare che esse sono rivelazioni private che vanno interpretate alla luce del messaggio che Dio ha voluto mandare attraverso Maria a quel veggente e, in quel contesto e per riflesso, anche a noi. Esse non aggiungono nulla alla “rivelazione pubblica” di Dio, culminata in Cristo, e non vanno interpretate in modo assoluto e senza la luce che viene dalla Chiesa. La volontà di Maria non è mai diversa da quella di Gesù e perciò la voce della madre è la calda voce di Dio che pone Gesù nel cuore dell’uomo nella culla della Chiesa. In particolare, il messaggio di Lourdes, dove la Vergine Maria si è presentata come l’Immacolata Concezione, ci invita a riscoprire la nostra vocazione: «Il Padre ci ha scelti… per essere santi e immacolati al suo cospetto nell’amore» (Ef 1,34). Ecco la nostra chiamata: essere santi ovvero “pieni di Dio”, conformi a Lui; ed essere <em>immacolati</em>, limpidi, puri, liberi dal peccato. La Vergine Santa ci ricorda la nostra grandezza, ci invita a raggiungerla e ci aiuta nel percorso. Come lui ha esemplarmente fatto, anche noi siamo chiamati ad accogliere il Signore Gesù, a custodire il rapporto con Lui, a seguirlo, conformandoci al suo amore. Il Vangelo di oggi ci chiama a vivere questo dinamismo della fede, a non ridurre il nostro rapporto con Dio all’osservanza superficiale di alcune regole, per sentirci a posto e – magari – meglio degli altri. Siamo chiamati al cielo, alla santità, a diventare “campioni d’amore”. Ecco la nostra chiamata. Qualora l’avessimo persa di vista, qualora ci stessimo ingolfando in cose di poco conto, qualora lo sconforto stesse prendendo il sopravvento o la schiavitù del peccato ci stesse soffocando, volgiamo nuovamente lo sguardo a Maria, nostra tenera madre, preghiamola, affidando a lei i nodi della nostra vita. E serbiamo nel cuore il suo “testamento”, sintesi mirabile di tutto il suo agire e del nostro vivere: «qualunque cosa [Gesù] vi dica, fatela!» (cf Gv 2,1-11).</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-11';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span>IL MESSAGGIO DI LOURDES</span></span></p>
<p>
 <span><span>Durante la terza apparizione, il 18 febbraio 1858, la Vergine parla per la prima volta: <em>“Ciò che le devo dire, non è necessario scriverlo”</em>. </span></span></p>
<p>
 <span><span>Questo significa che Maria vuole entrare, con Bernadette, in una relazione che è propria dell’amore, che si trova al livello del cuore. Bernadette viene subito invitata ad aprire le profondità del suo cuore a ques  to messaggio d’amore. Alla seconda frase della Vergine: <em>“Vuole avere la grazia di venire qui per quindici giorni?”. </em>Bernadette è sconvolta. È la prima volta che qualcuno le si rivolge dandole del “lei”. Bernadette, sentendosi così rispettata ed amata, vive l’esperienza di essere lei stessa una persona. Siamo tutti degni agli occhi di Dio perché ciascuno di noi è amato da Lui. La terza frase della Vergine: <em>“Non le prometto di renderla felice in questo mondo ma nell’altro.”</em> Quando Gesù, nel Vangelo, ci invita a scoprire il Regno dei cieli, ci invita a scoprire, qui nel nostro mondo, un “altro mondo”. Là dove c’è l’Amore, Dio è presente.</span></span></p>
<p>
 <span><span>Malgrado la sua miseria, la sua malattia, la sua mancanza di cultura, Bernadette è sempre stata profondamente felice. È quello il Regno di Dio, il mondo del vero Amore. Durante le prime sette apparizioni di Maria, Bernadette mostra un volto radioso di gioia, di felicità, di luce. Ma, tra l’ottava e la dodicesima apparizione, tutto cambia: il suo viso diviene triste, doloroso, ma soprattutto lei compie gesti incomprensibili…. Cammina in ginocchio fino al fondo della Grotta; ne bacia il suolo sporco e disgustoso; mangia l’erba amara; scava il suolo e prova a bere l’acqua fangosa; si imbratta il viso col fango. Poi, Bernadette guarda la folla e tutti dicono: “È pazza”. Nel corso delle apparizioni Bernadette ripete gli stessi gesti. Che cosa significa? Nessuno comprende! Questo tuttavia è il cuore del “Messaggio di Lourdes”. I gesti di Bernadette sono gesti biblici. Bernadette esprimerà l’incarnazione, la Passione e la Morte del Cristo. Camminare in ginocchio fino al fondo della Grotta è il gesto dell’incarnazione, dell’abbassamento di Dio fatto uomo. Mangiare le erbe amare ricorda la tradizione ebraica che si trova nei testi antichi. Imbrattarsi il viso ci riporta al profeta Isaia, quando parla del Cristo descrivendolo con i tratti del Servitore sofferente.</span></span></p>
<p>
 <span><span>Alla nona apparizione, “la Signora” chiederà a Bernadette di andare a scavare il suolo, dicendole: <em>“Vada a bere ed a lavarsi”</em>. Con questi gesti, ci è svelato il mistero stesso del cuore del Cristo: “Un soldato, con la sua lancia, gli trapassa il cuore e, subito, sgorgano sangue e acqua”. Il cuore dell’uomo, ferito dal peccato, è rappresentato dalle erbe e dal fango. Ma in fondo a questo cuore, c’è la vita stessa di Dio, rappresentata dalla sorgente. Quando verrà chiesto a Bernadette: “la “Signora” ti ha detto qualcosa?” lei risponderà: <em>“Sì, ogni tanto dice: “Penitenza, penitenza, penitenza. Pregate per i peccatori”</em>. Con la parola “penitenza”, bisogna intendere anche la “conversione” che consiste, come insegnato da Cristo, nel rivolgere il proprio cuore verso Dio, verso i propri fratelli.</span></span></p>
<p>
 <span><span>Nel corso della tredicesima apparizione, Maria si rivolge così a Bernadette: <em>“Vada a dire ai sacerdoti che si venga qui in processione e che vi si costruisca una cappella”.</em> “Che si venga in processione”, significa camminare, in questa vita, sempre vicino ai nostri fratelli. A Lourdes, le cappelle sono state costruite per accogliere la folla di pellegrini. La cappella è la “Chiesa” che dobbiamo costruire, là dove siamo. Il 25 marzo 1858, giorno della sedicesima apparizione, Bernadette chiede alla “Signora” di dire il suo nome. “La Signora” le risponde in dialetto: “Que soy era Immaculada Councepciou”, che significa “Sono l’Immacolata Concezione”: è “Maria concepita senza peccato, grazie ai meriti della Croce del Cristo” (definizione del dogma promulgato nel 1854). Bernadette va subito dal parroco per trasmettergli il nome della “Signora” ed egli comprende così che è la Madre di Dio che appare alla Grotta. Più tardi, il vescovo di Tarbes, Mons. Laurence, autenticherà questa rivelazione.</span></span></p>
<p>
 <span><span>La firma del messaggio, quando la Signora dice il suo nome, arriva dopo tre settimane di apparizioni e tre settimane di silenzio (dal 4 al 25 marzo). Il 25 marzo è il giorno dell’Annunciazione, della “concezione” di Gesù nel seno di Maria. La Signora della Grotta ci parla della sua vocazione: è la madre di Gesù, tutto il suo essere consiste nel concepire il Figlio di Dio, è tutta per Lui. Per questo è Immacolata, abitata da Dio. Così la Chiesa ed ogni cristiano devono lasciarsi abitare da Dio per divenire a loro volta immacolati, radicalmente perdonati e graziati in modo da essere, anch’essi, testimoni di Dio. </span></span></p>
<p>
 <span><span>https://www.lourdes-france.com/it/il-messaggio-di-lourdes/</span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-11';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Gesù oggi ci dà una lezione preziosissima di interiorità. Guardiamo a ciò che alimentiamo nel nostro cuore, è questo che ci rende persone libere o, al contrario, schiave. A che cosa abbiamo legato il cuore? Quante sottili dipendenze ci deturpano e ci tolgono tempo ed energie! Oppure, a chi abbiamo legato il cuore? Quanti amori malati! Pensiamo ancora che l’amore “si sente” soltanto? Che quello che ci piace è necessariamente buono e va fatto? Che la vita è bella se cogliamo l’attimo, se seguiamo indiscriminatamente il cuore? Non dobbiamo dimenticare che un cuore schiavo del peccato sceglie il peccato. È ciò che abbiamo dentro che va guardato e incanalato; dobbiamo decidere di essere liberi e scegliere. Dunque, l’amore è una scelta? Sì, amare significa scegliere, significa donarsi, significa comunicare amore, perché quello che sentiamo è momentaneo, quello che costruiamo è per sempre. L’amore certamente è fatto anche di sentimenti ma i sentimenti non devono essere scissi dalla persona: non si vive solo di mente o solo di cuore, si vive come persone, con maturità. Amare è buttarsi nel vuoto per imparare a volare, non per precipitare sempre più in basso ma per tendere verso l’alto. L’amore di cui parliamo, la cui unica fonte è Dio, non è da rivolgersi solo verso una persona ma anche verso le cose, le scelte, i sogni. Che cosa amo? Quale grande errore è pensare che i figli vadano allontanati da persone diverse da loro o che noi (magari senza prove) riteniamo negative. Invece dovremmo avere fiducia in quello che abbiamo seminato nel loro cuore. Certo, se abbiamo seminato… se i figli sono stati “educati” dalla TV o dai divi del potere e del successo, non possiamo pretendere che “estraggano dal sacco” altre cose. Non possiamo preoccuparci di mantenere il male sempre fuori dagli spazi delle persone che amiamo ma dovremmo puntare sull’interiorità. Ciò che conta non è tanto la quantità del tempo che si trascorre insieme, ma la qualità del tempo. Posso trascorrere delle ore con le persone care ma seminare solo banalità. Impariamo a indicare il mondo dell’interiorità: cosa senti, cosa provi, cosa ami, cosa pensi dia la felicità… Gli esseri liberi non possono essere costretti o plasmati a modo nostro ma sceglieranno sicuramente ciò che amano, anche se pensano che l’amore venga da cose sbagliate. È l’amore che cerchiamo e che ci cerca disperatamente. Aiutare a scoprire cos’è l’amore vero, dare criteri per imparare a discernere, scommettendo sulla capacità al bene di ognuno. Ecco ciò che conta. Ecco allora che Gesù oggi è come se ci dicesse: guardate all’interiorità! Niente può scalfire un cuore libero: né ciò che mangiamo, né ciò che ascoltiamo, né ciò che subiamo. Puntiamo al cuore: è lì la chiave della libertà e della felicità.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-12';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Del brano di oggi, forse più del miracolo di Gesù colpisce l’atteggiamento di questa donna siro-fenicia, dunque pagana, non appartenente al popolo di Israele. In particolare, ci è di esempio la sua umiltà: prega Gesù con insistenza, non si scoraggia dopo il rifiuto, non si offende dopo le motivazioni del diniego e non parla mossa dall’orgoglio ferito. Chi di noi ci sarebbe riuscito? L’atteggiamento di questa donna sembra suggerirci che l’umiltà può tutto: non la superbia, non l’arroganza ma l’umiltà. Questa donna si fa umile perché ha chiaro che c’è qualcosa di più importante di sé stessa e del proprio orgoglio: il bene di sua figlia. Cosa conta più di noi stessi? Il bene, l’amore, la verità. Non potremo mai accogliere il molto che Dio ci vuol dare se non ci rendiamo umili. Non potremo mai amare sul serio se non diventiamo umili. Non potremo mai difendere e diffondere la verità se non ci facciamo umili. Più siamo pieni di noi, più saremo vuoti di Dio. Più siamo pieni di boria, meno lo saremo della grazia! Gesù per primo ha percorso la via dell’umiltà, spogliandosi della sua divinità pur di salvarci. Lui, nostro Signore, creatore e salvatore, si è lasciato sbeffeggiare e umiliare durante la passione. Quale esempio! E San Paolo dirà che proprio per questa sua umiltà, e il suo farsi obbediente fino alla morte, Dio Padre lo ha risuscitato. E così, in scia a Gesù, vediamo la Vergine Maria; umile, piccola, nascosta, eppure piena di ogni grazia. E come lei stessa cantò nel Magnifica: «il Signore ha guardato l’umiltà della sua serva, tutte le generazioni mi chiameranno beata». Cosa è che vince il mondo? A cosa Dio “non resiste”? Qual è il fondamento di ogni virtù? Qual è quella cosa senza la quale non vi è vera santità? Una parola sola: l’umiltà!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-13';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span>«Il bambino di qualche mese che vuole un oggetto luccicante può gridare per farselo dare. Può anche tendere la mano, lasciarla ricadere per la stanchezza, tenderla ancora, per ore. Sua madre finirà col notarlo e non potrà sopportarlo: gli darà l’oggetto. Una formica si arrampica su un piano verticale e liscio, fa qualche centimetro, e cade, si arrampica ancora, e cade, si arrampica ancora, e cade. Un bambino che l’osservi si divertirà dinanzi a questo spettacolo per dieci minuti, poi non potrà più sopportarlo; mette la formica su un filo di paglia e la solleva al di sopra del piano verticale. Così, stancando Dio con la nostra pazienza, lo costringiamo a trasformare il tempo in eternità. Una pazienza capace di stancare Dio procede da un’umiltà infinita. L’umiltà ci dà un potere su di Lui. Solo il nulla perfettamente vuoto può coniugarsi con l’essere perfettamente compatto. Solo mediante l’umiltà possiamo essere perfetti come il Padre nostro. Per questo occorre un cuore completamente stritolato. Una preghiera fatta di gesti, come quella della formica che sale e ricade, è ancora più umile di una preghiera espressa con parole o grida anche interiori o con un desiderio tacitamente diretto. Significa sapere che non si può nulla, e tuttavia esaurirsi in sforzi riconosciuti come inutili, nell’attesa umile del giorno in cui forse sarà notato dalla Potenza che non si osa implorare. Non c’è atteggiamento di maggiore umiltà dell’attesa muta e paziente» (Simon Weil). </span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-13';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Servitori sempre bisognosi. Potremmo riassumere così il Vangelo di oggi. Gesù designa il lavoro specifico dei discepoli: annunciare la sua presenza nel mondo e nei cuori, cioè il regno di Dio. Per i consacrati, le consacrate e i sacerdoti, la vita non è questione di cariche, di studi altisonanti o di attività pastorali (tutte cose buone, per carità) ma di testimonianza del regno e di minorità, cioè di umiltà che fa trasparire che il vero bene che portiamo è Dio. Non dimentichiamo che il Papa viene denominato anche con il titolo “servo dei servi”. Un buon esame di coscienza verte proprio sul modo di porci nei confronti degli altri: siamo servizievoli? Umili? Facciamo sentire accolte le persone che abbiamo accanto? Tendiamo a rapportarci agli altri “guardandoli dall’alto verso il basso”? O trattiamo tutti con egual stima? Non dimentichiamo ciò che ci ha ricordato il papa: l’unico caso in cui siamo autorizzati a guardare gli altri dall’alto verso il basso e quando ci accostiamo a loro per aiutarli a rialzarsi dalle loro cadute!</span></p>
<p>
 <span>Gesù poi chiama i discepoli ad annunciare facendosi anche bisognosi degli altri, andando senza nulla. Significa non sentirsi mai padrone, mantenersi in un consapevole stato di “bisogno” degli altri, rinunciando ai segni del potere che contraddicono apertamente il Vangelo. Senza dimenticare che il proprio lavoro è ricompensato prima da Dio e poi dalla carità dei fratelli. Pensate che i sacerdoti che ricevono l’otto per mille ricevano uno stipendio? No, ricevono la carità delle persone necessaria per vivere e svolgere il loro ministero, una carità utilissima ma che li chiama a vivere con responsabilità, a non dare scandalo. Perciò siamo esigenti con i nostri consacrati, con i sacerdoti, con i vescovi: chiediamogli tempo, chiediamogli spiegazioni della parola di Dio, chiediamogli il regno di Dio, aiutiamoli a custodire la loro testimonianza di vita. E, soprattutto, quest’oggi preghiamo perché vi siano vocazioni alla vita consacrata e al sacerdozio, sapendo che servono tanti portatori di Dio nel mondo che offrano la loro vita per questo.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-14';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <strong><span><em><span>Ci accompagni in questo cammino la preghiera composta da San Paolo VI per la I Giornata Mondiale delle Vocazioni, 11 aprile 1964:</span></em></span></strong></p>
<p>
 <em><span>«O Gesù, divino Pastore delle anime, che hai chiamato gli Apostoli per farne pescatori di uomini, attrai a te ancora anime ardenti e generose di giovani, per renderli tuoi seguaci e tuoi ministri; falli partecipi della tua sete di universale Redenzione, […] dischiudi loro gli orizzonti del mondo intero, […] affinché, rispondendo alla tua chiamata, prolunghino quaggiù la Tua missione, edifichino il Tuo Corpo mistico, che è la Chiesa, e siano “sale della terra”, “luce del mondo” (Mt 5,13)».</span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-14';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>La compassione di Gesù dovrebbe riguardare il nostro modo di rapportarci con gli altri, specie di coloro con i quali fatichiamo di più e che spesso sono vittime dei nostri giudizi avventati. Gesù ha uno sguardo di misericordia per la folla che si priva di mangiare pur di seguirlo e ascoltarlo. Certo, costoro non avevano ben capito chi fosse Gesù e la salvezza che lui portava era oltre la guarigione fisica, ma Gesù vede il loro bisogno e rende possibile l’impossibile. Invece noi, talvolta, ci rifiutiamo di fare anche il possibile, critichiamo, cerchiamo pretesti per battibeccare con chi non ci capisce. Quindi, mossi dalla gelosia o spinti dalla superbia, giudichiamo gli altri e, quando sbagliano, ci sentiamo ancora più in diritto di screditarli. Gesù ci insegna la compassione: saper vedere i bisogni degli altri prima ancora che li manifestino; saper ascoltare le necessità e le sofferenze di chi abbiamo accanto; saper esprimere il pensiero con dolcezza, venire incontro a chi non ci capisce, donando loro benedizione. Gesù oggi ci insegna la compassione profonda che rende possibile che una persona di buona educazione comprenda un’altra persona maleducata e cerchi di capire di cosa abbia bisogno senza giudicarla. Gesù si dona sempre, cerca di saziare il cuore della persona, non vede mai folla ma dentro la folla coglie il passaggio di ciascuno, dell’emorroissa che lo tocca, del cieco che grida, perché egli vede le persone. Quanti egoismi mettiamo in atto quando non riusciamo a vedere persone ma folle, quando non riusciamo ad andare nel profondo, quando etichettiamo e classifichiamo in base ai nostri principi e criteri. E poi, scendendo al piano della carità materiale, quanti conti in tasca ci facciamo per donare qualcosa in elemosina, per condividere un solo piatto di pasta (o meglio, per donare un pacco di pasta; perché condividerlo, accogliendo chi non ha da ricambiare, ci “costa” troppo!). Quante case vuote che non diventano casa per altri! Non si tratta di cose impossibili, ma cose possibilissime con un po’ di amore. Se fossimo veramente consapevoli che siamo di passaggio su questa terra, e che raccoglieremo ciò che avremo donato, saremmo meno attaccati ai sette pani e ai pochi pesci, ed impareremmo a condividere bellezza ovunque. Ed è proprio ciò che oggi vogliamo chiedere al Signore!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-15';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>«Oltre alla fame fisica l''uomo porta in sé ancora un''altra fame, una fame più fondamentale… Si tratta di fame di vita, di fame di eternità. Il segno della manna era l''annuncio dell''avvento di Cristo, che avrebbe soddisfatto la fame di eternità da parte dell''uomo diventando Lui stesso il "pane vivo" che "dà la vita al mondo". Ed ecco: coloro che l''ascoltano chiedono a Gesù di compiere ciò che veniva annunziato dal segno della manna, forse senza rendersi conto di quanto lontano andava quella loro richiesta: "Signore, dacci sempre questo pane"(Gv 6, 34). Quanto è eloquente questa richiesta! Quanto generoso e quanto sorprendente è il suo compimento. "Io sono il pane della vita; chi viene a me non avrà più fame e chi crede in me non avrà più sete . . . Perché la mia carne è vero cibo e il mio sangue vera bevanda. Chi mangia la mia carne e beve il mio sangue dimora in me e io in lui"(Gv 6, 35.55-56). "Chi mangia la mia carne e beve il mio sangue ha la vita eterna e io lo risusciterò nell''ultimo giorno"(Gv 6, 54)» (S. Giovanni Paolo II). </em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-15';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo di oggi ci propone le beatitudini nella prospettiva di san Luca. A quattro beatitudini seguono quattro ammonimenti formulati con l’espressione “guai a voi”. Con le sue parole Gesù ci conduce in profondità, aiutandoci a leggere le cose secondo verità, con una prospettiva di fede. <em>«Gesù dichiara beati i poveri, gli affamati, gli afflitti, i perseguitati… La ragione di questa paradossale beatitudine sta nel fatto che Dio è vicino a coloro che soffrono e interviene per liberarli dalle loro schiavitù; Gesù vede questo, vede già la beatitudine al di là della realtà negativa. E ugualmente il “guai a voi”, rivolto a quanti oggi se la passano bene [i ricchi, sazi, ridenti e acclamati dalla gente] serve a “svegliarli” dal pericoloso inganno dell’egoismo e aprirli alla logica dell’amore, finché sono in tempo per farlo» (papa Francesco).</em></span></p>
<p>
 <span>Queste parole paradossali ci fanno bene e ci aiutano a capire dove stia la vera felicità. Non nel benessere egoista, non nel potere e nella logica arrivista, non nella superbia tracotante né nella visibilità, ottenuta magari svendendo la verità e comportandosi secondo il mondo. No, la felicità, la beatitudine non è qui. Se la stiamo inseguendo su questo versante, ingannati dal mondo, stiamo correndo fuori strada!</span></p>
<p>
 <span>Gesù ci ricorda che la beatitudine è anzitutto dono suo, che ci raggiunge se siamo poveri, cioè non pieni di noi stessi. Dio può renderci felici e consolarci se lo cerchiamo, se lo invochiamo, consapevoli di non bastare a noi stessi. Sì, siamo pacificati nella misura in cui ci lasciamo aiutare dagli altri, in cui sappiamo metterci a servizio degli altri. Poveri, appunto. </span></p>
<p>
 <span>La beatitudine di Dio può toccarci se siamo affamati, non sazi. Se desideriamo il suo regno, se cerchiamo la giustizia, se non lasciamo che le cose e le logiche del mondo spengano quell’anelito di pienezza e di felicità che abbiamo dentro.</span></p>
<p>
 <span>La beatitudine di Dio può misteriosamente raggiungerci se siamo nel pianto. Se sappiamo piangere davanti alle miserie del mondo, se ci lasciamo raggiungere dalla sofferenza degli altri, se non abbiamo lasciato che il nostro cuore si anestetizzasse davanti alle ingiustizie, piangendo e lottando per essere quel segno di cambiamento che Dio ha sognato.</span></p>
<p>
 <span>La beatitudine di Dio, infine, può colmarci quando siamo perseguitati per il suo nome, a causa del Vangelo. Quando cerchiamo di essere cristiani autentici, che non vivono la vita come se fosse un eterno carnevale adattando la maschera più opportuna a seconda del contesto in cui ci si trova, seguiremo il loro Signore anche quando costa fatica e incomprensione. Sì, la sua consolazione ci raggiunge proprio lì, quando dirci e mostrarci credenti costa fatica, persecuzione, emarginazione. Proprio qui Gesù è con noi, ricordandoci: «Rallegratevi in quel giorno ed esultate perché, ecco, la vostra ricompensa è grande nel cielo».</span></p>
<p>
 <span>Che queste parole possano incidersi nel nostro cuore, perché possiamo sperimentare e testimoniare la felicità che non delude, quella di Dio che non delude mai!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-16';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>PREGHIERA</span></em></span></p>
<p>
 <span><em><span>Signore Gesù, che chiami beati coloro che sanno soffrire per la loro fede e sono fedeli alla tua volontà: donaci il coraggio di annunciare la tua Parola e di essere tuoi veri testimoni negli ambienti che frequentiamo.</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-16';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>I farisei chiedono un segno per mettere alla prova il Signore; chiedono cioè una manifestazione visibile, miracolosa e, per di più, senza disponibilità a credergli. Sembra quasi che per concedere a Gesù di credergli, egli si debba piegare alle loro richieste. Quante volte rischiamo di fare lo stesso? Quante volte ci arrabbiamo se le cose non vanno come avremmo voluto, continuando poi a “crocifiggerlo” con i nostri malumori e mormorazioni? Possiamo dire di pregare anzitutto per stare con il Signore? E perché desideriamo capire e fare la sua volontà? Gesù, davanti all’atteggiamento dei suoi interlocutori, sospirando profondamente disse: «a questa generazione non sarà dato nessun segno» cioè a tutti coloro che, in ogni tempo e luogo, la pensano e si comportano come questi farisei. Se ci sembra che Dio taccia, forse è perché abbiamo chiesto male o perché non è tempo o perché ciò che chiediamo non ci giova. Anziché scoraggiarci, perseveriamo; e chiediamo la grazia di saper riconoscere il Signore vivo, presente e operante in noi e accanto a noi, anche se in modo diverso da quello che avremmo voluto. </span></p>
<p>
 <span>Chiediamo al Signore la grazia dell’abbandono fiducioso in Lui; se chiediamo segni, l’importante è che il nostro cuore sia aperto e disponibile a vederli!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-17';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«L’importante non sono i miracoli; l’importante è la parola di Dio, è la fede. Perciò Gesù loda la gente che si avvicina a lui con fede. Infatti a quel papà che chiese la guarigione del figlio, disse: Tutto è possibile a colui che crede… Ognuno di noi può domandarsi: ma come seguo, io, Gesù? E come so, come posso sapere se seguo bene Gesù o se sono interessato? Da qui un consiglio: il consiglio della memoria… di “rinfrescare” la memoria. Cioè, noi possiamo domandarci: cosa ha fatto Gesù per me?, pensando soprattutto e concretamente alla nostra vita. Allora troveremo tante cose grandi che Gesù ci ha dato gratuitamente, perché ci ama: a ognuno di noi. Una volta che io vedo le cose che Gesù ha fatto per me, mi faccio la seconda domanda: e io, cosa devo fare per Gesù? E così, con queste due domande, forse riusciremo a purificarci di ogni maniera di fede interessata. Infatti, ha aggiunto il Papa, «quando vedo tutto quello che Gesù mi ha dato, la generosità del cuore va a: Sì, Signore, do tutto! E non farò più questi sbagli, questi peccati. Si potrà imboccare «la strada della conversione per amore: tu mi hai dato tanto amore, anche io ti do questo amore. Grazie a queste due domande, ognuno potrà fare un bel test di come noi seguiamo Gesù: interessati o no? E così saremo capaci di purificare la nostra fede da ogni interesse» (Papa Francesco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-17';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Mentre Gesù mette in guardia i suoi discepoli dalla pericolosa ipocrisia dei farisei, usando simbolicamente l’immagine del lievito, i discepoli fraintendono bloccati nella dimensione dei loro bisogni materiali (= altro che lievito, qui ci manca il pane!). Gesù dunque, parla delle cose del cielo, loro di quelle della terra; Gesù parla di una cosa profonda, i discepoli ne capiscono un’altra più superficiale ma per loro prioritaria. Anche a noi può capitare di fraintendere le priorità nella vita, dando un valore sbagliato alle cose, alle parole. Il rischio di pensare alle cose del cielo (le virtù, i valori, l’amore, il perdono, ecc…) come cose “di poco conto” rispetto alle cose materiali è sottile e pernicioso. Ad esempio, andiamo in ansia se non possiamo comprare il vestito di marca o il cellulare nuovo al figlio ma “dormiamo” sulle cattive amicizie che frequenta. Ci preoccupiamo di avere i soldi per cambiare l’auto o la cucina ma di cambiare una certa abitudine sbagliata, no. Passiamo il tempo a pulire sul pulito la casa ma se la nostra anima è lercia e sfigurata dal peccato non importa… Ci affanniamo a costruire strutture, edifici sacri ma non a edificare comunità significative e accoglienti. Il Signore, che ha cura di ogni dimensione della vita, ci chiama a non ridurci a delle bocche da sfamare, illusi che una volta che abbiamo soldi, potere e salute fisica si ha tutto; siamo nati per non morire mai e per vivere per sempre, uniti a Lui. Facciamo dunque attenzione a tutto ciò che mette in pericolo la nostra e l’altrui salvezza eterna, e chiediamoci seriamente: quali sono in questo momento le mie priorità? Che cosa è veramente importante per me?</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-18';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«L’allusione al lievito è il tentativo di Gesù di spiegare che ci sono delle mentalità che sono alla base dei nostri pensieri e delle nostre scelte e che ne rappresentano quindi il lievito nascosto. Questo tipo di mentalità ci trasforma molto spesso in ciò che ci allontana di più dal Vangelo, perché sono mentalità mondane che hanno quasi sempre come scopo l’affermazione di sé, l’amore per il potere, l’autoredenzione. I discepoli invece sono tutti assorbiti dalla preoccupazione di non avere da mangiare. Ecco allora Gesù che dice loro: “ma non vi ricordate che vi ho sfamato con la moltiplicazione dei pani?”, che è un po’ come dire: “non capite che dovete smettere di vivere preoccupati delle cose del mondo perché ho cura io di ciascuno di voi?”. Il compito dei discepoli dovrebbe essere un altro: “cercare il regno di Dio e la sua giustizia”, cioè andare al fondamento delle cose e non alla parte superficiale. Chi vive aggrappato a ciò che conta, non ha paura delle tempeste perché sa che non potranno fargli nulla. Un cristiano è tale quando ha trovato ciò che conta, non quando ha trovato un po’ più di pane per la sua dispensa» (don Luigi Epicoco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-18';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Nella guarigione del cieco possiamo vedere la parabola del cammino di conversione. Anzitutto si tratta di un cammino che dura tutta la vita: talvolta, all’inizio, ci può sembrare di “volare sulle ali”, o di essere già arrivati alla santità o quasi. Oppure, dopo aver corrisposto alla chiamata di vita religiosa, ci si può illudere di essere quasi già “perfetti” o che il più è fatto, e che “nel giro di poco si arriva”. In realtà, passo dopo passo, caduta dopo caduta e rialzata dopo rialzata, ci si rende conto che il cammino di perfezione, cioè di totale conformazione e unione con Cristo, è un cammino graduale, che si snoda nel tempo, e quello non era che l’inizio! Il Signore ci accompagna gradualmente a vedere e riconoscere le cose per come sono, nella loro verità. Solo gradualmente si scoprono (e con umiltà si possono accettare) le proprie infermità, i propri limiti, le difficoltà ad amare, a perdonare… Camminando (ovvero frequentando la Chiesa, meditando la Parola, pregando, confessandosi) si conosce il Signore e sé stessi; passo dopo passo si imparano a vedere gli altri per quello che sono, non degli “alberi” ma dei fratelli e delle sorelle da amare. Gradualmente si impara a non dare giudizi affrettati, riconoscendo dietro ogni volto una storia, con le sue piaghe, i suoi pregi e le sue fragilità. Noi a volte vorremmo tutto e subito, pretendendo di cambiarci e di cambiare gli altri “con uno schiocco di dita”. Chiediamo al Signore che ci aiuti a crescere e a far crescere chi ci sta accanto, tendendo alla perfezione senza pretendere la perfezione. Tendere al bene, al meglio, alla crescita ma con pazienza, con umiltà. Un passo dopo l’altro.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-19';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Ho sempre desiderato d''essere una santa, ma, ahimè, ho sempre constatato, quando mi sono confrontata con i Santi, che tra loro e me c''è la stessa differenza che esiste tra una montagna la cui vetta si perde nei cieli e il granello di sabbia, oscuro, calpestato dai piedi dei passanti. Invece di scoraggiarmi, mi sono detta: il Buon Dio non potrebbe ispirare desideri irrealizzabili; quindi, nonostante la mia piccolezza, posso aspirare alla santità. Farmi diversa da quello che sono, più grande, mi è impossibile: mi devo sopportare per quello che sono con tutte le mie imperfezioni; ma voglio cercare il modo di andare in Cielo per una piccola via tutta nuova. Vorrei trovare anch''io un ascensore per innalzarmi fina a Gesù, perché sono troppo piccola per salire la dura scala della perfezione. Allora ho cercato nei libri santi l''indicazione dell''ascensore, oggetto del mio desiderio; e ho letto queste parole uscite dalla bocca della Sapienza Eterna: ‘Se qualcuno è molto piccolo, venga a me’. Così sono arrivata a intuire che avevo trovato ciò che cercavo. E volendo sapere, o mio Dio, ciò che faresti al molto piccolo che rispondesse alla tua chiamata, ho continuato le mie ricerche ed ecco quello che ho trovato: ‘Come una madre accarezza il figlio, così io vi consolerò: vi porterò in braccio e vi cullerò sulle mie ginocchia!’ L''ascensore che mi deve innalzare fino al Cielo sono le tue braccia, o Gesù! Per questo non ho bisogno di crescere, anzi bisogna che io resti piccola, che lo diventi sempre più» (Santa Teresa di Gesù Bambino).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-19';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>La preoccupazione di Pietro al sentir Gesù parlare di passione è ben comprensibile: quando vuoi bene a qualcuno, il solo pensiero che debba soffrire ti fa star male. Quante volte l’amore ci ha portati a chiedere al Signore di togliere la sofferenza a quella persona cara e darla a noi! Inoltre, Pietro ha una sua idea sull’agire di Dio: non può permettere che il giusto soffra, figuriamoci se può soffrire il Messia (e, ancor più, Dio stesso nel suo farsi uomo!). Pietro dovrà lasciare che Gesù purifichi l’immagine distorta di un dio-amuleto. Solo Gesù ci svela il vero volto di Dio e solo passando attraverso la sua carne (e la croce) possiamo davvero conoscerlo. Gesù “deve” passare di lì, non perché è masochista o perché Dio Padre è un carnefice che gode al vedere il sangue di suo figlio ma perché Gesù, entrando in un mondo segnato dal peccato e dalla morte, “deve soffrire” per vincere il male. Se ci avesse amato solo se e quando eravamo amabili, che amore sarebbe stato? Se di fronte al rifiuto si fosse tirato indietro, se davanti al male avesse risposto allo stesso modo, come ci avrebbe salvato? Perciò, nell’ora della prova, Gesù testimonia la fedeltà di Dio e il suo amore per noi: tentato e provato, non pensa neanche un attimo a sé stesso ma solo a far la volontà del Padre; non pensa a “salvarsi la pelle” ma a salvare noi. Rifiutato e oltraggiato, continua ad amarci sin lì per liberarci dalla paura di Dio, facendoci riscoprire, nel suo volto sfigurato, l’amore infinito di Dio che non smette mai di amarci e cercarci. E attraversando con quest’amore, nella fedeltà al Padre, il valico della sofferenza e della morte, vince, liberandoci dalla paura più profonda: quella che la morte segni la “fine” della vita. Non solo: con essa vince un’altra paura originaria e profonda: la paura di Dio, che ci porta a pensare a un Dio avverso, che ci ama solo se siamo all’altezza. Fermiamoci in serena contemplazione davanti al Signore e al “dovere” di soffrire per amare sul serio. Cosa dice al mio cuore? C’è qualcosa che mi inquieta? C’è qualche paura che mi blocca? </span><span>E, infine, chiediamo al Signore nella preghiera che il suo amore muova il nostro cuore, perché possiamo donarci a nostra volta con sempre maggior generosità, anche quando amare l’altro comporta il dover soffrire.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-20';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Dicendo “beati quelli che sono nel pianto”, Gesù non intende dichiarare felice una condizione sfavorevole e gravosa della vita. La sofferenza non è un valore in sé stessa, ma una realtà che Gesù ci insegna a vivere con l’atteggiamento giusto. Ci sono, infatti modi giusti e modi sbagliati di vivere il dolore e la sofferenza. Un atteggiamento sbagliato è quello di vivere il dolore in maniera passiva, lasciandosi andare con inerzia e rassegnandosi. Anche la reazione della ribellione e del rifiuto non è un atteggiamento giusto. Gesù ci insegna a vivere il dolore accettando la realtà della vita con fiducia e speranza, mettendo l’amore di Dio e del prossimo anche nella sofferenza: é l’amore che trasforma ogni cosa» (Papa Francesco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-20';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo di oggi potrebbe sembrare complicato, una sorta di inno alla sofferenza. Niente di tutto ciò. Mediante queste parole, Gesù ci indica da che parte ci si salva, mettendoci in guardia. Troppo spesso pensiamo di salvarci da soli, cioè pensiamo di risolvere autonomamente i nostri problemi, estromettendo Dio, facendo a meno degli altri. Salvo poi scoprire l’inganno della solitudine proprio nei momenti di sofferenza e di prova. Altre volte pensiamo solo a salvaguardare noi stessi; passiamo la vita secondo “l’arte dell’arrangiarsi”, dove ciò che conta è cadere in piedi. Salvo poi scoprire l’inganno quando ci si ritrova a terra nei propri fallimenti, o perlomeno nell’ora di sorella morte. Gesù oggi ci ricorda che il cristiano è colui che si lascia salvare da Lui; che credere in Lui significa andargli dietro, lasciandoci indicare dal Signore come vivere e come amare. <em>«In pratica Gesù ci invita a fidarci e ad abbandonarci fiduciosamente a Lui. Quanta pace ci sarebbe nella nostra vita se riuscissimo davvero a farlo sempre. Invece ci piace fare tutto da soli e in alcuni momenti ci sembra di essere in grado anche di conquistare il mondo. Ma Gesù avverte: Che giova infatti all’uomo guadagnare il mondo intero, se poi perde la propria anima? E che cosa potrebbe mai dare un uomo in cambio della propria anima? Oggi il Vangelo ci invita a ridimensionarci, a smettere di vivere da soli le cose difficili e a illuderci di poter essere felici riempiendo la nostra vita delle cose di questo mondo, perché ciò che appaga il cuore dell’uomo è solo l’amore, e Dio è l’Amore più affidabile che esiste» (don Luigi Epicoco). </em></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-21';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Oggi celebriamo la festa della Cattedra di San Pietro e il Vangelo ci offre un momento decisivo nel rapporto tra Gesù, Pietro e la comunità: si tratta della professione di fede di Pietro e del ruolo che Gesù gli conferisce. Soffermiamoci su due punti. </span></p>
<p>
 <span>Primo: la risposta di Pietro. Pietro, stimolato dalla domanda di Gesù («voi chi dite che io sia»), professa la sua fede: «tu sei il Cristo, il Figlio del Dio vivente». Come a dire: tu sei colui che stiamo aspettando, tu sei colui che tutti aspettano, il solo capace di portare a pienezza la vita!  Da notare che la risposta di Pietro non è frutto «della carne e del sangue», cioè del suo sapere o dello studio ma è frutto dell’ispirazione di Dio. Questo ci ricorda che noi possiamo dare risposte umane a chi chiede conto della nostra fede, possiamo rispondere in base al nostro sapere ma le risposte decisive vengono dall’alto. Le intuizioni più felici sono quelle che sgorgano da Dio. Dire con convinzione che per me Gesù è il Signore, che Lui mi ha cambiato la vita, non è frutto di uno studio ma è qualcosa che mi supera: è opera dello Spirito Santo! Riuscire a parlare al cuore di qualcuno nel nome del Signore e recargli beneficio è opera dello Spirito Santo! Ricordarci che la fede non è una semplice educazione ma relazione viva con il Signore aiuta tutti a mettersi in una corretta postura di umiltà davanti a Dio. Tutto ciò ci invita a “drizzare le antenne dell’anima” desiderosi di cogliere le ispirazioni al bene, i suoi suggerimenti, gli impulsi della grazia. Dio opera, agisce, “suggerisce” le giuste risposte da dare alla vita. A noi volerle sentire, a noi saperle cogliere!</span></p>
<p>
 <span>Secondo: Gesù rivela a Pietro la sua identità e il suo ruolo. Con semplicità potremmo dire che Gesù rivela Pietro a se stesso! Se da una parte lo Spirito Santo ha aiutato Pietro a capire chi è Gesù, dall’altro lato è Gesù che aiuta Pietro a capire chi è. Come a dire: più entriamo in relazione con Cristo più cresciamo nell’intimità con Lui più conosciamo Lui e noi stessi. In Dio troviamo la risposta a quella domanda presente in ciascuno di noi: “io chi sono?”. È soltanto in Cristo che possiamo capire chi siamo, ciò per cui siamo nati e per cui vale la pena vivere. </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-22';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>«Avvicinandosi la festa della santissima Croce del mese di settembre, una notte frate Leone andò al luogo e all''ora fissata per dire il mattutino con santo Francesco. E dicendo da un lato del ponte, com'' egli era solito, “Signore apri le mie labbra”, e santo Francesco non rispondendo, frate Leone non tornò addietro, come santo Francesco gli aveva comandato, ma con buona e santa intenzione passò il ponte ed entrò silenziosamente nella sua cella, e non trovandolo, si pensò che Francesco fosse per la foresta in qualche luogo in orazione. Perciò egli esce fuori e al lume della luna va cercando pianamente per la selva: e finalmente egli udì la voce di santo Francesco e, appressandosi, lo vide stare ginocchio in orazione con la faccia e con le mani levate al cielo, e in fervore di spirito sì diceva: « Chi sei tu, o dolcissimo Iddio mio? Che sono io, vilissimo verme e disutile servo tuo?»</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-22';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo di oggi non avrebbe bisogno di grandi commenti. Servirebbe solo leggerlo, meditarlo, interiorizzarlo, pregando il Signore perché ci aiuti a viverlo, cioè a vivere del suo amore e secondo il suo amore!</span></p>
<p>
 <span>Se infatti riducessimo questo Vangelo a delle parole da leggere e poi praticare senza un cuore redento, senza un cuore aperto alla grazia, falliremmo. Le ridurremmo a sterile moralismo, a delle cose “da dover vivere” senza riuscire a viverle. Qui siamo al culmine del Vangelo, alla vetta della santità: amare tutti, persino il nemico. Essere persone benedicenti verso la realtà e verso ogni persona, anche nei confronti di coloro che ci maledicono; non rispondere al male con il male ma con il bene, senza piegarsi alle bassezze ricevute. Essere persone disponibili, non egoiste, capaci di dare e di prestare gratuitamente. E ancora: non essere persone giudicanti quanto piuttosto comprensive e giustificanti, misericordiose, capaci di mettere sempre una buona parola.</span></p>
<p>
 <span>Tutto ciò, per quanto difficile possa essere, ci attrae, lo sentiamo vero. In fondo lo desideriamo. Non siamo fatti per la banalità, per la bassezza del male; veniamo da Dio, siamo simili a Lui, siamo nati per amore e per amare. Ecco allora tre passi perché queste parole possano diventare vita. Il punto da cui partire è il desiderio. Desiderare questa vita, desiderare di crescere nell’amore, desiderare di diventare persone sante, capaci di quest’amore! Se i nostri desideri sono rivolti alle cose materiali o al raggiungimento di certi obiettivi, stiamo desiderando troppo poco. Dobbiamo desiderare il cielo, di vivere secondo il cielo, di diventare persone grandi nell’amore!</span></p>
<p>
 <span>E al desiderio segue la preghiera: chiedere al Signore che ci doni il suo amore, il suo Santo Spirito. E lasciare che queste parole si incidano nel cuore, rileggendole, meditandole, perché possano diventare sorgente nuova del nostro agire. </span></p>
<p>
 <span>Infine, il terzo passo lo potremmo chiamare “il santo esercizio”. Non si cresce in un colpo solo ma un passo dopo l’altro, con l’esercizio. Se si vuol crescere nell’amore c’è da esercitarsi. Forse fino a ieri alla prima parola negativa reagivo di pancia. Oggi proverò a tacere. Domani (si fa per dire…) forse riuscirò non solo a tacere ma a cercare di far riflettere la persona, tenendo il dialogo sul piano dei fatti e non delle offese. Forse fino a ieri ne avevo una per tutti, sentenziando senza ritegno la qualunque. Oggi proverò a chiedermi: “chissà perché quella persona fa così”. Forse domani (si fa sempre per dire…) riuscirò a chiederlo all’interessato, mosso da compassione nei suoi confronti. Forse ieri se qualcuno mancava una virgola nei miei confronti con me aveva chiuso. Oggi proverò, dopo aver “sbollentato” a tenere la porta del dialogo aperta. Magari domani (ormai abbiamo capito…) riuscirò a passarci sopra tranquillamente e a continuare a fare del bene a quella persona.</span></p>
<p>
 <span>Insomma, gli esempi si potrebbero moltiplicare. Alla fin fine ciò che conta è amare.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-23';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>PREGHIERA</em></span></span></p>
<p>
 <span><span><em>Signore, insegnami a non parlare come un bronzo risonante </em></span></span><em>o un cembalo squillante, ma con amore. </em><em>Rendimi capace di comprendere  </em><em>e dammi la fede che muove le montagne, ma con l’amore. </em><em>Insegnami quell’amore che è sempre paziente e sempre gentile; </em><em>mai geloso, presuntuoso, egoista o permaloso; </em><em>l’amore che prova gioia nella verità, </em><em>sempre pronto a perdonare, a credere, a sperare e a sopportare. </em><em>Infine, quando tutte le cose finite si dissolveranno e tutto sarà chiaro, </em><em>che io possa essere stato il debole </em><em>ma costante riflesso del tuo amore perfetto.</em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-23';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>La conclusione del Vangelo di oggi ci consegna una chiave importante per vincere i nostri combattimenti spirituali: la necessità della preghiera. Matteo riporta il medesimo detto di Gesù con un’aggiunta: il digiuno. Preghiera e digiuno. Ecco due armi fondamentali per vincere le seduzioni del maligno. Pregare, dunque relazionarsi con Dio, cercando di vivere uniti a Lui. E digiunare, astenendosi dal cibo e da ciò che ci lega. Con il digiuno si fa spazio a Dio, con la preghiera si riempie questo spazio di Dio. Siamo qui agli antipodi di quella tendenza volontarista che ci porta a pensare di poter vincere le nostre battaglie partendo dal nostro sforzo. Per carità, la buona volontà è fondamentale, ma il punto di partenza è la grazia. È Dio che dilata il cuore, che rafforza, che libera dall’attrazione del peccato, che stimola e rafforza la nostra volontà. È da Lui che bisogna partire e ripartire, senza scoraggiarsi mai. A volte, le reiterate cadute possono aiutarci a scoprire e a prendere consapevolezza di tutto ciò: che da soli non ce la facciamo. Che il Signore possa aiutarci a capire che è da Lui che si deve partire, che è Lui la fonte di ogni bene, della vita. Possa il Signore liberarci dalla sottile tentazione dell’autosufficienza, sapendo che nella vita spirituale più si avanza e più ci si scopre bisognosi, più si cresce e più ci si sente bisognosi di Lui!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-24';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>La via di Santa Teresina è stata fondata sulla fiducia e sull''amore. Ella dice: «Custodite con cura la vostra fiducia, è impossibile che Dio non ne tenga conto, perché Egli misura sempre i suoi doni secondo la nostra fiducia». Ella racconta la storia seguente: «Un re, partito per la caccia, stava inseguendo un coniglio bianco che i suoi cani stavano per raggiungere, quando il coniglietto, sentendosi perduto, ritornò rapidamente indietro e saltò nelle braccia del cacciatore. Costui, commosso da tanta fiducia, non volle più separarsi dal coniglio bianco, e non permise a nessuno di occuparsene, riservandosi perfino il compito di nutrirlo. Lo stesso farà con noi il Buon Dio se inseguiti dalla giustizia, rappresentata dai cani, cercheremo rifugio nelle braccia stesse del nostro Giudice...».</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-24';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Mentre Gesù parla del dono di sé agli altri, i discepoli discutono di chi sia il più grande tra gli altri. E Gesù cosa fa? Con pazienza spiega a loro e a noi che la vera gloria è un’altra: è quella del dono di sé! Mentre nel mondo il più grande è colui che si fa servire, per Dio il più grande è chi più sa servire. Mentre nel mondo è più grande chi domina e mette gli altri sotto, per Dio è più grande chi si mette sotto agli altri per sostenerli e farli diventare grandi. Quante volte la ricerca del primato e della vanagloria ci travolge il cuore? Quante volte ci si aggredisce verbalmente (e purtroppo, non solo) perché si bada solo ad aver ragione? In quante famiglie si coltivano rancori decennali e silenzi generazionali per “un fatto di principio”? Quante volte, anche nella Chiesa, si scambiano i ministeri per possessi e gli incarichi per primati? Spesso, in questi casi, dov’è il male oscuro? Nell’altro? No, nel nostro cuore, nel nostro “io ferito”, bramoso, avido, narcisista. Lasciamoci dunque interpellare dalla parola di oggi, focalizziamo l’immagine di Gesù che prende in mezzo un bambino, proponendolo come modello. Che il Santo Vangelo possa aiutarci a cambiare il cuore e dirigere i nostri passi sulla via dell’amore!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-25';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>«Con questo gesto Gesù vuole far capire ai suoi, destinati ad avere il primo posto nella comunità, che per essere primi bisogna essere ultimi, come un bambino, un piccolo, un povero, un escluso. Non va assolutamente fraintesa o banalizzata la radicalità proposta ed espressa da Gesù nel Vangelo secondo Marco… Purtroppo la radicalità di Gesù proposta spesso viene smentita nelle scelte che facciamo nelle nostre comunità cristiane: si sceglie il più visibile, quello che si impone da sé, il più munito intellettualmente, il più brillante e il più forte, qualche volta anche il prepotente e il narcisista. Vigiliamo seriamente e responsabilmente, con un discernimento più sapienziale, sulle scelte che facciamo nelle nostre Chiese, per essere più coerenti con il pensiero di Gesù ed essere più obbedienti alla Sua volontà. Il Vangelo di oggi aiuta soprattutto chi è Pastore o chi ha posti di responsabilità nella Chiesa a confrontarsi rigorosamente con la Parola e a lasciarsi convertire, cambiare il modo di pensare e di agire. La minaccia più radicale all’essere oggi Pastore o responsabile nella Chiesa è vivere il servizio come potere o egemonia e non come servo umile egli stesso. L’autorità che non sa stare accanto agli ultimi, che non sa condividere la loro condizione e non sa ascoltare, è una autorità narcisistica patologica che genera sempre più scarti e residui umani, anche purtroppo dentro la Chiesa. Con Francesco d’Assisi, però, possiamo rialzare il nostro sguardo alla speranza di una novità. “Mentre dormiva in una cella a Siena, una notte chiamò a sé i compagni che dormivano: ho invocato il Signore, spiegò loro, perché si degnasse di indicarmi quando sono suo servo e quando no; perché non vorrei essere altro che suo servo. E il Signore nella sua immensa benevolenza e degnazione mi ha risposto: Riconosciti mio servo quando pensi, dici e agisci santamente. Per questo vi ho chiamato fratelli, perché voglio arrossire davanti a voi se avrò mancato in queste tre cose” (FF 743)» (Vescovo Francesco Savino).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-25';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Nel testo di oggi potremmo dire che Gesù incoraggia i suoi discepoli a non spegnere il bene, anche in germe, che c’è negli altri. Il Signore ci chiama ad essere inclusivi e accoglienti, non esclusivi ed escludenti! Guardiamo al testo: i discepoli vedono un tale che stava compiendo un esorcismo nel nome di Gesù ma loro volevano impedirglielo perché non era del loro gruppo! Il bene compiuto passa in secondo piano rispetto all’appartenenza alla propria cerchia. Quando atteggiamenti faziosi, sospettosi, di chiusura di fronte alla diversità (dell’altro, di un carisma, di un movimento nella Chiesa) si fanno largo, è segno che si stanno chiudendo le porte del cuore allo Spirito! Quando il “bene secondo me” prende il sopravvento sul “bene in sé” si possono giungere ad ostacolare gli altri che, nella varietà dei doni e dei carismi, stanno seguendo il Signore e operando nel suo nome! Quando viene meno il senso di appartenenza a Cristo e alla Chiesa o lo si assolutizza in riferimento al gruppo o al movimento di cui si fa parte, il rischio è quello di chiudersi agli altri e non riuscire a vedere e valorizzare il bene che essi compiono. Riflettiamo seriamente sul nostro modo di guardare, di parlare, di scegliere e di agire. E chiediamoci: siamo costruttori di comunione? Concretamente, cosa facciamo per costruirla? </span></p>
<p>
 <span>Tra i tanti aspetti possibili, portiamo nel cuore un importante principio esistenziale ed educativo: esercitiamoci nel valorizzare il bene che c’è negli altri. Tante volte lamentiamo che le persone che abbiamo accanto non cambiano. La domanda è: <em>noi diamo loro modo e tempo di cambiare? </em>Ad esempio, una persona che vive con noi fa una cosa bella? Anziché dire <em>“era ora, oggi nevica!”</em>, oppure <em>“va beh, ma potevi fare meglio”</em>, diciamo un bel grazie o facciamo un bel complimento! Oppure una persona sbaglia a dire o a fare qualcosa: anziché stroncarla con improperi di ogni genere, cerchiamo di capire perché l’ha fatto; se c’è, mostriamo il lato positivo di ciò che ha detto e a quel punto, indichiamo ciò che può essere fatto o detto meglio e incoraggiamola! Valorizzare dunque il bene, per portarlo alla perfezione: ecco un grande principio dell’educazione! Un principio che Dio per primo usa con noi e che anche noi suoi figli siamo chiamati ad usare gli uni con gli altri.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-26';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>«La carità si rallegra nel veder crescere l’altro. Ecco perché soffre quando l’altro si trova nell’angoscia: solo, malato, senzatetto, disprezzato, nel bisogno… La carità è lo slancio del cuore che ci fa uscire da noi stessi e che genera il vincolo della condivisione e della comunione» (papa Francesco).</em></span></span></p>
<p>
 <em>«Il nostro compito di cristiani è testimoniare la gioia del Risorto  restando uniti, anche in mezzo a tante sofferenze. Dovremmo essere una presenza di amore e di speranza per tutti anche per i dubbiosi e gli incerti. Ma dove trovare le forze? Dove attingere il coraggio e la gioia di testimoniare? Mentre “la connessione digitale non basta per gettare ponti, non è in grado di unire l’umanità”, la connessione con Dio, invece, nella preghiera, libera il cuore da ogni pesantezza spirituale e morale e lo rende capace di comunicare con tutti al di là di ogni limite o difetto di connessione. L’ascolto della Parola di Dio ci guarisce e ci rende capaci di uscire da noi stessi per affrancarci non solo dal Covid ma anche da quel “virus mortifero dell’indifferenza, dell’autoreferenzialità che ci isola dagli altri e ci ripiega su noi stessi”. </em><em>Restare uniti e connessi significa dialogare, incontrarsi e trasmettersi, reciprocamente,  tutte quelle belle iniziative di carità  che, come singoli o come gruppi e comunità, stiamo già realizzando in uno spirito di servizio umile e generoso, consapevoli che può servire “con amore solo chi comprende che tutto, nel suo esistere, è dono e che la sua stessa vita acquista senso solo nel donarla» (don Alfonso Giorgio).</em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-26';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Per un cristiano amare significa anche non scandalizzare! Si tratta di evitare tutti quegli atteggiamenti e parole che non edificano e possono ostacolare gli altri nel loro cammino di fede. Il cristiano medio, anzi, mediocre e mondano, non pensa proprio al danno che i suoi comportamenti sbagliati possono recare. Quante persone ci rimproverano dicendo: “se essere cristiani significa essere così, preferisco non esserlo... Meglio io che faccio del bene e non vado in chiesa, che quelli che si battono il petto in chiesa e poi fuori, ne combinano di tutti i colori”. Se è vero che spesso ci si nasconde dietro queste parole per giustificare la propria pigrizia, e che ognuno risponderà personalmente della sua vita a Dio, è altresì vero che siamo responsabili gli uni degli altri, siamo custodi gli uni degli altri. Se da credente coltivo un modo di fare che non va, se uso parole vuote che possono scandalizzare e deludere l’altro, devo ravvedermi, ed essere disposto a cambiare. Non solo perché quella cosa in sé è sbagliata (e possibilmente offende Dio e mi fa cadere nel peccato) ma anche per amore dell’altro, per non scandalizzarlo. È brutto quando persone non credenti o poco praticanti, o semplicemente deboli, al guardarci arrivano a pensare: ma se lo fa lui, perché non posso farlo anche io? Che bello invece se le persone al vederci possono pensare: se ce la fa lui/lei a vivere così bene, perché non posso farlo anche io? </span><span>Più camminiamo con il Signore più si sensibilizza il cuore, più sapremo renderci conto di tanti piccoli atteggiamenti da limare per non ferire e scandalizzare: gesti di stizza, parole buttate lì, modi affrettati di agire. Più l’amore informerà il nostro cuore, più saremo attenti e desiderosi a non fare alcun male al nostro prossimo, anzi, lo edificheremo, lo custodiremo e lo aiuteremo nel suo cammino. </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-27';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Il Signore “rivolgendosi ai suoi dice: “State attenti a voi stessi!”; cioè state attenti a non scandalizzare”. Lo scandalo è brutto perché ferisce la vulnerabilità del popolo di Dio, ferisce la debolezza del popolo di Dio, e tante volte queste ferite si portano per tutta la vita. Di più: lo scandalo non solo ferisce ma è capace di uccidere: uccidere speranze, uccidere illusioni, uccidere famiglie, uccidere tanti cuori. Lo scandalo è un tema sul quale Gesù tornava spesso… Perché lui aveva cura di non scandalizzare… E a noi, a tutti dà questo avvertimento: “State attenti a voi stessi!”. Perché c’è lo scandalo del popolo di Dio, dei cristiani, quando un cristiano, dicendosi cristiano, vive come pagano. Del resto, quante volte nelle nostre parrocchie abbiamo sentito gente che dice: “No, io in Chiesa non vado perché quello o quella che sta tutto il giorno leccando le candele lì dentro, poi esce, sparla degli altri, semina la zizzania...”. E quanti cristiani allontanano la gente con il loro esempio, con la loro incoerenza: l’incoerenza dei cristiani è una delle armi più facili che ha il diavolo per indebolire il popolo di Dio e per allontanare il popolo di Dio dal Signore. È lo stile di dire una cosa e farne un’altra, insomma. Proprio quello che Gesù diceva al popolo sui dottori della legge: “Fate quello che loro dicono, ma non fate quello che fanno”. Ecco l’incoerenza. Domandiamoci oggi, ognuno di noi: come è la mia coerenza di vita? Nella mia vita c’è coerenza col Vangelo, coerenza col Signore? Domandiamoci se per la mia incoerenza sono motivo di scandalo per gli altri. E incoerente è anche il cristiano che dice: Io vado tutte le domeniche a messa, sono dell’azione cattolica o di questa associazione o dell’altra, ma pago in nero i miei dipendenti o faccio loro un contratto da settembre a giugno” — “E luglio e agosto?” — “Arrangiati caro!”. Proprio queste sono le incoerenze di tutti i giorni. Ma sono motivo di scandalo anche i cristiani imprenditori che non pagano il giusto e approfittano della gente per arricchirsi. Certo poi possiamo domandarci sullo scandalo dei pastori, perché nella Chiesa ci siamo anche noi pastori. Il profeta Geremia parlava dicendo “guai a voi!”, riferendosi proprio ai pastori che sfruttano la gente, sfruttano le pecore, per arricchirsi cercano il latte o la lana, così dice Geremia, per vestirsi e per la vanità, ma non curano la pecora. Poi c’è anche lo scandalo del pastore che incomincia, per esempio, ad allontanarsi dalla gente: il pastore lontano. Invece Gesù ci insegna che il pastore deve essere vicino e quando il pastore si allontana scandalizza: è un “signore”. Infatti Gesù ci dice che non si possono servire due signori, Dio e i soldi: quando il pastore è uno attaccato ai soldi, scandalizza». E «la gente si scandalizza vedendo il pastore attaccato ai soldi. Per questa ragione ogni pastore deve chiedersi: come è la mia amicizia con i soldi? C’è, inoltre, lo scandalo del pastore che cerca di andare su: la vanità lo porta ad arrampicarsi, invece di essere mite, umile, perché la mitezza e l’umiltà favoriscono la vicinanza al popolo. O anche lo scandalo del pastore che si sente “signore” e comanda tutti, orgoglioso, e non il pastore servitore del popolo di Dio. Si potrebbe continuare su queste cose…. ma questo, credo, per oggi sarà sufficiente per domandarci, ognuno di noi: scandalizzo come cristiano, come cristiana, come pastore? Scandalizzo? Ferisco la vulnerabilità del mio popolo? Invece di attrarre il popolo, di farlo uno, di farlo felice, di dare la pace, la consolazione, lo caccio via perché io mi sento un pastore “signore” o mi sento un cristiano più importante di te?... Oggi può essere una bella giornata per fare un esame di coscienza su questo: scandalizzo o no e come? E così possiamo rispondere al Signore e avvicinarci un po’ di più a lui» (Papa Francesco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-27';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>L’indissolubilità matrimoniale potrebbe sembrare qualcosa di vecchio, di superato, di fuori moda o se non altro di impossibile da vivere. Eppure sentiamo che queste parole sono la verità. Le parole di Gesù sono Spirito e vita; è lo Spirito Santo che le compie in noi, che ci dà modo di viverle, non la nostra semplice umanità. Parlare dell’amore in chiave eterna, indissolubile, significa parlare della verità dell’amore. L’amore vero, infatti, non è a tempo né a condizione: è per sempre ma solo la grazia di Cristo può darci modo di viverlo. Parlare di indissolubilità matrimoniale significa parlare della verità della relazione sponsale. Ogni autentica e profonda relazione è indissolubile. Pensiamo anche alle relazioni familiari: se tuo padre ti fa del male o tua sorella ti fa sclerare, puoi anche scappare a Honolulu e cambiare cognome, ma tuo padre e tua sorella saranno sempre tuo padre e tua sorella. Un amico autentico resta tale qualunque cosa accada. Gesù ci ricorda dunque che l''amore vero è per sempre!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-02-28';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>«I rapporti umani veri sono definitivi, altrimenti sono solo calcolo, commercio: sarò tuo amico, padre, sposo o fratello finché i conti mi tornano. Quando non te lo meriterai più, vattene per i fatti tuoi. C’è da chiedersi se le persone arrivino al sacramento del matrimonio con le dotazioni essenziali, che sono fondamentalmente due: che siano state redente ed introdotte alla vita nuova che sola può garantire l’amore senza limiti, e che abbiano constatato l’esistenza di questo tipo di relazione fra loro… I matrimoni falliscono troppo spesso. Ed è inevitabile perché molti sposi sono come persone che vanno a scalare l’Everest con le scarpe da ginnastica. Dieci incontri di corso prematrimoniale, combinati con una mezza specie di religiosità fra il sentimentale, il tradizionale e lo scenico da “chiesetta carina”, non sono l’attrezzatura sufficiente per scalare la montagna dell’amore incondizionato che sgorga dalla misericordia illimitata di Cristo – che il matrimonio celebra sacramentalmente… Abbiamo tutti bisogno – per essere sposi, preti, suore, padri, madri, amici o altro – di essere il bambino della seconda parte del brano, quello che Gesù abbraccia… Ossia: abbiamo bisogno di lasciarci amare incondizionatamente, perché Dio metta la sua eternità in noi il suo amore indissolubile nel nostro cuore» (don Fabio Rosini).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-02-28';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>A chi appartiene il regno di Dio? Secondo una logica mondana le cose di questo mondo appartengono ai potenti; ma qui Gesù sottolinea che le cose del cielo, il Regno di Dio appartiene ai poveri, ai deboli, agli afflitti, simboleggiati da quei bambini che in quel tempo non avevano nessun valore per la società. Il Regno di Dio non lo si conquista ma lo si eredità quando si vive da figli di Dio. Viene donato a chi ha compreso che da solo non si salva, che non è il salvatore del mondo; lo eredita chi ha fatto quell’atto di umiltà di ammettere che non basta a se stesso. Quante volte ci atteggiamo a persone forti, abbiamo difficoltà a mostrare le nostre debolezze per paura di essere giudicati, di non essere all’altezza di questo mondo che vive di competizioni, di successo, di dominio. Tempo addietro ho conosciuto una ragazza che con le lacrime agli occhi mi ha detto: <em>“basta, sono stanca di dover sempre apparire, non ce la faccio più!”.</em> In fondo è questo il punto finale: non riuscire a sostenere il peso di voler apparire altro da ciò che si è veramente. Oggi ci fa bene domandarci quali sono le maschere che indossiamo, le fragilità che nascondiamo. Ognuno di noi ha un bambino dentro che chiede di essere abbracciato, accarezzato, amato anche nel proprio peccato. Che il Signore ci faccia comprendere sempre più che è solo nell’ammettere le nostre fragilità, le nostre paure, il nostro peccato che possiamo iniziare un cammino di guarigione.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-01';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span>«Nella vita riconoscersi piccoli è un punto di partenza per diventare grandi. Se ci pensiamo, cresciamo non tanto in base ai successi e alle cose che abbiamo, ma soprattutto nei momenti di lotta e di fragilità. Lì, nel bisogno, maturiamo; lì apriamo il cuore a Dio, agli altri, al senso della vita. Quando ci sentiamo piccoli di fronte a un problema, piccoli di fronte a una croce, a una malattia, quando proviamo fatica e solitudine, non scoraggiamoci. Sta cadendo la maschera della superficialità e sta riemergendo la nostra radicale fragilità: è la nostra base comune, il nostro tesoro, perché con Dio le fragilità non sono ostacoli, ma opportunità. Una bella preghiera sarebbe questa: “Signore, guarda le mie fragilità…” ed elencarle davanti a Lui. Questo è un buon atteggiamento davanti a Dio. […] Lo sa bene chi prega con perseveranza: nei momenti bui o di solitudine, la tenerezza di Dio verso di noi si fa – per così dire – ancora più presente. Quando noi siamo piccoli, la tenerezza di Dio la sentiamo di più» (papa Francesco).  </span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-01';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo di questa domenica ci interroga su chi seguiamo, su come giudichiamo e su quali frutti stiamo portando nella vita. </span></p>
<p>
 <span>Gesù inizia ponendoci un interrogativo anche simpatico: «Può forse un cieco guidare un altro cieco?». A chi sono rivolte queste parole? A tutti noi che crediamo di vedere quando, invece, non riusciamo a vedere al di là del nostro naso! Si è ciechi quando non seguiamo Gesù ma tanti altri presunti santoni che ci indicano strade senza via d’uscita. Siamo ciechi quando la bussola che guida il nostro cammino non è la Parola di Dio, che è «lampada ai miei passi e luce sul mio cammino» (Sal 118,105), ma sono le parole vuote, quelle parole umane che non hanno il sapore di eternità. La domanda è: se siamo ciechi, come possiamo pretendere di guidare le persone che Dio ci ha affidato? Questo vale per tutti: vale per i consacrati, per gli educatori, per i genitori! </span></p>
<p>
 <span>L’altro aspetto è il nostro giudizio sugli altri facendoci forti della nostra ipocrisia. «Perché guardi la pagliuzza che è nell’occhio del tuo fratello e non ti accorgi della trave che è nel tuo occhio?». Tante volte, lo sappiamo bene, è più facile (o comodo) scorgere e condannare i difetti e i peccati altrui, senza riuscire a vedere i propri con altrettanta lucidità. Noi spesso nascondiamo i nostri difetti, anche a noi stessi; noi siamo spesso quegli ipocriti che amano farsi vedere perfettini, quando dentro siamo peggio di molti pubblici peccatori. Siamo capaci di compiere nel buio opere delle quali dovremmo avere una grande vergogna. <em>«Forti di questa ipocrisia è facile vedere i difetti altrui. La tentazione è quella di essere indulgenti con se stessi – manica larga con se stessi – e duri con gli altri. È sempre utile aiutare il prossimo con saggi consigli, ma mentre osserviamo e correggiamo i difetti del nostro prossimo, dobbiamo essere consapevoli anche noi di avere dei difetti. Dobbiamo esserne consapevoli e, prima di condannare gli altri, dobbiamo guardare noi stessi dentro» (papa Francesco). </em></span></p>
<p>
 <span>Il terzo aspetto che vogliamo cogliere da questo Vangelo è sui frutti che portiamo nella nostra vita, che ci rendono più o meno credibili agli occhi degli altri. Infatti «Non vi è albero buono che produca frutto cattivo, né vi è d’altronde albero cattivo che produca un frutto buono. Ogni albero si riconosce dal suo frutto». </span><em>«Il frutto sono le azioni, ma anche le parole. Anche dalle parole si conosce la qualità dell’albero. Infatti, chi è buono trae fuori dal suo cuore e dalla sua bocca il bene e chi è cattivo trae fuori il male, praticando l’esercizio più deleterio fra noi, che è la mormorazione, il chiacchiericcio, parlare male degli altri. Questo distrugge tutto ciò che ci sta intorno» (papa Francesco). </em></p>
<p>
 <span>Alla luce del Vangelo odierno riflettiamo sul nostro agire: io parlo male degli altri? Per me è più facile vedere i difetti altrui che i miei? Quali frutti vi sono nella mia vita? Chi e che cosa guida i miei passi perché io veda alla luce vera e possa guidare verso la vera vita quelli che Dio mi ha affidato, invece di condurli verso il baratro del nulla? Cerchiamo tutti di correggerci almeno un po’, perché tutti abbiamo bisogno di correzione per crescere e far crescere nel cammino della vita!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-02';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>PREGHIERA</span></em></span></p>
<p>
 <span><em><span>Signore, concedi al tuo servo un cuore docile, </span></em></span><span><em><span>perché sappia rendere giustizia al tuo popolo </span></em></span><em><span>e sappia distinguere il bene dal male; infatti chi può governare questo tuo popolo così numeroso senza il tuo aiuto? </span></em><em><span>(cf Sap 3,9)</span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-02';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo di quest’oggi ci mette in crisi; certo, se ci lasciamo interpellare... Noi, magari, siamo di quelli che frequentano la chiesa, ci accostiamo ai sacramenti, cerchiamo di fare del bene, osserviamo i comandamenti, ma se ci guardiamo interiormente cosa ci manca? (Naturalmente se pensiamo che ci manchi qualcosa!). I comandamenti che Gesù cita, e che questo ricco dice di osservare, sono quelli che riguardano il rapporto con il prossimo ma non il rapporto con Dio. Questo tale di certo non è una persona cattiva, come magari pensiamo di noi stessi, ma Dio quale posto occupa veramente nella sua vita e nella mia vita? In fondo è questa la domanda che il tale di questo Vangelo si sente dire e che oggi rivolge a me. Davvero Gesù viene prima di tutti i miei beni, delle mie ambizioni, di tutti i miei affetti, delle persone a me più care? Il tale di questo Vangelo alla proposta di Gesù di vendere tutto e di seguirlo «si fece scuro in volto e se ne andò rattristato; possedeva infatti molti beni». In fondo anche oggi, anzi, forse ancor di più, c’è tanta gente dal volto rabbuiato e triste perché le vicende della vita non vanno secondo i loro desideri. C’è gente che non è mai contenta di quello che ha e pensa e desidera quello che non ha. E noi, di che cosa ci lamentiamo? Quali sono le cose che non riusciamo ad accettare nella fede? Siamo spesso tristi? Con tanta umiltà chiediamoci quale posto occupa Dio nella nostra vita, e come risponderemmo se ci chiedesse di lasciare quella cosa che riteniamo la più importante nella (e per la) nostra vita.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-03';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span>«C’è una tristezza, che è una malattia dell’anima. Nasce nel cuore dell’uomo quando svanisce un desiderio o una speranza. Nel cuore dell’uomo nascono speranze che vengono a volte deluse. Tutti attraversiamo prove che generano in noi tristezza, perché la vita ci fa concepire sogni che poi vanno in frantumi. In questa situazione, qualcuno, dopo un tempo di turbamento, si affida alla speranza; ma altri si crogiolano nella malinconia, permettendo che essa incancrenisca il cuore… C’è qualcosa nel passato di tutti che dev’essere guarito. I padri del deserto descrivevano la tristezza come un verme del cuore, che erode e svuota chi l’ha ospitato… dobbiamo stare attenti a questa tristezza e pensare che Gesù ci porta la gioia della risurrezione. Per quanto la vita possa essere piena di contraddizioni, di desideri sconfitti, di sogni irrealizzati, di amicizie perdute, grazie alla risurrezione di Gesù possiamo credere che tutto sarà salvato. Gesù non è risorto solo per sé stesso, ma anche per noi, per riscattare tutte le felicità che nella nostra vita sono rimaste incompiute. La fede scaccia la paura, e la risurrezione di Cristo rimuove la tristezza come la pietra dal sepolcro. Ogni giorno del cristiano è un esercizio di risurrezione… Uno scrittore francese, León Bloy, ci ha lasciato questa stupenda frase: “Non c’è che una tristezza, […] quella di non essere santi”. Che lo Spirito di Gesù risorto ci aiuti a vincere la tristezza con la santità» (papa Francesco).</span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-03';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>«Ecco, noi abbiamo lasciato tutto e ti abbiamo seguito». La domanda sottintesa che Pietro pone a Gesù è: cosa ce ne viene dal seguirti? Quale ricompensa ne avremo? In fondo, questa è una domanda che ci appartiene. In ogni cosa che facciamo ci chiediamo sempre se vi è un utile, un beneficio, un guadagno. Nessuno di noi fa una cosa se c’è solo da perdere. Eppure con il Signore la logica del mondo è capovolta. Da ciò possiamo cogliere due piccoli aspetti. Il primo è che è bene alimentare in noi il desiderio di grandezza: non vi è uomo o donna che non miri alle cose alte e belle. Solo che il Signore ci mostra un’altra via per raggiungerla: quella della spoliazione, dell’essere ultimi, dal farsi bisognosi. Anche sant’Agostino così scriveva: <em>«poiché alto è il coronamento, prima pensa al fondamento. "Ma a quale fondamento?", domandi. Impara da lui ch''è mite ed umile di cuore. Scava in te il fondamento dell''umiltà e arriverai al coronamento della carità»</em>. Il secondo aspetto è che questo grande guadagno che avremo sono le persone che Dio ci dona! Ecco il guadagno: fratelli, sorelle, madri, figli… Il Signore ci tira fuori dalla solitudine, da una vita intrisa di egoismo e ci fa ricchi di relazioni e di persone con cui volerci bene!</span></p>
<p>
 <em>«Il maestro buono non ha come obiettivo inculcare la povertà in quell''uomo ricco e senza nome, ma riempire la sua vita di volti e di nomi. Seguire Cristo non è un discorso di sacrifici, ma di moltiplicazione: lasciare tutto ma per avere tutto. Infatti il Vangelo continua: Pietro allora prese a dirgli: Signore, ecco noi abbiamo lasciato tutto e ti abbiamo seguito, cosa avremo in cambio? Avrai in cambio cento volte tanto, avrai cento fratelli e un cuore moltiplicato. Non rinuncia, se non della zavorra che impedisce il volo, il Vangelo è addizione di vita» (p. Ermes Ronchi)</em></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-04';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>LA QUARESIMA.</span></em></span></p>
<p>
 <span><em><span>Nella liturgia si parla di Quadragesima, cioè di un tempo di quaranta giorni. La Quaresima richiama alla mente i quaranta giorni di digiuno vissuti dal Signore nel deserto prima di intraprendere la sua missione pubblica. Si legge nel Vangelo di Matteo: «Gesù fu condotto dallo Spirito nel deserto, per essere tentato dal diavolo. Dopo aver digiunato quaranta giorni e quaranta notti, alla fine ebbe fame».</span></em></span></p>
<p>
 <em><span>I segni: digiuno, elemosina, preghiera</span></em></p>
<p>
 <span><em><span>Il digiuno, l’elemosina e la preghiera sono i segni, o meglio le pratiche, della Quaresima. </span></em></span></p>
<p>
 <span><em><span>Il digiuno significa l’astinenza dal cibo, ma comprende altre forme di privazione per una vita più sobria.</span></em></span></p>
<p>
 <span><em><span>Il digiuno è legato poi all’elemosina. San Leone Magno, in uno dei suoi discorsi sulla Quaresima, insegnava: «Quanto ciascun cristiano è tenuto a fare in ogni tempo, deve ora praticarlo con maggiore sollecitudine e devozione, perché si adempia la norma apostolica del digiuno quaresimale consistente nell''astinenza non solo dai cibi, ma anche e soprattutto dai peccati. A questi doverosi e santi digiuni, poi, nessuna opera si può associare più utilmente dell’elemosina, la quale sotto il nome unico di “misericordia” abbraccia molte opere buone». Così il digiuno è reso santo dalle virtù che l’accompagnano, soprattutto dalla carità, da ogni gesto di generosità che dona ai poveri e ai bisognosi il frutto di una privazione. </span></em></span></p>
<p>
 <em><span>La Quaresima, inoltre, è un tempo privilegiato per la preghiera. Sant’Agostino dice che il digiuno e l’elemosina sono «le due ali della preghiera» che le permettono di prendere più facilmente il suo slancio e di giungere sino a Dio. E san Giovanni Crisostomo esorta: «Abbellisci la tua casa di modestia e umiltà con la pratica della preghiera. Così prepari per il Signore una degna dimora, così lo accogli in splendida reggia».</span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-04';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Eccoci ad un altro mercoledì delle ceneri. Un altro rito dell’imposizione delle ceneri sul capo. Tanta gente viene in chiesa, anche quelli che non vengono quasi mai. È bello questo rito, anche se a volte sa un pochino di superstizione. Chissà se ascoltiamo bene le parole che il sacerdote ci rivolge mentre impone le ceneri sul nostro capo: <em>“convertiti e credi al vangelo”</em> oppure <em>“ricordati, uomo, che povere sei e polvere ritornerai”</em>. Davanti a quest’invito a cambiare vita, pensando anche all’ultimo istante della nostra vita quando lasceremo questo nostro corpo terreno, quale è la nostra risposta? Noi siamo spesso tra quelli che preferiscono non pensare mai alla morte, che non pensano alla conseguenza delle proprie azioni, o che comunque ritengono che ci sia sempre tempo per cambiare vita. Spesso non pensiamo che non abbiamo che l’oggi per cambiare in meglio. Non abbiamo che l’oggi anche per chiedere perdono a Dio, ai fratelli, alle sorelle per le nostre mancanze, dato che <em>«il Signore ci ha promesso la sua misericordia ma non ci ha promesso il domani» (s. Agostino).</em>  Ogni inizio di conversione parte da una contrizione per le colpe commesse, per le omissioni di bene, dall’essersi resi conto che di non essere Dio e che da soli non ci si dà la salvezza. Per questo, oltre alle opere di penitenza che il Vangelo di oggi ci invita a compiere <em>(preghiera, elemosina e digiuno)</em>, il Signore ci chiede un cuore contrito e umiliato. Chiediamogli, dunque, la grazia della conversione, della povertà di spirito; chiediamogli un cuore nuovo perché questa Quaresima sia davvero l’inizio di una vita nuova.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-05';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span>«La Quaresima ci immerge in un bagno di purificazione e di spoliazione: vuole aiutarci a togliere ogni trucco, tutto ciò di cui ci rivestiamo per apparire adeguati, migliori di come siamo. Entrare nel segreto significa ritornare al cuore. Si tratta di un viaggio dall’esterno all’interno, perché tutto ciò che viviamo, anche la nostra relazione con Dio, non si riduca ad esteriorità, a una cornice senza quadro. Ritornare al cuore significa ritornare al nostro vero io e presentarlo così com’è, nudo e spoglio, davanti a Dio. Significa guardarci dentro e prendere coscienza di chi siamo davvero, togliendoci le maschere che spesso indossiamo, abbracciando la vita e la verità di noi stessi. La vita non è una recita, e la Quaresima ci invita a scendere dal palcoscenico della finzione, per tornare al cuore, alla verità di ciò che siamo. Per questo, con spirito di preghiera e di umiltà, riceviamo sul capo la cenere. È un gesto che vuole riportarci alla realtà di noi stessi: noi siamo polvere, la nostra vita è come un soffio, ma il Signore – lui e soltanto lui – non permette che essa svanisca; egli raccoglie e plasma la polvere che siamo, perché non venga dispersa dai venti impetuosi della vita e non si dissolva nell’abisso della morte» (papa Francesco).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-05';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Abbiamo davvero deciso di seguire Gesù? Bene; allora prendiamo tre aspetti che il Vangelo di oggi per capire cosa significhi seguirlo. </span></p>
<p>
 <u>Rinnegare.</u><span> Innanzitutto rinnegare noi stessi. Questo non significa avercela con sé ma vivere liberi da sé stessi, non assolutizzare il proprio modo di pensare. Per far questo occorre una conversione profonda: rinnovare il cuore e la mente. Rinnegare sé stessi vuol dire anche imparare a dirci dei no. Ad esempio, è il momento della preghiera? Non ho voglia, ma dico di no e vado a pregare; oppure sono in mezzo a persone o situazioni di maldicenza e dico di no; vedo una persona bisognosa, istintivamente vorrei andare oltre, ma mi fermo; ecco, mi sono detto un no. Tutto ciò è rinunciare a ciò che ci impedisce di vivere, a quella malattia che si chiama egoismo! </span></p>
<p>
 <span><u>Prendere la propria croce.</u> La croce non è qualcosa che ci manda il Signore dall’alto, ma dice la nostra missione con le sue gioie, con le sue difficolta, con le sue fatiche, insomma tutto ciò che fa parte della vita. Non si può vivere da slalomisti cercando di evitare ogni difficoltà, come certi genitori cercano di fare con i loro figli! Ecco, la croce è adempimento del quotidiano. Noi siamo chiamati ad amare e per fare questo occorre che crocifiggiamo il nostro egoismo. </span></p>
<p>
 <span><u>Salvare la vera vita.</u> Questa è la strada per ritrovare la nostra vita, per vivere la vita felice dell’amore. Se la vita la si dona la si trova. Qui non si parla di una vita bella da perdere ma perdere la propria vita brutta per avere la vita bella, per vivere la vita di Dio!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-06';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>VIETATO LAMENTARSI</span></em></span></p>
<p>
 <span><em><span>Legge n° 1 sulla tutela della salute e del benessere. </span><span>I trasgressori sono soggetti ad una sindrome da vittimismo con conseguente abbassamento del tono dell''umore e della capacità di risolvere i problemi. </span><span>La misura della sanzione è raddoppiata qualora la violazione sia commessa in presenza di bambini. </span><span>Per diventare il meglio di sé bisogna concentrarsi sulle proprie potenzialità e non sui propri limiti quindi: smettila di lamentarti e agisci per cambiare in meglio la tua vita.</span></em></span></p>
<p>
 <span><em><span>Il cartello è realizzato dallo psicologo e psicoterapeuta italiano Salvo Noè, che lo ha donato a Papa Francesco al termine dell''Udienza generale di mercoledì 14 giugno 2017.</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-06';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>«Perché noi e i farisei digiuniamo e i tuoi discepoli no?». Ecco la domanda che i discepoli di Giovanni rivolgono a Gesù. Magari pensavano che il loro stile di vita fosse più austero, ma non riuscivano a cogliere il motivo del digiuno. Digiunavano perché lo si era sempre fatto ma non riuscivano a cogliere la cosa più importante: il motivo del digiuno, in quel momento si era realizzato: Gesù, il Messia, era venuto in mezzo a loro! Digiunavano i farisei legati al passato e alle tradizioni, digiunavano i discepoli del Battista nell’attesa della venuta del Messia, senza comprendere che il Messia era venuto ed era in mezzo a loro, ma in modo nuovo, non come se l’aspettavano. È un Gesù diverso dalla loro attese, un Gesù che mangia con i pubblicani e i peccatori, che si rivolge ai pagani, che cerca gli ultimi. Come? Facendosi uno di loro, camminando con loro, entrando nelle loro vite fatte di miseria e di peccato. I discepoli di Gesù non digiunano perché Gesù, lo sposo dell’umanità, è in mezzo a loro. In un matrimonio non si digiuna, anzi, si fa festa, ed è quello che vivono i discepoli di Gesù. Quel momento è il momento della festa, è “l’ora” da vivere in pienezza, senza essere legati ad un passato e senza essere proiettati in un futuro lontano. Davanti a ciò ci domandiamo: sappiamo vivere il presente senza essere di quelli che recriminano per le cose passate? O che sono sempre in ansia per le cose future?</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-07';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>Finalmente sarò felice. Questa è la storia di un uomo che quando era ragazzo e andava a scuola continuava a dire: «Ah! quando lascerò la scuola e comincerò a lavorare, allora sarò felice». Lasciò la scuola, cominciò a lavorare e diceva: «Ah! quando mi sposerò, sarà la felicità!». Si sposò, e in capo a pochi mesi constatò che la sua vita mancava di varietà, e allora disse: «Ah, come sarà bello quando avremo dei bambini!». Vennero i bambini, ed era un''esperienza affascinante, ma piangevano tanto, anche alle due di notte, e il giovane sospirava: «Crescano in fretta!». E i figli crebbero, non piangevano più alle due di notte, ma facevano una stupidaggine dopo l''altra e cominciarono i veri problemi. E allora l''uomo sognò il momento in cui sarebbe stato di nuovo solo con sua moglie: «Staremo così tranquilli!». Adesso è vecchio, e ricorda con nostalgia il passato: «Era così bello!» (https://www.qumran2.net/ritagli/?&pag=5)</em></span></span></p>
<p>
 <em>Un tizio domandò al mio amico Jaime Cohen: «Secondo te, qual è la cosa più divertente degli esseri umani?»</em></p>
<p>
 <span><span><em>Cohen rispose: «Il fatto che siano sempre contraddittori: hanno fretta di crescere e poi sospirano per l''infanzia perduta. Sacrificano la salute per ottenere il denaro, e poi spendono i soldi per avere la salute. Pensano in modo talmente impaziente al futuro che trascurano il presente e così non si godono né il presente né il futuro. Vivono come se non dovessero morire mai, e muoiono come se non avessero mai vissuto.</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-07';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo di oggi dà grande speranza a ogni persona che ha perso la fiducia in una vita nuova. Sono tutte quelle persone che hanno sperimentato il fallimento, il peccato, il tradimento subito o perpetrato, che scoraggiati si sono seduti nella loro tristezza, incapaci di alzarsi per riprendere il cammino della loro vita. Ma una voce risuona anche per loro: «alzati e seguimi». È quella voce che ha udito Matteo il pubblicano, esattore delle tasse, amico dei romani, magari avvezzo a praticare l’usura, uno condannato dallo sguardo e dal giudizio degli altri. Gesù ci dice che c’è salvezza per ogni uomo, c’è riscatto da una vita mediocre. Matteo si sente subito guardato e amato: lo sguardo di Gesù su di lui non è di condanna, ma di amore. È lo sguardo del Signore che scommette sulla vita di Matteo e sulla nostra vita: siamo chiamati a fare cose grandi, siamo stati creati per fare cose grandi! Domandiamoci quali sono le cose che ci affliggono, quali sono le vicende della vita che hanno ucciso le nostre speranze, che ci hanno schiacciato a tal punto da non riuscire più ad alzarci. Coraggio dunque, in questo momento il Signore ti chiama a vita nuova e ti dice: «Perché ancora ti affliggi? Alzati e seguimi!».</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-08';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>Il contadino e il poeta. </span></em></span></p>
<p>
 <span><em><span>Un contadino stanco della solita routine quotidiana, tra campi e duro lavoro, decise di vendere la sua tenuta. Dovendo scrivere il cartello per la vendita decise di chiedere aiuto al suo vicino che possedeva delle doti poetiche innate. </span></em></span><em><span>Il romantico vicino accettò volentieri e scrisse per lui un cartello che diceva: "Vendo un pezzettino di cielo, adornato da bellissimi fiori e verdi alberi, con un fiume, dall''acqua così pura e dal colore più cristallino che abbiate mai visto." </span></em><em><span>Fatto ciò, il poeta dovette assentarsi per un po'' di tempo, al suo rientro però, decise di andare a conoscere il suo nuovo vicino. </span></em><span><em><span>La sua sorpresa fu immensa nel vedere il solito contadino, impegnato nei suoi lavori agricoli. </span></em></span><span><em><span>Il poeta domandò quindi: "Amico non sei andato via dalla tenuta?" </span></em></span><em><span>Il contadino rispose sorridendo: "No, mio caro vicino, dopo aver letto il cartello che avevi scritto, ho capito che possedevo il pezzo più bello della terra e che non ne avrei trovato un altro migliore."</span></em></p>
<p>
 <em><span>Non aspettare che arrivi un poeta per farti un cartello che ti dica quanto è meravigliosa la tua vita, la tua casa, la tua famiglia e tutto ciò che possiedi... Ringrazia sempre Dio per la salute che hai, la vita che vivi, per la caparbietà che hai nel lottare per andare avanti. Che il Signore benedica questo pezzettino di cielo che è la tua vita. </span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-08';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Oggi, in questa prima domenica di Quaresima, il Vangelo invita tutti noi a vivere un tempo di deserto. Sant’Agostino lo ricorda a tutti noi con forza, quasi supplicandoci: <em>«Rientrate nel vostro cuore! Dove volete andare lontano da voi? Rientrate dal vostro vagabondaggio che vi ha portato fuori strada; ritornate al Signore. Egli è pronto… Rientra nel cuore: lì esamina quel che forse percepisci di Dio, perché lì si trova l’immagine di Dio; nell’interiorità dell’uomo abita Cristo».</em> Il cuore è la nostra parte più profonda, dove ciascuno vive il suo essere persona, in relazione a Dio, agli altri uomini e alla creazione intera. Spesso usiamo dire “Andiamo al cuore del problema”, come a dire: andiamo all’origine, a quell’essenziale da cui dipende la spiegazione di tutte le altre parti del problema. <em>«È sul cuore che avviene il giudizio di ogni persona, su ciò che porta dentro di sé e che è la fonte della sua bontà o della sua cattiveria, per cui si conosce quella persona per quello che veramente essa è e vale» (R. Cantalamessa).</em></span></p>
<p>
 <span>I vangeli ci parlano di tre tentazioni: «Se sei Figlio di Dio, di’ che questi sassi diventino pane»; «Se sei Figlio di Dio, gettati giù»; «Tutte queste cose io ti darò, se, prostrandoti, mi adorerai». Esse han¬no uno scopo unico e comune e sono rivolte a tutti noi: distoglierci dalla missione che Dio ci ha affidato, farci dimenticare la meta finale! Noi siamo chiamati a non aver paura del demonio e delle sue tentazioni, perché la cosa più importante non è che il demonio esista, ma che Cristo ha vinto il demonio. </span><em>«Con Cristo non abbiamo nulla da temere. Niente e nessuno può farci del male, se noi stessi non lo vogliamo. Satana, diceva un antico padre della Chiesa, dopo la venuta di Cristo, è come un cane legato sull’aia: può latrare e avventarsi quanto vuole; ma, se non siamo noi ad andargli vicino, non può mordere. Gesù nel deserto si è liberato da satana per liberarci da satana!» (R. Cantalamessa)</em><span>. </span></p>
<p>
 <span>Inoltre, non diamo sempre la colpa al diavolo per il male che c’è in noi e attorno a noi, perché spesso “siamo diavoli a noi stessi!”. Chi è che ci porta a tagliare i ponti con le persone che amiamo per delle futilità o per i beni di questo mondo? Chi è che ci conduce a odiare, a non perdonare, a parlare male degli altri, a non farci aprire all’amore e alla solidarietà? Non vi è in tutto ciò una chiusura del nostro cuore che impedisce alla grazia di Dio di operare nella nostra vita? </span></p>
<p>
 <span>In conclusione, è bene ricordare che il fine di farci condurre dallo Spirito Santo nel deserto non è solo lasciare qualcosa (il chiasso, il mondo, le occupazioni) per farci tentare! No, si va nel deserto per incontrare Gesù, perché Egli guarisca il nostro cuore! </span><em>«Andare nel deserto è ritrovare il contatto con Dio e la sua verità. Questo è il segreto della felicità. Cosa desidera di più un innamorato se non stare da solo, in intimità, con la persona amata? Dio è innamorato di noi e desidera che noi ci innamoriamo di lui. Parlando del suo popolo come di una sposa, Dio dice: “La condurrò nel deserto e parlerò al suo cuore” (Os 2, 16). Si sa qual è l’effetto dell’innamoramento: tutte le cose e tutte le altre persone arretrano, si collocano come sullo sfondo. C’è una presenza che riempie tutto e rende tutto il resto “secondario”. Non isola dagli altri, che anzi rende ancora più attenti e disponibili verso gli altri, ma come di riflesso, per ridondanza di amore. Gesù ci aspetta nel deserto: non lasciamolo solo in tutto questo tempo» (R. Cantalamessa).</em></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-09';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>PREGHIERA</span></em></span></p>
<p>
 <em><span>O Dio, tu che conosci la mia fragilità, ferita dal peccato, </span></em><em><span>concedimi di intraprendere con la forza della tua Parola </span></em><em><span>il cammino quaresimale, per vincere le seduzioni del maligno </span></em><em><span>e giungere alla Pasqua nella gioia dello Spirito. Amen </span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-09';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo di oggi ci mostra il metro di giudizio che il Signore adopererà nell’ultimo giorno: la carità. Ogni uomo e ogni donna, credente o no, ha la possibilità di poter scegliere come comportarsi davanti ai bisogni dei più poveri, degli indigenti, degli ultimi. Qui non si tratta di studiare, di conoscere, di essere brillanti; qui si tratta di amare. A tutti noi, poveri peccatori, il Signore dà una grande opportunità: operare quella carità che copre una moltitudine di peccati! Che grande occasione abbiamo! E poi, parliamoci chiaro: mica operiamo la carità di Cristo! Infatti, come ci ricorda san Gregorio Magno,<em> «Quando doniamo ai poveri le cose indispensabili non facciamo loro delle elargizioni personali, ma rendiamo loro ciò che è loro. Più che compiere un atto di carità, adempiamo un dovere di giustizia»</em>. Domandiamoci se e quante volte abbiamo sprecato l’opportunità di fare del bene, cercando di comprendere sempre più che non saremo giudicati solo sui peccati commessi ma soprattutto sul bene che avremmo potuto compiere e non abbiamo compiuto!  Forse, è anche bene non cullarci troppo, pensando di non avere molte opportunità anche economiche perché: <em>«sulla bilancia della giustizia divina non si pesa la quantità dei doni, bensì il peso dei cuori. La vedova del Vangelo depositò nel tesoro del tempio due spiccioli e superò i doni di tutti i ricchi. Nessun gesto di bontà è privo di senso davanti a Dio, nessuna misericordia resta senza frutto» (s. Leone Magno).</em> </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-10';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>«Signore, quando ho fame, dammi qualcuno che ha bisogno di cibo, quando ho un dispiacere, offrimi qualcuno da consolare; quando la mia croce diventa pesante, fammi condividere la croce di un altro; quando non ho tempo, dammi qualcuno che io possa aiutare per qualche momento; quando sono umiliato, fa che io abbia qualcuno da lodare; quando sono scoraggiato, mandami qualcuno da incoraggiare; quando ho bisogno della comprensione degli altri, dammi qualcuno che ha bisogno della mia; quando ho bisogno che ci si occupi di me, mandami qualcuno di cui occuparmi; quando penso solo a me stesso, attira la mia attenzione su un’altra persona. Rendici degni, Signore, di servire i nostri fratelli Che in tutto il mondo vivono e muoiono poveri ed affamati. Dà loro oggi, usando le nostre mani, il loro pane quotidiano, e dà loro, per mezzo del nostro amore comprensivo, pace e gioia» (Madre Teresa di Calcutta). </em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-10';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Ai discepoli che chiedono a Gesù di insegnare loro a pregare, Egli risponde così: «Pregando, non sprecate parole come i pagani: essi credono di venire ascoltati a forza di parole». Ecco, prima di iniziare a pregare sarebbe cosa buona chiedere al Signore la capacità di ascoltare la sua voce, perché non sempre quello che chiediamo è un bene per noi. La speranza che noi abbiamo quando chiediamo delle cose, deve anche lasciarsi deludere. <em>«Dobbiamo – come suggerisce un poeta  diventare complici della speranza. Hai sperato ardentemente una cosa, un intervento di Dio, e non è successo niente? Sei tornato a sperare di nuovo la volta successiva, e ancora niente? Tutto è andato avanti come prima, nonostante tante suppliche, tante lacrime, e forse anche tanti segni che questa volta saresti stato esaudito? Tu continua a sperare, spera ancora un’altra volta, spera sempre, fino alla fine. Diventa complice della speranza! Diventare complici della speranza significa permettere a Dio di deluderti, quaggiù tutte le volte che vuole. Di più: significa essere in fondo contenti, in qualche parte remota del proprio cuore, che Dio non ti abbia ascoltato la prima e la seconda volta e che continui a non ascoltarti, perché così ti ha permesso di dargli una prova in più, di fare un atto di speranza in più e ogni volta più difficile. Ti ha fatto una grazia ben più grande di quella che chiedevi: la grazia di sperare in lui. Lui ha l’eternità per farsi perdonare del ritardo! Ma bisogna fare attenzione a una cosa. La speranza non è solo una bella e poetica disposizione interiore, difficile quanto si vuole, ma che lascia, per il resto, inoperosi e senza compiti concreti, e perciò, alla fine, sterile. Al contrario, sperare significa proprio scoprire che c’è ancora qualcosa che si può fare, un compito da assolvere e che non si è, perciò, lasciati in balìa del vuoto e di una paralizzante inattività.  Quand’anche non ci fosse nulla più da fare da parte nostra per cambiare una certa situazione difficile, resterebbe pur sempre un grande compito da assolvere, tale da tenerci abbastanza impegnati e tenere lontana la disperazione: quello di sopportare con pazienza fino alla fine» (Raniero Cantalamessa)</em>. Compreso ciò, anche noi ora possiamo dire: “Padre, sia fatta la tua volontà qualunque essa sia!”</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-11';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>Preghiera: Padre mi abbandono a te. </em></span></span></p>
<p>
 <span><span><em>«Padre, mi abbandono a Te, fa'' di me ciò che ti piace. Qualsiasi cosa tu faccia di me, ti ringrazio. Sono pronto a tutto, accetto tutto, pur ché la tua volontà si compia in me, e in tutte le tue creature: non desidero nient''altro, mio Dio. Rimetto l''anima mia nelle tue mani, te la dono, mio Dio, con tutto l''amore del mio cuore, perché ti amo. E per me un''esigenza di amore, il donarmi a Te, l''affidarmi alle tue mani, senza misura, con infinita fiducia: perché Tu sei mio Padre» (Charles de Foucauld).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-11';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Una generazione malvagia cerca un segno ma non le sarà dato nessun segno, se non quello di un uomo che con la sua vita parla di Dio. Gesù, con queste parole, si sta rivolgendo ad una generazione malvagia, cioè a certa gente che non ha nessun desiderio di cambiare vita. Anche noi possiamo essere tra coloro che chiedono segni ma senza nessun desiderio di cambiare vita. A volte siamo quelli che chiedono sempre segni al Signore perché confermi la sua vicinanza e il suo amore, quando dovremmo anche saper camminare nell’aridità e nella notte oscura, che non significa lontananza di Dio ma momento di crescita per noi. A volte siamo di quelli che cercano solo segni eclatanti, che vanno in giro in cerca di posti dove vi sono presunte apparizioni e miracoli, mentre la nostra fede rimane piccina e senza nessun fondamento! E allora? Una cosa è certa: i segni Dio li dà a chi vuol veramente compiere la sua volontà! Ma i segni di Dio sono piccoli, nascosti, occorre avere una profonda vita interiore per scorgerli, una capacità e un desiderio di fare silenzio per unire mente e cuore. E noi siamo disposti a fare ciò? Abbiamo il desiderio di compiere la volontà di Dio, anche se ci scomoda parecchio? </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-12';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span>«Questi dottori della legge non capivano i segni del tempo e chiedevano un segno straordinario (Gesù gliel’ha dato dopo). Perché non capivano? Prima di tutto, perché erano chiusi. Erano chiusi nel loro sistema, avevano sistemato la legge benissimo, un capolavoro. […] Era tutto sistemato. […] Loro non capivano che Dio è il Dio delle sorprese, che Dio è sempre nuovo […] E loro non capivano e si chiudevano in quel sistema fatto con tanta buona volontà e chiedevano a Gesù: ‘Ma, fai un segno!’. E non capivano i tanti segni che faceva Gesù e che indicavano che il tempo era maturo. Chiusura! Secondo, avevano dimenticato che loro erano un popolo in cammino. In cammino! E quando ci si incammina, quando uno è in cammino, sempre trova cose nuove, cose che non conosceva. […] E questo deve farci pensare: io sono attaccato alle mie cose, alle mie idee, chiuso? O sono aperto al Dio delle sorprese? Sono una persona ferma o una persona che cammina? Io sono capace di capire i segni dei tempi ed essere fedele alla voce del Signore che si manifesta in essi?» (papa Francesco).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-12';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>«Chiedete e vi sarà dato; cercate e troverete, bussate e vi sarà aperto» Quanta gente che ho incontrato è rimasta delusa da Dio perché ha bussato incessantemente al suo cuore, ma invano. Ha chiesto ma non ha ricevuto. Allora hanno pensato e detto che le parole di questo Vangelo non sono vere, che Dio non ci ama, che è indifferente alle nostre sofferenze. E noi? Forse anche noi non siamo stati esauditi in tutto ciò che abbiamo chiesto; ma abbiamo fatto un salto nella fede, pensando che Dio ci dona ciò che veramente ci serve e non tutto ciò che gli chiediamo? Anche s. Agostino scrive che non tutto ciò che ci piace ci giova! Spesso ciò che ci fa più soffrire non è la realtà in se stessa, ma le aspettative che abbiamo sulle cose e sulle persone. Tante volte le cose e le persone non cambiano e occorre che cambiamo noi nell’accogliere la vita. Chiediamo dunque al Signore la forza di accettare quelle situazioni difficili che ci fanno tanto soffrire e farle divenire non solo luoghi problematici, ma luoghi di incontro con Colui che, dall’interno, ha trasformato persino un luogo di morte (la croce) in un luogo di vita!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-13';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span>«Sì, è vero che Dio ci esaudisce con cose buone (cf. Mt 7,11), ma queste non sempre sono quelle da noi giudicate buone. La preghiera non è magia, non è un “affaticare gli dèi” – come scriveva il filosofo pagano Lucrezio (La natura delle cose IV,1239) – o uno stordire Dio a forza di parole moltiplicate, dice altrove Gesù (cf. Mt 6,78). Dio non è a nostra disposizione per esaudire i nostri desideri, spesso egoisti ma soprattutto ignoranti, in senso letterale: non sappiamo ciò che vogliamo! Ecco perché – precisa la versione lucana – “le cose buone” sono in realtà “lo Spirito santo”. Sempre Dio ci dà lo Spirito santo, se glielo chiediamo nella preghiera, e lo Spirito che scende nella nostra mente e nel nostro cuore, lui che si unisce al nostro spirito (cf. Rm 8,16), è la risposta di Dio. Ma è bene fare un esempio, a costo di essere brutali. Se io, affetto da una grave malattia, chiedo a Dio la guarigione, non è detto che questa si verifichi effettivamente, ma posso essere certo che Dio mi darà lo Spirito santo, forza e amore per vivere la malattia in un cammino in cui continuare ad amare e ad accettare che gli altri mi amino. Questo è l’esaudimento vero e autentico, questo è ciò di cui abbiamo veramente bisogno!» (Enzo Bianchi).</span></em></p>
<p>
 <em><span><strong>Giulia Gabrieli</strong> (19972011). </span></em><em><span>È morta a 14 anni, dopo due anni di sofferenza a causa di un tumore. Sembra incredibile che una ragazza della sua età abbia saputo affrontare la malattia con una capacità emotiva e interiore ben superiore ai suoi anni. Invece di abbatterla, la malattia ha favorito una maturazione ancora più rapida fino al punto di lasciare una traccia luminosa che ha sorpreso tutti quelli che hanno avuto modo di incontrarla. Nell’ultimo anno della sua vita ha voluto scrivere un libro, pubblicato dopo la morte, in cui racconta la sua testimonianza. Vi consegno solo una pagina che raccoglie lo sguardo innocente di una ragazzina che ha tanta voglia di vivere ma non vede la morte come un ostacolo. </span></em></p>
<p>
 <em><span>«Il fatto è che la gente ha paura della malattia, della sofferenza. Ci sono molti malati che restano soli, tutti i loro amici spariscono spaventati. Non bisogna avere paura. È proprio questo allontanamento che mette timore a noi malati. Se invece gli altri ci stanno vicino, ci vengono accanto, ci mettono una mano sulla spalla e ci dicono: dai che ce la fai, è quello che ci dà la forza di andare avanti. Se questo non succede, ti chiedi: perché vanno così lontano? Se loro, che non sono coinvolti in prima persona, hanno paura, allora anch’io devo temere. Perché dovrei lottare per la guarigione, se nessuno mi sta accanto? Io non ho avuto nessuno che si è allontanato da me, anzi estranei, persone che non conoscevo si sono avvicinate a me. Ma non tutti sono così fortunati, io invece vorrei che fosse così per tutti. Ora io so che <strong>la mia storia può finire soltanto in due modi</strong>: o grazie a un miracolo con la completa guarigione, che io chiedo al Signore perché ho tanti progetti da realizzare e li vorrei realizzare proprio io oppure incontro il Signore, che è una bellissima cosa. Sono entrambi due finali molto belli!». </span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-13';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>«Se la vostra giustizia non supererà quella degli scribi e dei farisei, non entrerete nel regno dei cieli». La giustizia dei farisei era ed è un’osservanza delle leggi, ma questa basta? L’apostolo Paolo non dice forse che la legge ha racchiuso tutti quanti nella maledizione, visto che non si è in grado di osservarla tutta? E dare il giusto agli altri, per quello che si meritano, basta? Basta il minimo sindacale? Forse una madre che dà il giusto a suo figlio, per quello che si merita, è una brava madre? E dove sta il di più dell’amore che Cristo ha portato? Si coglie subito la differenza di un consacrato che si è ridotto a burocrate o ad arrampicatore di posti di prestigio da un consacrato che ama e serve. Si coglie subito la differenza tra chi fa qualcosa solo per dovere e chi fa le cose con amore. Il Vangelo di oggi ci dice che non basta fare solo il nostro dovere, ma occorre mettere amore dove vi è solo una fredda osservanza della legge; mettere il di più dell’amore dove ognuno non mette che il minimo sindacale. Domandiamoci cosa stiamo mettendo “in più” nei nostri rapporti; e preghiamo che la nostra giustizia non sia quella di certi scribi e farisei, ma simile a quella di Cristo che si è rivelata sulla croce per amore nostro.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-14';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span><strong>Preghiera semplice</strong> O Signore, fa'' di me uno strumento della tua Pace: Dove c''è odio, fa'' ch''io porti l''Amore. Dove c''è offesa, ch''io porti il Perdono. Dove c''è discordia, ch''io porti l''Unione. Dove c''è dubbio, ch''io porti la Fede. Dove c''è errore, ch''io porti la Verità. Dove c''è disperazione, ch''io porti la Speranza. Dove c''è tristezza, ch''io porti la Gioia. Dove ci sono le tenebre, ch''io porti la Luce. O Maestro, fa'' ch''io non cerchi tanto: Essere consolato, quanto consolare. Essere compreso, quanto comprendere. Essere amato, quanto amare. Poiché è dando, che si riceve; Dimenticando se stessi, che si trova; Perdonando, che si è perdonati; Morendo, che si resuscita a Vita Eterna».</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-14';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 «Amate i vostri nemici e pregate per quelli che vi perseguitano». Le parole che Gesù ci rivolge oggi sono da vertigini: è lo straordinario di Dio che ci chiama a fare cose straordinarie. Che bello questo! Dio si fida a tal punto di noi, da ritenerci capaci di fare cose straordinarie! Ma queste parole ci turbano, ci mettono in crisi, perché noi sappiamo quanto sia difficile viverle! Davanti a una cattiveria, a un’ingiustizia, a un tradimento subito non è certo facile amare quella persona e pregare per lei!  Noi che abbiamo subito un tradimento, una cattiveria gratuita, un’ingiustizia, cosa proviamo in questo momento nel nostro cuore? Desideriamo guarire dal rancore e dall’odio che magari albergano nel nostro cuore? Abbiamo chiesto questa grazia al Signore? Abbiamo aperto il nostro cuore? Certo, amare chi ci ha fatto del male non è qualcosa di immediato, non una guarigione improvvisa ma un processo graduale, un’apertura di cuore perché possa essere inondato dall’amore di Dio; solo Lui, che vive in noi, può renderci capaci di fare ciò! Oggi vogliamo chiedere al Signore la guarigione del cuore, lasciando risuonare in noi le sue parole: «Ti darò un cuore nuovo, metterò dentro di te uno spirito nuovo, toglierò da te il cuore di pietra e ti darò un cuore di carne. Porrò il mio spirito dentro di te e ti farò vivere secondo i miei statuti e ti farò osservare e mettere in pratica le mie leggi» (cf Ez, 36,26-27). Sì, oggi vogliamo chiedere al Signore la grazia di mettere in pratica la sua legge, la legge dell’amore! </p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-15';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>Dalle Fonti Francescane. Lo stesso [fra Leonardo] riferì che Un giorno il beato Francesco, presso Santa Maria [degli Angeli], chiamò frate Leone e gli disse: "Frate Leone, scrivi". Questi rispose: "Eccomi, sono pronto". "Scrivi  disse  quale è la vera letizia". "Viene un messo e dice che tutti i maestri di Parigi sono entrati nell''Ordine, scrivi: non è vera letizia. Così pure che sono entrati nell''Ordine tutti i prelati d''Oltralpe, arcivescovi e vescovi, non solo, ma perfino il Re di Francia e il Re d''Inghilterra; scrivi: non è vera letizia. E se ti giunge ancora notizia che i miei frati sono andati tra gli infedeli e li hanno convertiti tutti alla fede, oppure che io ho ricevuto da Dio tanta grazia da sanar gli infermi e da fare molti miracoli; ebbene io ti dico: in tutte queste cose non è la vera letizia". "Ma quale è la vera letizia?". "Ecco, io torno da Perugia e, a notte profonda, giungo qui, ed è un inverno fangoso e così rigido che, all’estremità della tonaca, si formano dei ghiaccioli d''acqua congelata, che mi percuotono continuamente le gambe fino a far uscire il sangue da siffatte ferite. E io tutto nel fango, nel freddo e nel ghiaccio, giungo alla porta e, dopo aver a lungo picchiato e chiamato, viene un frate e chiede: "Chi è?". Io rispondo: "Frate Francesco". E quegli dice: "Vattene, non è ora decente questa, di andare in giro, non entrerai". E poiché io insisto ancora, I ‘altro risponde: "Vattene, tu sei un semplice ed un idiota, qui non ci puoi venire ormai; noi siamo tanti e tali che non abbiamo bisogno di te". E io sempre resto davanti alla porta e dico: "Per amor di Dio, accoglietemi per questa notte". E quegli risponde: "Non lo farò. Vattene al luogo dei Crociferi e chiedi là". Ebbene, se io avrò avuto pazienza e non mi sarò conturbato, io ti dico che qui è la vera letizia e qui è la vera virtù e la salvezza dell''anima" (FF 258).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-15';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Nella prima domenica di Quaresima la liturgia ci ha invitato a seguire Gesù nel deserto per affrontare e vincere con Lui le tentazioni. Oggi, in questa seconda domenica di Quaresima, Gesù ci conduce sul monte Tabor, sul “monte” della preghiera, per contemplare la sua gloria. Gli aspetti del Vangelo di oggi che vogliamo cogliere sono due: farsi condurre da Gesù e il motivo per cui Egli si trasfigura.</span></p>
<p>
 <span>«In quel tempo, Gesù prese con sé Pietro, Giovanni e Giacomo e salì sul monte a pregare». Tutti noi siamo chiamati alla gloria, a contemplarla, a raggiungerla, ma perché ciò accada occorre che qualcuno ci conduca nel giusto posto. Se ci pensiamo, in ogni scelta siamo mossi verso qualcosa e ci lasciamo attrarre da qualcosa. Anche se inconsapevolmente, il nostro agire è finalizzato, mosso dal desiderio di arrivare da qualche parte, di raggiungere qualcosa. Ecco, dobbiamo aver chiaro che la nostra meta è il cielo e ogni atto ci può avvicinare o allontanare da esso. Perciò dovremmo sempre chiederci: ma questo pensiero, questa intuizione, questa azione mi porta verso il cielo o no? Mi dà gloria vera o no? </span></p>
<p>
 <span>Gesù si lascia guidare dalle Scritture, rappresentate da Mosè ed Elia, si confronta con esse per dirigere al meglio il suo cammino; quindi, si cammina deciso verso il suo esodo, verso il compimento della sua missione. E io verso cosa cammino? Da cosa mi lascio condurre? Mi lascio condurre da Gesù o mi conduce il mondo? Non è che da pellegrino sto finendo a fare il turista, dimenticando verso cosa e verso chi sono diretto? S. Tommaso d’Aquino ci ricorda che <em>«È meglio zoppicare sulla via, che camminare a forte andatura fuori strada. Infatti, chi zoppica sulla strada, anche se avanza poco, si avvicina tuttavia al termine. Chi invece cammina fuori strada, quanto più velocemente corre, tanto più si allontana dalla meta».</em></span></p>
<p>
 <span>Il secondo passo è il motivo della salita al monte e della Trasfigurazione di Gesù. Gesù, in precedenza, ha parlato apertamente ai suoi discepoli della sua passione ma essi non hanno capito o non hanno voluto comprendere: Dio che soffre, per loro non è possibile! Per questo Gesù conduce con sé, sul monte Tabor, Pietro, Giacomo e Giovanni. <em>«Gesù vuole che la sua Trasfigurazione, la sua gloria illumini gli apostoli quando attraverseranno il buio fitto della sua passione e morte, quando lo scandalo della croce sarà per loro insopportabile. Dio è luce, e Gesù vuole donare ai suoi amici più intimi l’esperienza di questa luce, che dimora in Lui. Così, dopo questo avvenimento, Egli sarà in loro luce interiore, capace di proteggerli dagli assalti delle tenebre» (papa Benedetto XVI).</em> Anche nella notte più oscura, Gesù è la lampada che non si spegne mai. Dunque, <em>«lo scopo principale della trasfigurazione era di rimuovere dal cuore degli apostoli lo scandalo della croce, affinché l’umiltà della passione da lui voluta non turbasse la loro fede, essendo stata rivelata ad essi in anticipo l’eccellenza della sua dignità nascosta» (S. Leone Magno).</em> Spesso, anche nella nostra vita, il Signore permette momenti di grazia e di consolazione prima di “forti tempeste”. Santa Chiara d’Assisi, nei momenti di buio e tribolazione, invitava a fare memoria delle cose belle. La grazia che Dio ci dona, le cose belle che in Lui viviamo, è come rugiada che ristora la nostra anima nei momenti di sofferenza. Stasera, nel nostro esame di coscienza, domandiamoci se nella nostra vita abbiamo fatto esperienza della Trasfigurazione e se siamo capaci di farne memoria nei momenti difficili che attraversiamo.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-16';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>PREGHIERA</em></span></span></p>
<p>
 <em>Guidami, Luce Amica, nel buio intorno, guidami Tu! </em><em>La notte è scura, e io lontano da casa, guidami Tu! </em><em>Guida Tu i miei piedi; io non Ti chiedo </em><em>l’orizzonte intero, un passo sol mi basta. </em><em>Non sempre è stato così, non Ti chiedevo che mi guidassi Tu. </em><em>Volevo scegliere io la strada, ma adesso guidami Tu! </em><em>Per forre e steppe, sopra scogli e abissi, finchè non è più notte e con l’alba nuova ecco sorridermi volti d’angelo                        amati tanto, perduti sol per poco.                      </em></p>
<p>
 <em>(San John Henry Newman)</em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-16';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>«Siate misericordiosi, come il Padre vostro è misericordioso… perdonate e sarete perdonati». Le parole del Vangelo di oggi dovremmo ripetercele prima di ogni nostra confessione col sacerdote. Andiamo a chiedere perdono al Signore, desideriamo essere perdonati e non giudicati per le nostre colpe, abbiamo bisogno di una carezza, di parole di conforto e di incoraggiamento, ma quanto siamo disposti a fare tutto ciò agli altri? È facile essere gentili, disponibili, affettuosi con le persone che ci vogliono bene, ma è meno facile con gli altri. Magari abbiamo subito un torto; ma noi, non abbiamo fatto mai nessun torto? Forse qualcuno pensa proprio di sì, dato che quando va a confessarsi racconta i peccati degli altri, citando di sé solo le proprie presunte buone azioni! Meno male che il Signore ci misura con il suo metro che è quello dell’amore misericordioso, perché se ci misurasse in base alle nostre azioni, non si salverebbe nessuno! Oggi, dunque, guardiamo il nostro cuore, pensiamo a quelle persone con le quali abbiamo difficoltà o litigi in corso e domandiamoci se vogliamo deporre le armi del demonio che divide, e usare le armi spirituali della fede per costruire ponti di riconciliazione e di perdono, perché <em>«solamente chi è forte (nel Signore) è capace di perdonare. Il debole non sa né perdonare né punire» (Gandhi)</em>.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-17';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span><strong>I biscotti bruciati.</strong> Quando ero piccola, a mia mamma piaceva preparare come cena ciò che solitamente si mangia a colazione. Quella sera, una lunga e dura giornata di lavoro, mia mamma mise davanti a mio padre un piatto di uova, salsiccia e biscotti estremamente bruciati. Io aspettavo in silenzio per vedere se qualcuno se ne fosse accorto! Mio padre prese il suo biscotto, sorrise a mia madre e mi chiede come era andata la mia giornata a scuola. Non ricordo cosa gli ho detto, ma ricordo benissimo di averlo visto spalmare burro e gelatina su quel brutto biscotto bruciato. Mangiò ogni boccone senza scomporsi e senza pronunciare una parola al riguardo! Quando mi sono alzato dal tavolo quella sera, mia madre si scusò con mio padre per aver bruciato i biscotti. E non dimenticherò mai quello che risposte mio padre: “Tesoro, adoro i biscotti bruciati di tanto in tanto.» Più tardi quella sera andai a baciare la buonanotte a papà e gli chiesi se gli piacevano davvero i suoi biscotti bruciati. Mi abbracciò e mi disse: «Tua mamma ha passato una dura giornata di lavoro oggi ed è davvero stanca. E poi un biscotto bruciato non ha mai fatto male a nessuno!»</span></span></em></p>
<p>
 <em><span><span>Quando sono cresciuto, ci ho pensato molte volte. La vita è piena di cose imperfette e persone imperfette. Non sono il migliore in quasi nulla, e dimentico compleanni e anniversari proprio come tutti gli altri. Ma quello che ho imparato nel corso degli anni è che imparare ad accettare i reciproci difetti e scegliere di celebrare le reciproche differenze è una delle chiavi più importanti per creare una relazione sana, in crescita e duratura. </span></span></em></p>
<p>
 <em><span><span>(https://www.qumran2.net/ritagli/?&pag=3)</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-17';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Meditiamo il Vangelo di oggi aiutati dalle parole di p. Ermes Ronchi che evidenzia due questioni di fondo. La prima: essere o apparire. La seconda: l''amore per il potere. </span></p>
<p>
 <span><em>«Praticate ciò che vi dicono, ma non fate secondo le loro opere, perché essi dicono e non fanno». La severità di Gesù non va contro la debolezza di chi vorrebbe ma non ce la fa, bensì contro l''ipocrisia di chi fa finta. Verso la nostra debolezza Gesù si è sempre mostrato premuroso, come il vasaio che, se il vaso non è riuscito bene, non butta via l''argilla, ma la rimette sul tornio e la plasma di nuovo, fino a che realizza il suo progetto. Gesù non sopporta gli ipocriti. Ipocrita (termine greco che significa "attore di teatro") è il moralista che invoca leggi sempre più dure, ma per gli altri (legano pesi enormi sulle spalle delle persone, ma loro non li toccano con un dito); ipocrita è l''uomo di Chiesa che più si mostra severo e duro con gli altri, più si sente giusto, vicino a Dio (mentre è vicino solo alla propria aggressività o invidia verso i fratelli). L''ipocrita non si accontenta di essere peccatore, vuole apparire buono. Gesù poi stigmatizza un secondo errore che rovina la vita: l''amore del potere. Non fatevi chiamare maestro, dottore, padre, come se foste superiori agli altri. Voi siete tutti fratelli. Ma a Gesù questo non basta, e opera un ulteriore capovolgimento: il più grande tra voi è colui che serve. Il più grande è chi ama di più. Il mondo ha bisogno d''amore. E allora il più grande del nostro mondo sarà forse una mamma sconosciuta, che lavora e ama nel segreto della sua casa, o nelle foreste d''Africa, o uno di voi che legge, o colui o colei che vi è vicino. Siete grandi quando sapete amare, quando sapete farlo con lo stile di Gesù, traducendo l''amore nella divina follia del servizio: sono venuto per servire non per essere servito. Dio è il grande servitore, non il padrone. Lui io servirò, perché Lui si è fatto mio servitore» (p. Ermes Ronchi).</em></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-18';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span>«Il pavone con le sue belle piume è il rappresentante ufficiale della superbia, dell’ipocrisia e della vanagloria. Un tipo che non fa niente, tranne andare in giro a mostrare quanto è bella la sua coda. Con una ironica contraddizione che ci viene regalata da una poesia medievale di raro acume, scritta da Cecco d’Ascoli. Il poeta si immagina il pavone che gode della sua bellezza e prova piacere a guardarsi spalancando la sua ruota di piume multicolori. Fino a quando lo sguardo gli cade sulle zampe che non sono davvero all’altezza di tanta beltà «e guardandosi a li piè prende tristezza e allegrezza da lui sta remota».</span></span></em></p>
<p>
 <em><span><span>Uno scoppio d’ira. Una parola della famiglia del pavone ci riserva ancora una sorpresa che è direttamente collegata proprio ai suoi colori. La parola fa riferimento ad un viola piuttosto scuro, difficile da rendere altrimenti se non facendo riferimento alle misteriose sfumature della coda del pavone. Ma a noi arriva come colorito di chi è assalito da uno scoppio di collera, o diventa «paonazzo» per la vergogna. Insomma un colore estremo per emozioni violente difficile da descrivere altrimenti.</span></span></em></p>
<p>
 <em><span><span>Quindi per capirci i pavoni umani che ci circondano affaticano soprattutto noi che li dobbiamo sopportare. Con poche certezze: non si guardano mai i piedi, altrimenti conoscerebbero l’umiltà. Non conoscono Cecco d’Ascoli, altrimenti conoscerebbero l’ironia, hanno tempo solo per loro stessi. Altrimenti dovrebbero concedersi il regalo di guardare e ascoltare gli altri» (Paolo Fallai).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-18';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Oggi celebriamo la Solennità di s. Giuseppe che, insieme a Maria “madre della Via”, è Patrono della nostra Comunità. Partendo dal Vangelo di oggi, vogliamo meditare sulla sua pronta obbedienza al volere di Dio, come sta scritto: «Quando si destò dal sonno, Giuseppe fece come gli aveva ordinato l''angelo del Signore». Attraverso questa obbedienza immediata inizia per Giuseppe una vita nuova con prospettive assolutamente inaspettate e con la scoperta di un senso più profondo del suo essere sposo e padre, non secondo i suoi progetti ma secondo il progetto di Dio. <em>«Egli si fa carico del disegno di Dio, portandone il peso».</em> Quanto ci fanno bene queste parole! Quando siamo tentati dall’egoismo, quando non riusciamo a fare spazio a Dio e al suo progetto, quando pensiamo di stare bene se l’altro ci fa stare bene o solo se si realizzano i nostri progetti (ma che talvolta non combaciano con quelli che Dio ha su di noi), occorre che impariamo da Giuseppe, con coraggio e senza paura, a saper obbedire a Dio, anche se ci dovesse rivelare una via diversa da quella che noi abbiamo pensato. Inoltre, ciò che Giuseppe comprende essere la volontà di Dio ha il carattere della definitività. Non si lascia dietro una porta aperta da dove poter fuggire in caso di difficoltà. Come Maria stava sotto la croce, Giuseppe starà vicino a Maria e al Bambino in ogni situazione, bella o brutta. Come stride tutto ciò con la nostra mentalità odierna dell’usa e getta, che non riguarda solo le cose ma in maniera ancor più drammatica anche le persone! Persone che fanno della vita “una libertà di scelta”, riducendo la libertà allo scegliere oggi una cosa e domani un’altra, lasciando magari quella di prima. Certo, non voglio fare un discorso generico o semplicistico, dato che a volte ci sono situazioni così drammatiche che non lasciano altra strada, ma ho conosciuto persone che per cose di nessun peso, per stanchezza di coppia, di vita in comune, di desiderio di trasgressione, hanno tradito la loro vocazione. Di fronte a tale pericolo, chiediamo l’intercessione di s. Giuseppe perché possiamo essere fedeli fino alla fine alla missione che Dio ci ha affidato!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-19';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span> «I Vangeli non ci riportano nessuna parola di Giuseppe di Nazaret, niente, non ha mai parlato. Ciò non significa che egli fosse taciturno, no, c’è un motivo più profondo. Con questo suo silenzio, Giuseppe conferma quello che scrive Sant’Agostino: “Nella misura in cui cresce in noi la Parola – il Verbo fatto uomo – diminuiscono le parole”. Nella misura che Gesù  la vita spirituale  cresce, le parole diminuiscono. Il silenzio di Giuseppe non è mutismo; è un silenzio pieno di ascolto, un silenzio operoso, un silenzio che fa emergere la sua grande interiorità. Come sarebbe bello se ognuno di noi, sull’esempio di San Giuseppe, riuscisse a recuperare questa dimensione contemplativa della vita spalancata proprio dal silenzio. Ma tutti noi sappiamo per esperienza che non è facile: il silenzio un po’ ci spaventa, perché ci chiede di entrare dentro noi stessi e di incontrare la parte più vera di noi. E tanta gente ha paura del silenzio, deve parlare, parlare, parlare o ascoltare, radio, televisione …, ma il silenzio non può accettarlo perché ha paura. Il filosofo Pascal osservava che “tutta l’infelicità degli uomini proviene da una cosa sola: dal non saper restare tranquilli in una camera”. Non è facile riconoscere la Voce del Signore, che molto spesso è confusa insieme alle mille voci di preoccupazioni, tentazioni, desideri, speranze che ci abitano; ma senza questo allenamento che viene proprio dalla pratica del silenzio, può ammalarsi anche il nostro parlare. Senza la pratica del silenzio si ammala il nostro parlare. Infatti le nostre parole possono diventare adulazione, vanagloria, bugia, maldicenza, calunnia. È un dato di esperienza che, come ci ricorda il Libro del Siracide, «ne uccide più la lingua che la spada» (28,18). Gesù lo ha detto chiaramente: chi parla male del fratello e della sorella, chi calunnia il prossimo, è omicida (cfr Mt 5,21-22). Uccide con la lingua. Noi non crediamo a questo ma è la verità. Pensiamo un po’ alle volte che abbiamo ucciso con la lingua, ci vergogneremmo! Ma ci farà tanto bene, tanto bene. Silenzio, parlare giusto, qualche volta mordersi un po’ la lingua, che fa bene, invece di dire stupidaggini» (papa Francesco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-19';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo odierno ci mostra una malattia molto comune oggi: quella dell’indifferenza e dell’egoismo; e ci mostra l’esito finale tra chi l’ha perpetrata e chi l’ha subita. I protagonisti sono due: un ricco senza nome, la cui identità è data dal denaro (che con la morte svanirà), e un povero chiamato per nome e conosciuto da Dio. Si tratta di un povero di cui soltanto Dio si prende cura; infatti <em>«a differenza del ricco, egli ha un nome, Lazzaro, abbreviazione di Eleazaro, che significa appunto "Dio lo aiuta» (Benedetto XVI).</em> L’esito finale della loro vita? Morirono tutti e due ma il povero fu portato nel seno di Abramo, mentre il ricco e fu sepolto nell''inferno. La distanza che vi era in vita continua ma a parti invertite. Il ricco che stava in alto ora sta in basso, e il povero Lazzaro che stava in basso, sotto il tavolo, mendicando le briciole che cadevano dalla tavola, ora sta in alto. Perché il ricco è condannato? Per la sua ricchezza? No, ma per la sua indifferenza egoista, per non aver fatto buon uso dei beni che possedeva! Il contrario dell''amore non è l''odio, ma il possesso, che genera l’indifferenza, per cui l''altro neppure esiste. <em>«Tre gesti sono assenti dalla storia del ricco: vedere, fermarsi, toccare. Mancano, e tra le persone si scavano abissi, si innalzano muri. Ma chi erige muri, isola solo se stesso» (p. Ermes Ronchi).</em> L’esito finale della parabola dice che l’eternità inizia già ora, in questo tempo che Dio ci dona da vivere. L’inferno non sono gli altri ma la solitudine, l’indifferenza generata e nutrita dall’egoismo. Oggi i ricchi per cambiare vita non hanno persone che risorgono dai morti: hanno la Parola di Dio che li esorta a cambiare in meglio, e hanno i poveri che li circondano. Gesù ci ricorda che nel giorno del giudizio ciò che farà la differenza è ciò che abbiamo fatto o non fatto per i poveri, per gli ultimi, per gli invisibili, per Dio stesso, perché negli affamati è Lui che è affamato! <em>«Nelle piaghe dei poveri è Dio che è piagato. Non c''è apparizione o miracolo o preghiera che conti quanto il loro grido: «Se stai pregando e un povero ha bisogno di te, corri da lui. Il Dio che lasci è meno sicuro del Dio che trovi» (San Vincenzo de’ Paoli).</em></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-20';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span><u><strong>Un delitto perfetto.</strong></u> Chiesi agli uomini: "Che cosa state portando avvolto in quella coperta, fratelli?". Mi risposero: "Portiamo un corpo morto, fratello". Chiesi: "È stato ucciso o è morto di morte naturale?". "È una domanda difficile, fratello! Ha tutta l''aria di essere stato un assassinio", mi risposero. "Com''è stato ucciso quest''uomo! Con un coltello o una pallottola, fratelli?", chiesi. "Non è stato né un coltello né una pallottola. Si è trattato di un delitto perfetto, un delitto che non lascia tracce". "Ma allora come è stato ucciso quest''uomo?", insistetti, ed essi mi risposero con calma: "Quest''uomo è stato ucciso dalla fame, fratello" (Josuè de Castro). </span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-20';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo di oggi ci pone una domanda: di chi è la nostra vita? A chi appartiene? La vita è nostra nel senso che è affidata a noi, ma nessuno si è dato la vita da solo, nessuno ha chiesto di venire alla luce, ognuno di noi l’ha ricevuta in dono. Di conseguenza, se la nostra vita è un dono, tutto il resto non è possesso ma sempre dono. Gli operai della vigna di cui si parla nel Vangelo non compresero ciò e impossessandosene, invece di fare il bene compirono il male. Ognuno di noi ha la responsabilità di ciò che gli è stato donato; ogni dono non è per averne un possesso ma perché sia a servizio degli altri. Noi tendiamo ad impossessarci di tutto: la nostra stessa vita, le persone, le cose, il creato, senza pensare che siamo chiamati a responsabilità perché tutto ciò che ci è stato affidato sia reso migliore di come ci è stato donato, cosicché quanti lo erediteranno possano dire: “che bello ciò che ci ha lasciato la generazione precedente!”. Quando Gesù ci ricorda che la vita non è nostra ma “in comodato d’uso”, e questo comodato d’uso prima o poi finirà, non lo fa per metterci paura ma per chiamarci a responsabilità, per dirci che noi siamo stati chiamati a fare grandi cose; che la nostra vita è bella, è preziosa ed è utile quando è messa a servizio del bene degli altri. Il Signore Gesù si è fidato di noi, e proprio per questo giungerà il giorno in cui ci chiederà i frutti, ci chiederà conto della nostra vita, di ciò che ne abbiamo fatto. <em>«Chi ha vissuto per sé stesso vede Dio come un usurpatore di libertà, ma chi ha vissuto nella logica dell’amore non ha paura di riconsegnare ciò che gli era stato affidato» (don Luigi M. Epicoco).</em> Ora domandiamoci: oggi ho posseduto, ho poltrito o ho donato? E che cosa ho donato? A chi mi sono fatto dono? </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-21';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il padre di questa parabola ci mette in crisi. Il suo amore, il suo perdono, la sua comprensione, il suo andare sempre incontro, tutto il suo agire va al di là dei nostri schemi di vita, di ciò che abitualmente esercitiamo verso gli altri. Noi, spesso, siamo disposti a dare misericordia se chi ha sbagliato è stato umiliato, se è stato punito, se è stato condannato, se ha chiesto perdono. Con il nostro agire abbiamo stabilito quando si può perdonare e quando no, al punto da pensare che per alcuni peccati non ci può essere perdono! Per questo l’agire di questo padre misericordioso, figura del Padre nostro che è nei cieli, ci mette in crisi, perché chiama anche noi a fare altrettanto! Come mai non riusciamo a comprendere che l’Onnipotenza di Dio si manifesta nel suo perdono? Non è forse ciò che esercita con ognuno di noi? Le parole di Gesù scandalizzano i tanti presunti giusti che si sentono esenti dai grandi peccati e dagli smarrimenti, scandalizza tutti coloro che si sentono differenti, migliori dagli altri e credono di poter vantare dei diritti davanti a Dio! <em>«Che Dio accolga i peccatori pentiti è cosa buona e lodevole, perché “è amore” (1Gv 4,8.16), ma che i peccatori e le prostitute precedano nel regno di Dio proprio quelli che sono giusti e si ritengono esperti della Legge (Mt 21,32), questo è inaudito, ed è pericoloso affermarlo. Eppure Gesù l’ha detto apertamente, e proprio in faccia a questi ultimi…» (Enzo Bianchi). </em>Tante volte ci ribelliamo di fronte alla misericordia del Signore perché pensiamo che porti tanti a peccare: tanto Dio perdona sempre! Quale convenienza a comportarsi bene se Dio perdona sempre? Allora dove è la giustizia se ognuno fa quello che vuole e poi è sempre perdonato? Sì, la misericordia di Gesù, ci sembra esagerata, eppure è questa misericordia che ci è chiesta, e che chiediamo prima di ogni nostra liturgia per poter rendere degnamente culto a Dio: “Voglio misericordia e non sacrificio». (Os 6,6). Sì, tutta questa vita è tempo di misericordia da ricevere e donare; solo dopo questa vita sarà tempo di giustizia, ma questa spetta al Dio misericordioso e giusto e non a noi con le nostre categorie!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-22';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Misericordia: è la legge fondamentale che abita nel cuore di ogni persona quando guarda con occhi sinceri il fratello che incontra nel cammino della vita» (papa Francesco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-22';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo di oggi ci parla del grande mistero della sofferenza, un argomento così delicato davanti al quale piuttosto che dire cose insensate spesso è meglio tacere. <em>«Dio non è venuto per cancellare la sofferenza. Egli non è venuto neppure per darne la spiegazione, bensì egli è venuto per colmarla della sua presenza» (Paul Claudel). </em></span></p>
<p>
 <span>Nel Vangelo alcuni vanno da Gesù per riferire un fatto di cronaca abominevole. Pilato ha esercitato il suo potere in maniera sanguinaria: facendo uccidere delle persone nel Tempio, ha mischiato il sangue di alcuni Galilei con quelli dei sacrifici. Un atto forte per tenere tutti imprigionati nella paura e nel terrore. Costoro chiedono a Gesù una spiegazione, il perché di questo fatto. Ma da parte di Gesù c’è solo una riflessione e un invito che loro devono cogliere: «Credete che quei Galilei fossero più peccatori di tutti i Galilei, per aver subito tale sorte? No, io vi dico, ma se non vi convertite, perirete tutti allo stesso modo». Non solo, ma Gesù, passando da un eccidio ad una disgrazia, cita la caduta della torre di Siloe su diciotto persone, ripetendo sempre lo stesso invito: «convertitevi!». </span></p>

<p>
 <span>Quante volte quando ci arriva una malattia, quando ci capita un fatto doloroso, subito ci poniamo la domanda: “Ma cosa ho fatto di male per meritarmi questo?”. Noi cerchiamo risposte, ed è anche lecito, ma occorre che entriamo nella consapevolezza che a certi eventi non vi sono risposte. Oggi è come se Gesù ci chiedesse di non pensare che la nostra sofferenza sia una punizione di Dio per i peccati commessi, o che Dio sia assente, o che non ci ami o che non gli importi della nostra sofferenza. Oggi <em>«Gesù ci invita a fare una lettura diversa di quei fatti, collocandoli nella prospettiva della conversione”. Infatti, le sventure, gli eventi luttuosi [...] devono rappresentare occasioni per riflettere, per vincere l’illusione di poter vivere senza Dio, e per rafforzare, con l’aiuto del Signore, l’impegno di cambiare vita. La vera saggezza è lasciarsi interpellare dalla precarietà dell’esistenza e leggere la storia umana con gli occhi di Dio, il quale, volendo sempre e solo il bene dei suoi figli, per un disegno imperscrutabile del suo amore, talora permette che siano provati dal dolore per condurli a un bene più grande» (Benedetto XVI). </em></span></p>
<p>
 <span>Noi viviamo in un’epoca che del dolore ne ha fatto uno spettacolo. Tutti davanti alla TV per fatti di cronaca nera, spinti solo da una morbosa curiosità. Eppure, al mistero della vita, della sofferenza non ci si avvicina da semplici spettatori sdraiati su una poltrona intenti a godersi lo spettacolo. <em>«No, ci si mette davanti alla sofferenza e ci si chiede come e cosa devo fare Se non mi converto io cammino verso quel nero, vivrò senza senso. Si sta davanti alla vita per farsi cambiare. Le tragedie sono appelli, come devo rispondere di fronte al dolore, quello è importante! Non domandarmi solo il perché, ma che io risponda con amore, con la conversione, che io mi lasci trasformare dalle notizie» (don Fabio Rosini). </em>È questa la lettura dei fatti dolorosi: che io mi converta, che io inizi ad amare, che io inizi a guardare la sofferenza degli altri non da spettatore, ma come colui che sa farsi prossimo e piangere con chi è nel pianto!</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-23';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>PREGHIERA</em></span></span></p>
<p>
 <span><span><em>Signore, mio Dio, eccomi davanti a te: sono malato, Signore, e tu conosci la mia sofferenza e la mia fatica, tu conosci anche la mia paura. Signore, nella mia notte sii tu la mia luce, non lasciarmi solo nella mia angoscia, fa’ che io creda nel tuo amore e nell’amore degli altri.</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-23';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Gesù si trova a Nazaret, dove è cresciuto, dopo aver predicato e aver detto che in Lui si compiono le Scritture, e la gente lo guarda incredula e perplessa. Lo conoscono come il figlio di Maria, il figlio di Giuseppe il falegname; come può dire queste cose! E davanti alla loro incredulità, Gesù risponde loro: «In verità io vi dico: nessun profeta è bene accetto nella sua patria». Questo “non essere riconosciuti” accade ancora oggi e, purtroppo, tante volte. Accade in tante famiglie, dove i figli cambiano, crescono, diventano migliori dei loro genitori ma non sono ascoltati, sono conosciuti ma non riconosciuti. Tanti genitori, che per grazia di Dio hanno figli consacrati, continuano a chiamarli come prima, con diminutivi, vezzeggiativi ma non riescono cogliere che quei figli sono diventati i loro padri e le loro madri nella fede! Questo avviene anche tra gli amici, tra tutte quelle persone che li hanno conosciuto in precedenza: imprigionati nei loro pregiudizi li hanno incasellati e, ciechi, sono incapaci di riconoscere il bene e di accoglierlo nella loro vita. Beh, in fondo non c’è poi molto da meravigliarsi: molti allora non hanno riconosciuto Gesù, e molti oggi continuano a non riconoscerlo!  </span><span>Davanti a questo Vangelo chiediamo al Signore la grazia di saper discernere, e di essere scevri da ogni pregiudizio, di saper riconoscere il bene da qualsiasi parte viene, per non perdere la grande possibilità di essere migliori.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-24';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«In verità, io vi dico: nessun profeta è bene accetto nella sua patria. E quando Gesù finì di spiegare questo, della vedova di Sarèpta, del lebbroso di Sidone, del lebbroso che era stato guarito da Eliseo, tutti si riempirono di sdegno. Si alzarono, lo cacciarono via, non erano persone, erano una muta di cani selvaggi. Non ragionavano. Davanti a questo atteggiamento però Gesù taceva. Lo portarono sul ciglio del monte per buttarlo giù. Ma egli, passando in mezzo a loro, si mise in cammino. La dignità di Gesù: con il suo silenzio vince quella muta selvaggia e se ne va. Questo ci insegna che quando c’è questo modo di agire, di non voler vedere la verità, resta il silenzio. Ma quante volte nelle famiglie incominciano delle discussioni sulla politica, sullo sport, sui soldi e una volta e l’altra e quelle famiglie finiscono distrutte, in queste discussioni nelle quali si vede che il diavolo è lì che vuol distruggere. Dire la sua e poi tacere. Perché la verità è mite, la verità è silenziosa, la verità non è rumorosa. Con le persone che non hanno buona volontà, con le persone che cercano soltanto lo scandalo, che cercano soltanto la divisione, che cercano soltanto la distruzione: silenzio. E preghiera. E sarà il Signore, dopo, a vincere, sia, come in questo caso, con la dignità di Gesù che rafforza e torna libero da quella volontà di buttarlo giù, sia con la dignità della vittoria della risurrezione, dopo la croce» (papa Francesco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-24';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Oggi, solennità dove si celebra l’Annunciazione del Signore, vogliamo chiedere a Maria che ci aiuti a crescere nella fede. Vogliamo imitarla, per quanto ci è possibile, perché Cristo nasca anche in noi; perché, prima ancora di generare Cristo nella carne, Maria lo ha generato nella fede. Desideriamo che Gesù nasca in noi? Che il nostro corpo, la nostra mente, la nostra anima, tutto il nostro essere, sia la nostra offerta al Signore? Che Dio ci converta all’amore! Perché: <em>«Quando l''anima comincia a convertirsi, viene chiamata ''Maria'', riceve cioè il nome della donna che ha portato Cristo nel grembo: è diventata un''anima che spiritualmente genera Cristo».</em>  </span><span>Certo, Maria è la tutta pura, la tutta bella, la totalmente altra da ciò che la nostra mente riesce ad immaginare. Eppure, nonostante ciò, lei non è lontana da noi perché è sempre nostra Madre, sempre vicina a me, sempre vicina a noi: anche noi portiamo il suo nome quando comincia a crescere in noi la presenza di Cristo.  </span><span>Maria dunque ci è maestra nella fede. Ella è colei che ha creduto alla Parola del Signore, Colei che, prima nella fede e poi nella carne, ha generato Gesù. La stessa cugina Elisabetta non le dice “sei beata perché porti in grembo Gesù”, ma: “sei beata perché hai creduto alla Parola!”. All’angelo che le porta l’annuncio che lei sarà la madre di Dio, Maria chiede «come avverrà questo?». Non cerca, cioè, di conoscere sul piano razionale qualcosa che la trascende, ma si pone sul piano dell’avvenimento: cioè questo avverrà perché è Dio che lo dice. Lei si fida di Dio. Ella ci insegna che la fede non entra tutta nel cervello; ciò non significa che non si debba usare la ragione, ma che la fede è oltre, è fidarsi di Dio che opera l’impossibile in chi crede e si affida a Lui. Noi, invece, abituati a voler tenere tutto sotto controllo, vorremmo capire tutto e subito; ma se facciamo così, senza aprirci all’impossibile di Dio, Lui non potrà mai agire. Nella nostra vita ci accadono tante cose che rimangono oscure, non accessibili, e noi dobbiamo accettare ciò. Occorre che accettiamo i nostri limiti nel capire. Spesso, quando ci accade qualcosa, ci poniamo delle domande, ci chiediamo il perché, e questo non è sbagliato ma prima viene la fiducia in Dio. A volte non vi è risposta ai nostri perché, e lì c’è solo il nostro sì a Dio. In quei nostri perché senza risposta, è come se Lui ci dicesse: “tu ti fidi di me?”. La fede per crescere richiede sempre atti di fede, di abbandono fiducioso come quello che fa Maria dicendo “sì” al Signore. Per questo è importante che anche noi ci chiediamo: quali sono stati i nostri atti di fede nel cammino che stiamo facendo? Quando è stata l’ultima volta che ci siamo fidati di Dio in una situazione incerta e oscura, abbandonandoci fiduciosi a Lui, dicendogli: “Signore mi fido di te?”. Maria, nostra Madre, è per noi dunque icona di fede obbediente, di abbandono fiducioso in Colui che è sempre fedele, stabile nel suo amore; fede non ci mette al riparo dalla notte ma ci dà la certezza della sua Presenza nella notte; fede che non ci preserva dalla sofferenza, ma certezza della Sua Presenza nella sofferenza; fede che non ci ripara dalla croce ma ci dà la certezza della Sua Presenza su quella croce; fede che non ci salva dalla morte ma nella morte si apre alla luce della Risurrezione, perché il Signore porta la vita dove vita non c’è. </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-25';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Possa la Madre nostra essere madre per ognuno di noi, essere cioè la causa della nostra letizia. E ognuno di noi sia un altro Gesù per lei, diventando così la causa della sua gioia. Nessuno come Maria ha appreso perfettamente la lezione dell''umiltà. Essa si definì "serva". Essere servi implica mettersi a completa disposizione di qualcuno, per essere utilizzati secondo i suoi desideri..., con assoluta fiducia e gioia. Entusiasmo e gioia costituirono la forza della Madonna. Solo la gioia può averle dato la forza recarsi "con sollecitudine" sulle colline della Giudea per farsi serva nei riguardi di sua cugina. Così noi: saliamo con sollecitudine le colline delle nostre difficoltà» (Madre Teresa di Calcutta).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-25';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>«Non crediate che io sia venuto ad abolire la Legge o i Profeti; non sono venuto ad abolire, ma a dare pieno compimento». Con queste parole Gesù ci sta dicendo che non è venuto ad abolire, ad eliminare l‘Antico Testamento ma a darne compimento, cioè a darne pienezza di verità e di grazia, perché, come dice l’apostolo Paolo: «il pieno compimento della legge è l’amore!» È allora chiaro che una fredda osservanza di leggi, di regole, che sia a casa, al lavoro, in una comunità religiosa non basta, non ci dà salvezza se queste regole non sono riempite d’amore! Qui non si tratta di fare cose grandi, ma cose grandi nell’amore, per questo santa Teresina di Lisieux diceva che <em>«anche raccattare una spilla da terra, se fatto con amore, conduce alla santità!».</em> Noi possiamo correre il rischio, da cristiani di facciata, di fare le cose per sentirci a posto con la coscienza, per compiacerci, per essere ammirati dagli altri, per sentirci migliori degli altri, per criticare gli altri! Guardiamo oggi il nostro cuore, chiediamoci se nelle cose che facciamo a casa, con gli amici, al lavoro o in comunità mettiamo amore; e di questo ce ne renderemo conto se amiamo le persone che ci circondano! E <em>«l’Amore di Cristo non è un buonismo a basso costo, ma un profondo e straordinario sentimento capace di strutturare scelte, decisioni e persino sacrifici… l’amore più grande è “dare la vita per chi si ama”» (don Luigi M. Epicoco).</em></span></p>
<p>
 <span>Soffermiamoci ora un istante, meditando sul bellissimo “Inno alla carità” di San Paolo, riscoprendo “le coordinate della carità”, così che il nostro cuore possa esserne illuminato:</span></p>
<p>
 <em><span>«Se anche parlassi le lingue degli uomini e degli angeli, ma non avessi la carità, sono come un bronzo che risuona o un cembalo che tintinna. E se avessi il dono della profezia e conoscessi tutti i misteri e tutta la scienza, e possedessi la pienezza della fede così da trasportare le montagne, ma non avessi la carità, non sono nulla. </span></em><em><span>E se anche distribuissi tutte le mie sostanze e dessi il mio corpo per esser bruciato, ma non avessi la carità, niente mi giova. La carità è paziente, è benigna la carità; non è invidiosa la carità, non si vanta, non si gonfia, non manca di rispetto, non cerca il suo interesse, non si adira, non tiene conto del male ricevuto, non gode dell''ingiustizia, ma si compiace della verità. Tutto copre, tutto crede, tutto spera, tutto sopporta. La carità non avrà mai fine» (1 Cor 13,1-13)</span></em></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-26';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Vangelo di oggi ci dice che quando un cuore è chiuso alla grazia e abitato dal pregiudizio e dalla condanna, può dire che il bene è male! Gesù non forza, non impone, non manda segni eclatanti come chiedono in tanti, ma guarisce, cura con la compassione dell’amore. Gesù è andato incontro alla diffidenza, alla calunnia che viene dal maligno, che servendosi delle persone è capace di dire che il bene è male e il male è bene! Tutto ciò accade anche oggi, purtroppo anche da parte di uomini di Chiesa. Ma come un giorno mi disse un bravo sacerdote: “vi sono uomini di Chiesa e uomini di Dio!”. Noi vogliamo pregare affinché tutti gli uomini di Chiesa diventino anche uomini di Dio! Noi vogliamo pregare affinché anche il nostro cuore sia libero da pregiudizi, perché anche io, anche tu, siamo capaci di dire cattiverie e maldicenze quando l’altro non è come noi vorremmo, quando l’altro ci toglie visibilità, quando l’altro è più bravo, quando l’altro è amato perché ama sempre e senza esclusione alcuna. Stasera guardiamo il nostro cuore, guardiamo da cosa e da chi è abitato.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-27';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«“Gesù stava scacciando un demonio che era muto. Uscito il demonio, il muto cominciò a parlare e le folle rimasero meravigliate”. </span></em></span><em><span>Siamo abituati a pensare alle manifestazioni del male come eventi eclatanti che ci spaventano e ci terrorizzano. Nel Vangelo di oggi il male ha solo un sintomo: blocca la comunicazione di quest’uomo, gli impedisce di parlare. Credo che tante volte abbiamo fatto la medesima esperienza, cioè ci siamo sentiti bloccati, incapaci di condividere, di raccontarci, di aprire il cuore. Gesù guarisce quest’uomo ed è un po’ come se questo racconto volesse dire a ognuno di noi che anche quando ci troviamo in simili condizioni il Signore può liberarci. Il vero problema è accorgersene e desiderare di tornare ad aprirsi» (don Luigi M. Epicoco). </span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-27';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>La risposta di Gesù allo scriba che gli domanda quale è il primo dei comandanti ci mette in crisi. Innanzitutto Gesù cita due comandamenti facendone uno solo: amare Dio e il prossimo. «Non c''è altro comandamento più grande di questi». Non ci sono olocausti e sacrifici che ci danno salvezza se non sappiamo amare. Perché? Perché tutto comincia dall’amore. <em>«Perché credete di esistere in questo mondo? Perché credete di essere nati? Per caso? No. Tutti noi, tutte le persone che esistono e che vivono sono nate da un atto di amore, un atto di amore dei nostri genitori, e prima ancora da un atto d’amore di Dio. Siamo tutti figli dell’amore. L’amore crea, l’indifferenza non crea nulla, l’indifferenza è sterile. L’odio distrugge, distrugge tutto, distrugge fuori, distrugge dentro. L’amore, invece, edifica, l’amore costruisce, dove c’è l’amore, c’è la vita, la vita fiorisce, la vita rifiorisce. Tutto comincia e tutto ricomincia con l’amore. Ecco perché è il primo, perché è la fonte di tutto, tutto viene da lì» (Enzo Bianchi).  </em></span></p>
<p>
 <span>Ma vi è ancora un''altra parola che ci mette in crisi ed è quel tutto. «Amerai il Signore con tutto il tuo cuore e con tutta la tua anima, con tutta la tua mente e con tutta la tua forza». Noi sappiamo che non amiamo Dio con tutto noi stessi. Il nostro cuore è diviso in tanti spicchi. Vi sono tante cose nel nostro cuore, amiamo cose e persone prima e più del Signore. Se guardiamo il nostro cuore con sincerità, non possiamo non ammettere che Dio non è il nostro tutto, e che il nostro tutto non è rivolto a Lui. Oggi vogliamo chiedere al Signore, con tutto noi stessi, la purificazione del cuore, che ci aiuti a scacciare dal nostro cuore tutte quelle cose superflue che impediscono a Lui di dimorare in noi, e che ci impediscono di amare come Lui ha amato.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-28';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>«In noi si dovrà trovare tutto, il bicchiere d’acqua, il cibo per chi ha fame, tutto il vero cibo per tutti i veri affamati, tutti i veri cibi e tutti i veri mezzi per distribuirli, l’alloggio per i senza tetto, il “pellegrinaggio” alle carceri e agli ospedali, la compassione per le lacrime, quelle che si devono versare insieme e quelle di cui occorrerebbe eliminare le cause, l’amicizia per ogni peccatore e per coloro che sono malvisti, la capacità di mettersi al livello di tutte le piccolezze, di lasciarsi attrarre da tutto ciò che non conta: e tutto avrà il suo orientamento, la sua pienezza nella parola “fraterno”» (Madeleine Delbrêl).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-28';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>«Gesù disse ancora questa parabola per alcuni che avevano l''intima presunzione di essere giusti e disprezzavano gli altri». Le prime parole di questa parabola raccontata anche per noi, ci mettono in guarda da un pericolo che corriamo tutti: sentirsi migliori degli altri! Due uomini salgono al Tempio: un fariseo e un povero pubblicano. Il fariseo racconta le cose buone che fa, si sente forte, vanta dei diritti, quasi una salvezza conquistata con le sue sole forze; è uno che si aspetta anche da Dio un “bravo” per il suo essere migliore di tanti. Poi abbiamo il povero pubblicano, consapevole di essere un povero peccatore che invoca la misericordia del Signore. Il fariseo, confrontando la sua vita con quella del povero pubblicano, si sente a posto, dimenticando che il modello non possono essere le persone ma Dio! «Ti ringrazio perché non sono come gli altri uomini, ladri, ingiusti, adùlteri, e neppure come questo pubblicano»; ecco le sue parole! Sentirsi migliori degli altri è il segno che ci dice che non abbiamo una seria e concreta vita spirituale. Chi ha un’autentica vita spirituale sa che nessuno è giusto davanti a Dio, che anche lui ha bisogno della misericordia di Dio e che se non è caduto in peccati anche gravi è perché Dio gli ha usato maggior misericordia! Chi cura la vita interiore non si sente mai superiore agli altri, ma sente crescere dentro di sé una grande compassione che lo fa sentire in comunione con tutto e tutti, perché sa che lui per primo ha bisogno della misericordia del Signore! Nessuno è giusto davanti a Dio, ma ognuno di noi è salvato per la misericordia che Dio ci ha mostrato nel suo Figlio Gesù! Ecco perché il pubblicano che chiede solo perdono, senza mettersi a paragone con nessuno; e solo lui torna a casa giustificato. <em>«L’esperienza di fede infatti ci dà una parte un grande realismo su chi siamo noi, sulla nostra miseria, sui nostri limiti, sulle nostre fragilità, ma allo stesso tempo ci fa sentire profondamente amati così come siamo e proprio per questo innesca in noi una possibilità di cambiamento» (don Luigi M. Epicoco). </em></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-29';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>La parabola di oggi ci parla della libertà di due figli e di ciò che arreca al padre. Vi è un figlio minore che ad un certo punto della sua vita dice al padre: «dammi la mia parte di eredità». Questo <em>dammi</em> è una parola molto in voga oggi. Questo figlio domanda le cose del padre. Qui vi è la prima grande riflessione: desiderare le cose invece di una relazione. L''amore dice dono, l’egoismo dice dammi. «Pochi giorni dopo, il figlio più giovane, raccolte tutte le sue cose, partì per un paese lontano e là sperperò il suo patrimonio vivendo in modo dissoluto». La seconda cosa che accade quando si vive ripiegati sui propri bisogni non è una semplice sensazione di insoddisfazione ma anche l''esperienza dell''allontanamento. È il delirio di sentirsi autosufficienti, perché ci si illude di bastare a se stessi. <em>Il dammi</em> si è trasformato in <em>“faccio ciò che voglio”</em>; ma questo “faccio ciò che voglio” non libera questo figlio ma lo rende uno schiavo insoddisfatto, affamato, deluso. Eppure, come spesso accade, è questo il momento in cui si può riflettere sul senso della vita, su dove si sta andando. Questo figlio comprende che ha lasciato ciò che veramente buono, e questo suo rientrare in se stesso lo conduce a far ritorno, al ritornare all’origine buona, alla casa del Padre; ed è qui che scopre le cose belle che aveva lasciato ma che non aveva compreso ed apprezzato. È qui che si sente amato dal Padre, è qui che la sua venuta provoca la gioia del Padre, è qui che la festa della vita ha inizio.</span></p>
<p>
 <span>Ma di fronte a questo ritorno, a questa festa della vita, vi è la reazione del figlio maggiore: «Egli si indignò, e non voleva entrare». Sembra strano, ma la felicità degli altri molto spesso risveglia dentro di noi gelosia, invidia. Quando noi non siamo contenti della nostra vita, la vita ritrovata degli altri a volte non suscita in noi la gioia. Non si riesce a partecipare della gioia degli altri. Non è necessario andarsene da casa come aveva fatto il figlio minore per sentirsi soli. A volte basta un senso di incomprensione e di ingiustizia a farci percepire lontani dalle persone che ci vivono accanto. Questo figlio maggiore, pur essendo rimasto fisicamente sempre vicino al padre, è stato così lontano da lui da giudicare la vita e il cuore degli altri a cominciare dal cuore del padre. Egli non </span><em>«dice mai “padre”, non dice mai “fratello”, pensa soltanto a sé stesso, si vanta di essere rimasto sempre accanto al padre e di averlo servito; eppure non ha mai vissuto con gioia questa vicinanza. E adesso accusa il padre di non avergli mai dato un capretto per fare festa. Povero padre! Un figlio se n’era andato, e l’altro non gli è mai stato davvero vicino! La sofferenza del padre è come la sofferenza di Dio, la sofferenza di Gesù quando noi ci allontaniamo o perché andiamo lontano o perché siamo vicini ma senza essere vicini» (papa Francesco). </em></p>
<p>
 <span>In fondo l’atteggiamento prepotente del figlio maggiore ci appartiene. Quando le cose non vanno secondo i nostri pensieri o i nostri schemi ce la prendiamo con tutti, Dio compreso. Perciò, chiediamo la grazia di aprirci al nuovo di Dio che è diverso dal nostro, di saper gioire con gli altri e per la gioia degli altri. Questa non ci toglie nulla e non indica che Dio ci ama di meno. E se le cose non vanno come vorremmo, ricordiamo che in quel momento Dio ci è ancora più vicino, e ci chiede di imparare ad accogliere e ad offrirgli ciò che ci fa male, perché le nostre sofferenze e le nostre difficoltà diventano feconde se sono vissute con Lui e in Lui. </span></p>
<p>
 <span>Alla luce di tutto ciò, dobbiamo ammetterlo: noi siamo un po’ ambedue i figli della parabola, perché a volte somigliamo a uno e a volte all’altro. Perciò, oggi vogliamo chiedere al Padre la grazia di vivere come suoi figli che non si allontanano mai da Lui e che sanno gioire con Lui. Spetta a noi scrivere il finale di questa storia.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-30';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>PREGHIERA</em></span></span></p>
<p>
 <span><span><em>Signore Gesù Cristo, </em></span></span><em>tu ci hai insegnato a essere misericordiosi come il Padre celeste, </em><em>e ci hai detto che chi vede te vede lui. </em><em>Mostraci il tuo volto e saremo salvi (papa Francesco).</em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-30';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Arriva un momento nella vita dove sperimentiamo tutta la nostra impotenza nell’affrontare certe cose. Ora, quella difficoltà è, o almeno può essere, se lo vogliamo, la porta d’ingresso perché Gesù possa entrare nella nostra vita. Il Vangelo di oggi ci parla di un funzionario del re, non dice il suo nome, ma dice che è un padre. È il padre di un figlio gravemente ammalato ed è proprio questo dolore che lo spinge a mettersi in cammino. È consapevole che Gesù è l’Unico che può guarire suo figlio, ed è con questo desiderio del cuore che si mette in cammino. Davanti a ciò, chissà noi con quale fretta, con quale desiderio, con quale fede andiamo incontro a nostro Signore nelle difficoltà della vita, per presentargli anche le persone che amiamo, per affidarle alla sua infinità bontà e misericordia. Ma ciò che colpisce ancora di più in quest’uomo è la sua fede nella parola del Signore: «egli credette alla parola del Signore che gli aveva detto [= va’, tuo figlio vive]». Ed è con questa certezza che intraprende il viaggio di ritorno e riconosce il segno nell’orario in cui Gesù gli aveva detto ciò. Quest’uomo crede e sa cogliere i segni. E noi? Chissà se anche noi sappiamo cogliere i segni del passaggio di Dio nella nostra vita! Passaggi spesso discreti, silenziosi, di un Dio che non si mostra con segni eclatanti ma con i segni del suo amore. Certo, a volte non avvengono guarigioni eclatanti come in questo caso, ma ciò non deve mettere in discussione l’amore di Dio per noi! Lui è anche un Dio misterioso che agisce per vie a noi sconosciute, e a noi chiede solo di fidarci di Lui. Alla fine di questo racconto, è interessante notare che credette non solo l’uomo ma, con lui, tutta la sua famiglia. Ecco, la fede certa di una persona produce meraviglie negli altri, permette al Signore di lavorare il cuore degli altri. In quante famiglie abbiamo assistito a miracoli di conversione grazie al sì di una moglie, o di un marito, o di una nonna, o di un giovane. Quanti danno la propria vita per la salvezza degli altri! Sta scritto che non c’è amore più grande di chi dona la propria vita per gli altri! E noi, cosa vogliamo donare della nostra vita?</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-03-31';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em>«Non credo ad una fede che impedisce di soffrire: la fede in un Cristo crocifisso non può essere tale. Credo invece alla fede che spiega e colloca nell''ordine dell’amore sia la sofferenza sia la morte; credo alla fede che, attraverso il dolore, ci fa entrare in una beatitudine oscura ma definitiva» (Madeleine Delbrêl). </em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-03-31';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Non è forse scontato che un uomo malato da trentotto anni desideri guarire? Perché allora fare una domanda che sembra ovvia?      Gesù ci insegna l’arte del saper chiedere, lasciando all’altro lo spazio di riflettere su sé stesso, sui suoi bisogni, su ciò che veramente gli è caro. Le domande di Gesù avevano proprio la qualità di far emergere la fiducia in sé stessi, far sentire l’uomo capace di Dio, veramente libero e responsabile. Perciò, la domanda posta al paralitico era indispensabile per spingerlo a guardarsi dentro, per fare verità. Dobbiamo riflettere sul fatto che l’annuncio di Gesù, che spesso è presentato come la risposta a tutto, ha in realtà una natura dialogica: Gesù più che rispondere, domanda. A noi talvolta piace essere riconosciuti come maestribenefattori ai quali gli altri devono rendere grazie, quelli che sanno tutto e sono portatori di saggezza, quelli che dispensano risposte. Gesù, invece, fa all’uomo il dono di poter essere sé stesso, di sapersi libero e amato. </span><span>In questa cornice dialogica, cogliamo due punti sui quali lavorare oggi. Gesù ci insegna che il bene dell’uomo è prioritario rispetto al sabato, sottolineando che l’Amore viene prima di ogni cosa. Quando il paralitico fu guarito, alcuni gli ricordarono che: “di sabato non è lecito guarire!”, poiché secondo la legge, il sabato (come la nostra domenica) è un giorno di riposo dedicato alla preghiera, alla famiglia e a Dio. Era come se dicessero: “com’è possibile pensare di tornare a camminare proprio di sabato?”. Le regole avevano ormai preso il sopravvento sull’amore, tant’è che invece di gioire per il miracolo ricevuto dall’uomo si pensava a quanto fosse corretto guarire in quel giorno. Facciamo attenzione, fratelli e sorelle, a non cadere negli estremismi. Questo brano del Vangelo non è così lontano da noi come potrebbe sembrare. A volte, le regole e le nostre certezze possono portarci a costruire barriere e persino un cameratismo escludente, che finisce per privare gli altri della loro dignità. Non accade forse nelle famiglie di trovarsi di fronte a persone che vengono considerate non in grado di gestire, parlare, giudicare, con il risultato che gli altri assumono un atteggiamento da maestri, rischiando di ferirne la dignità? Non facciamo così quando riteniamo qualcuno privo di esperienza o capacità? Quante volte nelle nostre case si zittisce un familiare solo perché il suo modo di pensare è diverso dal nostro e mette in discussione le nostre certezze? E nelle nostre comunità cristiane, non risuona forse quel famoso detto, “abbiamo sempre fatto così!”, che ci rinchiude nel conformismo? Cari fratelli e sorelle, non dobbiamo avere paura davanti alle nostre paralisi, riconoscerle ci fa risorgere. </span><span>Il secondo punto su cui vogliamo riflettere oggi riguarda il paralitico, simbolo non solo di una condizione fisica deficitaria ma anche di una profonda esclusione sociale. Quest’uomo, abituato a pensarsi solo, era convinto che gli fosse negato l’aiuto: altri, più rapidi di lui, si immergevano nella piscina prima, togliendogli ogni opportunità di guarigione. La sua unica scelta sembrava essere la rassegnazione. Ma il Signore interviene per aprire nuove prospettive di speranza. Egli ci invita, come ha fatto con il paralitico, a uscire dalla chiusura in noi stessi e dalla visione disfattista della realtà. Ci chiama a reagire alle strutture di peccato che ci opprimono e ci privano della dignità, invitandoci a un nuovo modo di rapportarci al mondo. Qualunque sia la nostra “paralisi”, non siamo soli né destinati a rimanere vittime. Possiamo alzare lo sguardo, perché il regno dei cieli può vivere in mezzo a noi. Gesù, con la Sua presenza viva ed efficace, ci chiede: «Vuoi guarire?». Sta a noi accogliere questa chiamata, rimanere saldi nella preghiera per liberarci da ciò che ci tiene immobili, che spesso non è una barriera fisica ma un impedimento, un’incapacità, una paralisi interiore che ci priva della speranza.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-01';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«È bello, Gesù sempre dice questo a noi: Vuoi guarire? Vuoi essere felice? Vuoi migliorare la tua vita? Vuoi essere pieno dello Spirito Santo? Vuoi guarire?’ […] Credere in Gesù è prendere la vita così com’è e andare avanti con gioia, senza lamentele, senza lasciarsi paralizzare dal brutto peccato dell’accidia. Oggi il Signore a ognuno di noi dice: ‘Alzati, prendi la tua vita come sia, bella, brutta come sia, prendila e vai avanti. Non avere paura, vai avanti con la tua barella’ – ‘Ma Signore, non è l’ultimo modello…’. Ma vai avanti! Con quella barella brutta, forse, ma vai avanti! È la tua vita, è la tua gioia. ‘Vuoi guarire?’, prima domanda che oggi ci fa il Signore? ‘Sì, Signore’ – ‘Alzati’. E nell’antifona all’inizio della Messa c’era quell’inizio tanto bello: ‘Voi che avete sete venite alle acque – sono acque gratis, non a pagamento – Voi dissetatevi con gioia’. E se noi diciamo al Signore ‘Sì, voglio guarire. Sì, Signore, aiutami che voglio alzarmi’, sapremo com’è la gioia della salvezza» (papa Francesco).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-01';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Cercavano di ucciderlo perché Gesù violava il sabato e chiamava Dio suo Padre, facendosi uguale a Lui. Queste parole ci dicono una motivazione dell’avversione verso Gesù, e sono forti perché ci mostrano la percezione di Gesù che avevano alcuni che lo ascoltavano. Gesù sovvertiva gli schemi; possiamo dire che era scomodo! La scomodità del suo annuncio e della sua vita non derivava dal fatto che egli animava moti rivoluzionari o la disobbedienza civile, ma dal fatto che affermava la verità di sé stesso. La scomodità, perciò, era conseguenza della verità che annunciava, del mostrarsi senza infingimenti. Essere noi stessi è un grande dono, che non vuol dire che siamo già buoni e perfetti, ma che nella sincerità ci mostriamo e siamo pronti umilmente a trasformare il nostro cuore alla luce dell’Amore di Dio. È un grande esercizio quello della verità su noi stessi, perché ci porta a non vivere di finzioni, cercando di adattarci sempre alle circostanze: ricchi di buone maniere quando c’è da sembrare buoni, scaltri quando c’è da cogliere occasioni per riempirci le tasche; escludenti quando l’altro ci scomoda, amiconi quando l’altro ci serve. Gesù ci invita a vivere come persone responsabili e risolte che non si sentono sempre insufficienti se non si adattano al “fare comune”, consapevoli che il proprio valore risiede nella verità davanti a Dio. Chi vive così è disposto a spendersi per portare avanti umilmente e con speranza ciò in cui crede. Oggi, perciò, prendiamo un proposito di verità, per essere dei veri rivoluzionari dell’amore. I sacramenti ci aiutano in questo percorso di verità, ci aprono il cuore, ci rendono portatori di una luce che illumina di novità; una luce scomoda ma sempre gentile.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-02';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span>«Io credo che l’uomo non possa realizzarsi senza il silenzio e la preghiera. Ciò che più manca a questo nostro tempo, a questa civiltà, è lo spirito di preghiera. Questa sarebbe la vera rivoluzione: il mondo non prega? Io prego. Il mondo non fa il silenzio? Io faccio il silenzio. E mi metto in ascolto. Rivoluzione non consiste nel rompere o nel distruggere, ma nell’immettere uno spirito nuovo nelle forme di sempre. Ciò che più manca è proprio il rapporto con il mistero, l’apertura sull’infinito di Dio: per questo l’uomo è così solo, insufficiente e minacciato» (p. David Maria Turoldo).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-02';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il Signore ci pone davanti a un’evidenza: se conosciamo le cose di Dio ci accorgiamo prontamente di quando Egli agisce e opera. Una religiosità che ammanta di sacralità l’umano ma non è nutrita dalla presenza di Gesù, è soltanto esteriore e porta a non riconoscere le cose di Dio. Si invera così una contraddizione: dirsi cristiani ma non somigliare a Gesù. Rimanere nel Signore è il contrario di utilizzare la fede per sentirci possessori del divino da dispensare agli altri. Perciò Gesù usa parole forti: «come potete credere, voi che ricevete gloria gli uni dagli altri, e non cercate la gloria che viene dall’unico Dio?». Sì, chi utilizza la fede per cercare la gloria, usa Dio per un proprio tornaconto. Possiamo essere noi quelli che vivono una fede così, esteriore, una fede del solo ricevere per sentirsi riconosciuti e importanti, i migliori della famiglia, gente onesta per il proprio paese: “quelli che vanno in chiesa!”.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-03';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Non vi ricordate di quella mezza pagina di Vangelo? «Simone, mi ami tu?». Affermare una presenza è un amore. Osservare delle leggi è una routine, un''abitudine, una convenienza, qualcosa «a Dio spiacente ed ai nemici sui» che non vale granché, che non vale niente, che non impone molto da scegliere. È la differenza tra il moralismo e la rivoluzione morale cristiana, che nasce dall''incontro con una presenza da cui scaturisce un amore che, lasciandoti tale e quale, con tutti i tuoi sbagli, con tutti i tuoi errori, ti cambia. La rivoluzione morale cristiana, che è un cammino teso a realizzare un destino, spinto e attratto da un amore, si differenzia dal moralismo, che è un insieme di leggi, di norme applicate, un buon ordine applicato. La questione è grossissima, amico mio. Se tutto parte dal riconoscimento di una presenza, nasce da un amore. Se parte, invece, non dal riconoscimento nudo e crudo di una presenza, ma anche da qualche altra cosa, è moralismo. Non è più amore, ma è un''abitudine, una soggezione, un tornaconto» (don Luigi Giussani).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-03';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>La vita pubblica di Gesù fu tutt''altro che semplice. Egli era costretto a spostarsi da una città all''altra anche per sfuggire ai tentativi di ucciderlo, mentre le persone, come riportano i Vangeli, mormoravano alle sue spalle. Era risaputo che Gesù fosse visto male da alcuni e verso di Lui si attuava un atteggiamento ambivalente: certi capi del popolo, non rimproverandolo, inducevano qualcuno a pensare che le sue opere fossero autentiche, mentre altri, dopo aver udito le sue parole di testimonianza, cercavano di denigrarlo e farlo arrestare. Tuttavia, nessuno vi riuscì fino all’ora della crocifissione. Ogni realtà sinceramente cristiana somiglia a questa pagina del Vangelo. In alcune parti del mondo si parla di vere e proprie persecuzioni dei cristiani, soprattutto quando si trovano ad essere una minoranza. In generale, però, dirsi cristiani, anche in società di tradizione cattolica, espone a un certo sarcasmo. Molti pensano alla Chiesa come ad un’istituzione obsoleta, che cerca ancora a stento di imporsi nella società. Questo può essere un bene, perché questa persecuzione dell’indifferenza, richiede ai cristiani il coraggio della testimonianza, di smettere di pensarsi come “piazza del paese” o “l’ombelico del mondo”. Forse ci ha fatto male questa pretesa di verità assoluta da imporre agli altri, questo dominare gli spazi. Spesso non si è testimoniato il regno di Dio e la Chiesa di Cristo, ma si è attestato un regno del potere. Accettare come il “potere sugli spazi” sia una via fallimentare è un buon inizio per ricordarci che siamo figli di un Dio che si è fatto uomo, e non un uomo con le insegne regali ma un tipo di uomo specifico: povero, itinerante, umile, mansueto, misericordioso, inclusivo, amante della verità e della giustizia. Se Dio si è mostrato così con noi, vuol dire che, come cristiani, dobbiamo portare prima di tutto il suo esempio. Il nostro compito non è incidere nella società, vincere, imporci, avere potere, essere rilevanti, essere un riferimento per gli altri. A noi è chiesto molto di più, come ci ricorda il Vangelo: «Voi siete il sale della terra […] Voi siete la luce del mondo» (Mt 5, 13.14). Per fare questo, non serve il potere, serve la gentilezza del sale e del lievito, che se si impongono guastano tutto. Il cristianesimo va avanti a prescindere dalle nostre megalomanie, perché si nutre di una presenza divina efficace, spesso testimoniata in modo straordinario da tante anime buone nel popolo di Dio: tante mamme, nonne, sorelle, come vescovi, sacerdoti, religiosi, suore, diaconi, persone a volte irrilevanti secondo i criteri del mondo ma decisive e incisive nell’ottica di Dio.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-04';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Il Vangelo […] non esisterebbe nella nostra storia se non fosse reso effettivamente «presente»: innanzi tutto da Gesù Cristo stesso– e in suo nome – dai suoi, cioè dalla sua Chiesa. La tradizione cristiana non è una religione del «libro», foss''anche la religione della Bibbia, unicamente a disposizione di coloro che la sanno leggere, né quella di una «dottrina complessa» […] No, il Vangelo è una «presenza» (parousia) di persone in relazione da esso abitate, una «presenza» ecclesiale sempre nuova perché in situazione, qui e ora. Solo una tale «presenza» concreta in mezzo agli uomini e alle donne, e in seno alle nostre società in carenza di fiducia, potrà essere all''altezza […] e ripristinare la credibilità della Chiesa» (Christoph Theobald sj,). </span></em></span></p>
<p>
 <strong><span><em><span>Oggi ricordiamo Francisco de Jesus Marto, uno dei piccoli santi pastorelli di Fatima:</span></em></span></strong></p>
<p>
 <span><em><span>La vita di Lucia, Francesco e Giacinta, piccoli pastori di Fatima, è una storia di grazia e misericordia. In questi bambini vediamo messa in atto la stessa forza paradossale che sigilla tutta la storia della salvezza: la sproporzione infinita tra la storia dei superbi e dei potenti, con i loro schemi, strategie e conflitti e la storia degli umili che, nella verità della loro esistenza, sono invitati da Dio ad essere fermento di trasformazione dell’umanità. Come veggenti della misericordia di Dio, i pastorelli renderanno visibile il messaggio che hanno accolto, attraverso le loro vite innocenti. Sono stati testimoni della presenza dell’amore di Dio, di questo Dio che è Amore (1 Gv 4,8), rendendo trasparente al mondo il Suo volto misericordioso; esso convertirà la loro vita in un riflesso di quella Luce che era lo stesso Dio, nella quale, all’ombra di un leccio, la Signora li aveva fatti vedere a se stessi (M 170). Ricevono un invito inaspettato: «Volete offrirvi a Dio?» E’ con questa audacia che una Signora più splendente del sole, il 13 maggio del 1917, irrompe nella vita dei tre bambini alla Cova da Iria. Per sei mesi, ogni giorno 13, la Vergine Maria verrà a rinnovare tale invito, attraverso il quale i tre pastori saranno fatti umili testimoni del cuore di Dio, nella complessità di un mondo sofferente.</span></em></span></p>
<p>
 <span><em><span>Lucia, Francesco e Giacinta, ancora assaporando gli echi della profondità che hanno sperimentato, si accordano per non dire nulla di ciò che è accaduto. Ma Giacinta è presa dalla bellezza della Signora e la sua gioia è tale che non riesce a contenerla solo per sé. Lei è la prima messaggera di questa gioia divina, appena scoperta, che la Signora comunicava. E come i discepoli di Emmaus (Lc 24,32), che davanti al mistero pasquale avevano sentito ardere il cuore nel petto, confessa agli amici: "Ma io avevo qui dentro qualcosa che non mi permettava di star zitta" (M 45). La notizia delle manifestazioni della Signora del Rosario presto farà il suo cammino. E se il numero di coloro che giungono, pellegrini, alla Cova da Iria non cesserà di aumentare, i piccoli dovranno molto soffrire per mano di coloro che dubitavano o che gli si opponevano. Già nel primo incontro, confermando il fiat dei bambini, la Signora li aveva avvisati che avrebbero dovuto soffrire molto. Allo stesso modo dei profeti (Ger 1,19), la vocazione dei bambini accoglie la sofferenza come parte integrante della loro missione. Saranno molti ad accusarli di frode o di ambizione. Le stesse famiglie dei bambini, tranne forse il padre di Francesco e Giacinta, temono che essi stiano diffondendo una menzogna e sono in ansia per la loro vita. In casa e ovunque sono sottoposti a incontri e a interrogatori incessanti ed estenuanti. Ma la prova più grande sarebbe arrivata il 13 agosto. La mattina di quel giorno, i bambini sono sorpresi dalla visita del sindaco del Comune di Ourem, conosciuto massone e libero pensatore. Dopo averli interrogati in casa loro e nella canonica, volendo a tutti i costi che gli rivelino il segreto che essi insistono a non rivelare, il sindaco si propone astutamente per accompagnarli alla Cova da Iria, portandoli, tuttavia, a casa sua a Ourém. Lì continua a far pressione sui piccoli affinchè rivelino il segreto, arrivando a metterli per qualche tempo in una cella con altri detenuti e a minacciarli di farli friggere nell’olio. La risposta innocente di Francesco irradia pace e gioia: «Se ci ammazzano, come dicono, fra poco saremo in Cielo! Che bello! Non m’ importa niente» (M 144). Riconsegnati ai genitori il 15 agosto, torneranno ad incontrarsi con la Bianca Signora il giorno 19, a Valinhos, ed in settembre e ottobre, alla Cova da Iria. Una grande moltitudine si raduna in questo ultimo incontro – assetati di Dio o semplici curiosi – ed è testimone di un segno, come la Signora aveva promesso. Ma per i piccoli, Lucia, Francesco e Giacinta, l’ultimo incontro diventa una permanente evocazione d’essere stati chiamati a fare della loro vita una benedizione (Gen 12,2).</span></em></span></p>
<p>
 <span><em><span>La vita dei piccoli pastori non cessò mai d’essere ritmata dal cuore di Dio. Il fiat dato alla Signora più splendente del sole veniva costantemente rinnovato dal desiderio innocente di Lucia, Francesco e Giacinta di attualizzare, nella loro vita, l’innamoramento di Dio. […] La vita di Francesco, Giacinta e Lucia assume questa vocazione inseparabilmente contemplativa, compassionevole e annunciatrice. Ma ciascun dei bambini assumerà con maggiore rilevanza la specificità della sua chiamata. </span></em></span></p>
<p>
 <span><em><span>Francesco Marto, mosso dal suo sguardo interiore sensibile alla luce dello Spirito, si sente chiamato all’adorazione e alla contemplazione. Si rifugiava dietro una roccia o sulla cima di un monte per pregare da solo. Altre volte ancora, stava lunghe ore nella chiesa parrocchiale, nell’intimità del silenzio, a tenere compagnia a Gesù nascosto. Lì rimaneva a pregare e pensare a Dio, assorto nella contemplazione del mistero insondabile di Colui che viene incontro all’uomo. Francesco, e solo lui, con lo sguardo del suo cuore, scopre la tristezza di Dio di fronte alle sofferenze del mondo, soffre con essa e desidera consolarLo (M 145). Il piccolo pastore, che non aveva sentito l’Angelo e la Signora, soltanto li aveva visti, è il più contemplativo dei tre pastori. In tal modo si evidenzia che, nella vita di questo bambino, la contemplazione nasce dall’ascolto attento del silenzio che parla di Dio, del silenzio in cui Dio parla. L’atteggiamento contemplativo di Francesco è quello di lasciarsi abitare dall’ indicibile presenza di Dio  «Io sentivo che Dio stava in me, ma non sapevo come era!» (M 138)  ed è questa presenza che deve essere trasfigurata in accoglienza orante dell’altro. In Francesco si scopre una vita di contemplazione.</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-04';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Gesù subisce la persecuzione in modo viscerale perché la gente e soprattutto i potenti dell’epoca cercavano di screditare profondamente quello che Egli era e rappresentava. Fu presentato come un ingannatore, un millantatore, un uomo che creava scompiglio e divisione, e anche chi credeva in Lui portava avanti diverse ipotesi su chi fosse davvero Gesù. Spesso pensiamo che il bene sia immediatamente palese e riconosciuto da tutti, in realtà tutto ciò che viviamo deve essere soggetto al discernimento. Se pensassimo che in modo assoluto ciò che è buono è visto da tutti, ci inganneremmo! Gesù, infatti, è arrivato al fallimento, ad essere rinnegato persino dalle persone vicine a Lui, che sono state amate da Lui, ma che hanno deciso di far finta di non conoscerlo, di scappare nel momento della prova, di litigare mentre si doveva restare uniti. Anche in questa epoca dove il mondo virtuale prende il sopravvento, esiste sempre più gente che decide di parlare della vita degli altri anche se non la conosce, che si associa con i like allo screditare gli altri senza riflettere sull’effetto che hanno le cattive parole. Gesù è stato ucciso non solo dalle mani di chi ha piantato i chiodi, da chi lo ha fustigato, incoronato di spine e issato su una croce; Gesù è stato ucciso dalle parole che annientano, dalla mancanza di discernimento di chi deve custodire gli altri. Il criterio utilizzato dai farisei per convincere la gente era: “Ha forse creduto in lui qualcuno dei capi o dei farisei?”. Cioè, il nostro criterio per stabilire se qualcosa è buono non è solo il numero, il seguito ma anche il prestigio di chi segue quell’opera. Se non sono criteri da sottovalutare, non possono diventare principi assoluti, tant’è che con questa modalità non è stato riconosciuto Gesù! Il buon Nicodemo, facente parte di una classe privilegiata, prova a dire: “La nostra Legge giudica forse un uomo prima di averlo ascoltato e di sapere ciò che fa?». È come dire: “guardate che stiamo tormentando una persona senza conoscerla, senza rispetto, con pregiudizio”. Eppure, la risposta è un altro pregiudizio: “Studia, e vedrai che dalla Galilea non sorge profeta!”. Cioè, tu che parli non sei abbastanza competente. Ma per attuare un discernimento c’è bisogno di una competenza da acquisire, da chiedere in dono, come regalo gratuito, che è l’amore. Questa è l’unica competenza che vale per la salvezza! Questo non è un invito a non studiare e approfondire ma ad utilizzare tutto ciò che facciamo e viviamo per imparare ad amare di più. A cosa serve sapere tutto su Dio e poi non riconoscerlo presente nella storia? Quali sono i nostri criteri di discernimento? Un parroco di campagna con tre vecchiette che celebrano con lui, può essere sconosciuto, disprezzato perché non è un grande predicatore, ma essere un uomo che vale veramente agli occhi di Dio. Perché? Gesù non pone come criterio di qualità il numero, la sapienza umana, la provenienza, la posizione sociale… no, solo l’amore è il criterio. Finalità ultima di ogni discernimento è conformarsi a Cristo, all’amore. San Paolo lo dice chiaramente nella lettera ai Corinzi: «[se] non avessi l’amore, non sarei nulla» (cf 1Cor 13,1-13).</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-05';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Per essere compiacenti con ogni tipo di potere abusante, bisogna adattarsi al modo comune di pensare le cose, di recepirle, di giudicarle. Il banco di prova per Gesù, perciò, non poteva che essere una donna considerata “irregolare”, fuori dagli schemi, una da poter mettere in mezzo, una di quelle persone che gli altri guardano con disprezzo. Questo, perciò, è il racconto di una donna usata, messa in mezzo anche fisicamente, esposta alla vista di tutti e, soprattutto, additata con chiarezza a Gesù con il titolo della sua colpa. Era un’adultera, una da lapidare per la legge religiosa. Lo stabiliva perciò la Legge di Dio. Perciò quella domanda posta a Gesù: “Tu che dici?” è proprio un modo di mettere alla prova Colui che con le donne parlava anche da solo, Colui che vogliono dimostrare essere un “fuori Legge”, uno che di Dio non ne sa nulla. Coloro che organizzarono questo smascheramento di Gesù non erano persone qualsiasi, erano uomini di Dio, abituati però a ritenere i principi superiori alle persone, le loro regole superiori al bene dell’altro. Per osservare una regola potevano perciò reprimere anche certi sentimenti umani basilari. Chissà se quella donna l’avevano vista passare o se era stata trovata in adulterio poco prima; ma la provocazione di quegli uomini che presto sarebbero passati all’azione, facendo compiere la legge che prevedeva la lapidazione, incontra il silenzio, possiamo dire il silenzio di Dio che scrive. Con un’immagine suggestiva possiamo dire che si tratta di Gesù che scrive sulla sabbia, dove il vento del perdono può portare via ogni segno di peccato. Quel distacco silenzioso di Gesù e l’insistenza di quegli uomini per ricevere una risposta, fa sì che possiamo oggi ripetere parole bellissime pronunciate da Gesù dopo essersi alzato in piedi: «Chi di voi è senza peccato, getti per primo la pietra contro di lei». È l’espressione di Gesù che dovremmo aver presente ogni giorno, perché ci ricorda che non siamo meglio degli altri, non possiamo dirci in nessun modo superiori. Il Papa è senza peccato? Il cardinale, il vescovo o il sacerdote insieme ai diaconi sono senza peccato? Oppure i laici praticanti? Secondo una certa mentalità, dire che questi ultimi sono peccatori ci suona bene ma più saliamo nominando quelli che abbiamo fatto diventare dei “livelli di vicinanza” a Cristo, più la parola “peccatori” stride. Ecco, dobbiamo sapere che anche i santi erano peccatori! Nessuno di noi, perciò, si può porre su un piano superiore riguardo alla propria dignità umana. Papa Francesco, perciò, più volte nel suo ministero ci ha ripetuto: <em>«Ricordiamoci che è lecito guardare una persona dall’alto in basso soltanto per aiutarla a sollevarsi: niente di più. Noi cristiani dobbiamo avere lo sguardo di Cristo, che abbraccia dal basso, che cerca chi è perduto, con compassione» (Angelus, 30.10.2022).</em></span></p>
<p>
 <span>Questa scena rappresenta in modo sublime l''amore di Gesù, un amore che si china, si abbassa con umiltà per sollevare non solo la donna ma anche i farisei, colpevoli di un grave peccato: quello di ferire la vita altrui pensandosi puri davanti a Dio. Quegli uomini religiosi si ritrovarono davanti alla verità della propria coscienza; e, consapevoli del loro essere peccatori, abbandonarono uno ad uno il luogo, senza osare scagliare alcuna pietra contro la donna. Questo gesto silenzioso è un potente richiamo alla misericordia e alla consapevolezza dei propri limiti. Chissà quella donna invece cosa provò! Liberata dalla paura dell’altro, ricollocata nella giusta dimensione di figlia amata si sente dire: «”Donna, dove sono? Nessuno ti ha condannata?”. Ed ella rispose: “Nessuno, Signore”. E Gesù disse: “Neanch''io ti condanno; va'' e d''ora in poi non peccare più”». </span></p>
<p>
 <span>Come cristiani, quand’è che abbiamo smesso di ricordare al mondo che Dio è un Padre amorevole, che educa all’amore e non è un lapidatore di peccatori? Quand’è che abbiamo smesso di ricordare che non siamo superiori agli altri al punto da poterli lapidare in nome di Dio? Anche nelle nostre case, nelle nostre comunità, nei luoghi di lavoro, dovremmo chiederci se le persone e la loro dignità valgono più di ogni cosa e di ogni loro peccato e, soprattutto, se siamo persone che condannano gli altri, che manipolano e usano le relazioni per il proprio tornaconto. I maestri spirituali ci insegnano come combattere questo atteggiamento comune e malevolo: <em>«[Alcuni] fanno giudizi temerari, non per acidità, ma per orgoglio; pensano che nella misura in cui abbassano l''onore degli altri, alzano il proprio! Sono spiriti arroganti e presuntuosi, pieni di ammirazione per se stessi, che si collocano così in alto nella propria stima, da vedere tutto il resto come cose piccole e basse […] Quali sono i rimedi [per ogni persona giudicante]? Coloro che bevono un estratto di un oppiaceo detto ofiusa, che cresce in Etiopia, credono di vedere ovunque serpenti e altre cose orribili: coloro che hanno trangugiato orgoglio, invidia, ambizione, odio, vedono tutte le cose come cattive e riprovevoli; chi ha bevuto l''oppiaceo, se vuol guarire, deve bere vino di palma; la stessa cosa devono fare i viziosi di cui sopra. Bevi più che puoi il sacro vino della carità; ti libererai da quegli umori perversi che ti fanno dare giudizi. […]. Per tutti i mali il grande rimedio è la carità; in modo particolare per questo» (San Francesco di Sales Filotea, Capitolo XXVIII).</em> In qualsiasi modo ci approcciamo agli altri, cerchiamo di rifiutare la condanna, anche quando dobbiamo dire la verità, che è un segno di amore autentico per l’altro. Gesù non nasconde alla donna il suo essere peccatrice, sa cosa ha fatto la donna, ma nella verità la rialza, non la condanna. Nel nostro rapporto con gli altri siamo chiamati non solo a evitare di condannare ma anche a non ostacolare l’azione di Dio nel cuore di ogni anima. Non spetta a noi decretare che qualcuno sia perduto per sempre, assumendoci un ruolo che appartiene solo a Dio. </span></p>
<p>
 <span>Preghiamo, invece, che il Signore ci doni il Suo sguardo misericordioso, capace di discernere il bene con acutezza, affinché possiamo essere strumento del Suo abbraccio e portare luce e amore all’umanità.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-06';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>PREGHIERA</em></span></span></p>
<p>
 <em>Signore, anche oggi, pure se abbiamo perso perfino la nozione di peccato, siamo sempre pronti ad accusare: Signore, vorremmo dirti grazie con il cuore stesso dell''adultera e sentirci tutti come lei quando le dicesti: «Donna, va'' in pace» (p. David Maria Turoldo).</em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-06';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>I confronti tra farisei, scribi e Gesù erano intensi e carichi di tensione. Era chiaro che fossero alla ricerca di qualsiasi pretesto per accusarlo, alimentati dal desiderio di screditare il suo messaggio. Tuttavia, è possibile che alcuni tra loro tentassero, seppur con difficoltà, di comprenderlo, lottando contro i pregiudizi radicati nei loro cuori e cercando di conciliare la particolarità di Gesù con le proprie convinzioni. Queste ultime sono spesso all’origine di molte distorsioni della realtà. Ogni volta che, invece di lasciarci interrogare dalla realtà, cerchiamo di piegarla ai nostri schemi o di idealizzarla, perdiamo di vista la sua complessità. Va anche riconosciuto come non fosse semplice, per i sacerdoti dell’epoca, confrontarsi con un uomo che, apparendo simile a loro, affermava: «Io sono la luce del mondo!». In una situazione simile forse anche noi avremmo reagito con scetticismo, chiedendoci: “Ma dai testimonianza a te stesso? Sarà solo vanagloria?”. Se da un lato i pregiudizi giocano un ruolo importante, dall’altro non si può ignorare l’esistenza di una difficoltà oggettiva nel comprendere l’unicità di Cristo. Eppure, ciò che Gesù ci insegna, anche in queste circostanze, è il rispetto incondizionato che dobbiamo agli altri, indipendentemente da come ci appaiono o da ciò che rappresentano per noi. Una chiave di lettura per il discernimento, per accorgerci della presenza di Gesù e non ingannarci, può venirci dalle parole: «Voi non conoscete né me, né il Padre mio». Quando ci avviciniamo alle cose di Dio, il nostro cuore si apre alla sensibilità verso la Sua presenza, che possiamo riconoscere sia nel mondo che negli altri. Questo non significa diventare "creduloni" o "sensitivi" ma sviluppare la capacità di discernere con profondità e di riconoscere la voce del Pastore, la somiglianza con Cristo. A volte potremmo essere come i farisei, certi delle nostre ragioni ma incapaci di utilizzare un''intelligenza non solo emotiva ma anche spirituale che ci permetta di cogliere i segni di Dio. Quando vedo un figlio che con dedizione si prende cura di un genitore anziano posso scorgere Dio all’opera in quell’amore; quando incontro un credente che si astiene dal giudicare o sparlare di qualcuno che ha sbagliato o che appare diverso, lì riconosco Dio che opera attraverso la carità. E quando vedo un sacerdote, un diacono o una consacrata che, con totale dedizione, si schiera dalla parte dei poveri pagando di persona, sento profondamente la presenza di Dio in azione. Ecco, conoscendo Dio possiamo avvertire la Sua opera concreta che si propaga nell’umanità. Non facciamo come coloro che seppure esperti delle leggi di Dio, non riconoscevano la Sua presenza. Dio ci liberi da una razionalità asfittica, ci renda sensibili alla Sua presenza.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-07';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span>“Quando perdi la sensibilità del tatto o del gusto, te ne accorgi subito. Invece, quella dell’anima, quella sensibilità dell’anima puoi ignorarla a lungo, vivere senza accorgerti che hai perso la sensibilità dell’anima. L’insensibilità dei sensi spirituali riguarda la compassione e la pietà, la vergogna e il rimorso, la fedeltà e la dedizione, la tenerezza e l’onore, la responsabilità propria e il dolore per l’altro. È curioso: l’insensibilità non ti fa capire la compassione, non ti fa capire la pietà, non ti fa provare vergogna o rimorso per avere fatto una cosa brutta” (papa Francesco). </span></span></em></p>
<p>
 <em><span><span>L’esempio del santo del giorno</span></span></em></p>
<p>
 <strong><em><span><span>San Giovanni Battista de La Salle </span></span></em></strong></p>
<p>
 <em><span><span>Combatte l’ignoranza per tutta la vita, e molti combattono lui. Nato da genitori nobili, ma non ricchi, e con dieci figli, Giovanni Battista si laurea in lettere e filosofia; è sacerdote nel 1678, e a Reims assume vari incarichi, collaborando anche all’attività delle scuole fondate da Adriano Nyel, un laico votato all’istruzione popolare. Scuole che vanno male, però, soprattutto perché hanno maestri ignoranti e senza stimoli. E di qui parte lui. Dai maestri. Riunisce quelli di Nyel in una casa comune, vive con loro, studia e li fa studiare, osserva metodi e organizzazione di altre scuole... Comunica a questi giovani raccogliticci la gioia dell’insegnamento, dell’aprire scuole; li appassiona a un metodo che da “ripetitori” li fa veri “insegnanti”, abolendo le lezioni in latino, e introducendo in ogni disciplina la viva lingua francese. Da quel primo nucleo ecco svilupparsi nel 1680 la comunità dei “Fratelli delle Scuole Cristiane”: il sodalizio degli educatori. In genere non sono preti (lui li vuole laici, vicini al mondo che devono istruire nella fede, nel sapere, nelle professioni); vestono una tonaca nera con pettorina bianca, con un mantello contadino e gli zoccoli, e sotto la guida del La Salle aprono altre scuole. Nel 1687 hanno già un loro noviziato. Nel 1688 sono chiamati a insegnare a Parigi dove in un solo anno i loro allievi superano il migliaio. Poi cominciano le battaglie, e tutto sembra crollare. Il fondatore si trova via via attaccato dall’alto clero di Parigi, da vari parroci e dall’autorità civile, dai cattolici integrali e dai giansenisti, abbandonato da gente che credeva fedele, e più tardi anche esautorato. Lui in quei momenti si immerge – si inabissa, potremmo dire – nell’isolamento penitenziale, nella meditazione. Studia e si studia. Ma resiste, con la sua mitezza irreducibile. Da Parigi dovrà portare la sua comunità nel paesino di SaintYon, presso Rouen. Però la semina continua a dare frutti: nascono le scuole per adulti, le scuole per maestri, gli istituti d’istruzione nelle carceri, i collegi “di istruzione civile a pagamento”: e i suoi libri, trattati e sillabari pilotano l’opera dei maestri. Nei momenti più desolati giunge a dubitare della propria vocazione per la scuola e si accusa di nuocere alla stessa opera. Ma intanto le dedica ogni energia, scrivendo e insegnando per il futuro dei Fratelli, che la fine del XX secolo troverà presenti e attivi ben oltre i confini della Francia e dell’Europa. Quando muore nel piccolo centro di SaintYon, le sue case sono 23 e gli allievi diecimila. Ma per i funerali accade l’imprevedibile: trentamila persone si riversano nel paese per dargli l’ultimo saluto. Trentamila risposte a persecuzioni e tradimenti. Papa Leone XIII lo canonizzerà nell’anno 1900. E, cinquant’anni dopo, Pio XII lo proclamerà "patrono celeste presso Dio di tutti gli insegnanti".(Domenico Agasso, vaticanista).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-07';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>«Voi siete di quaggiù»: è l’espressione fondamentale di Gesù che ci dice il pericolo di rimanere persone “terra-terra”, cioè rimanere ancorati a troppa materialità, a una visione solo mondana che pensa al profitto. Una vita impostata in questo modo diventa rigida e stagnante, incapace di guardare oltre, giudicando il successo esclusivamente in base al consenso, all’apparire e al controllo su persone e situazioni. I farisei incarnavano questa mentalità distruttiva: per proteggere la loro immagine respingevano l’altro e non riuscivano a riconoscere la presenza di Dio. Anche noi rischiamo di cadere nella stessa trappola, facendoci scandalizzare dall’altro, finendo per escluderlo. Certamente bisogna ricordare che i farisei si trovarono davanti a parole che, secondo il loro modo di pensare, risultavano estremamente gravi: persino pronunciare il nome di Dio era vietato. Pensiamo dunque a come appariva ai loro occhi l’attribuire a sé l’essere Dio; doveva sembrare una provocazione intollerabile, quasi una follia. In questo contesto, come avrebbero mai potuto comprendere la verità profonda e disarmante di quelle parole? Noi ora ci sentiamo i perfetti che riconoscerebbero Gesù, che lo accoglierebbero immediatamente ma dobbiamo sapere che per accogliere la grazia bisogna aprire il cuore, in ogni contesto. Gesù, nel suo discorso, per aiutare ad accogliere la verità su sé stesso, non si appella alle sole parole: chiede di contemplare le sue opere che vengono dal Padre. Le opere di Dio impongono la loro verità, si affermano dal piccolo e diventano luminose per tanti. Anche noi, guardando le opere di Dio che ancora emergono nella storia, possiamo beneficiare della Sua presenza liberante. Quel Figlio dell’uomo innalzato di cui parla il Vangelo del giorno è proprio il crocifisso che rivela il Padre, l’opera d’amore di Dio per eccellenza. Egli non è solo una vittima finita per sbaglio su una croce senza aver fatto nulla, ma il Figlio di Dio che ci porta salvezza, che prende su di sé le brutalità umane, l’indifferenza, che viene abbandonato, che vede la madre soffrire: l’Amore che viene appeso. Quel crocifisso che molti cristiani portano al collo è proprio segno dell’Amore che viene innalzato, che non possiamo che contemplare.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-08';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Quando le tenebre della notte si apprestavano a scendere su quel Venerdì unico nella storia, quando ormai il sacrificio della Croce si era consumato e i presenti si affrettavano per poter celebrare regolarmente la Pasqua ebraica, le poche parole, carpite dalle labbra di un anonimo comandante della truppa romana, risuonarono nel silenzio dinanzi a quella morte molto singolare. Questo ufficiale della truppa romana, che aveva assistito all’esecuzione di uno dei tanti condannati alla pena capitale, seppe riconoscere in quell’Uomo crocifisso il Figlio di Dio, spirato nel più umiliante abbandono. La sua fine ignominiosa avrebbe dovuto segnare il trionfo definitivo dell’odio e della morte sull’amore e sulla vita. Ma così non fu! Sul Golgota si ergeva la Croce da cui pendeva un uomo ormai morto, ma quell’Uomo era il “Figlio di Dio”, come ebbe a confessare il centurione  “vedendolo morire così”, precisa l’evangelista. La professione di fede di questo soldato ci viene riproposta ogni volta che riascoltiamo il racconto della Passione secondo san Marco. Questa sera anche noi, come lui, ci soffermiamo a fissare il volto esanime del Crocifisso […] Abbiamo rivissuto la vicenda tragica di un Uomo unico nella storia di tutti i tempi, che ha cambiato il mondo non uccidendo gli altri, ma lasciandosi uccidere appeso ad una croce. Quest’Uomo, apparentemente uno di noi, che mentre viene ucciso perdona i suoi carnefici, è il “Figlio di Dio”, che  come ci ricorda l’apostolo Paolo  “non ritenne un privilegio l’essere come Dio, ma svuotò se stesso assumendo una condizione di servo… umiliò se stesso facendosi obbediente fino alla morte e a una morte di croce” (Fil 2,6-8). La dolorosa passione del Signore Gesù non può non muovere a pietà anche i cuori più duri, poiché costituisce l’apice della rivelazione dell’amore di Dio per ciascuno di noi. Osserva san Giovanni: “Dio ha tanto amato il mondo da dare il Figlio unigenito, perché chiunque crede in lui non vada perduto, ma abbia la vita eterna” (Gv 3,16). È per amore nostro che Cristo muore in croce! Lungo il corso dei millenni, schiere di uomini e donne si sono lasciati affascinare da questo mistero e hanno seguito Lui, facendo a loro volta, come Lui e grazie al suo aiuto, della propria vita </span></em></span></p>
<p>
 <span><em><span>un dono ai fratelli. Sono i santi ed i martiri, molti dei quali restano a noi sconosciuti. Anche in questo nostro tempo, quante persone, nel silenzio della loro quotidiana esistenza, uniscono i loro patimenti a quelli del Crocifisso e diventano apostoli di un vero rinnovamento spirituale e sociale! Cosa sarebbe l’uomo senza Cristo? Osserva sant’Agostino: “Ti saresti trovato sempre in uno stato di miseria, se Lui non ti avesse usato misericordia. Non saresti ritornato a vivere, se Lui non avesse condiviso la tua morte. Saresti venuto meno, se Lui non fosse venuto in tuo aiuto. Ti saresti perduto, se Lui non fosse arrivato” (Discorso 185,1). Perché allora non accoglierLo nella nostra vita?» (Benedetto XVI).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-08';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>In questo tempo di Quaresima meditiamo sempre più intensamente sulla passione di Gesù e su tutte le mancanze di libertà che ci rendono persone schiave e schiavizzanti. Gesù possiamo dire che è stato vittima di persone che credavano di essere libere ma non lo erano. È la verità che fa liberi, che fa prendere decisioni che non sono corrotte dal possesso, che ci fa custodire gli altri e non distruggerli. Secondo le parole di Gesù non possiamo essere liberi se la Parola di Dio non trova accoglienza vera in noi: «Se rimanete nella mia parola, siete davvero miei discepoli, conoscerete la verità e la verità vi farà liberi». Anche nella Chiesa le più grandi follie (che hanno creato e creano scandalo) vengono dalla mancata accoglienza della Parola di Dio, che viene proclamata ma non si fa carne e spesso viene resa un consiglio astratto ed estemporaneo, utilizzata strumentalmente, ma non vissuta come Parola viva ed efficace che opera in noi (cf Eb 4,12). Le peggiori follie spesso non sono frutto di un male strutturato e pensato ma dalla superficialità nel vivere la fede che genera repulsione in tanti cuori sinceri. Se la fede diventa un vestito elegante che sfoggiamo socialmente per sentirci migliori degli altri, se la fede dunque non si incarna in noi, non testimonieremo la forza liberante del Vangelo. Quando viviamo in modo superficiale è facile illuderci di essere liberi semplicemente perché le cose vanno secondo i nostri desideri o perché la fede è per noi strumentale, perché ci presenta socialmente come “brave persone” o perché, come nel caso di alcuni, ci procura un ruolo sociale o ci colloca politicamente. In questa prospettiva rischiamo di diventare “cristiani da salotto”, “attori della cristianità”, impeccabili solo in apparenza, pronti a esibirci nella società con mani pulite ma vuote. La vera libertà richiede autenticità e si manifesta con forza soprattutto quando dire la verità comporta sacrifici personali, quando seguire la Parola di Dio richiede impegno e costa fatica. Solo in questa autenticità evangelica la libertà trova il suo senso più profondo. Cosa è successo a quei buoni cristiani che si sono arruolati in guerra e hanno ucciso persone in nome dell’obbedienza? Cosa succede a coloro che in nome di Dio fanno la guerra o la benedicono? Cosa succede a coloro che vanno in Chiesa o fanno parte di una comunità cristiana ma alimentano divisioni? Dov’è la verità, la libertà, l’essere seguaci di Cristo che è amore? Quando la nostra fede viene messa alla prova nel quotidiano, quando dobbiamo schierarci dalla parte del bene ed essere costruttori di pace, quello è il momento nel quale si rivela ciò che amiamo. Se amiamo la terra e le cose della terra non ci sporcheremo per difendere gli immigrati, i poveri, i maltrattati. Se amiamo le cose del cielo, saremo inquieti finché la Parola non si fa carne in noi: «Se Dio fosse vostro padre, mi amereste». È un atto quotidiano di libertà vivere da cristiani nel luogo di lavoro, soccorrere il povero e lo straniero, soffrire per la verità, farci vicini a gente considerata disonorevole, persino a prostitute e filibustieri. Non faceva così Gesù? Cosa serve dirci cristiani ed essere schiavi dei pregiudizi, essere schiavi della vanità, essere schiavi del peccato anche se travestiti con insegne di libertà? E noi siamo persone libere? Siamo realmente capaci di fare totalmente spazio a Dio al punto che la Parola si faccia carne in noi? Qualsiasi ruolo ricopriamo, anche come sacerdoti o consacrati, non dovremmo mai abbassare la guardia, mai dovremmo dimenticare che siamo chiamati a libertà e a fuggire dalle schiavitù. Possiamo essere benissimo persone schiave del potere, del denaro, del pregiudizio, uomini e donne litigiosi, escludenti, schiavizzanti. Siamo disposti ad essere persone che accolgono realemente la Parola di Dio e che sanno essere libere davanti alle mentalità schiavizzanti, pagando persino di  persona? </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-09';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Noi riusciamo a conseguire la libertà soltanto se ci facciamo una giusta opinione della vita. Se non m’importa di quanto progredirò nella carriera e di quanto potrò guadagnare, allora sarò interiormente libero. Allora potrò oppormi alle ingiustizie che si perpetrano nella mia azienda. Allora potrà anche rischiare di nuotare contro corrente. Questo perché io non mi definisco a partire dalla reazione del capo o dell’approvazione degli altri, ma a partire da Dio. Se io sono consapevole di avere le mie radici in Dio, sono libero e non avrò bisogno di continuare a sbirciare che cosa pensano gli altri di me, nemmeno se mi accolgono bene. Naturalmente devo anche agire con giudizio ed essere consapevole dei miei limiti. Non posso combattere come un donchisciotte contro il mondo intero. Devo sapere quanta libertà mi posso concedere, in quale misura mi sorregge la fede di essere radicato in Dio. […] L’adattarmi continuamente per essere ben voluto dagli altri e per raggiungere i gradini più alti della carriera mi priva, oltre che della mia liberà, anche della mia dignità. Mi piegherà. E questo mi farà ammalare sia nel corpo che nell’anima» (p. Anselm Grün).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-09';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Le parole di Gesù penetravano profondamente nei cuori di molti. Tuttavia, la sua determinazione era fonte di timore tra i suoi conterranei, pensiamo a quando affermava: «Se uno osserva la mia parola, non vedrà la morte in eterno». Erano parole sconvolgenti ma non solo; Gesù ulteriormente arrivava a denunciare apertamente alcuni come menzogneri e si presentava senza ambiguità come Dio, dichiarando: «Se non credete che <em>Io sono</em>…». Questa affermazione suscitava scandalo e rabbia, tant’è che cercavano di ucciderlo. A ogni domanda insidiosa, nel tentativo di metterlo alla prova e screditarlo, Gesù rispondeva con fermezza, dichiarando che la sua gloria non proveniva dagli uomini ma era radicata nella verità divina che Egli incarnava. Anche noi come cristiani possiamo essere messi alla prova, essere fraintesi, essere tentati di dare gloria a noi stessi per essere riconosciuti e apprezzati, pensando che il senso di inadeguatezza che talvolta affiora si possa affrontare attraverso l''apparenza, costruendo un''immagine esteriore che possa guadagnare approvazione e riconoscimento. Pensiamo, perciò, di poter affrontare la vita non con la consapevolezza di essere figli ma con l’apparenza. Così, la tentazione di vivere da “sepolcri imbiancati” è sempre alle porte.  </span></p>
<p>
 <span>Allo stesso tempo possiamo anche comportarci come i farisei, cercando di incasellare gli altri nei nostri pregiudizi. Può capitare che proviamo a usare un linguaggio ambiguo, che alteriamo la realtà per renderla più comoda o che siamo tentati di giudicare con durezza chi sbaglia o chi è diverso da noi. Per i sacerdoti dell’epoca anche le opere buone di Gesù, per quanto straordinarie, non erano abbastanza convincenti. Non è forse molto simile ad alcuni comportamenti che noi attuiamo verso gli altri? Anche noi davanti all’altro possiamo essere chiusi, o essere vittime di un pregiudizio logico. Se qualcuno mi indica un nemico e mi ripete più volte la sua colpa associandola a tanti eventi, finirò per ritenere logico ogni nesso fra una situazione e un’altra, arrivando persino a riconoscere un generico straniero, povero, vicino di casa, come un nemico. Gesù perciò ci ha “intrappolato”, ci ha detto che nel povero, in quella persona strana, si nasconde Lui stesso, in persona” (cf Mt 25,40). Gesù si è identificato genericamente con gli scartati. Perciò dovremmo convertirci a uno sguardo genericamente buono, positivo, costruttivo. In questo tempo di Quaresima possiamo avvicinare ancora di più il nostro cuore a quello di Dio, così da guardalo per bene e vedere quanto gli somigliamo. </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-10';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>«San Giovanni della Croce ha voluto esprimere che nell’esperienza mistica l’amore incommensurabile di Cristo risorto non è sentito come estraneo alla nostra vita. L’Infinito in qualche modo si abbassa affinché attraverso il Cuore aperto di Cristo possiamo vivere un incontro d’amore veramente reciproco: «È infatti possibile che un uccello di basso volo prenda un’aquila reale dal volo sublime, se questa, desiderando di essere presa, viene in basso» (papa Francesco).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-10';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Il rifiuto di riconoscere Gesù non si limitava alle sue opere (e che di per sé non erano l’ostacolo principale). Il vero problema era che i suoi interlocutori avevano compreso perfettamente il significato delle sue parole: Egli si dichiarava Dio! Questa affermazione, così straordinaria e sconvolgente, superava i loro schemi e li spingeva a un rifiuto radicale, nonostante l''evidenza delle sue azioni straordinarie. La difficoltà stava proprio nell''accettare l''identità divina che Gesù proclamava con chiarezza. Quest’affermazione che rappresentava per loro una bestemmia era inaccettabile, perciò cercavano di catturarlo e ucciderlo. Il brano che oggi meditiamo, infatti, inizia con queste parole: «raccolsero delle pietre per lapidare Gesù». E Gesù cosa faceva? Fuggiva. Davanti ai farisei che non sono predisposti verso Gesù e che lo minacciano, non possiamo pensare in modo semplicistico ad un tipico buonismo umano. Gesù non era un “buonista” che viveva di fantasie, Egli è morto per la verità. Egli scappava quando volevano ucciderlo, non si metteva lì a farsi torturare; ha accettato la follia del male solo quando era giunta la sua ora. A una vittima potremmo dire: “Se quella persona ti ha fatto del male, tu dimostrale che le vuoi bene!”. Per quanto possa essere un consiglio poeticamente sincero e astrattamente vero, si tratta di un discorso non immerso nella carne delle vittime, che hanno bisogno di un percorso di riconciliazione che prevede la riaffermazione della verità e della giustizia. Non si può chiedere a una vittima di banalizzare il male; si può chiedere di avviare un processo di riconciliazione che ristabilisca la verità. L’essere cristiani non è farci vittime degli altri o essere dei masochisti amanti del dolore e della morte, ma è accogliere nella verità quello che ci accade, portare la vita di Dio nella storia. Noi non dobbiamo dimostrare il bene esponendoci al male, non siamo chiamati al vittimismo ma ad essere innalzati sulla croce, a rivelare che Dio è con noi anche nei momenti in cui siamo rinnegati, a rivelare che il dolore che irrimediabilmente incontriamo non ha l’ultima parola. Gesù non sorride sotto la croce, non minimizza, vive nella carne il cielo, dice: “Perdonali, perché non sanno quello che fanno!”. Gesù sa perfettamente che stanno compiendo il male, non fa finta che il male non ci sia! Perdonare non vuol dire far finta che il male non ci sia stato. Possiamo capire così perché il Signore con i farisei avesse questo linguaggio schietto, fermo, che ad alcuni suscitava la fede, ad altri, invece, suscitava di volerlo uccidere. Gesù è veramente l’immagine perfetta dell’umanità che ama. Gesù vede l’uomo accecato che lo vittimizza, vede i suoi amici abbandonarlo, vede gli altri crocifissi agonizzare, vede sua madre ai piedi della croce e rivela come muore Dio, con le braccia aperte, vittima gloriosa di coloro che ama. Ha provato a fuggire dalla lapidazione, è andato da una città all’altra, ha parlato, ha chiesto conto del perché lo schiaffeggiassero, ha rimproverato la mancanza di giustizia ponendo al centro i poveri e gli esclusi, ha resistito sotto i colpi di frusta, ha rivolto lo sguardo a chi lo tradiva, si è definito verità, e poi ha accolto le conseguenze del suo mostrarsi senza infingimenti: Dio con noi, <em>Io sono</em>! Gesù non era un bonaccione ma la bontà in persona, perciò sulla croce Dio non dimostra amore ai suoi crocifissori ma dona amore gratuito. Il concetto di dimostrazione inteso come atto di convincimento può farci cadere in situazioni abusanti, che partono dal dover convincere chi ci fa del male a volerci bene. Perché Gesù invece di farsi lapidare è andato via? Non doveva avvicinarsi a coloro che lo volevano uccidere e fargli una carezza mentre alzavano la pietra per scagliarla contro di lui? O forse all’uomo accecato dall’odio doveva dare spiegazioni? Perché Gesù chiede conto e sollecita anche con il silenzio la coscienza di chi ha di fronte? Perché Gesù sulla croce non muore in silenzio ma invoca il perdono per i suoi carnefici? Una donna maltrattata dovrebbe resistere ai colpi ricevuti per dimostrare l’amore? Un uomo abusato dovrebbe stare in silenzio per dimostrare di essere buono o virile? Il cristiano è chiamato a farsi uccidere eroicamente per i suoi ideali come un buon filosofo o ad amare come Gesù, nella verità? Forse si potrebbe pensare che non denunciare il male sia un modo di dimostrare la nostra bontà o che non fuggire davanti ai colpi sia un giusto dono da fare a Dio, una dimostrazione del bene. Quando l’amore deve essere “dimostrato”, fallisce nella presunzione di voler essere riconosciuto. L’amore non si impone, non si dimostra ma si dona, disarma l’altro, rinuncia alla violenza, fa gesti di custodia davanti all’orrore e all’errore, si compiace della verità, crede nel bene, scommette sul ristabilimento delle relazioni, e quando chi ama è costretto a morire, fa diventare la croce uno strumento di salvezza e di pace. Nella spiritualità della comunità c’è una frase che accompagna la meditazione della preghiera delle comunità: “La verità senza carità ferisce, la carità senza verità fallisce!”.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-11';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Il Signore si riferisce alle situazioni più difficili, quelle che costituiscono per noi il banco di prova, quelle che ci mettono di fronte a chi ci è nemico e ostile, a chi cerca sempre di farci del male. In questi casi il discepolo di Gesù è chiamato a non cedere all’istinto e all’odio, ma ad andare oltre, molto oltre. Andare oltre l’istinto, andare oltre l’odio. Gesù dice: «Amate i vostri nemici, fate del bene a quelli che vi odiano» (Lc 6,27). E ancora più concreto: «A chi ti percuote sulla guancia, offri anche l’altra» (v. 29). Quando noi sentiamo questo, ci sembra che il Signore chieda l’impossibile. E poi, perché amare i nemici? Se non si reagisce ai prepotenti, ogni sopruso ha via libera, e questo non è giusto. Ma è proprio così? Davvero il Signore ci chiede cose impossibili, anzi ingiuste? È così? […]  Durante la passione, nel suo ingiusto processo davanti al sommo sacerdote, a un certo punto riceve uno schiaffo da una delle guardie. E Lui come si comporta? Non lo insulta, no, dice alla guardia: «Se ho parlato male, dimostrami dov’è il male. Ma se ho parlato bene, perché mi percuoti?» (Gv 18,23). Chiede conto del male ricevuto. Porgere l’altra guancia non significa subire in silenzio, cedere all’ingiustizia. Gesù con la sua domanda denuncia ciò che è ingiusto. Però lo fa senza ira, senza violenza, anzi con gentilezza. Non vuole innescare una discussione, ma disinnescare il rancore, questo è importante: spegnere insieme l’odio e l’ingiustizia, cercando di recuperare il fratello colpevole» (papa Francesco). </span></em></span></p>
<p>
 <em><span>«Il perdono deve essere accompagnato dalla verità. Non perdoniamo soltanto perché ci sentiamo impotenti e complessati. Spesso si è confusa l’espressione «porgi l’altra guancia” con l’idea della rinuncia ai nostri legittimi diritti. Non si tratta di questo. Porgere l’altra guancia significa denunciare e interpellare a chi lo ha fatto, con un gesto pacifico però deciso, l’ingiustizia che ha commesso; è come dirgli «Mi hai picchiato in una guancia. Allora, vuoi picchiarmi anche nell’altra? Ti sembra corretto il tuo comportamento?». Gesù rispose con serenità al servo insolente del sommo sacerdote: «Se ho parlato male, dimostrami dov’è il male; ma se ho parlato bene, perché mi percuoti?» (Gv 18,23). Vediamo, dunque, quale deve essere la condotta del cristiano: non cercare la rivincita, però si mantenersi fermi; essere disposti al perdono e dire le cose con chiarezza. Certamente non è un’arte facile, però è l’unico modo di frenare la violenza e manifestare la grazia divina a un mondo spesso privo di grazia. San Basilio ci consiglia: «Fate caso e dimenticherete le ingiurie e gli oltraggi che vi giungano dal prossimo. Potrete vedere i nomi diversi che avrete l’uno e l’altro; a lui lo chiameranno collerico e violento, e a voi mansueti e pacifici. Lui si pentirà un giorno della sua violenza e voi non vi pentirete mai della vostra mansuetudine» (don Joaquim Meseguer García). </span></em></p>
<p>
 <em><span>«Sono i gesti di Gesù che spiegano le sue parole: quando riceve uno schiaffo nella notte della prigionia, Gesù non risponde porgendo l’altra guancia, ma chiede ragione alla guardia: se ho parlato male dimostramelo. Lo vediamo indignarsi, e quante volte, per un’ingiustizia, per un bambino scacciato, per il tempio fatto mercato, per le maschere e il cuore di pietra dei pii e dei devoti. E collocarsi così dentro la tradizione profetica dell’ira sacra. Non ci chiede di essere lo zerbino della storia, ma di inventarsi qualcosa – un gesto, una parola – che possa disarmare e disarmarci. Di scegliere, liberamente, di non far proliferare il male» (p. Ermes Ronchi).</span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-11';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>«Se lo lasciamo continuare, tutti crederanno in lui». Il centro di molti dei nostri problemi non è discernere se ciò che esaminiamo o viviamo sia vero, buono e bello, ma se intacca il nostro spazio e il nostro potere. I farisei usavano abusare del loro potere per fare del male. È chiaro che il sommo sacerdote, autorità spirituale e morale per quell’anno, aveva “pensato bene” di profetizzare che Gesù doveva morire per salvare la nazione intera, cosicché molti volevano uccidere Gesù. Aveva usato il suo ruolo e il suo ascendente per dire a tutti che Gesù era un pericolo per la nazione, da eliminare. Nel mondo, qualsiasi ruolo abbiamo nella società, dobbiamo sapere che le nostre parole possono benedire o maledire, possono creare guerre o mettere pace; le nostre parole possono essere persino armi che feriscono e uccidono. Gesù è costretto a fuggire a causa di maldicenze e dell’odio perpetuato verso di lui. Tutti, dobbiamo essere consapevoli di avere piccoli e grandi poteri. Ci liberi il Signore da ogni forma di abuso nelle nostre relazioni! Anche un marito o una moglie possono abusare del loro potere: quante profezie di sventure facciamo sugli altri ogni volta che li screditiamo o miniamo il loro valore. Vale lo stesso nei posti di lavoro, nelle chiese, nella comunità religiosa, in ogni gruppo umano. Il Signore ci faccia portatori di pace, persone costruttive, così da preoccuparci prima di tutto di amare sempre e comunque. Allontaniamoci da ogni forma di maldicenza sulla vita degli altri e di abuso, che fanno perdere il rispetto per il valore sacro della vita e della dignità dell’altro e soprattutto nascondono Dio dal nostro orizzonte.  </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-12';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«Oggi esistono alcune malattie: manipolatori dotati di fascino, persone che seducono, che hanno un lato gentile o affascinante e non accettano oppositori o dissidenti. Ti amano e il giorno in cui non balli la loro musica ti rendono la vita impossibile. Esiste il ricatto emotivo e gli autori degli abusi diventano vittime quando vengono contraddetti o hanno un’opinione diversa. Dobbiamo aprire gli occhi e creare comunità dove ci sia trasparenza e verità, uomini e donne maturi, che riconoscano i propri limiti e si lascino aiutare. Dobbiamo ripulire le nostre vite e ‘disingannarci’. Dobbiamo aiutare chi protegge i propri complessi utilizzando rigidità ed eccessivo autoritarismo nei confronti degli altri» (p. Miguel Márquez Calle).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-12';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Leggendo il Vangelo della passione possiamo visualizzare nella nostra mente questa storia crudele, suddividendo automaticamente buoni e cattivi. Abitualmente noi siamo dalla parte dei buoni! In realtà dentro di noi vivono le stesse contraddizioni che caratterizzano l’umanità, le stesse che ci fanno scappare davanti al pericolo, che ci fanno prendere accordi con i potenti, che ci fanno “lavare le mani” davanti alle responsabilità, che ci fanno tradire il Signore per un tornaconto umano, che ci fanno leggere le sofferenze come punizioni. È difficile per noi accettare che il nostro cuore, come diceva Manzoni, è un guazzabuglio, un centro di intricati sentimenti che spesso emergono soprattutto nei momenti di crisi. Essere dei cristiani autentici alla luce della passione di Gesù ci chiama ad entrare in noi stessi per rendere la nostra fede vita concreta, iniziando ad accettare la nostra vulnerabilità, ammettere che siamo deboli, fragili, influenzabili dal mondo. Quando neghiamo tutto ciò, cominciamo a praticare la fede d’apparenza, che non va nel profondo, non incarna Cristo nel mondo ma vive del “sembrare di Cristo”. Davanti alla prova, però, cadono le maschere dell’apparenza e si manifesta la persona, quella che fa finta di essere buona mentre dentro, come tutti, è capace di tradire, rinnegare, falsificare. Se non partiamo da questa consapevolezza ma coltiviamo l’intima presunzione di essere giusti, non incarneremo mai una fede autentica. La passione ci invita ad attraversare queste immaturità che mettiamo in atto, che rendono la vita difficile a noi e agli altri, che rendono Gesù un uomo innocente che soffre ma non il redentore, cioè Colui che è venuto a salvarci dal nostro peccato, dalle nostre schiavitù, dalle nostre mancanze di fraternità. Il giorno delle Palme possiamo mettere in scena una contraddizione talvolta presente nella nostra vita. Mentre sventoliamo i ramoscelli per accogliere Gesù, quel Gesù relegato ai giorni di festa, poi gridiamo: “vogliamo Barabba!”, nell’ora della prova. Anche noi possiamo relegare Gesù ai giorni di festa: non lo facciamo? Possiamo essere quelli che vanno in chiesa e poi quando c’è da truffare l’assicurazione e risparmiare qualcosa, chiudiamo un occhio. Possiamo essere quelli che tengono a Gesù nelle feste comandate e poi vivono come se non ci fosse nella quotidianità. Possiamo essere di quelli che non sgarrano un digiuno il venerdì e poi non pagano adeguatamente le donne delle pulizie o i propri operai, o trattano con poco rispetto quelli della loro casa. Gesù per noi può diventare il manto da vestire per dire a tutti: “siamo brave persone”. Anche noi, cari fratelli e sorelle, possiamo essere non incarnazione di Cristo ma gente di facciata, animatori di divisioni e violenze, persone che chiudono gli occhi davanti al bene e voltano le spalle al fratello. Il Vangelo non è la mentalità del mondo, perciò lo Spirito di Dio proprio nel giorno in cui siamo in festa e sventoliamo le palme della gioia ci racconta la crocifissione, per ricordarci di partire da noi. Ci sono tante guerre nelle famiglie, nei quartieri, nel vicinato, fra i parenti, nelle comunità cristiane; e noi dove siamo collocati? Il crocifisso ci ricorda l’amore disinteressato, la pace da costruire, la verità da elevare, la vera regalità che non è quella del dominio, la carità che sembra fallire e morire, ma risorge sempre più luminosa. Noi davanti a ciò vogliamo fare veramente spazio al crocifisso risorto che porta la speranza o vogliamo vivere secondo il mondo, con i criteri del mondo, con i suoi principi? Proprio i discepoli hanno fatto una esperienza di Dio che li ha portati a confrontarsi con le loro vulnerabilità, e a partire da esse hanno deciso di fare spazio alla Spirito Santo, così da fuggiaschi sono diventati evangelizzatori capaci di morire come Cristo stesso, innocenti e risorti. Don Tonino Bello, ha usato parole bellissime per ricordarci cosa significa vivere da cristiani: <em>«Non fidatevi dei cristiani “autentici” che non incidono la crosta della civiltà. Fidatevi dei cristiani “autentici sovversivi” come san Francesco d’Assisi che ai soldati schierati per le crociate sconsigliava di partire. Il cristiano autentico è sempre un sovversivo. Uno che va contro corrente non per posa ma perché sa che il Vangelo non è omologabile alla mentalità corrente" (A. BELLO, Senza misura. Riflessioni sulla carità, La Meridiana, Molfetta 1993, 61)</em>.</span></p>

<p>
 <span>PREGHIERA</span></p>
<p>
 <span>Nel giorno in cui sventoliamo le palme della festa e della pace, ricordaci Signore di muovere queste fronde anche nel nostro cuore, perché sia ripulito da tutto ciò che non viene da Te. Tante volte abbiamo tradito il comandamento: “Amatevi gli uni gli altri, come io ho amato voi" facendo spazio all’odio, cancro del cuore che genera guerre. Aiutaci tu Signore, prepara in noi la Pasqua del cuore, affinché possiamo vivere da risorti.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-13';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>All’inizio della Settimana Santa ci immettiamo nel Vangelo di Giovanni che ci racconta una giornata conviviale di Gesù, invitato a cena dal suo amico Lazzaro che aveva risuscitato dai morti. Non solo Gesù viveva l’amicizia sincera ma in quella casa l’affetto e la gratitudine erano palpabili, al punto che Maria pensò di prendere un costosissimo profumo e di bagnare i piedi di Gesù per poi asciugarli con i suoi capelli. La casa sprigionava quell’aroma profumato e quella scena dolce e commovente sicuramente toccava il cuore. Che amore grande che avevano per Gesù! Ma Giuda non sa assaporare la bellezza di ciò che vede, si preoccupa dello spreco del profumo, è interessato a quanto si poteva guadagnare vendendo quell’essenza così preziosa. Il Vangelo ci tiene a ricordarci che i poveri erano messi in mezzo al discorso di Giuda in modo strumentale, perché erano i soldi l’interesse vero. Gesù, però, risponde a Giuda cogliendo l’occasione per annunciare la sua morte e per ricordare al fratello (preso più dalla sete del guadagno che dalla bellezza di quel gesto) che stava assistendo a un momento d’amore vero. Gesù, in un certo modo, sembra dirgli: “i poveri potete amarli e aiutarli sempre, quanto a me, mi dimostrate il vostro amore?”. Che belle le parole di Gesù che ci invitano ad apprezzare i gesti d’amore spontanei e profondi che fanno bella l’umanità. Egli ci invita ad amarlo, ad esprimere con Lui con i sentimenti più belli che abbiamo. Spesso, anche nelle nostre case e nelle nostre relazioni, abbiamo vergogna di fare dei gesti d’amore: dimentichiamo che le carezze, gli abbracci, i baci, le tenerezze sprigionano profumo nelle nostre case. Non dimentichiamo mai che è più importante far sentire le persone amate, perché l’amore viene prima. È normale che la moglie, il marito, i figli hanno bisogno del denaro per comprare le cose utili, ma siamo disposti a rinunciare all’utilità per fare un gesto d’amore gratuito, donando qualcosa che faccia sentire semplicemente amato l’altro? Noi spesso siamo attenti agli sprechi, alla giustizia di ciò che facciamo, dimenticando di far sentire amate le persone. Anche quando ci riuniamo per qualche servizio, la perfezione spesso va a discapito delle relazioni. Perciò capita anche in chiesa che dobbiamo cantare bene, dobbiamo operare in modo efficace e funzionale, dobbiamo organizzare eventi, poi però possiamo ferire l’altro, non farlo sentire amato. Per mantenere i nostri piccoli spazi di potere e i nostri princìpi siamo disposti a litigare, e forse coltivando questo rancore arriviamo pure all’estremo; come quelli che, seppure esperti delle cose di Dio, decisero di far uccidere non solo Gesù ma anche Lazzaro, perché la sua resurrezione era una testimonianza scomoda. La storia di quell’uomo uscito dalla tomba attirava curiosità e molti credevano in Gesù proprio per quell’evento. Riusciamo anche noi a pensar male di tutto e tutti quando filtriamo ciò che guardiamo con occhi malati, quando utilizziamo uno sguardo severo, cosicché l’amore soccombe davanti alle nostre idee di bene. Riusciamo non solo a non far sentire amate le persone ma critichiamo anche l’amore che vediamo negli altri: riusciamo a non gioire di un uomo risorto dalla tomba! Così facendo pian piano il cuore si chiude e decidiamo di voler rendere infelice chiunque non rientri nei nostri parametri e intralci i nostri piani. Non rifiutiamo la bellezza; siamo pazienti davanti al bene espresso dagli altri anche quando non è “perfetto”; non cataloghiamo in schemi ottusi ogni cosa! Dio interviene in modo non preconfezionato, lo Spirito agisce dove vuole e in modi sorprendenti. Impariamo a riconoscere e rispettare prima di tutto la fraternità, l’amore che dobbiamo custodire e che ci designa come cristiani (cf Gv 13,35). Ci sono tante persone fraterne in mezzo a noi che costruiscono la pace. Quanti uomini e donne imparano e vivono l’arte del silenzio, la mitezza pacificatrice, fanno doni disinteressanti, gioiscono del bene altrui, sanno puntare all’amore, distribuiscono sorrisi gratuiti che aprono il cuore. </span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-14';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><em><span>«L’amore degli uomini non è un mezzo rispetto all’amore di Dio. L’amore di Dio è uno stato nel quale non si può non amare soprannaturalmente gli uomini.  I mezzi che il Cristo ci ha dato per realizzare l’amore di Dio sono dunque, nello stesso tempo, quelli che ci permetteranno di realizzare l’amore degli altri. La prova dell’autenticità d’una vita di Chiesa e di Vangelo sta nella sua intensità d’amore soprannaturale per gli altri: “Colui che non ama il fratello che vede, come potrà amare Dio che non vede?» (Madeleine Delbrêl).</span></em></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-14';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>«Uno di voi mi tradirà»; «prima che il gallo canti tre volte…». Queste sono le parole con cui Gesù annuncia i tradimenti più emblematici, parole rivolte a traditori, a chi rinnega il suo amore. Capita che per compromessi umani o per debolezza anche noi siamo disposti a rinnegare il Signore, non schierandoci dalla parte del bene. Sì, perché il bene va indicato chiaramente, non possiamo solo predicarlo: ci mette in gioco, ci ferisce, a volte ci espone al dolore, a pagare in prima persona. Partendo da ciò, dovremmo guardare al nostro cuore e sentirci capaci di tradire profondamente il Signore. Noi ci descriviamo sempre come buoni e bravi; invece, quante volte siamo pronti a voltare le spalle quando ci sentiamo chiamati ad agire, chiamati in causa. Quante povertà ci passano vicino e non le vediamo, quante volte quando gli amici deridono chi è credente preferiamo stare zitti, quante volte cambiamo strada pur di non incontrare quel nemico da perdonare. Lo facciamo spesso perché stare dalla parte di Dio costa tanto dal punto di vista umano, ci richiede una radicale coerenza. Dovremmo esaminarci ogni volta che qualcuno ci espone un suo problema e noi non lo prediamo a cuore sul serio, ogni volta che possiamo fare del bene ma abbiamo fretta, ogni volta che tentiamo di nasconderci dinanzi alle responsabilità, ogni volta che i nostri calcoli opportunistici valgono più del bene comune o del bene della persona che abbiamo davanti. Gesù è stato tradito prima di tutto dal silenzio, dall’ipocrisia di chi gli dava un bacio, dalle parole di chi ha detto quando l’ha visto nei guai: “io non ti conosco”. Possiamo essere noi questi pusillanimi, quei meschini che non si vogliono scomodare per il bene altrui, soprattutto quando temono di perdere qualcosa. I poveri, infatti, quelli dietro i quali si nasconde la presenza di Gesù, portano problemi, ti creano grattacapi; difendere chi è oppresso significa prendersi sulle spalle la sua stessa oppressione. Quando c’è da pagare personalmente per fare il bene, il rischio è quello di fuggire, entrare in confusione, dimenticare l’amore, non purificare i pensieri, rinnegare la realtà, pensare alla sopravvivenza personale, mancare di giudizio.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-15';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>«La preparazione (al male) è giunta a buon punto quando gli individui hanno perso il contatto con i loro simili e con la realtà che li circonda; perché insieme con questo contatto, gli individui perdono la capacità di esperienza e di pensiero» (Hannah Arendt).</em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-15';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Trenta monete: ecco quanto vale la vita del Signore; vale poco la vita di chi è venduto, come fosse una merce! Un destino simile toccò a Giuseppe, venduto dai suoi fratelli per invidia, come narrato nel libro della Genesi (cf Gn 37,28): prima lo gettarono in una cisterna, poi lo cedettero per denaro. Un tradimento nato da sentimenti meschini, eppure Giuseppe, colui che venne venduto, sarà lo stesso che li salverà dalla carestia. Anche Gesù fu consegnato per invidia. Essa non fa provare giovamento, fa corrodere l’animo di chi la prova, rende infelici. L’invidioso subisce già la conseguenza del suo peccato! Chi invidia, infatti, non prova piacere, si strugge dentro e desidera vedere eliminato l’altro; quel desiderio di violare la dignità dell’altro, gli si tramuta in veleno che gli scorre dentro. Come diceva san Tommaso d’ Aquino: <em>«L’invidia è tristezza per il bene d’altri in quanto ostacolo alla propria superiorità» (Summa Th., II q. 36).</em> Giuda, come i fratelli di Giuseppe, sentiva di aver capito tutto, di voler esercitare una certa superiorità sugli eventi, sulla storia, sulla stessa idea di Dio. È a Gesù che quel fratello scelto e amato darà un bacio traditore; e Gesù lo guardò negli occhi, gli mostrò di conoscere le sue intenzioni, e in qualche modo gli disse: “so già che dimenticherai l’amore che ho avuto per te per farti assoldare dal potere, per obbedire alle tue passioni e a quelle degli altri”. Giuda, ingannato dai farisei, inganna Gesù: bacia l’Amore per tradirlo. Oggi esaminiamoci, piangiamo pure se sentiamo il “sangue verde” dell’invidia che scorre dentro di noi; se sentiamo di essere così miseri da sperare miseria per gli altri. L’invidia è la prima figlia della superbia, che possiamo immaginare nel volto di Caino che pensa che Dio ami più Abele; la riconosciamo in azione con il codardo Pilato consapevole che: «i capi dei sacerdoti [avevano consegnato Gesù] per invidia» (cf Mc 15,10); la sentiamo citare nel canto delle donne che si accorsero del tarlo che rodeva Saul: «Saul ne ha ucciso mille, ma Davide diecimila» (cf 1 Sam 18, 7). L’invidia corrompe le relazioni e ci porta, come tutti i vizi, all’infelicità, come ha fatto con i personaggi che abbiamo citato, soli con la loro passione triste. Per riconoscere l’invidia possiamo dire che a primo acchito essa ci porta non a offendere l’altro ma a diffamarlo, perché l’invidioso ha sempre bisogno di complici e alleati. Teologicamente possiamo chiamare lo sparlare una “detrazione”: <em>«Pare che la detrazione sia il più grave di tutti i peccati contro il prossimo. […] La detrazione, […] non nasce dall‘ira, come la contumelia, ma dall‘invidia, che tenta di sminuire in qualsiasi modo la fama del prossimo» (S. Tommaso d’Aquino, Summa Th., Questio 73).</em> Anche in noi l’invidia si rivela e si accresce ogni volta che sparliamo del prossimo, ogni volta che superficialmente ci accostiamo alla vita altrui e tentiamo di sporcarla agli occhi degli altri e con la complicità degli altri! Esaminiamo perciò il nostro cuore.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-16';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span>«L’invidioso, quando avverte ogni innalzamento sociale di un altro al di sopra della misura comune, lo vuole riabbassare fino ad essa […] Egli pretende che quell’uguaglianza che l’uomo riconosce, venga poi anche riconosciuta dalla natura e dal caso. E perciò si adira che agli uguali le cose non vadano in modo uguale» (F. Nietzsche).</span></span></em></p>
<p>
 <em><span><span> «Vorreste vedere Dio glorificato da voi? Ebbene, rallegratevi dei progressi del vostro fratello, ed ecco che Dio sarà glorificato da voi. Dio sarà lodato  si dirà  dalla vittoria sull''invidia riportata dal suo servo, che ha saputo fare dei meriti altrui il motivo della propria gioia» (San Giovanni Crisostomo). </span></span></em></p>

<p>
 <em><span><span>Il santo del giorno: </span></span></em></p>
<p>
 <em><strong>San Benedetto Giuseppe Labre</strong><span>, pellegrino</span></em></p>
<p>
 <em><span>«"Il pellegrino della Madonna”, “Il povero delle Quarantore”, “Il penitente del Colosseo”, “Il nuovo sant’Alessio”. Così il popolo romano chiamava Benedetto Giuseppe Labre, che morì a Roma a 35 anni. Un francese che trascorse parte della sua breve vita come pellegrino, sostando in preghiera davanti alle immagini più care della Madonna e davanti all’Eucarestia. San Benedetto Giuseppe Labre, nacque ad Amette il 26 marzo del 1748, primo di quindici fratelli. Più tardi potè entrare nei Certosini, da cui usci quasi subito, e fra i trappisti di cui pure dovette allontanarsi per grave malattia. Di nuovo libero, si mosse al pellegrinaggio di Roma, secondo il voto fatto durante la convalescenza. Durante il viaggio ebbe una luce interna così viva sulla vocazione che gli era riservata, che non ne dubitò mai più. Egli diceva come S.Alessio: "Bisogna  abbandonare la patria ed i propri parenti, per condurre una nuova specie di vita di estrema penitenza, ma in mezzo al mondo, visitando in pellegrinaggio i Santuari cattolici più celebrati". Si decise, adunque, dopo ripetute approvazioni di direttori spirituali, ad iniziare la lunga serie di pellegrinaggi, che durò tutta la sua vita. Vestì un abito rozzo e logoro, trascurando ogni norma di igiene personale: non domandò mai elemosina: visitò nei primi sei anni Loreto, Assisi, Compostella, nella Spagna, i Santuari della Svizzera e della Francia. Gli ultimi sei anni li trascorse a Roma, da dove ogni anno partiva per una visita alla Santa Casa di Loreto. Poichè la più dolce compagnia di Benedetto Labre è Gesù e Maria, il Santuario dove si compì il mistero della Incarnazione, il Santuario testimone di tutte le virtù intime della Sacra Famiglia, Benedetto che portava pure il nome di Giuseppe e che onorava grandemente il casto Sposo della Santa Vergine, vorrebbe non abbandonarlo mai: ed infatti egli non se ne allontanerebbe, se il senso cristiano di cui egli è ben penetrato, non gli avesse fatto conoscere in Roma una fonte ancor più feconda di vita religiosa che in qualsiasi altro luogo. A Roma passa i suoi giorni e, quando può, anche le sue notti nelle chiese: egli sa venerare tutte le memorie dei Santi Apostoli e dei Martiri. Là egli è assiduo in tutte le chiese, secondo i turni fissati, dinnanzi al Santissimo Sacramento, tanto che a voce di popolo viene battezzato il povero delle Quarantore. Lo si vedeva dinnanzi all''altare ora immobile come una statua, ora trasportato verso Dio da un impulso che si manifesta dal suo atteggiamento esteriore. Attraverso tutti gli strappi delle sue vesti il lume della grazia, direi quasi della gloria, sfolgora da ogni parte: "Vedete dunque questo povero, esclamava un giorno una donna, come è buono! come è bello! Bello?! Sì: la stessa scrittura che ci dipinge Gesù Cristo come l''uomo abietto e l''ultimo degli esseri, ce lo rappresenta altrove il più bello dei figli degli uomini. Ora Benedetto Labre ha conciliato in sè questo doppia caratteristica, che i profeti avevano dato di Cristo: un tipo superiore si rivela attraverso questa grossolana corteccia. Egli è il rifiuto del mondo, eppure nè è il fiore. </span></em><em><span><span>Alla fine, logoro dalle austerità, Benedetto Labre il 16 aprile del 1783 cadde sui gradini della Chiesa di S. Maria dei Monti a Roma e, portato in una casa vicina, vi morì. La sua morte fu seguita da una grande quantità di grazie e di miracoli. Fu beatificato da Pio IX nel 1839 e canonizzato da Leone XIII l''8 dicembre 1883» </span></span></em><em><span><span>(Don Luca Roveda).</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-16';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>«Li amò fino alla fine»: un’espressione bellissima che ci ricorda che siamo tutti amati, in ogni circostanza e situazione. Gesù dimostra un amore immutabile per l’umanità: pensiamo che, mentre il suo amico Giuda aveva nel cuore di tradirlo, Gesù si mise a lavare i piedi ai discepoli, in un modo così umile che Pietro esclamò: “Tu non laverai i piedi a me!”. È vero che il Signore ci ama, eppure spesso ci sentiamo soli, non visti; il nostro dolore, le nostre ferite, i tradimenti ricevuti, quella perdita della persona amata, tutta la nostra sofferenza ci logora dentro e sembra gridarci: “Dio non si cura di te!”. Eppure è proprio la lavanda dei piedi che ci dà un indizio: «come io ho lavato i piedi a voi, fate altrettanto». Dio ti ama anche tramite gli altri, tramite quell’incontro che hai fatto, tramite quel nuovo amore, quella nuova amicizia, Dio ti ama anche attraverso ciò che ti circonda, anche nella comunità. Possiamo accorgerci che Dio è presente nella realtà, nell’amore che ci ha insegnato che sa di eternità. Gesù scommettendo sulla fraternità ci insegna ad essere veramente cristiani, sue prolunghe nel mondo.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-17';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span><em>«Ti ringrazio, Signore, perché ti manifesti a noi come non ci aspetteremmo, in maniera sempre inedita, nuova, sorprendete. Ti chiediamo che neppure un briciolo di questa manifestazione resti nell’aria, ma che subito si applichi a tutte quelle situazioni nella quali riconosciamo vicino a noi qualcuno che ti rappresenta , che rivela il tuo volto. Concedici, Signore, una vita quotidiana pratica, illuminata e approfondita nella conoscenza nell’amore della tua Passione e morte.  Guidaci in questa ricerca difficile nella quale possiamo facilmente illuderci. Fa che le parole che pronunciamo e che ascoltiamo siano percepite come parole serie, che un gioco ci potranno condannare se restano solo verbali. Salvaci Signore per la tua misericordia, tu che ci dono lo Spirito e vivi e regni nel secoli dei secoli. Amen» (Card. Carlo Maria Martini). </em></span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-17';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>La passione e morte di Gesù mette in comunione pienamente il cielo e la terra, apre i nostri dolori all’eternità. Quando siamo nel dolore, quando siamo vittime di soprusi, di abusi, di incomprensioni o di qualsiasi male, sentiamo di essere soli, inondanti da una coltre di fango che ci soffoca. Contemplare la passione di Gesù significa metterci davanti alle conseguenze del peccato, aprendo le braccia alla speranza. Il Signore non ci ha dato consolazioni a buon mercato, non ci ha detto parole di circostanza né ci ha regalato poemi o spiegazioni sulla sofferenza: ci ha mostrato che anche quando il male ci assale e ci rende impotenti, anche quando siamo costretti a mostrare la nostra faccia sfigurata dal dolore, anche in quel momento l’ultima parola è sempre quella di Dio. Possiamo decidere, perciò, come vivere il nostro dolore, consapevoli che tutto finirà comunque nelle mani di Dio. </span><span>Allo stesso tempo la passione di Gesù ci mostra come anche noi possiamo essere consolatori degli altri o fautori di soprusi. Stiamo attenti, perciò, non banalizziamo ciò che si muove dentro di noi, anche le parti più oscure. Possiamo essere noi quelli che gridano “crocifiggilo”, quelli che non stanno vicino alle persone quando conta la loro presenza, che si lavano le mani quando si devono schierare per salvaguardare il debole, che per paura dicono di non conoscere Gesù, che schiaffeggiano e insultano, che deridono.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-18';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span>«Chi è Gesù dinanzi a me? È ogni mio fratello vittima delle mie ripicche, delle mie rivalse, del falso uso della mia libertà. Continua in noi, attorno a noi e accanto a noi questo gioco drammatico di Gesù e Giuda, questo malinteso sostanziale di un uomo che, volendo vedere in se stesso, si butta contro gli altri. Dio non manda più il Figlio direttamente (ricordiamo la parabola dei vignaioli omicidi); ci manda i nostri fratelli, ci affida gli uni agli altri. Di ogni nostro fratello o sorella possiamo fare ciò che vogliamo, possiamo fare il peggiore uso della nostra libertà. È tremendo il pensiero che l’uso della liberà umana verso ogni altro essere non ha limiti, che Dio affida ciascun fratello a noi e noi agli altri. Così si realizza la scena finale del giudizio: vi siete riconosciuti? Che usa avete fatto della vostra libertà reciproca? Mi avete accolto? Vi siete accolti? Oppure vi siete serviti dell’altro come ha fatto Giuda con Gesù, quale oggetto di rivalsa, di rivincita, quale sfogo della vostra sete delusa si essere qualcuno? Occorre ragionare, evidentemente, non solo a livello familiare, bensì a livello sociale e politico: la rivalsa dei gruppi, le ripicche, i personalismi entrano in gioco in tutta la conflittualità della vita politica e sociale, nazionale e internazionale, costituendo le forze che incitano gli uni contro gli altri, che spingono alcuni a far valere il proprio orgoglio, magari mascherato da fini umanitari, ma sempre a scapito degli altri. [..] Sono la natura umana che è in ciascuno di noi, che alterna il servilismo ossequiante con la rivalsa cu chi ci sembra minore di noi. La rivalsa ha tante forme subdole: c’è per esempio una rivalsa culturale (di chi sa parlare verso chi non sa), una rivalsa dell’educazione (di chi ha modi fini verso chi non li ha); tutto ciò che serve a mantenerci in uno stato di superiorità. [I soldati ad esempio] sfogano su Gesù le loro frustrazioni, le ore di guardia pesantissime, la loro vita grigia, senza futuro, sempre col pericolo che capito loro qualcosa. […] Chiediamoci [anche] cosa c’è in noi di Pilato, cosa ci impedisce di essere liberi, quali sono le nostre paure, le nostre etichette, le vesti e le maschere che portiamo in pubblico, per cui non sappiamo rischiare; cerchiamo di scoprire tutte le nostre assurdità, la capacità di trascurare e calpestare l’altro per l’apparenza, per mantenere la facciata o il posto importante, o il buon giudizio della gente sulla nostra onorabilità, sulla nostra fama o buona stima. Parla con me dice il Signore fatti liberare» (card. Carlo Maria Martini).</span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-18';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span><span><em>Ascoltiamo oggi il Signore che parla nel silenzio…</em></span></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-19';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Pietro è superato sia da Maria sia da Giovanni ma nessuno gli toglie il primato dato da Gesù. Tutti vanno verso Pietro: Maria per avvisarlo, Giovanni per farlo entrare per primo. L’autorità, la maturità, la saggezza sono fondamentali, così come la passione, lo zelo, l’impazienza dell’innamorato. La Chiesa è il luogo in cui nessuno basta a sé stesso, nel quale non solo c’è posto per tutti ma tutti hanno posto e importanza. Qualsiasi altro tipo di andamento o di visione della Chiesa la farebbe cadere in estremismi, in uno snaturamento. La Chiesa è di per sé universale e fonte di diversità! Nell’istituzione, perciò, la necessità della gerarchia, fondamentale per la missione e il servizio della Chiesa, non annulla una dignità uguale fra i membri. Si tratta, infatti, di una dignità costituzionale che si fonda sul battesimo che ci rende tutti figli, dotati di un sacerdozio, di una regalità e una profezia comune.</span></p>
<p>
 <span>La Chiesa in passato è stata definita una società ineguale dove vigeva il verticismo; con il Concilio Vaticano II, si è ripresa la bellissima immagine di Chiesa come popolo di Dio che papa Francesco spiega così: <em>«Gesù, per la sua Chiesa, non ha adottato nessuno degli schemi politici del suo tempo: né farisei, né sadducei, né esseni, né zeloti. Nessuna “corporazione chiusa”; semplicemente riprende la tradizione di Israele: “Tu sarai il mio popolo e io sarò il tuo Dio» (papa Francesco, Congregazione generale della XVI Assemblea generale ordinaria del sinodo dei vescovi, 25 ottobre 2023).</em> Anche nel Diritto Canonico sta scritto: <em>«Tra tutti i fedeli, in forza della loro rigenerazione in Cristo, sussiste una vera uguaglianza nella dignità e nell''agire, e per tale uguaglianza tutti cooperano all''edificazione del Corpo di Cristo, secondo la condizione e i cómpiti propri di ciascuno» (can 208). </em>Avere la stessa dignità significa riconoscerci tutti come figli di Dio, figli di re, diversi ma con pari dignità. Ancora di più dovremmo ricordare che in cielo ci presenteremo come figli e non saremo giudicati in base ai titoli o alle gerarchie ma in base all’amore che avremo vissuto. È proprio avere consapevolezza del battesimo che dispiega il senso di ogni ministerialità, di ogni servizio, della gerarchia stessa. Alla luce della grazia del battesimo comune alcuni discorsi sarebbero banali, come quelli sul servizio femminile. Si dovrebbero infatti recuperare i fondamenti evangelici anche in questo. Pensiamo a Maria che arriva prima al sepolcro che può rappresentare questa presenza femminile missionaria che va valorizzata. Così come recuperare la velocità di Giovanni che può rappresentare i carismi che intercettano Dio nella storia. La bellezza della Chiesa, alla luce dell’insegnamento e della prassi di Gesù, possiamo vederla in questo Vangelo del giorno: Maria come donna è protagonista dell’annuncio, Giovanni arriva prima guidato dallo Spirito, Pietro custodisce, accoglie e viene riconosciuto nella sua paternità. Non dobbiamo perciò avere paura delle diversità, dobbiamo tutti poter dire: io sono figlio di Dio, nella mia unicità, nel mio servizio, Dio mi ha a cuore come ha a cuore i miei fratelli e le mie sorelle; è dall’amore e dal rispetto che ci riconosceranno. Perciò non si è “più Chiesa” perché si hanno dei carismi particolari o perché si arriva primi, non si è Chiesa se si fa a meno della gerarchia, così come non si è Chiesa pensando che il servizio istituito designi una superiorità nella dignità (cf CCC 872). Stiamo attenti a tutto ciò che trasforma la Chiesa in qualcosa che Gesù non ha vissuto e voluto. Perciò impariamo ad avere anche un linguaggio evangelico; il problema non dovrebbe essere se le donne devono o possono “comandare”, facendo persistere l’idea che chi è più in alto ha il privilegio del comando. Quando Gesù ha detto che nella Chiesa si comanda? O forse ci ha parlato con chiarezza del fatto che l’unico primato è quello del servizio? La Chiesa è il luogo dell’abbraccio universale di Dio all’umanità, a tutti i suoi figli, è il luogo in cui devono coesistere delle diversità, è il luogo in cui si dovrebbe sperimentare prima di tutto il linguaggio di Dio, la sua Presenza viva ed efficace.</span></p>


<p>
 <strong><span><span>PREGHIERA</span></span></strong></p>
<p>
 <span><span>Signore aiutaci ad essere persone che si sentono parte di un popolo, non di un’azienda del sacro. Rendici sicuri delle dignità che ci hai donato, e in funzione di ciò persone che sanno obbedire alla Tua presenza. Che la diversità dei ministeri diventi ai nostri occhi bellezza vera, obbedienza spontanea e gioiosa. Facci aprire gli occhi per essere sempre più simili a come ci hai pensati, diffusori dell’universalità dell’amore.</span></span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-20';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Che bello questo momento di gioia dopo il sepolcro! Sembra l’abbraccio liberante dopo aver sopportato l’orrore, la morte, la disperazione, la solitudine, il fallimento. Mentre si andava ancora a cercare Gesù nel luogo del dolore e della desolazione, si fa incontro nuovamente la vita. Il <em>“non temere”</em> è proprio l’ingresso all’abbraccio che giunge ai discepoli. A Gesù, infatti, non era nascosto il dolore dei suoi, la loro paura di aver fallito la vita, così come non gli è sconosciuto il nostro dolore. Perciò non solo Egli ci invita a non temere ma ci chiama a essere missionari della gioia della Sua presenza; ci dice: “io ci sono per te, vai a portare questa gioia al mondo!”. Gesù si fa abbraccio consolante delle nostre fragilità e ci dona la forza di partire, di andare verso gli altri, ci dice che l’ultima parola non sono il dolore e la morte. </span><span>Al contrario le guardie che giungono al sepolcro fanno l’esperienza della morte, pensano: “diciamo una bugia, mettiamo in giro una calunnia”. Per cui non solo era stato ucciso un innocente ma pensavano di accordarsi per colpevolizzare i suoi discepoli, accusarli di averlo trafugato. I soldati non fanno un’esperienza di gioia ma si calano nella morte. Possiamo dire che mentre la gioia parte in missione anche il male si incammina attraverso la calunnia. </span><span>Noi cosa vogliamo mettere in circolo, la gioia o la calunnia? Siamo portatori di luce o di oscurità?</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-21';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <em><span><span>«La calunnia non è il "venticello" di rossiniana memoria. È bensì un ciclone devastatore che abbatte ed uccide prima colui che ne è l''autore, poi i suoi destinatari diretti o indiretti. È soprattutto  la calunnia – è un peccato così obbrobrioso che non ci sono parole per definirlo ed esecrarlo a sufficienza. È, inoltre, peccato così diffuso non solo nell''ambiente sociale ma anche in quello ecclesiale, che rischia di perdere, data la sua sempre più allargata consistenza, quella abominevole malizia che ne fa il peccato satanico per eccellenza, frutto, inoltre, dell''odio e di una gratuita volontà distruttiva. Per questo mi sono sentito in dovere di metterne in guardia i miei fedeli» (vescovo Andrea Gemma).</span></span></em></p>
<p>
 <em><span><span>Nonostante la triste realtà della calunnia, ormai diventata quasi uno “sport” comune nella nostra società che si riempie di “false notizie”, Gesù ci chiama a rispondere con l’annuncio della Sua presenza. Purtroppo, anche all''interno della Chiesa, siamo chiamati a reagire a questo brutto male da definire satanico. Impariamo a scegliere la gioia come risposta e impegniamoci a diffondere pace e bene nel mondo.</span></span></em></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-21';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Perdere una persona cara o affrontare il dolore di una separazione è un’esperienza profondamente difficile, che lascia un senso di vuoto e una lacerazione nell’anima. In quei momenti sembra che anche la speranza svanisca, come se si spegnesse insieme all’amore per chi abbiamo perduto. Anche Maria, vicina al sepolcro, fa l’esperienza della delusione: non solo ha perso una persona cara ma pensa che abbiano trafugato le sue spoglie. In quel dolore le lacrime intercettano il cuore di Gesù che si presenta a lei nelle vesti di un giardiniere. È lì che Maria si sente chiamare per nome e riconosce la dolcezza del Signore; il “giardiniere della sua anima”, sa chiamarla con quel tono di una voce amica. Secondo Raymond E. Brown questo è l’unico punto nella Bibbia in cui si trova la parola <em>kēpouros</em>, cioè giardiniere. Vogliamo coglierne un’immagine utile alla nostra crescita. Dobbiamo essere consapevoli che Dio vuole curare il nostro giardino interiore, ed è capace di raggiungerci anche quando siamo nei pressi di un sepolcro per ricordarci la bellezza della nostra vita. È fondamentale, perciò, curare la nostra interiorità e farci aiutare in questo processo. Non dobbiamo dimenticare mai che abbiamo bisogno degli altri e ciò non significa che dobbiamo solo aiutare l’altro ma che l’altro mi aiuta a crescere, che ho bisogno di mediazioni umane. È consigliabile nella vita spirituale cercare un aiuto, una persona che mi affianchi per riconoscere alla luce del Vangelo la presenza di Dio; ma abbiamo anche bisogno di amicizia, di comunità, di familiarità vera e concreta. </span><span>L’altro insegnamento che vogliamo cogliere, in questi esercizi quotidiani, viene dal gesto che compie Maria quando si rende conto di essere davanti al Maestro. La gioia che prova la spinge a trattenere, ma Gesù (che non è mai un possesso) la chiama ad annunciare, cioè a donare; e lei lo fa, non si ferma a quel momento. Nelle prove più difficili della nostra vita il rischio è proprio quello di essere annebbiati dal dolore, di non vedere più Gesù che si presenta a noi oppure dopo averlo visto, di fermarci in uno stato di tranquillità. Così facendo non diamo spazio al giardiniere della nostra anima che ci apre alla bellezza della vita, all’ottimismo necessario per annunciare. Non richiudiamoci in noi stessi, apriamo il cuore al Signore, anche e soprattutto quando siamo davanti a un sepolcro.</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-22';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>
 <span><span>Anche se sono triste o disperato, Signore, so che sei qui, vicino a me. Se Tu sei qui, anche nella tenebra più fitta si accende una luce. E quella luce è il segno che la tua Vita è più forte. E la tua Vita è così forte da rimettermi in piedi, da asciugare le mie lacrime, da spingermi a gridare al mondo che perfino nella tristezza e nella depressione, perfino nella disperazione che attanaglia il cuore, c’è ancora un posto per la speranza, c’è ancora un posto per Te che sei Luce, Forza, Ottimismo irresistibile (don Fabrizio Centofanti).</span></span></p>', 'html', 2 FROM gospel_daily gd WHERE gd.date = '2025-04-22';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'main', NULL, '<p>
 <span>Due discepoli disorientati e delusi camminavano verso il villaggio di Emmaus e si raccontavano le loro pene. Gesù si fa loro vicino, intercetta la loro delusione, e loro si aprono e spiegano tutto a questo pellegrino sconosciuto che sembra ignaro dei fatti della sua terra. Il loro racconto è disfattista, è il ripercorrere una storia fallimentare che sembra aver segnato la loro vita, tant’è che dicono: «Noi speravamo che egli fosse colui che avrebbe liberato Israele; con tutto ciò, sono passati tre giorni da quando queste cose sono accadute». La delusione è palpabile e la mancanza di speranza è il motivo ricorrente del loro racconto: tutto ciò che loro speravano non era accaduto. Eppure, quel pellegrino, quello straniero, fa ripercorrere loro le Scritture, fa rivivere in loro la speranza di Israele, il ricordo di un Cristo che doveva patire, che non avrebbe vinto secondo criteri umani. Quando lo straniero si stava accomiatando da loro qualcosa li fa rimanere aggrappati a quella interpretazione nuova dei fatti e chiedono: “resta con noi!”. La prima opera che lo Spirito Santo fa nella nostra vita é donarci una lettura diversa delle cose. Lo Spirito Santo è proprio il narratore di Dio, Colui che viene a dirti: “falla raccontare a me la tua storia!”. Le cose raccontate da Dio, come la stessa Scrittura, fanno emergere la bellezza di un processo di salvezza, ci rivelano che Dio interviene anche quando ti sembra che per te sia stato preparato solo il deserto senza cibo, anche quando il mare che ti ostacola, il sopruso ti viene davanti, anche quando sperimenti il fallimento più totale. I discepoli di Emmaus che richiedevano speranza, che cercavano luce mentre erano nel dispiacere, vennero intercettati dai passi di Dio che si fermò con loro e spezzò il pane. Lì lo riconobbero: quel gesto e quella celebrazione parlò ai loro cuori. Noi spesso cerchiamo liturgie sofisticate, grandi oratori, spettacoli, eppure Dio, anche dalle mani del più vile sacerdote, si presenta come pane per noi. Oggi non dimentichiamo la grandezza di Dio che si spezza per noi, che non ci lascia soli nella delusione. Diciamo al Signore, davanti a quel pane spezzato: “grazie perché non solo sei capace di raccontami la mia storia non come una via fallimentare ma come un processo di salvezza, ma soprattutto perché ti doni come cibo per me, ti spezzi per me, ti fai riconoscere, vivo e presente”. E noi riconosciamo Dio nello spezzare il pane? Percepiamo la sua grandezza nascosta in quella piccola ostia? Lo riconosciamo anche nello straniero che si accosta a noi, nel povero, nel derelitto ai crocicchi delle strade? Riconosciamo la sua voce nel mondo e i suoi passi nel nostro cammino? Oggi come ti intercetterà Gesù?</span></p>', 'html', 1 FROM gospel_daily gd WHERE gd.date = '2025-04-23';
INSERT INTO comment_sections (gospel_daily_id, section_type, title, content, content_format, sort_order) SELECT gd.id, 'reflection', NULL, '<p>